INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1062783, 'Frankenstein', 'https://image.tmdb.org/t/p/original/sj7jCrV94LRzkxWcXKrwuf8V99j.jpg', 'Dr. Victor Frankenstein, a brilliant but egotistical scientist, brings a creature to life in a monstrous experiment that ultimately leads to the undoing of both the creator and his tragic creation.', 150, '16', '2025-10-17', 'Drama/Horror/Fantasy'),
(1062784, 'Czarny telefon 2', 'https://image.tmdb.org/t/p/original/9DYFa0yAZ8DUPZvxInElqh1ifwv.jpg', 'Four years after escaping The Grabber, Finney Blake is struggling with his life after captivity. When his sister Gwen begins receiving calls in her dreams from the black phone and seeing disturbing visions of three boys being stalked at a winter camp, the siblings become determined to solve the mystery and confront a killer who has grown more powerful in death and more significant to them than either could imagine.', 114, '16', '2025-10-15', 'Horror/Thriller'),
(1062785, 'Six jours', 'https://image.tmdb.org/t/p/original/foyiQu23zq4WhmffnQkFiNAvqcJ.jpg', '11 years ago, inspector Malik couldn’t solve a kidnapping case and a little girl died. Now with only a few days before the crime gets classified, he decides to reopen the case. Malik owes it to the mother and to himself. As he digs into the past, a child is kidnapped again. The pattern is the same one as a decade ago, it’s no coincidence. Malik knows he has a few days to make things right and to bring justice.', 95, '0+', '2024-12-11', 'Thriller/Action'),
(1062786, 'Predator: Strefa zagrożenia', 'https://image.tmdb.org/t/p/original/zzlCI1DKmnhx4jRL3vLiNkDK9qp.jpg', 'Cast out from his clan, a young Predator finds an unlikely ally in a damaged android and embarks on a treacherous journey in search of the ultimate adversary.', 107, '0+', '2025-11-05', 'Action/Science Fiction/Adventure'),
(1062787, 'End of Loyalty', 'https://image.tmdb.org/t/p/original/c4QA1rFQcyBZKaOOdUrDeL1G9Er.jpg', 'When the head of a notorious crime family is murdered, his son Grant is hell bent on payback and the only person that can stop him from tearing the city apart and destroying himself in the process is his best friend and federal agent, Ray Rose.', 90, '0+', '2023-03-07', 'Crime/Action'),
(1062788, 'Kod 3', 'https://image.tmdb.org/t/p/original/gIAYMDb5mIAeCAj76q1sRsKjkzo.jpg', 'A burned-out paramedic tries to survive his last 24 hours on the job while training a new recruit.', 104, '0+', '2025-09-12', 'Action/Comedy'),
(1062789, 'Chainsaw Man – The Movie: Reze Arc', 'https://image.tmdb.org/t/p/original/aZwfY1P57MrEQKW5m9JrtcWg0IB.jpg', 'In a brutal war between devils, hunters, and secret enemies, a mysterious girl named Reze has stepped into Denji\'s world, and he faces his deadliest battle yet, fueled by love in a world where survival knows no rules.', 100, '16', '2025-09-19', 'Animation/Action/Romance/Fantasy'),
(1062790, 'Wojna światów', 'https://image.tmdb.org/t/p/original/s20qugrUD5mPGQdyQ1LMLCYUOmy.jpg', 'Will Radford is a top analyst for Homeland Security who tracks potential threats through a mass surveillance program, until one day an attack by an unknown entity leads him to question whether the government is hiding something from him... and from the rest of the world.', 91, '0+', '2025-07-29', 'Science Fiction/Thriller'),
(1062791, 'Demon Slayer: Kimetsu no Yaiba – Infinity Castle', 'https://image.tmdb.org/t/p/original/ylCHprN1XfKIe5Mcbo7E65CwW0Y.jpg', 'The Demon Slayer Corps are drawn into the Infinity Castle, where Tanjiro, Nezuko, and the Hashira face terrifying Upper Rank demons in a desperate fight as the final battle against Muzan Kibutsuji begins.', 156, '16', '2025-07-18', 'Animation/Action/Fantasy/Thriller'),
(1062792, 'Afterburn', 'https://image.tmdb.org/t/p/original/xR0IhVBjbNU34b8erhJCgRbjXo3.jpg', 'Set against the backdrop of a postapocalyptic Earth whose Eastern Hemisphere was destroyed by a massive solar flare, leaving what life remains mutated from radiation and fallout. The story revolves around a group of treasure hunters who extract such objects as the Mona Lisa, the Rosetta Stone and the Crown Jewels while facing rival hunters, mutants and pirates.', 105, '0+', '2026-08-20', 'Science Fiction/Action/Comedy'),
(1062793, 'Baramulla', 'https://image.tmdb.org/t/p/original/2raITTyjXVUcsbJ7lJAQt8HzjDK.jpg', 'A cop\'s inquiry into child kidnappings unravels chilling secrets as supernatural events endanger his family and the peaceful town of Baramulla.', 120, '16', '2025-11-06', 'Horror'),
(1062794, 'Captain Hook: The Cursed Tides', 'https://image.tmdb.org/t/p/original/bcP7FtskwsNp1ikpMQJzDPjofP5.jpg', 'In the aftermath of a devastating defeat by his archnemesis Admiral Smee, Captain Hook finds refuge in the coastal town of Eldritch Landing.', 90, '0+', '2025-07-11', 'Adventure/Action/Horror'),
(1062795, 'xXx', 'https://image.tmdb.org/t/p/original/1Ka8EhUah4L9Bco0MXOs3ZvTbHk.jpg', 'Xander Cage is your standard adrenaline junkie with no fear and a lousy attitude. When the US Government \"recruits\" him to go on a mission, he\'s not exactly thrilled. His mission: to gather information on an organization that may just be planning the destruction of the world, led by the nihilistic Yorgi.', 124, '12', '2002-08-09', 'Action/Adventure/Thriller/Crime/Drama'),
(1062796, 'Fantastyczna 4. Pierwsze kroki', 'https://image.tmdb.org/t/p/original/1TguzeceNxpZKW1kutDOPXiDMZn.jpg', 'Against the vibrant backdrop of a 1960s-inspired, retro-futuristic world, Marvel\'s First Family is forced to balance their roles as heroes with the strength of their family bond, while defending Earth from a ravenous space god called Galactus and his enigmatic Herald, Silver Surfer.', 115, '12', '2025-07-23', 'Science Fiction/Adventure/Action'),
(1062797, 'Łowy', 'https://image.tmdb.org/t/p/original/cgZjpqRQt9sk6XMCwZ3B1NPAaoy.jpg', 'Desperate to find refuge for her children, Chloe Marvino runs away from her Mafia tied husband, and finds shelter in a cabin with a recluse drifter named Jake. But as her husband\'s henchmen draw closer to her, it turns out that Jake is the biggest enemy of them all.', 89, '0+', '2025-05-16', 'Action/Thriller'),
(1062798, 'Martin', 'https://image.tmdb.org/t/p/original/rmCJCFrEwPC0u0Y1smihwDo4Cf1.jpg', 'Martin revolves around Lt. Brigadier Arjun Saxena, whose journey takes him from Pakistan to India to discover his real identity and fight against black market dealers, who are involved with terrorists to orchestrate massive attacks in the country.', 147, '0+', '2024-10-11', 'Action/Drama/Thriller'),
(1062799, 'Eran brujas', 'https://image.tmdb.org/t/p/original/85rlLCjpHbY0puR1FSL7jYyN1cu.jpg', 'Mia, an expert speaker in witchcraft, takes a trip to see a therapist. On the way she meets a group of young people who will begin to die one by one to bring an evil spirit back from death.', 100, '0+', '2025-09-08', 'Horror'),
(1062800, 'Uprowadzona dziewczyna', 'https://image.tmdb.org/t/p/original/rAqAnPVRsncgg3ZcX9qivir5k7M.jpg', 'In 1993, Maureen’s six-year-old daughter Amina is snuck out of the country by her ex-husband, Karim. After years of unsuccessful attempts to find her, Maureen intersects with a professional retriever of internationally abducted children who promises to help her find Amina in exchange for her collaboration.', 110, '0+', '2025-09-04', 'Thriller/Action/Adventure'),
(1062801, 'K-popowe łowczynie demonów', 'https://image.tmdb.org/t/p/original/zT7Lhw3BhJbMkRqm9Zlx2YGMsY0.jpg', 'When K-pop superstars Rumi, Mira and Zoey aren\'t selling out stadiums, they\'re using their secret powers to protect their fans from supernatural threats.', 96, '0+', '2025-06-20', 'Fantasy/Music/Comedy/Animation'),
(1062802, 'Brzydka siostra', 'https://image.tmdb.org/t/p/original/57L0gexJHK5QD7h8ors8PIzvRov.jpg', 'In a fairy-tale kingdom where beauty is a brutal business, Elvira battles to compete with her incredibly beautiful stepsister, and she will go to any length to catch the prince’s eye.', 109, '0+', '2025-03-07', 'Horror/Comedy/Fantasy/Drama'),
(1062803, 'Obecność 4. Ostatnie namaszczenie', 'https://image.tmdb.org/t/p/original/vVYdKfQjGbAWgQ6FV7cGPrVlaF4.jpg', 'Paranormal investigators Ed and Lorraine Warren take on one last terrifying case involving mysterious entities they must confront.', 136, '16', '2025-09-03', 'Horror'),
(1062804, 'Druga Furioza', 'https://image.tmdb.org/t/p/original/yOLnV1lM3NuMsgYwIhz454fQRgt.jpg', 'In the wake of murder, new Furioza leader Golden claims the reins of his violent and formidable hooligan gang and takes on a new focus across borders.', 166, '18', '2025-10-14', 'Action/Crime/Thriller'),
(1062805, 'The Toxic Avenger Unrated', 'https://image.tmdb.org/t/p/original/sIonGSpGNtH72OzbJllPOEMNjVU.jpg', 'When a downtrodden janitor, Winston Gooze, is exposed to a catastrophic toxic accident, he’s transformed into a new kind of hero: The Toxic Avenger. Now, Toxie must rise from outcast to savior, taking on ruthless corporate overlords and corrupt forces who threaten his son, his friends, and his community.', 102, '0+', '2026-08-28', 'Action/Comedy/Science Fiction'),
(1062806, 'The Book', 'https://image.tmdb.org/t/p/original/w8f8RqWg4SFrwf4YVbqkYLTygSI.jpg', '', 0, '0+', '2024-11-08', 'Horror/Thriller'),
(1062807, 'Padre no hay más que uno 5: Nido repleto', 'https://image.tmdb.org/t/p/original/7H27uvaPZfq794qVcLFrSEgHseZ.jpg', 'Some parents experience the anguish of the \"empty nest\" when their children leave home. Javier, on the other hand, suffers the trauma of the \"full nest\": no one wants to leave home.', 100, '0+', '2026-06-26', 'Comedy/Family'),
(1062808, 'Nasza wina', 'https://image.tmdb.org/t/p/original/y8VBZljNMjGdVZxZ7wSZWCvG0Un.jpg', 'Jenna and Lion\'s wedding brings about the long-awaited reunion between Noah and Nick after their breakup. Nick\'s inability to forgive Noah stands as an insurmountable barrier. He, heir to his grandfather\'s businesses, and she, starting her professional life, resist fueling a flame that\'s still alive. But now that their paths have crossed again, will love be stronger than resentment?', 112, '0+', '2025-10-15', 'Romance/Drama'),
(1062809, 'Święta Noc: Łowcy Demonów', 'https://image.tmdb.org/t/p/original/7MGnHpfhF8savUsrUJoI8Q7dTk9.jpg', 'When a devil-worshipping criminal network plunges Seoul into chaos, the police turn to Holy Night—a trio of supernatural demon hunters—to restore order and defeat the rising evil.', 92, '0+', '2025-04-30', 'Action/Fantasy/Horror/Thriller'),
(1062810, 'Nympho', 'https://image.tmdb.org/t/p/original/tWFUt3THd6QbSdp4GZekes7Tbv1.jpg', 'A woman seeking excitement meets a man who brings light and meaning to her world.', 71, '0+', '2025-11-07', 'Drama/Romance'),
(1062811, 'Prymitywna wojna', 'https://image.tmdb.org/t/p/original/nWBqU5YXmDVJWWEDJ4u3ZSseNVL.jpg', 'During the Vietnam War, a recon unit ventures to an isolated jungle valley to uncover the fate of a missing platoon. They soon find themselves in a fight for their lives against an unexpected enemy — prehistoric dinosaurs.', 133, '0+', '2025-08-21', 'Action/Horror/War'),
(1062812, 'മാർക്കോ', 'https://image.tmdb.org/t/p/original/6Nj8Y1A9lcReqZZvRHOSiO3iTl6.jpg', 'The adoptive son of the Adattu family, Marco, sets off on a ruthless quest for vengeance after his brother is brutally murdered, finding only betrayal, loss and unimaginable brutality at every step.', 145, '0+', '2024-12-20', 'Action/Crime/Thriller'),
(1062813, 'Szczury: Opowieść ze świata Wiedźmina', 'https://image.tmdb.org/t/p/original/1T0kO1cgR430AC9I6jurMOezKwg.jpg', 'To pull off a daring heist, a gang of six misfit outlaws will have to do something they\'ve never done before: trust each other — and a washed-up Witcher.', 83, '16', '2025-10-29', 'Fantasy/Drama/Adventure'),
(1062814, 'หมู่บ้านโคกะโหลก', 'https://image.tmdb.org/t/p/original/pRWBabtsYvqpPmxNYcejIUe6lc3.jpg', 'A terrifying serial murder spree grips Kogaloak village, with horrific injuries on male victims. Police face local legends and hidden secrets as they investigate. The latest victim, is taken for autopsy, intensifying fear. Officer and his team conduct a covert investigation, but the death toll rises. Villagers suspect newcomers have awakened a vengeful ghost. Is it real or a clever killer?', 99, '0+', '2025-11-06', 'Comedy/Horror/Thriller'),
(1062815, 'Jurassic World. Odrodzenie', 'https://image.tmdb.org/t/p/original/qQ4LresXCs7Nxz12TjYoGmjsW4c.jpg', 'Five years after the events of Jurassic World Dominion, covert operations expert Zora Bennett is contracted to lead a skilled team on a top-secret mission to secure genetic material from the world\'s three most massive dinosaurs. When Zora\'s operation intersects with a civilian family whose boating expedition was capsized, they all find themselves stranded on an island where they come face-to-face with a sinister, shocking discovery that\'s been hidden from the world for decades.', 134, '0+', '2025-07-01', 'Science Fiction/Adventure/Action'),
(1062816, 'The Lost Princess', 'https://image.tmdb.org/t/p/original/31S2ISsDtbnxb0kuXZl1SxSMD0K.jpg', 'After an Ayahuasca vision transports him to a haunted castle, Alec meets Hanna who tales him the story of her mother\'s forced marriage and how the forbidden passion with her father was in danger when the princess pregnancy became obvious', 105, '0+', '2025-10-16', 'Action/Adventure'),
(1062817, 'Anioł stróż', 'https://image.tmdb.org/t/p/original/r83HIGA0mUiy7I9qVr17pF7SCDP.jpg', 'A well-meaning but rather inept angel named Gabriel meddles in the lives of a struggling gig worker and a wealthy capitalist.', 98, '0+', '2025-10-14', 'Comedy/Fantasy'),
(1062818, 'Zwierzaki na zakręcie', 'https://image.tmdb.org/t/p/original/5FbWq4hiE4htddBtlenZW4kUcpY.jpg', 'Edda, a young mouse and the daughter of fairground operator Erwin, dreams of becoming a race car driver. Ahead of the 50th anniversary of the European Grand Prix, Edda gets the opportunity to meet her idol, racing star Ed, and to help her father save his failing business. But to do so, she\'ll have to get behind the wheel herself.', 98, '0+', '2025-07-24', 'Animation/Adventure/Comedy'),
(1062819, 'Superman', 'https://image.tmdb.org/t/p/original/g2e0gcSTFcyPkBqs3vKK1YpqBsy.jpg', 'Superman, a journalist in Metropolis, embarks on a journey to reconcile his Kryptonian heritage with his human upbringing as Clark Kent.', 130, '0+', '2025-07-09', 'Science Fiction/Adventure/Action'),
(1062820, 'Którą wybrać?', 'https://image.tmdb.org/t/p/original/bSUMh6vkPcRPxZir7PDvcfijZN9.jpg', 'Adam is allergic to love, but somehow ends up engaged to both his boss\'s daughter and his first love. Now he must try to keep his double life a secret.', 0, '0+', '2025-11-06', 'Romance/Comedy'),
(1062821, 'The Jester 2', 'https://image.tmdb.org/t/p/original/47dsw1jSOV0Be5zmy7CtLhYpqU.jpg', 'When teen magician Max crosses paths with the sinister Jester on Halloween night, she must outsmart a supernatural killer whose magic is all too real and whose tricks always end up in blood.', 87, '0+', '2025-09-15', 'Horror/Thriller/Crime'),
(1062822, 'TL', 'https://image.tmdb.org/t/p/original/xb1Y4LpShfJaKJwOowxfs8dZhDt.jpg', 'Brenda, a top agent in a BPO company, is always overlooked for promotion. But not this time; as she gets more than intimate with her TL. Is her long awaited position within her reach? Or did she just put herself in a bad situation?', 44, '0+', '2024-03-30', 'Drama'),
(1062823, 'Zniknięcia', 'https://image.tmdb.org/t/p/original/fr5qImekooiYvI3VYijy6cRvcPF.jpg', 'When all but one child from the same class mysteriously vanish on the same night at exactly the same time, a community is left questioning who or what is behind their disappearance.', 129, '16', '2025-08-04', 'Horror/Mystery'),
(1062824, 'Predator', 'https://image.tmdb.org/t/p/original/k3mW4qfJo6SKqe6laRyNGnbB9n5.jpg', 'A team of elite commandos on a secret mission in a Central American jungle come to find themselves hunted by an extraterrestrial warrior.', 107, '18', '1987-06-12', 'Science Fiction/Action/Adventure/Thriller'),
(1062825, 'Wielki marsz', 'https://image.tmdb.org/t/p/original/fIHVZohhVG5RA9o9GAGt3xf3Rs6.jpg', 'In a dystopian, alternate-America ruled by a totalitarian regime, 50 teenage boys take part in a deadly annual walking contest, forced to maintain a minimum pace or be executed, until only one survivor remains.', 108, '0+', '2025-09-10', 'Thriller/Horror/Science Fiction'),
(1062826, 'TRON: Ares', 'https://image.tmdb.org/t/p/original/e4KE2bvhTqko9UcOGiRPaIM2DS0.jpg', 'A highly sophisticated Program called Ares is sent from the digital world into the real world on a dangerous mission, marking humankind\'s first encounter with A.I. beings.', 119, '12', '2025-10-08', 'Science Fiction/Adventure/Action'),
(1062827, 'లైలా', 'https://image.tmdb.org/t/p/original/l4gsNxFPGpzbq0D6QK1a8vO1lBz.jpg', 'Sonu Model, a renowned beautician from the old city, is forced to disguise himself as Laila, leading to a series of comedic, romantic, and action-packed events. Chaos ensues in this hilarious laugh riot', 134, '0+', '2025-02-14', 'Comedy/Romance'),
(1062828, 'Smashing Machine', 'https://image.tmdb.org/t/p/original/mPuBDGrVIBGOymBxR6rO3iIvBSe.jpg', 'In the late 1990s, up-and-coming mixed martial artist Mark Kerr aspires to become the greatest fighter in the world. However, he must also battle his opiod dependence and a volatile relationship with his girlfriend Dawn.', 123, '0+', '2025-10-01', 'History/Drama'),
(1062829, 'Coco', 'https://image.tmdb.org/t/p/original/yMapvyFKryN8lgR1o0wD4tsCUw3.jpg', 'Despite his family’s baffling generations-old ban on music, Miguel dreams of becoming an accomplished musician like his idol, Ernesto de la Cruz. Desperate to prove his talent, Miguel finds himself in the stunning and colorful Land of the Dead following a mysterious chain of events. Along the way, he meets charming trickster Hector, and together, they set off on an extraordinary journey to unlock the real story behind Miguel\'s family history.', 105, '0+', '2017-10-27', 'Family/Animation/Music/Adventure'),
(1062830, 'Mission: Impossible - The Final Reckoning', 'https://image.tmdb.org/t/p/original/z53D72EAOxGRqdr7KXXWp9dJiDe.jpg', 'Ethan Hunt and team continue their search for the terrifying AI known as the Entity — which has infiltrated intelligence networks all over the globe — with the world\'s governments and a mysterious ghost from Hunt\'s past on their trail. Joined by new allies and armed with the means to shut the Entity down for good, Hunt is in a race against time to prevent the world as we know it from changing forever.', 170, '0+', '2025-05-17', 'Action/Adventure/Thriller'),
(1062831, 'Nieczysta gra', 'https://image.tmdb.org/t/p/original/3x2fnYOF5mIZ40T0R6LKa2afmjJ.jpg', 'Expert thief Parker gets a shot at a major heist, but to pull it off he and his team must outsmart a South American dictator, the New York mob, and the world\'s richest man.', 125, '0+', '2025-09-30', 'Crime'),
(1062832, 'War 2', 'https://image.tmdb.org/t/p/original/j8Gl3S4L7LE8GIF1J1phZ2Cbo72.jpg', 'Years ago Agent Kabir went rogue, became India’s greatest villain ever.  As he descends further into the deepest shadows... India sends its deadliest, most lethal agent after him, Agent Vikram  A Special Units Officer who is more than Kabir’s equal and a relentless Terminator driven by his own demons, determined to put a bullet into Kabir’s skull.', 173, '0+', '2025-08-13', 'Action/Adventure/Thriller'),
(1062833, 'Zwierzogród 2', 'https://image.tmdb.org/t/p/original/spA0RGbfFrl4THorwNtdM5NLnIQ.jpg', 'After cracking the biggest case in Zootopia\'s history, rookie cops Judy Hopps and Nick Wilde find their partnership isn\'t as solid as they thought when Chief Bogo orders them to join the Partners in Crisis counseling program. But it doesn\'t take long for their partnership to be put to the ultimate test when they find themselves on the twisting trail of a mystery tied to the arrival of a venomous snake in the animal metropolis.', 107, '7', '2025-11-26', 'Animation/Family/Comedy/Adventure/Mystery'),
(1062834, 'DR SEUSS: SNICZE', 'https://image.tmdb.org/t/p/original/5jqpfOY6q8ltnCFEfUPY3c0bpR5.jpg', 'An unexpected friendship forms between two young Sneetches on an island surrounded by beaches in this sweet musical special set in the world of Seuss.', 45, '0+', '2025-11-03', 'Animation/Family'),
(1062835, 'F1: Film', 'https://image.tmdb.org/t/p/original/3smWUC3KBq4ifvrmrt6OZTTb8Z5.jpg', 'Racing legend Sonny Hayes is coaxed out of retirement to lead a struggling Formula 1 team—and mentor a young hotshot driver—while chasing one more chance at glory.', 156, '12', '2025-06-25', 'Action/Drama'),
(1062836, 'Dom pełen dynamitu', 'https://image.tmdb.org/t/p/original/AiJ8L90ftPAwVf3SDx7Fj9IMZoy.jpg', 'When a single, unattributed missile is launched at the United States, a race begins to determine who is responsible and how to respond.', 113, '16', '2025-10-02', 'Thriller'),
(1062837, 'Czarny telefon', 'https://image.tmdb.org/t/p/original/bXhs4x9FNbOOWqDZwiODbAdkcTd.jpg', 'Finney Blake, a shy but clever 13-year-old boy, is abducted by a sadistic killer and trapped in a soundproof basement where screaming is of little use. When a disconnected phone on the wall begins to ring, Finney discovers that he can hear the voices of the killer’s previous victims. And they are dead set on making sure that what happened to them doesn’t happen to Finney.', 103, '16', '2022-06-16', 'Horror/Thriller'),
(1062838, 'The Devil’s Trap', 'https://image.tmdb.org/t/p/original/deq8OGRj45eX1EFYQayG5T3Prar.jpg', 'In the quiet nighttime corridors of a city hospital, Abigail (Nistratova) consoles her traumatized brother, Billy (Davi) who is now a paraplegic. Billy suffers from horrible nightmares in which he revisits his childhood, where we meet his alcoholic and violent father. Sharing Billy’s hospital room is a dying man, Mr. Cohen (Dern) who seems to know everything about Billy and Abigail. There’s also another horrific presence roaming in the hospital terrifying patients and staff alike.', 90, '0+', '2024-11-01', 'Horror/Thriller'),
(1062839, 'The Mannequin', 'https://image.tmdb.org/t/p/original/oFTpB1gzS02LtrsenTWxOKbsMpM.jpg', 'A stylist assistant investigates her sister\'s death in a historic LA building, only to face a vengeful ghost of a serial killer who dismembered victims decades ago. She must escape before she\'s next.', 85, '0+', '2025-08-24', 'Horror/Thriller/Crime/Mystery'),
(1062840, 'Valiant One', 'https://image.tmdb.org/t/p/original/sT8Z14RDCAd6szzxzWFAU4xcMwg.jpg', 'With tensions between North and South Korea, a US helicopter crashes on the North side. The survivors must work together to protect a civilian tech specialist and find their way out without the help of US military support.', 86, '0+', '2025-01-30', 'War/Thriller/Action'),
(1062841, 'Lilo i Stich', 'https://image.tmdb.org/t/p/original/db62AGWDtPy21dWfSztGaqxBvvz.jpg', 'The wildly funny and touching story of a lonely Hawaiian girl and the fugitive alien who helps to mend her broken family.', 108, '0+', '2025-05-17', 'Family/Science Fiction/Comedy/Adventure'),
(1062842, 'The Strangers: Chapter 2', 'https://image.tmdb.org/t/p/original/pqADzs5SJvI2jC0DThPVMuNJcWS.jpg', 'When The Strangers learn that one of their victims, Maya, is still alive, they return to finish what they’ve started.', 98, '0+', '2025-09-25', 'Horror/Thriller'),
(1062843, 'Moja wina', 'https://image.tmdb.org/t/p/original/tZAcTHuMN9TJR6LcoIoZwypEWiN.jpg', 'Noah must leave her city, boyfriend, and friends to move into William Leister\'s mansion, the flashy and wealthy husband of her mother Rafaela. As a proud and independent 17 year old, Noah resists living in a mansion surrounded by luxury. However, it is there where she meets Nick, her new stepbrother, and the clash of their strong personalities becomes evident from the very beginning.', 117, '16', '2023-06-08', 'Drama/Romance/Thriller'),
(1062844, 'Jeniec wojenny', 'https://image.tmdb.org/t/p/original/1XET89sjRm9mUuHXhGIlKTNd5uD.jpg', 'British RAF Wing Commander James Wright is captured by the Japanese during WWII and forced to fight in brutal hand-to-hand combat. The Japanese soldiers get more than they bargained for when Wright’s years of martial arts training in Hong Kong prove him to be a formidable opponent.', 113, '0+', '2025-09-19', 'Action/War/Thriller/History'),
(1062845, 'Jak wytresować smoka', 'https://image.tmdb.org/t/p/original/qzkgpqhSSJiJVCSXU2OwwCOUSqu.jpg', 'On the rugged isle of Berk, where Vikings and dragons have been bitter enemies for generations, Hiccup stands apart, defying centuries of tradition when he befriends Toothless, a feared Night Fury dragon. Their unlikely bond reveals the true nature of dragons, challenging the very foundations of Viking society.', 125, '0+', '2025-06-06', 'Fantasy/Family/Action/Adventure'),
(1062846, 'Bugonia', 'https://image.tmdb.org/t/p/original/inKvg8MT59w7wsxq1MggjTZqROn.jpg', 'Two conspiracy obsessed young men kidnap the high-powered CEO of a major company, convinced that she is an alien intent on destroying planet Earth.', 119, '0+', '2025-10-23', 'Science Fiction/Crime'),
(1062847, 'Modliszka', 'https://image.tmdb.org/t/p/original/gRPSu4sG5iVnWyLv9um7t3L0yhH.jpg', 'Mantis, an ace assassin, returns to the contract killer industry after a hiatus, encountering his trainee friend Jae-yi and a retired legendary killer Dok-go, who now runs the organization.', 113, '0+', '2025-09-26', 'Action/Crime/Thriller'),
(1062848, 'Szybcy i sprytni', 'https://image.tmdb.org/t/p/original/uAjTtiKS1JsMi70YAN4ncCMwT86.jpg', 'When a train unexpectedly starts up, taking only pets with it, the animals discover that Hans, a badger with a grudge is behind it all. While the crash seems inevitable, the animals can count on Falcon, a roguish Raccoon who will do anything to save them.', 87, '0+', '2025-07-02', 'Animation/Comedy/Adventure/Thriller'),
(1062849, 'Dracula', 'https://image.tmdb.org/t/p/original/vevuZVvb72VrbDzHiz4D8Z8XuGF.jpg', 'The story of 15th century Prince Vladimir who curses God following the death of his beloved wife and is turned into a vampire. Later, in 19th century London, he discovers his wife’s doppelgänger and dooms himself by pursuing her.', 129, '0+', '2025-07-30', 'Horror/Fantasy/Romance'),
(1062850, 'Jedna bitwa po drugiej', 'https://image.tmdb.org/t/p/original/ptK6T5dpw684oeCxqyYHNeDAOwY.jpg', 'Washed-up revolutionary Bob exists in a state of stoned paranoia, surviving off-grid with his spirited, self-reliant daughter, Willa. When his evil nemesis resurfaces after 16 years and she goes missing, the former radical scrambles to find her, father and daughter both battling the consequences of his past.', 162, '0+', '2025-09-23', 'Action/Thriller/Crime'),
(1062851, 'Władca Pierścieni: Drużyna Pierścienia', 'https://image.tmdb.org/t/p/original/bjWRzhXUXTNPnwptBkXQzCflVBE.jpg', 'Young hobbit Frodo Baggins, after inheriting a mysterious ring from his uncle Bilbo, must leave his home in order to keep it from falling into the hands of its evil creator. Along the way, a fellowship is formed to protect the ringbearer and make sure that the ring arrives at its final destination: Mt. Doom, the only place where it can be destroyed.', 179, '15', '2001-12-18', 'Adventure/Fantasy/Action'),
(1062852, 'The People In The Walls', 'https://image.tmdb.org/t/p/original/3NyL99rcDr5S4qQ8FXDwWiLujEE.jpg', 'A viral ritual allows three kids to conjure people from the walls as they must now try to put them back before it is too late.', 93, '0+', '2024-08-01', 'Horror/Thriller/Mystery'),
(1062853, 'Nikt 2', 'https://image.tmdb.org/t/p/original/zsqI1nxC52CcrucN6W6BWrbTAvs.jpg', 'Former assassin Hutch Mansell takes his family on a nostalgic vacation to a small-town theme park, only to be pulled back into violence when they clash with a corrupt operator, a crooked sheriff, and a ruthless crime boss.', 89, '0+', '2025-08-13', 'Action/Thriller'),
(1062854, 'Fran the Man', 'https://image.tmdb.org/t/p/original/fxST2MqYdafW5zucXX85qddvnjm.jpg', 'When non-league St Peter\'s Celtic are drawn to play titans Shamrock Rovers in the first round of the FAI Cup, assistant manager Fran Costello hopes his team will pull off one of the greatest shocks in football history. But it isn\'t long before the shit really hits the Fran…', 89, '0+', '2025-04-11', 'Comedy/Drama'),
(1062855, 'Ne Zha 2: W krainie potworów', 'https://image.tmdb.org/t/p/original/uVxWKqtFH4Uv50mYMD6z3rpugDU.jpg', 'After a catastrophic event leaves their bodies destroyed, Ne Zha and Ao Bing are granted a fragile second chance at life. As tensions rise between the dragon clans and celestial forces, the two must undergo a series of perilous trials that will test their bond, challenge their identities, and decide the fate of both mortals and immortals.', 144, '0+', '2025-01-29', 'Animation/Fantasy/Adventure/Action'),
(1062856, 'Voy a pasármelo mejor', 'https://image.tmdb.org/t/p/original/4ov5cLaFO8toC7HBDl6T0Vg8pQo.jpg', '', 0, '0+', '2025-07-18', 'Comedy'),
(1062857, 'Avengers', 'https://image.tmdb.org/t/p/original/RYMX2wcKCBAr24UyPD7xwmjaTn.jpg', 'When an unexpected enemy emerges and threatens global safety and security, Nick Fury, director of the international peacekeeping agency known as S.H.I.E.L.D., finds himself in need of a team to pull the world back from the brink of disaster. Spanning the globe, a daring recruitment effort begins!', 143, '12', '2012-04-25', 'Science Fiction/Action/Adventure'),
(1062858, 'Spinal Tap II: The End Continues', 'https://image.tmdb.org/t/p/original/h6DGrDHlDm6gVOiy3YeOb737jB4.jpg', 'The now estranged bandmates of Spinal Tap are forced to reunite for one final concert, hoping it will solidify their place in the pantheon of rock \'n\' roll.', 84, '0+', '2025-09-12', 'Music/Comedy'),
(1062859, 'Hedda', 'https://image.tmdb.org/t/p/original/ecflk7AZf0ij205yDswjlvdxlCO.jpg', 'Hedda Gabler finds herself torn between the lingering ache of a past love and the quiet suffocation of her present life. Over the course of one charged night, long-repressed desires and hidden tensions erupt—pulling her and everyone around her into a spiral of manipulation, passion, and betrayal.', 107, '0+', '2025-10-22', 'Drama/Thriller/Romance'),
(1062860, 'Ur mörkret', 'https://image.tmdb.org/t/p/original/zzxIUS5GFMmDVActt9IPMQ0XZde.jpg', 'Park ranger Angelica seeks the help of her dog handler ex-boyfriend, Viktor, to search for a missing woman in a dangerous nature reserve in Sweden. The search is complicated by a disturbing myth about the Cave Banshee, a vengeful spirit from the Nordic folklore that once lured miners to their deaths in the reserve\'s treacherous caves. As they delve deeper into the forest, Viktor starts to question his own sanity and whether the rumored Banshee is more than just a myth. To make matters worse, Angelica and Viktor share a painful history with the haunted place. Viktor must now confront his troubled past and work together with Angelica to survive the night and unravel the mystery behind the woman\'s disappearance.', 95, '0+', '2024-03-22', 'Horror/Mystery/Thriller'),
(1062861, 'Pan Wilk i spółka 2', 'https://image.tmdb.org/t/p/original/jEzJx1h7HBIXwmEgRBkSHnOGavd.jpg', 'The now-reformed Bad Guys are trying (very, very hard) to be good, but instead find themselves hijacked into a high-stakes, globe-trotting heist, masterminded by a new team of criminals they never saw coming: The Bad Girls.', 104, '7', '2025-07-24', 'Family/Comedy/Crime/Adventure/Animation'),
(1062862, 'Naga broń', 'https://image.tmdb.org/t/p/original/rDEyssohv6lBUbdYSwHkv8jWfp5.jpg', 'Only one man has the particular set of skills... to lead Police Squad and save the world: Lt. Frank Drebin Jr.', 85, '12', '2025-07-30', 'Comedy/Action/Crime'),
(1062863, 'Predator: Pogromca zabójców', 'https://image.tmdb.org/t/p/original/1MEV1CssOHKFxWm4h2RUnMc3nBp.jpg', 'While three of the fiercest warriors in human history—a Viking raider, a ninja in feudal Japan, and a WWII pilot—are killers in their own right, they are merely prey for their new opponent: the ultimate killer of killers.', 85, '18', '2025-06-05', 'Animation/Action/Science Fiction/Thriller'),
(1062864, 'Bone Lake', 'https://image.tmdb.org/t/p/original/bV9sEJiznCmZu5Gf35N8m7D7OpX.jpg', 'A couple’s romantic vacation at a secluded lakeside estate is upended when they are forced to share the mansion with a mysterious and attractive couple. In this darkly hilarious and seductive horror story, a dream getaway spirals into a nightmarish maze of sex, lies, and manipulation, bringing terrifying secrets to light and triggering a bloody battle for survival.', 94, '0+', '2025-10-02', 'Horror/Thriller/Mystery'),
(1062865, 'Czarny pies', 'https://image.tmdb.org/t/p/original/jFXcB5vOc1P2pu1EbjRumOcb62b.jpg', 'On the edge of the Gobi desert in Northwest China, Lang returns to his hometown after being released from jail. While working for the local dog patrol team to clear the town of stray dogs before the Olympic Games, he strikes up an unlikely connection with a black dog. These two lonely souls embark on a journey together.', 116, '0+', '2024-06-15', 'Drama'),
(1062866, 'Interstellar', 'https://image.tmdb.org/t/p/original/q4emCJmjNomEE2pVGgqr3nDEIzI.jpg', 'The adventures of a group of explorers who make use of a newly discovered wormhole to surpass the limitations on human space travel and conquer the vast distances involved in an interstellar voyage.', 169, '16', '2014-11-05', 'Adventure/Drama/Science Fiction'),
(1062867, 'Ted 2', 'https://image.tmdb.org/t/p/original/bRjEG6hjjLzSgb90n8JPB3qLQYM.jpg', 'Newlywed couple Ted and Tami-Lynn want to have a baby, but in order to qualify to be a parent, Ted will have to prove he\'s a person in a court of law.', 115, '12', '2015-06-25', 'Comedy/Fantasy'),
(1062868, 'Oszukać przeznaczenie: Więzy krwi', 'https://image.tmdb.org/t/p/original/ornXXqOyKN8GscogGFBVefXgymm.jpg', 'Plagued by a violent recurring nightmare, college student Stefanie heads home to track down the one person who might be able to break the cycle and save her family from the grisly demise that inevitably awaits them all.', 110, '0+', '2025-05-14', 'Horror/Mystery'),
(1062869, 'Tyler Perry: W poszukiwaniu szczęścia', 'https://image.tmdb.org/t/p/original/sUMdbrjHhMFDY327B31ctpF9MuY.jpg', 'Joy, a successful designer, seeks a proposal at Christmas. In Wyoming\'s mountains, she finds what she truly needs when the man she loves sees her as just a friend.', 107, '0+', '2025-11-05', 'Drama'),
(1062870, '정사 : 착한 며느리들 3', 'https://image.tmdb.org/t/p/original/vMkZ311wQLXsICzjcAqVQivqDKs.jpg', 'Seok-joon has two sons; Min-seok, who is married, and Yoon-soo, who is not. Seok-joon tells them he is going to give allowance and his wealth to his daughters-in-law only. Yoon-soo asks one of his lady friends to get married for Seok-joon\'s money. Min-yeong and Yoon-jin pretend to be Yoon-soo\'s girlfriends. Then Yoon-jin falls for Seok-joon. The women visit the house often to get on Seok-joon\'s good side, and so does Yoon-soo\'s ex-girlfriend, Min-yeong. However, Seok-joon falls in love with Yoon-jin, and Yoon-soo is very disappointed in Seok-joon, who wants to start a new life...', 82, '0+', '2019-11-20', 'Romance'),
(1062871, 'Ballerina. Z uniwersum Johna Wicka', 'https://image.tmdb.org/t/p/original/2VUmvqsHb6cEtdfscEA6fqqVzLg.jpg', 'Taking place during the events of John Wick: Chapter 3 – Parabellum, Eve Macarro begins her training in the assassin traditions of the Ruska Roma.', 125, '16', '2025-06-04', 'Action/Thriller/Crime'),
(1062872, 'Fight Another Day', 'https://image.tmdb.org/t/p/original/fKnLt1xQV0RdpN6RViowEiD1dFW.jpg', 'Follows a tough cop, who after being transported to a dystopian future, must enter a deadly combat tournament to be able to return to his past.', 108, '0+', '2024-10-09', 'Action'),
(1062873, 'Predator: Prey', 'https://image.tmdb.org/t/p/original/hRtI9YdgW21RlQJJXrzGO9zNZ8O.jpg', 'When danger threatens her camp, the fierce and highly skilled Comanche warrior Naru sets out to protect her people. But the prey she stalks turns out to be a highly evolved alien predator with a technically advanced arsenal.', 100, '0+', '2022-08-02', 'Thriller/Action/Science Fiction'),
(1062874, 'To: Rozdział 2', 'https://image.tmdb.org/t/p/original/qnDb7rErT7N58tScP2tiYbCC4eU.jpg', '27 years after overcoming the malevolent supernatural entity Pennywise, the former members of the Losers\' Club, who have grown up and moved away from Derry, are brought back together by a devastating phone call.', 169, '18', '2019-09-04', 'Horror/Thriller'),
(1062875, 'Eden', 'https://image.tmdb.org/t/p/original/jbFEESMVbpJU8IjZBjiWGJdEsxR.jpg', 'A group of disillusioned outsiders abandon modern society in search of a new beginning. Settling on a remote, uninhabited island, their utopian dream quickly unravels as they discover that the greatest threat isn’t the brutal climate or deadly wildlife, but each other.', 129, '0+', '2025-04-03', 'Thriller/Drama'),
(1062876, 'Kobieta z kabiny dziesiątej', 'https://image.tmdb.org/t/p/original/kMwwevkwYI3vK6NZVfe3LgwmEUJ.jpg', 'On a lavish yacht for an assignment, a journalist sees a passenger go overboard. But when no one believes her, she risks her life to uncover the truth.', 95, '16', '2025-10-09', 'Mystery/Thriller/Crime'),
(1062877, 'Iluzja 3', 'https://image.tmdb.org/t/p/original/oD3Eey4e4Z259XLm3eD3WGcoJAh.jpg', 'The Four Horsemen return along with a new generation of illusionists performing mind-melding twists, turns, surprises, and magic unlike anything ever captured on film.', 112, '16', '2025-11-12', 'Thriller/Crime/Mystery'),
(1062878, 'Wicked', 'https://image.tmdb.org/t/p/original/xDGbZ0JJ3mYaGKy4Nzd9Kph6M9L.jpg', 'In the land of Oz, ostracized and misunderstood green-skinned Elphaba is forced to share a room with the popular aristocrat Glinda at Shiz University, and the two\'s unlikely friendship is tested as they begin to fulfill their respective destinies as Glinda the Good and the Wicked Witch of the West.', 162, '0+', '2024-11-20', 'Drama/Romance/Fantasy'),
(1062879, 'Mango', 'https://image.tmdb.org/t/p/original/s9lDFwMqxIlJHD7ovZ9wUw0twwK.jpg', 'An ambitious hotelier and her reluctant daughter take a trip to Málaga, where they find what they\'ve been craving in a farmer\'s idyllic mango orchard.', 0, '16', '2025-11-06', 'Romance/Drama'),
(1062880, 'Koci domek Gabi: Film', 'https://image.tmdb.org/t/p/original/dnYW2BAKApv8HsgKnG0OQMwje7r.jpg', 'Gabby heads out on a road trip with her Grandma Gigi to the urban wonderland of Cat Francisco. But when Gabby\'s dollhouse, her most prized possession, ends up in the hands of an eccentric cat lady named Vera, Gabby sets off on an adventure through the real world to get the Gabby Cats back together and save the dollhouse before it\'s too late.', 98, 'AL', '2025-09-13', 'Family/Comedy/Adventure/Animation'),
(1062881, 'Die Pro', 'https://image.tmdb.org/t/p/original/hXtpdSvnsvDh2KKVsA9X6NrDZoc.jpg', 'The Pro tells the story of a young surfer, Tiaan Nothnagel that has to come to terms with the accidental death of his best friend, Dirkie Lawrence just before their last year at school.After Dirkie’s death, Tiaan swears off surfing for good, as he can’t stand to be reminded of everything that he and Dirkie shared. But then, Dirkie’s twin sister (who went to live with their dad after their parents split up the previous year) arrives in town on a mission: to be selected to go on Wave-Seekers, a fictional World Surf Tour and something that Tiaan and Dirkie dreamt of doing.', 98, '0+', '2015-09-18', 'Drama/Romance'),
(1062882, 'Mroczny Rycerz', 'https://image.tmdb.org/t/p/original/gKMDmGde8aAD8M6dvm6j7wciSbJ.jpg', 'Batman raises the stakes in his war on crime. With the help of Lt. Jim Gordon and District Attorney Harvey Dent, Batman sets out to dismantle the remaining criminal organizations that plague the streets. The partnership proves to be effective, but they soon find themselves prey to a reign of chaos unleashed by a rising criminal mastermind known to the terrified citizens of Gotham as the Joker.', 152, '16', '2008-07-16', 'Drama/Action/Crime/Thriller'),
(1062883, 'Vaiana 2', 'https://image.tmdb.org/t/p/original/iX5FaZlzqyOfhHZSyb8RZljHS3f.jpg', 'After receiving an unexpected call from her wayfinding ancestors, Moana journeys alongside Maui and a new crew to the far seas of Oceania and into dangerous, long-lost waters for an adventure unlike anything she\'s ever faced.', 100, '7', '2024-11-21', 'Family/Comedy/Adventure/Animation/Fantasy'),
(1062884, 'Ballada o drobnym karciarzu', 'https://image.tmdb.org/t/p/original/yiXpXNiBWENaSJmdKfoT5DU0bL4.jpg', 'Amid the glittering casinos of Macau, a gambler running from his past — and his debts — becomes fascinated by an enigmatic woman at the baccarat table.', 102, '0+', '2025-10-15', 'Mystery/Thriller/Crime/Drama'),
(1062885, 'Gnijąca panna młoda', 'https://image.tmdb.org/t/p/original/xpc12sKfmICyHe8d2WY6E6gyGuS.jpg', 'In a 19th-century European village, a young man about to be married is whisked away to the underworld and wed to a mysterious corpse bride, while his real bride waits bereft in the land of the living.', 77, '7', '2005-09-12', 'Romance/Fantasy/Animation'),
(1062886, 'Odwet', 'https://image.tmdb.org/t/p/original/npLvwol2oZGLc0VeYYxJ72KXYwY.jpg', 'A veteran Muay Thai expert goes on a take-no-prisoners mission of revenge after his wife and daughter are brutally murdered by mysterious forces.', 106, '0+', '2024-12-05', 'Action/Crime/Thriller'),
(1062887, '27 nocy', 'https://image.tmdb.org/t/p/original/vqReHIFJc1vgYLTQF768rFsRxRC.jpg', 'When a woman is admitted by her daughters to a psychiatric clinic for her carefree ways, an expert must judge if she is ill or simply wants to enjoy life.', 108, '0+', '2025-09-19', 'Comedy'),
(1062888, 'The Apocalypse', 'https://image.tmdb.org/t/p/original', 'The film is set in 90 AD and concerns Jesus Christ\'s last surviving disciple, John of Patmos, and his writings and visions from the Apocalypse of John. Emperor Domitian has declared himself to be God and ruler, over heaven and earth. The Christians do not recognize his divinity and face persecution, from the God Emperor. John has been imprisoned on, the island of Patmos, a Roman mining, penal colony, with many others. He writes out messages of his visions and sends the \"Revelation of God\", to the seven churches of Greek Asia Minor. The Christian church, in Ephesus, sends Irene to make sure John is alive and to confer with him in person. The movie depicts scenes from the Book of Revelation and links them to events happening to the church in Asia.', 0, '0+', '2002-12-10', NULL),
(1062889, 'Butchers Book Two: Raghorn', 'https://image.tmdb.org/t/p/original/uSLYBuDTHpTAJI9vcm2brMu4J9H.jpg', 'Book one followed a family of sadistic butchers, living in the backcountry, who see anyone that crosses their path as dead meat. In “Butchers Book Two: Raghorn,” the story continues when an accident leaves the captors in the hands of brutal cannibals who plan to hack them up for meat.', 88, '0+', '2024-02-29', 'Horror'),
(1062890, 'Elio', 'https://image.tmdb.org/t/p/original/uvcBTvWamYQKEwgj3aYrfLIDTbM.jpg', 'Elio, a space fanatic with an active imagination, finds himself on a cosmic misadventure where he must form new bonds with eccentric alien lifeforms, navigate a crisis of intergalactic proportions and somehow discover who he is truly meant to be.', 98, 'AL', '2025-06-18', 'Family/Comedy/Adventure/Animation/Science Fiction'),
(1062891, 'Lodowy szlak: Zemsta', 'https://image.tmdb.org/t/p/original/8NJCa9MoTma9FlEQ7jAsxygsFPn.jpg', 'Big rig ice road driver Mike McCann travels to Nepal to scatter his late brother’s ashes on Mt. Everest. While on a packed tour bus traversing the deadly 12,000 ft. terrain of the infamous Road to the Sky, McCann and his mountain guide encounter a group of mercenaries and must fight to save themselves, the busload of innocent travelers, and the local villagers’ homeland.', 113, '0+', '2025-06-27', 'Action/Thriller/Drama'),
(1062892, 'Assassin', 'https://image.tmdb.org/t/p/original/eNriIkhQusncgc5SipEgQUtrybO.jpg', '', 0, '0+', '2025-09-26', 'Action'),
(1062893, 'To', 'https://image.tmdb.org/t/p/original/jDOMQ0fm9A97gy9aD9vF7MEKzJA.jpg', 'In a small town in Maine, seven children known as The Losers Club come face to face with life problems, bullies and a monster that takes the shape of a clown called Pennywise.', 135, '18', '2017-09-06', 'Horror/Thriller'),
(1062894, 'M3GAN 2.0', 'https://image.tmdb.org/t/p/original/4a63rQqIDTrYNdcnTXdPsQyxVLo.jpg', 'After the underlying tech for M3GAN is stolen and misused by a powerful defense contractor to create a military-grade weapon known as Amelia, M3GAN\'s creator Gemma realizes that the only option is to resurrect M3GAN and give her a few upgrades, making her faster, stronger, and more lethal.', 120, '0+', '2025-06-25', 'Action/Science Fiction/Thriller'),
(1062895, 'Państwo Burakowie', 'https://image.tmdb.org/t/p/original/izYZGeOHhPWiga8Hb5P4JYfcH8T.jpg', 'When the meanest, nastiest villains pull a trick to take over their town, two brave children team up with a family of magical animals to bring them down.', 99, '0+', '2025-10-17', 'Animation/Comedy/Family/Fantasy'),
(1062896, 'Wicked: na dobre', 'https://image.tmdb.org/t/p/original/si9tolnefLSUKaqQEGz1bWArOaL.jpg', 'As an angry mob rises against the Wicked Witch, Glinda and Elphaba will need to come together one final time. With their singular friendship now the fulcrum of their futures, they will need to truly see each other, with honesty and empathy, if they are to change themselves, and all of Oz, for good.', 138, '0+', '2025-11-17', 'Romance/Fantasy/Adventure'),
(1062897, 'Minecraft. Film', 'https://image.tmdb.org/t/p/original/9fa0zIIPqKqS5YE9xweWW0xXtR3.jpg', 'Four misfits find themselves struggling with ordinary problems when they are suddenly pulled through a mysterious portal into the Overworld: a bizarre, cubic wonderland that thrives on imagination. To get back home, they\'ll have to master this world while embarking on a magical quest with an unexpected, expert crafter, Steve.', 101, 'AL', '2025-03-31', 'Family/Fantasy/Comedy/Adventure/Action'),
(1062898, 'Deadpool & Wolverine', 'https://image.tmdb.org/t/p/original/7Hi6mRLsQtTaEtKiHqSeRFR1TQ2.jpg', 'A listless Wade Wilson toils away in civilian life with his days as the morally flexible mercenary, Deadpool, behind him. But when his homeworld faces an existential threat, Wade must reluctantly suit-up again with an even more reluctant Wolverine.', 128, '0+', '2024-07-24', 'Action/Comedy/Science Fiction'),
(1062899, 'Labirynt fauna', 'https://image.tmdb.org/t/p/original/7iYVYtSIUHnH4FN2x5TzgOFFVHC.jpg', 'In post–civil war Spain, 10-year-old Ofelia moves with her pregnant mother to live under the control of her cruel stepfather. Drawn into a mysterious labyrinth, she meets a faun who reveals that she may be a lost princess from an underground kingdom. To return to her true father, she must complete a series of surreal and perilous tasks that blur the line between reality and fantasy.', 118, '0+', '2006-10-11', 'Fantasy/Drama/War'),
(1062900, '哪吒之魔童降世', 'https://image.tmdb.org/t/p/original/zb8xejiaNR0snSJgDepwFQUIi2e.jpg', 'A young boy is born as the reincarnation of a demonic power, into a society that hates and fears him. Destined by prophecy to bring destruction to the world, Nezha must choose between good and evil to see if he can change his fate.', 110, '0+', '2019-07-26', 'Animation/Fantasy/Adventure'),
(1062901, 'Zgiń, kochanie', 'https://image.tmdb.org/t/p/original/6YPb6nKx0RyZXfAAQeTUsq3jlLA.jpg', 'Grace, a writer and young mother, is slowly slipping into madness. Locked away in an old house in Montana, her increasingly agitated and erratic behaviour leaves her companion, Jackson, worried and helpless.', 119, '0+', '2025-10-06', 'Drama'),
(1062902, 'Punk Love', 'https://image.tmdb.org/t/p/original/qz98uCgBLL3WHFGYtT9xFXCB1Uc.jpg', 'Set in the rainy environs of Oregon and Washington, Punk Love is the story of two forlorn lovers, searching for that elusive Hollywood Ending to the story of their dreams. Sarah is a lost 15-year-old, trapped in an unloving home, in a dreary small paper mill town. When she meets Spike, she envisions a new life for herself. Falling in love, Sarah and Spike go on a crime spree of small-time con jobs, both to support themselves and their drug habit. Spike has dreams of his own, and when he successfully auditions for a band, he can\'t help but feel that he and Sarah are starting on the road to escaping their ill-fated existence. But just as things are looking up, everything goes uncontrollably wrong, and Spike and Sarah have only their undying love for each other as a means of survival against all odds. Director/writer Nick Lyon\'s Punk Love is a modern-day fairy tale about two fallen angels searching for meaning in a world without pity...', 96, '0+', '2006-03-04', 'Drama'),
(1062903, 'The Lie', 'https://image.tmdb.org/t/p/original/d2GFfWJvmmaRjuWsOBzqyCQfML0.jpg', 'Elinor Shale\'s happiness at being engaged to Gerald Forster is interrupted by the arrival of her sister Lucy, who confesses that she will soon give birth to an illegitimate child. Elinor goes into seclusion with her sister until the baby is born and then tries to find a foster mother. Seeking to estrange Gerald from Elinor so that she may marry him herself, Lucy convinces him that Elinor is the child\'s mother. After Lucy and Gerald\'s marriage, Elinor learns of her sister\'s perfidy and resolves to tell Gerald the truth, but at the sight of their happiness, she relents and returns home.', 50, '0+', '1918-04-08', 'Drama'),
(1062904, 'The Defilers', 'https://image.tmdb.org/t/p/original/gaY9sBa9beyZT1dSjILO0ceLitz.jpg', 'Two young thugs kidnap a young girl and keep her in the basement of an old warehouse where they forcibly make her their sex slave.', 69, '0+', '1965-10-01', 'Drama/Thriller/Horror');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1062905, 'Stone Markers', 'https://image.tmdb.org/t/p/original/8RoxG7C3vhlCACo0i2rYbnkwSOn.jpg', '\"I see you, friends...\" So says an eerie voice in the woods that seems to haunt identical twin brothers, Cory and Connor Sherman and their three friends after they discover a strange stone marker in the woods. And when a mental patient escapes and a young boy disappears, the group embarks on a quest that uncovers information related to the disappearances of seven children more than thirty years earlier. But what starts out as an adventure soon turns terrifying as one of the boys goes missing and the remaining boys are confronted by a horrifying truth that threatens their very lives.', 0, '0+', '2012-01-01', 'Adventure/Thriller'),
(1062906, 'Twoja wina', 'https://image.tmdb.org/t/p/original/dUuFgBo5bwCrlZpLQQHBfuyYNSc.jpg', 'The love between Noah and Nick seems unwavering despite their parents\' attempts to separate them. But his job and her entry into college open up their lives to new relationships that will shake the foundations of both their relationship and the Leister family itself.', 118, '0+', '2024-12-26', 'Drama/Romance'),
(1062907, 'Ojciec chrzestny', 'https://image.tmdb.org/t/p/original/g1BqW6xfiztwUVSQY9hevjtYyMr.jpg', 'Spanning the years 1945 to 1955, a chronicle of the fictional Italian-American Corleone crime family. When organized crime family patriarch, Vito Corleone barely survives an attempt on his life, his youngest son, Michael steps in to take care of the would-be killers, launching a campaign of bloody revenge.', 175, '18', '1972-03-14', 'Drama/Crime'),
(1062908, '角頭－鬥陣欸', 'https://image.tmdb.org/t/p/original/eoUcppppVNj8BkgBDkZTv82x3tx.jpg', 'Michael and his right-hand man Scorpion, who find themselves embroiled in their father Ko\'s turf war against rival gangs in Taipei, setting off a conflict between old and new generations of gangsters. The film is the latest installment in the Gatao franchise, following the narrative of a young successor trying to expand his power while navigating the volatile underworld.', 0, '0+', '2025-08-21', 'Crime/Action'),
(1062909, 'Karate Kid: Legendy', 'https://image.tmdb.org/t/p/original/1ntO2pT7wza6H2aF0xyrwyTkgZ2.jpg', 'After a family tragedy, kung fu prodigy Li Fong is uprooted from his home in Beijing and forced to move to New York City with his mother. When a new friend needs his help, Li enters a karate competition – but his skills alone aren\'t enough. Li\'s kung fu teacher Mr. Han enlists original Karate Kid Daniel LaRusso for help, and Li learns a new way to fight, merging their two styles into one for the ultimate martial arts showdown.', 94, '12', '2025-05-08', 'Action/Adventure/Drama'),
(1062910, 'Virtuous Sinners', 'https://image.tmdb.org/t/p/original/dYhNkRYkX9RXO4cHjROvTWsgzBl.jpg', 'A near-forgotten film, Virtuous Sinners tells the story of Dawn Emerson (Wanda Hawley), an abused wife cast out into the street by her uncaring husband. Rescued by a gang of down-and-out patrons of the “End of the Trail” mission, Dawn soon falls for a dapper mission benefactor, Hamilton Jones (Norman Kerry), who is also a high-end burglar. When a member of the mission gang, McGregor, is run over by a car while saving a child, Hamilton robs a home to pay his medical bills. Ratted out by a informant, Hamilton goes on trial, but Dawn and the rest of the gang – including a young Rudolph Valentino in a bit part – stand by his side.', 56, '0+', '1919-05-25', 'Romance/Crime'),
(1062911, 'Uciekinier', 'https://image.tmdb.org/t/p/original/aFp5lfVaq2nIPwBSyiuME0OTPk2.jpg', 'Desperate to save his sick daughter, working-class Ben Richards is convinced by The Running Man\'s charming but ruthless producer to enter the deadly competition game as a last resort. But Ben\'s defiance, instincts, and grit turn him into an unexpected fan favorite - and a threat to the entire system. As ratings skyrocket, so does the danger, and Ben must outwit not just the Hunters, but a nation addicted to watching him fall.', 133, '0+', '2025-11-11', 'Action/Thriller/Science Fiction'),
(1062912, 'Surviving Eden', 'https://image.tmdb.org/t/p/original/4LThZIfaufpnBkPnopTyIbaE0mz.jpg', 'A documentary crew captures the capitalistic trappings a reality show winner falls into during his short-lived stint with fame and fortune.', 89, '0+', '2004-03-01', 'Comedy'),
(1062913, 'Czerwona Sonja', 'https://image.tmdb.org/t/p/original/aE3yh4y0h96CZZpLo0UDFMWZAA9.jpg', 'A young girl rises from the ashes of tragedy to become the most feared warrior woman of all time: the She-Devil with a Sword.', 110, '0+', '2025-07-31', 'Adventure/Action/Fantasy'),
(1062914, 'Piraci z Karaibów. Na krańcu świata', 'https://image.tmdb.org/t/p/original/1c4zYjZdZxiBA3tPRmUpWZnUSIi.jpg', 'Will Turner and Elizabeth Swann join forces with the revived Captain Barbossa to free Jack Sparrow from Davy Jones\' locker. The group must navigate dangerous waters, confront many foes and, ultimately, choose sides in a battle wherein piracy itself hangs in the balance.', 169, '16', '2007-05-19', 'Adventure/Fantasy/Action'),
(1062915, 'Golden Hour', 'https://image.tmdb.org/t/p/original/7nfS3WRIh5SeMdmCPzZmbmmxxB6.jpg', 'Filmmaking can sometimes be a very chaotic process. Allie is about to learn it as the director just got one last crazy idea.', 6, '0+', '2022-10-24', 'Animation/Family'),
(1062916, 'Black Mold', 'https://image.tmdb.org/t/p/original/tEN12WSxepFqZmWEknBnrXoHDvL.jpg', 'Photographers Brooke Konrad and Tanner Behlman travel to rural, abandoned buildings to capture the inherent beauty of long-forgotten locations, but far from forgotten are the traumatic memories that surface in Brooke when they meet The Man Upstairs, an unsuspecting squatter. As tensions and uncertainties arise, Brooke must determine if this mysterious stranger will provide her the closure she so desperately seeks or let the fears of the past consume her.', 92, '0+', '2025-01-30', 'Horror/Thriller/Drama/TV Movie'),
(1062917, 'La pie voleuse', 'https://image.tmdb.org/t/p/original/lvNpUwVOlj9hoY0JiH5b5OHh9SJ.jpg', 'Maria, who\'s not as young as she used to be and who helps people older than her, is living from hand to mouth. She can\'t quite accept her precarious situation and steals a few euros here and there from all those lovely people she looks after with such devotion, and who adore her for it… But after an accusation of abuse of a vulnerable person, Maria winds up in police custody.', 0, '0+', '2025-01-29', 'Drama/Comedy'),
(1062918, 'Wąwóz', 'https://image.tmdb.org/t/p/original/3AzVTo0rVnNyCtQvU82YsdsgHsE.jpg', 'Two highly trained operatives grow close from a distance after being sent to guard opposite sides of a mysterious gorge. When an evil below emerges, they must work together to survive what lies within.', 128, '12', '2025-02-13', 'Romance/Science Fiction/Thriller'),
(1062919, 'Kraina lodu', 'https://image.tmdb.org/t/p/original/ydbRzsNjAbclgWYHDkZKlgaKZoR.jpg', 'Young princess Anna of Arendelle dreams about finding true love at her sister Elsa’s coronation. Fate takes her on a dangerous journey in an attempt to end the eternal winter that has fallen over the kingdom. She\'s accompanied by ice delivery man Kristoff, his reindeer Sven, and snowman Olaf. On an adventure where she will find out what friendship, courage, family, and true love really means.', 102, 'AL', '2013-11-20', 'Animation/Family/Adventure/Fantasy'),
(1062920, 'Fachowiec', 'https://image.tmdb.org/t/p/original/svOxLFytPajfYOuAjzySRzLwIB5.jpg', 'Levon Cade left behind a decorated military career in the black ops to live a simple life working construction. But when his boss\'s daughter, who is like family to him, is taken by human traffickers, his search to bring her home uncovers a world of corruption far greater than he ever could have imagined.', 116, '0+', '2025-03-26', 'Action/Crime/Thriller'),
(1062921, 'Girl Play', 'https://image.tmdb.org/t/p/original/2ZS0H8ysSzD0d0k8zdO2jeM3kge.jpg', 'Two real-life lesbian actresses meet by chance when they are cast as lovers in a local stage play, and end up actually falling in love. Robin, who is married to her girlfriend for half a dozen years, and Lacie, someone who never had a lasting relationship, are both cast to play lesbian lovers in a Los Angeles stage play. Innocently, the stage director, Gabriel runs the actresses through a series of rehearsals designed to \"bring out the intimacy\" in each performer. Soon the two women find themselves increasingly and undeniably attracted to each other and overcome with desire. They must ask themselves whether this relationship is manufactured, created for the sake of the \"girl play\", or is true love.', 80, '0+', '2004-07-11', 'Comedy/Romance'),
(1062922, 'W głowie się nie mieści 2', 'https://image.tmdb.org/t/p/original/qMOsTBu0FMqSLigMEvyxt6gU3nP.jpg', 'Teenager Riley\'s mind headquarters is undergoing a sudden demolition to make room for something entirely unexpected: new Emotions! Joy, Sadness, Anger, Fear and Disgust, who’ve long been running a successful operation by all accounts, aren’t sure how to feel when Anxiety shows up. And it looks like she’s not alone.', 97, '0+', '2024-06-11', 'Animation/Adventure/Comedy/Family'),
(1062923, 'Oddaj ją', 'https://image.tmdb.org/t/p/original/1Q3GlCXGYWELifxANYZ5OVMRVZl.jpg', 'Following the death of their father, a brother and sister are sent to live with a foster mother, only to learn that she is hiding a terrifying secret.', 104, '0+', '2025-05-28', 'Horror'),
(1062924, 'Obcy. Romulus', 'https://image.tmdb.org/t/p/original/6FsZvai0QZDdtOf2ideSRUZZyg.jpg', 'While scavenging the deep ends of a derelict space station, a group of young space colonizers come face to face with the most terrifying life form in the universe.', 119, '0+', '2024-08-13', 'Horror/Science Fiction'),
(1062925, 'Państwo Rose', 'https://image.tmdb.org/t/p/original/98n5HnCJ5LnXKIMNP9SBfVNyxCE.jpg', 'Life seems easy for picture-perfect couple Ivy and Theo: successful careers, a loving marriage, great kids. But beneath the façade of their supposed ideal life, a storm is brewing – as Theo\'s career nosedives while Ivy\'s own ambitions take off, a tinderbox of fierce competition and hidden resentment ignites.', 105, '16', '2025-08-27', 'Comedy/Drama/Romance'),
(1062926, 'Predator 2', 'https://image.tmdb.org/t/p/original/83X4VwY9sdSJykskmsplIVG0a4h.jpg', 'A police chief in the war-torn streets of Los Angeles discovers that an extraterrestrial creature is hunting down residents - and that he is the next target.', 108, '0+', '1990-11-21', 'Science Fiction/Action/Thriller'),
(1062927, 'Skazani na Shawshank', 'https://image.tmdb.org/t/p/original/sBnhJ4f5KAzg6C3FwnEb8QFj8SB.jpg', 'Imprisoned in the 1940s for the double murder of his wife and her lover, upstanding banker Andy Dufresne begins a new life at the Shawshank prison, where he puts his accounting skills to work for an amoral warden. During his long stretch in prison, Dufresne comes to be admired by the other inmates -- including an older prisoner named Red -- for his integrity and unquenchable sense of hope.', 142, '15', '1994-09-23', 'Drama/Crime'),
(1062928, 'Our Holiday Story', 'https://image.tmdb.org/t/p/original/15TXQSd0RerDV7XNtOcTNhnfhOq.jpg', 'Dave and Nell recount the Christmas where they unknowingly fell in love while working as rivals on a town festival, as their daughter’s boyfriend struggles to navigate his own relationship.', 84, '0+', '2024-11-02', 'TV Movie/Comedy/Romance'),
(1062929, 'Mamasan', 'https://image.tmdb.org/t/p/original/denXd5zWlcwhMy7XHUlgeTzrfjX.jpg', 'A seasoned woman and a budding one collide when passion ignites between them. Tanya, a mamasan, protects Pinky, the new girl in the bar, until she discovers her boyfriend Ador is having an affair with her.', 75, '0+', '2025-10-31', 'Drama'),
(1062930, 'Trois amies', 'https://image.tmdb.org/t/p/original/eEOUHNPUdEOpAT4js1eTaQqdrAi.jpg', 'Joan is no longer in love with Victor, but it pains her to feel she is being dishonest with him. Alice, her best friend, reassures her: She herself doesn’t feel passionate about her partner Eric and yet their relationship is smooth sailing. She has no idea he is having an affair with Rebecca, their mutual friend. When Joan finally decides to leave Victor and he disappears, the lives of the three friends and their relationships are turned upside down.', 117, '0+', '2024-11-06', 'Comedy/Romance/Drama'),
(1062931, 'Harry Potter i Kamień Filozoficzny', 'https://image.tmdb.org/t/p/original/wNRk1vec98vfAQa2YdZOt7h0DGe.jpg', 'Harry Potter has lived under the stairs at his aunt and uncle\'s house his whole life. But on his 11th birthday, he learns he\'s a powerful wizard—with a place waiting for him at the Hogwarts School of Witchcraft and Wizardry. As he learns to harness his newfound powers with the help of the school\'s kindly headmaster, Harry uncovers the truth about his parents\' deaths—and about the villain who\'s to blame.', 152, '12', '2001-11-16', 'Adventure/Fantasy'),
(1062932, 'Iniemamocni 2', 'https://image.tmdb.org/t/p/original/lvjRH6GwGO7vS6RFL5buJPFugVa.jpg', 'Elastigirl springs into action to save the day, while Mr. Incredible faces his greatest challenge yet – taking care of the problems of his three children.', 118, '7', '2018-06-14', 'Action/Adventure/Animation/Family'),
(1062933, 'Forrest Gump', 'https://image.tmdb.org/t/p/original/iixrNXX79OR7knBx1i9S51PfVlz.jpg', 'A man with a low IQ has accomplished great things in his life and been present during significant historic events—in each case, far exceeding what anyone imagined he could do. But despite all he has achieved, his one true love eludes him.', 142, '12', '1994-06-23', 'Comedy/Drama/Romance'),
(1062934, 'Link do zbrodni', 'https://image.tmdb.org/t/p/original/6BWNf7pztCW8Xax0OS5fc2QG7xw.jpg', 'Nick is excited to discover he\'s won a dinner date with his favorite actress, Jill Goddard. But when Jill refuses to honor the contest, he receives an offer he can\'t refuse: the ability to view Jill secretly via computer. Nick begins watching the unknowing star on her webcam, not realizing that this decision will put himself and Jill at risk as they enter a terrifying world of cat-and-mouse.', 101, '0+', '2014-07-04', 'Thriller/Action/Crime'),
(1062935, 'KL Vampires', 'https://image.tmdb.org/t/p/original/yAvYROLySws3nTU9Es2yi76a1Zg.jpg', 'The story is about 2 groups of Vampires, one decedents of Raja Bersiong, who protects Humans and drinks only synthetic blood and another bad vampires which drinks human blood and wants to conquer the world. The Good Vampire kingdom is headed by Vampire queen named Ratu Chitra Sari (Raja Ilya) and her main commander Shah (Josiah Hogan). The antagonist is played by (Donny Alamsyah) as AGUS. Agus is son of Panglima Adi Wijaya who betrayed Raja Bersiong (Father of Ratu Chitra sari) who is the 1st Vampire king who grew fangs after drank human blood. 200 years ago, Raja bersiong Killed Adi Wijaya and grounded his blood thirst soldiers under the ground with a spell. The soldiers can only be awaken by the spell and the blood of Raja Bersiong or his decedents After 200 years on the eclipse , Adi Wijaya, wants to awaken Adi Wijaya’s soldiers and take revenge on Ratu Chitra sari and conquer the human world.', 93, '0+', '2019-11-14', 'Action/Horror'),
(1062936, 'Night Carnage', 'https://image.tmdb.org/t/p/original/w0wjPQKhlqisSbylf1sWZiNyc2h.jpg', 'A blogger who is also a werewolf meets a dashing playboy with a dark secret of his own. Starring Logan Andrews and Christian Howard.', 80, '0+', '2025-07-29', 'Action/Horror/Romance'),
(1062937, 'Król snajperów', 'https://image.tmdb.org/t/p/original/r5C85R0Bc6RL51PnPv2HIvpSMJ7.jpg', 'The genius sniper Anna is forced to accept an assassination assignment. In the process, she gradually finds her true calling to fight for kindness and to defend a greater love. Tai, a special agent for the UN army, stands up for justice when drug lords try to harm innocent citizens. The two join forces to block the bill to legalize drug cultivation and distribution in Libiwala. They fight to the death with the drug lord Luo Jie and eventually foil his plans, protecting the people from the drugs. This is the exciting story of them working together to save a nation.', 98, '0+', '2023-01-24', 'Action/Crime/Comedy/War'),
(1062938, 'Piraci z Karaibów. Na nieznanych wodach', 'https://image.tmdb.org/t/p/original/yO3WUzGhp4xNpFCq5sUBNN7gE7.jpg', 'Captain Jack Sparrow crosses paths with a woman from his past, and he\'s not sure if it\'s love — or if she\'s a ruthless con artist who\'s using him to find the fabled Fountain of Youth. When she forces him aboard the Queen Anne\'s Revenge, the ship of the formidable pirate Blackbeard, Jack finds himself on an unexpected adventure in which he doesn\'t know who to fear more: Blackbeard or the woman from his past.', 136, '16', '2011-05-15', 'Adventure/Action/Fantasy'),
(1062939, 'O\' Horten', 'https://image.tmdb.org/t/p/original/uIHdJ1jwVdh9XhzRe5Oqp6DOt4v.jpg', 'Odd Horton is dependable and contained: he\'s a train driver retiring after 40 years of service, living a simple life. His idea of adventure is to fly from one city in Norway to another. Starting on the night of his retirement dinner, Odd has a series of dislocating experiences: a boy insists that Odd sit by his bedside while he falls asleep; misadventure causes Odd to miss his last run; he witnesses an arrest; he assists an old man and makes a friend; he takes a trip with a blindfolded driver; he adopts a dog; he takes stock late one night at the roundhouse; he revisits his mother\'s disappointment in him. How should he live the rest of his life?', 90, '0+', '2007-12-26', 'Drama/Comedy'),
(1062940, 'Scorpions - Forever and a Day', 'https://image.tmdb.org/t/p/original/sqipg4iG3QwAqzyIbdLw2CVGZ9A.jpg', 'A documentary on the acclaimed rock band Scorpions', 100, '0+', '2015-03-26', 'Documentary/Music'),
(1062941, 'Punkt wrzenia', 'https://image.tmdb.org/t/p/original/vcezXINs3aX55R7g1yptEHTjHde.jpg', 'A head chef balances multiple personal and professional crises at a popular restaurant in London.', 95, '16', '2021-07-05', 'Drama/Thriller'),
(1062942, 'Kac Vegas', 'https://image.tmdb.org/t/p/original/2gUIZ1LZMCtO4zcIZC4r7c5pV6Q.jpg', 'When three friends finally come to after a raucous night of bachelor-party revelry, they find a baby in the closet and a tiger in the bathroom. But they can\'t seem to locate their best friend, Doug – who\'s supposed to be tying the knot. Launching a frantic search for Doug, the trio perseveres through a nasty hangover to try to make it to the church on time.', 100, '18', '2009-06-02', 'Comedy'),
(1062943, 'The Unsuspected', 'https://image.tmdb.org/t/p/original/cUhDjZUHtWuB1tAnpHbIXeQMsGb.jpg', 'The secretary of an affably suave radio mystery host mysteriously commits suicide after his wealthy young niece disappears.', 103, '0+', '1947-10-11', 'Drama/Mystery/Thriller'),
(1062944, 'Batman Azteca: Choque de imperios', 'https://image.tmdb.org/t/p/original/2nifUnsraLRfZL4vWCTi7A92DiN.jpg', 'In the time of the Aztec empire, tragedy strikes Yohualli Coatl when his father is murdered by Spanish conquistadors. To warn King Moctezuma and his high priest, Yoka, of imminent danger, Yohualli escapes to Tenochtitlán. There, he trains in the temple of the bat god Tzinacan with his mentor, developing equipment and weaponry to confront the Spanish invasion and avenge his father’s death. Along the way, he encounters key figures like the fierce Jaguar Woman and the conquistador Hernán Cortés.', 90, '0+', '2025-09-18', 'Animation/Action/Adventure/Fantasy'),
(1062945, 'Dance Craze', 'https://image.tmdb.org/t/p/original/dlMjGCRZsvHVvjhAXz1ssUDvBfY.jpg', 'Rocksteady to both a visual and musical documentary of the big shots of the English 2-Tone movement of the late 1970s that has the exhaustive, high-energy performances exploding onto stage. Jump, shout, twist and crawl and dance to the tunes of Ska and its anthems of its rough riders and three-minute heroes captivated in the moment of a generation of England\'s concrete jungles and razor blade alleys. No longer on your radio but now on stage, together, with the likes of Madness, The Specials and The Beat et al, this concert footage of an era is a must-see, rare and fascinating look into a once vibrant youth culture of working-class England and its musical dance craze.', 85, '0+', '1981-02-10', 'Music/Documentary'),
(1062946, 'Avengers: Wojna bez granic', 'https://image.tmdb.org/t/p/original/zLLs37yOubp9Snt5n1UE0DKvWGo.jpg', 'As the Avengers and their allies have continued to protect the world from threats too large for any one hero to handle, a new danger has emerged from the cosmic shadows: Thanos. A despot of intergalactic infamy, his goal is to collect all six Infinity Stones, artifacts of unimaginable power, and use them to inflict his twisted will on all of reality. Everything the Avengers have fought for has led up to this moment - the fate of Earth and existence itself has never been more uncertain.', 149, '12', '2018-04-25', 'Adventure/Action/Science Fiction'),
(1062947, 'Zwierzogród', 'https://image.tmdb.org/t/p/original/kTPaxxk7FlV0J77U2ztywjGf8Sb.jpg', 'Determined to prove herself, Officer Judy Hopps, the first bunny on Zootopia\'s police force, jumps at the chance to crack her first case - even if it means partnering with scam-artist fox Nick Wilde to solve the mystery.', 109, '7', '2016-02-11', 'Animation/Adventure/Family/Comedy'),
(1062948, 'Hotel Dunsmuir', 'https://image.tmdb.org/t/p/original/1Jl5WbAEd7jaBfQklsbTwbGqkc3.jpg', 'A young woman with extrasensory perception flees her abusive husband, only to land at an historic hotel containing a sinister presence.', 104, '0+', '2022-10-04', 'Horror'),
(1062949, 'Crooked Arrows', 'https://image.tmdb.org/t/p/original/7U4h600YDepnrTOwa2MmQgYi8lN.jpg', 'A native-American lacrosse team makes its way through a prep school league tournament.', 105, '0+', '2012-05-18', 'Drama'),
(1062950, 'The Astronaut', 'https://image.tmdb.org/t/p/original/souvvkJHYhztC1UqZ8lEVUiJa3J.jpg', 'After returning from her first space mission, astronaut Sam Walker is placed under NASA’s care at a high security house for rehabilitation and medical testing. However, when disturbing occurrences begin happening around the property, she fears that something extraterrestrial has followed her back to Earth', 90, '0+', '2025-09-26', 'Horror/Science Fiction/Thriller'),
(1062951, 'Piraci z Karaibów. Klątwa Czarnej Perły', 'https://image.tmdb.org/t/p/original/uqReraSvOaQXLkFp3TjqQQT2daf.jpg', 'After Port Royal is attacked and pillaged by a mysterious pirate crew, capturing the governor\'s daughter Elizabeth Swann in the process, William Turner asks free-willing pirate Jack Sparrow to help him locate the crew\'s ship—The Black Pearl—so that he can rescue the woman he loves.', 143, '12', '2003-07-09', 'Adventure/Fantasy/Action'),
(1062952, 'Avatar: Istota wody', 'https://image.tmdb.org/t/p/original/jzJIKuu1OaZxtEDdgGAwvZYDuKL.jpg', 'Set more than a decade after the events of the first film, learn the story of the Sully family (Jake, Neytiri, and their kids), the trouble that follows them, the lengths they go to keep each other safe, the battles they fight to stay alive, and the tragedies they endure.', 192, '12', '2022-12-14', 'Action/Adventure/Science Fiction'),
(1062953, 'Grzesznicy', 'https://image.tmdb.org/t/p/original/xX737WktKAaCfPMTPVZMqyQna2Y.jpg', 'Trying to leave their troubled lives behind, twin brothers return to their hometown to start again, only to discover that an even greater evil is waiting to welcome them back.', 138, '0+', '2025-04-16', 'Horror/Action/Thriller'),
(1062954, 'Koralina i tajemnicze drzwi', 'https://image.tmdb.org/t/p/original/qA6GwcREVpAY6Ky3rZHbTfbAMhC.jpg', 'Wandering her rambling old house in her boring new town, 11-year-old Coraline discovers a hidden door to a strangely idealized version of her life. In order to stay in the fantasy, she must make a frighteningly real sacrifice.', 100, '12', '2009-02-05', 'Animation/Family/Fantasy'),
(1062955, 'Clothesline Patch', 'https://image.tmdb.org/t/p/original/hOgl4u6hmXfhfimYXV2JXd4Zbh9.jpg', 'Clothesline Patch is the story of a young girl trying to keep a secret in a small Newfoundland outport (c. 1966), an unlikely setting for keeping secrets. The central focus is the clothesline patch, the communal clearing where washing is set out to dry. It is also the place where gossip is shared. Hannah is determined that her secret of becoming a woman must never reach the clothesline patch. To ensure this, she goes to extraordinary lengths to hide the fact that she has entered puberty, sometimes with amusing results.', 23, '0+', '2000-01-01', 'Drama'),
(1062956, 'Thunderbolts*', 'https://image.tmdb.org/t/p/original/pWqAVY0GR6IsSluS4M9JccDtOI6.jpg', 'After finding themselves ensnared in a death trap, seven disillusioned castoffs must embark on a dangerous mission that will force them to confront the darkest corners of their pasts.', 127, '0+', '2025-04-30', 'Action/Science Fiction/Adventure'),
(1062957, 'Assisted Fishing', 'https://image.tmdb.org/t/p/original/9exTYke078YkgJ2jRv71WaooVo4.jpg', 'Dewey Winfield is a lovable loser who wants nothing more than to beat the guy who has bullied him his whole life in a big fishing tournament.  In order to win, Dewey will need the help of some eccentric senior citizens who are about to be evicted from their assisted living home.  When they all go fishing, comedy ensues - tragedy strikes - and Dewey discovers that his hopes and dreams of winning the fishing tournament may not be the most important thing in life after all.', 101, '0+', '2012-01-19', 'Comedy/Family'),
(1062958, 'Pédale douce', 'https://image.tmdb.org/t/p/original/eTsacNYD4grU2dAnINLUcttxzY2.jpg', 'A closeted gay man\'s attempt to \"act straight\" for the sake of his job has unexpected consequences.', 100, '0+', '1996-03-27', 'Comedy'),
(1062959, 'En röst ur det förgångna', 'https://image.tmdb.org/t/p/original/wfPI193r3nJws2ZHhL3YB3xxNYR.jpg', '\"A voice from the past: a program about the explorer and politician Sven Hedin (1865-1952)\" - based on his own statements and writings. Takes us through expeditions in Asia, Olympic Games in Stockholm and Berlin, two world wars, and a Swedish political conflict during the 1930s when the pro-Nazi Swedish party Sweden\'s National Federation aspired to power.', 41, '0+', '1971-04-10', 'Documentary'),
(1062960, 'Девочка Нина и похитители пианино', 'https://image.tmdb.org/t/p/original/6bLaxH75nOXBNaERh39l0VMUlpx.jpg', 'Eight-year-old Nina is an impulsive and emotional girl, quickly igniting ideas and dropping them halfway. Nina would probably have abandoned her new hobby - music - too, but a strange thing happened: the instrument began to behave defiantly, play by itself and provoke the hostess in every possible way. And soon Nina was completely kidnapped along with him. The villains plan to subjugate the world with the help of the piano.', 84, '0+', '2023-08-31', 'Music/Fantasy/Adventure/Family'),
(1062961, 'Reverse', 'https://image.tmdb.org/t/p/original/i5l4HELaDp6ncz4dKeiVEpPojVi.jpg', 'A man attempts to exit an underground car park. Something doesn\'t want him to.', 5, '0+', '2018-10-25', 'Horror'),
(1062962, 'Mały', 'https://image.tmdb.org/t/p/original/9UBRxLqRcoPYYXzc1GFxZkftzQl.jpg', 'After leaving the prison, the dwarf criminal Calvin Sims joins to his moron brother Percy to steal an expensive huge diamond in a jewelry for the mobster Walken. They are chased by the police, and Calvin hides the stone in the purse of the executive Vanessa Edwards, whose husband Darryl Edwards wants to have a baby. Percy convinces Calvin to dress like a baby and be left in front of the Edwards\'s house to get inside the house and retrieve the diamond. Darryl and Vanessa keep Calvin for the weekend and decide to adopt him, while Walken threatens Darryl to get the stone back.', 98, '0+', '2006-08-31', 'Comedy/Crime'),
(1062963, 'Cuando los amos duermen', 'https://image.tmdb.org/t/p/original/6YNscZbeUoZgAQmZ0Z8zoMhpFpR.jpg', 'Samuel and Lourdes are a humble marriage that go out of their way taking care of the land and their Lord properties. The owner of the house is Víctor, an ancient vampire that only feeds himself with the blood of bad people. Generation over generation, Samuel\'s family has been in charge of the duty of protecting their Lord but now, Samuel and Lourdes have two problems: they can not have a baby and a mysterious vampire relative arrives to the place turning everything upside down.', 98, '0+', '2023-10-15', 'Comedy/Drama/Fantasy/Horror'),
(1062964, 'American Brothers', 'https://image.tmdb.org/t/p/original/pTSV512ZCWPrxaygVEs0XfrZoAG.jpg', 'As boys, Dick, Joe, and Benny Mahoney wanted to be Heroes. But disaster struck and their family was never the same. Now grown up and recently paroled, Dick decides to reconnect once more with his brothers before leaving the country for good. Their parents long gone, Joe runs the family business, and takes care of the emotionally damaged Benny. They come together remembering the good times, but Dick sees his brothers drowning in their routine. Joe visits the same comic store every week, only to freeze up when the cute cashier flirts with him. Benny medicates, watching cartoons around the clock except to visit his psychiatrist where the other patients are his only friends. Knowing they want to make a difference in their community, Dick pushes his brothers to discover what it means to be the change you want to see in the world-- and become', 93, '0+', '2019-03-12', 'Drama'),
(1062965, 'Meteor Apocalypse', 'https://image.tmdb.org/t/p/original/dQmxTUlLYvy7tCkSctD4QpalPsb.jpg', 'A gigantic meteors enters Earth\'s orbit and begins to disintegrate, showering the entire planet with debris.', 88, '0+', '2010-02-23', 'Action/Science Fiction/Thriller'),
(1062966, 'Predator', 'https://image.tmdb.org/t/p/original/a3eWGF6YPF7No5Rbtjc8QpDvz7l.jpg', 'When a young boy accidentally triggers the universe\'s most lethal hunters\' return to Earth, only a ragtag crew of ex-soldiers and a disgruntled scientist can prevent the end of the human race.', 107, '18', '2018-09-05', 'Science Fiction/Action/Thriller'),
(1062967, 'Sonic 3. Szybki jak błyskawica', 'https://image.tmdb.org/t/p/original/jB2YMUEq4xbQAcL2q1mhCcPeEFP.jpg', 'Sonic, Knuckles, and Tails reunite against a powerful new adversary, Shadow, a mysterious villain with powers unlike anything they have faced before. With their abilities outmatched in every way, Team Sonic must seek out an unlikely alliance in hopes of stopping Shadow and protecting the planet.', 110, '7', '2024-12-19', 'Action/Science Fiction/Comedy/Family'),
(1062968, 'Manasichi Choodu', 'https://image.tmdb.org/t/p/original/1FGkaC7CVz9jZQjd0D1Y5eLUkKU.jpg', 'Manasichi Choodu is a comedy entertainer directed by Rudraraju Suresh Varma. This film mainly deals with youth unemployment. Ravi Teja, Raasi &amp; Vadde Naveen cast the main leads while the supporting cast has Suhasini, Ali &amp; Ganesh Babu. Naveen loves Raasi from his childhood but they go their seperate ways to pursue higher studies. When Naveen makes his feelings known to Raasi, she accepts him and tells him that her father will let Naveen marry her only if he\'s settled with a good job and is in a position to take care of her. So, Naveen focuses all his time and energy in getting a job. Meanwhile, Raasi\'s father, unaware of his daughter\'s choice, plans to get her married to Srihari but when he learns that Raasi is in love with Naveen, he calls off the wedding. Insulted, Srihari kidnaps Raasi and holds her hostage. How Naveen and Raasi unite and how all their friends find jobs for themselves and all the consequences that follow forms the rest of the story.', 150, '0+', '1998-08-08', NULL),
(1062969, 'Perforations 2001', 'https://image.tmdb.org/t/p/original/5e1UaGKyyaCdS65FvS5EZEmuupl.jpg', 'Perforations 2001 starts off 10 years after the original. Barbara Joyce stars as a businesswoman who works for an unseen partner in the creation of snuff tapes. Once again, the targets of these tapes are prison inmates whose disappearances won’t create much of a stir. The first order of business is to kill the real Dr. Julia (Tina Krause) and replace her with another prison doctor (Pamela Sutch). Debbie D is Carla, the mercenary hired to kill the inmates and Luke Marlowe is the cameraman recording the deaths and Dean Paul is Barbara’s assistant. Laura Giglio is Jade, the sadistic prison guard who loves using her cattle prod! Also starring as the inmates are Veronika Blu, Elizabeth Raven, Kathy Lynn and introducing Vanessa, with Jordan East as the “warden”. Will anyone survive this bloody rampage?', 60, '0+', '2001-01-01', 'Horror/Thriller'),
(1062970, 'Mulan', 'https://image.tmdb.org/t/p/original/bj3iSjLlkwHtJrPmvHXa8P7edI9.jpg', 'To save her father from certain death in the army, a young woman secretly enlists in his place and becomes one of China\'s greatest heroines in the process.', 88, '0+', '1998-06-18', 'Animation/Family/Adventure'),
(1062971, 'El diabólico', 'https://image.tmdb.org/t/p/original/vThg5oqd8HSqsTBBsodYxLuyxHv.jpg', 'Dave Boland (Carlos East) wears a strange medallion and robs the bank. He also takes the banker\'s daughter with him. Then he rapes her and put the satanic mark on  her body. He was caught and was prepared for hanging. At moment before hanging Dave uses his supernatural power and makes a local shoe-shiner his accomplice. While running from sheriff Dave was injured and after some time dies. But before his death Dave gives this medallion to shoe-shiner Oscar and asks him to take revenge in the name of Satan. So he does it and also continue to rape and kill women never forgetting to leave satanic mark on their bodies...', 93, '0+', '1977-11-24', 'Western/Horror/Mystery'),
(1062972, 'Judy', 'https://image.tmdb.org/t/p/original/9QKiOHTJC4K5IZWpLszEt1vkcPM.jpg', 'A man develops an intimate relationship with a female android.', 11, '0+', '2016-09-24', 'Science Fiction/Comedy/Romance'),
(1062973, 'Shelter', 'https://image.tmdb.org/t/p/original/v7Mscq4larnd79VVqxvX8otsdpd.jpg', 'In 2001 Woodshed Films released their third Moonshine Experiment surf movie entitled “Shelter.” With a similar style and feel to the first two Moonshine Experiments, “Thicker Than Water” and “September Sessions”, “Shelter” is one of Taylor Steele and Chris Malloy’s best productions. This surf movie does a great job of staying far away from the politics of surfing and focuses more on soul surfing. However, don’t think that there aren’t any surfers worth watching in this movie because there are plenty. “Shelter” is jam packed with professional and well-known surfers such as Rob Machado, Taylor Knox, Joel Tudor, Mick Fanning, Dean Morrison, Jack Johnson, The Malloy’s, Kelly Slater, Nat Young, Donavon Frankenreiter, Shane Dorian, Jon Swift and many more.  The soundtrack for “Shelter” is similar to “Thicker Than Water” and “September Sessions”. It has a slower and mellower feel, featuring artists such as Mason Jennings, The Shins, White Buffalo and even surfers Jon Swift and Rob Machado.', 40, '0+', '2001-01-01', 'Documentary'),
(1062974, 'Submarine Raider', 'https://image.tmdb.org/t/p/original/kwtUpay3VMtAxTe9QW5Ne3sk2YC.jpg', 'On December 6, 1941, Captain Yamanada of the Japanese aircraft carrier \"Hiranamu\", orders full steam ahead for Pearl Harbor. His ship encounters and sinks an American yacht and the single survivor, Sue Curry, is rescued by an American submarine, the \"Sea Serpent\", commanded by Commander Chris Warren. He hears her story and attempts to radio a warning to Pearl Harbor. Yamanada, hearing the signals, orders the airlines jammed, and then sends his son into the air to sink the sub. The attack fails, after the sub makes a crash dive, but they fail in their warning attempts. The next morning, December 7th, the men on the sub hear the story of the bombing of Pearl Harbor, and devise a desperate plan to sink the Japanese carrier by letting the carrier know their position. The carrier comes in search of the submarine.', 64, '0+', '1942-06-04', 'Drama/War'),
(1062975, 'Nasze magiczne Encanto', 'https://image.tmdb.org/t/p/original/7W47YfXkbwFrctZa8K68sgjHyjU.jpg', 'The tale of an extraordinary family, the Madrigals, who live hidden in the mountains of Colombia, in a magical house, in a vibrant town, in a wondrous, charmed place called an Encanto. The magic of the Encanto has blessed every child in the family—every child except one, Mirabel. But when she discovers that the magic surrounding the Encanto is in danger, Mirabel decides that she, the only ordinary Madrigal, might just be her exceptional family\'s last hope.', 102, 'AL', '2021-10-13', 'Animation/Comedy/Family/Fantasy'),
(1062976, 'Zbrojna Odpowiedź', 'https://image.tmdb.org/t/p/original/6ii3cMm7UWHRG60sbvdntlU3z9k.jpg', 'The story follows a team of highly trained operatives who find themselves trapped inside an isolated military compound.', 93, '0+', '2017-08-04', 'Action/Horror/Thriller'),
(1062977, 'Księgowy 2', 'https://image.tmdb.org/t/p/original/xwEoSZfuNFLugS5lEEjwwIarnZw.jpg', 'When an old acquaintance is murdered, Wolff is compelled to solve the case. Realizing more extreme measures are necessary, Wolff recruits his estranged and highly lethal brother, Brax, to help. In partnership with Marybeth Medina, they uncover a deadly conspiracy, becoming targets of a ruthless network of killers who will stop at nothing to keep their secrets buried.', 133, '0+', '2025-04-23', 'Mystery/Crime/Thriller'),
(1062978, 'Pork Pie', 'https://image.tmdb.org/t/p/original/rVq78wlHLWTf1QQ0BzdcBeg8vM.jpg', 'A trio of accidental outlaws travel the length of New Zealand, protesting conformity and chasing lost love, with a posse of cops and a media frenzy in pursuit.', 105, '0+', '2017-02-02', 'Action/Comedy/Crime'),
(1062979, 'The Bus', 'https://image.tmdb.org/t/p/original/5XwbNvkYdcRqZoWFfIFNJ2O6VEG.jpg', 'The struggle for civil rights has been one of the most important issues of American life for the last fifty years. In August of 1963, groups from all over the country journeyed to Washington D.C. for a massive demonstration, and this film is a fascinating document of this event. Celebrated filmmaker Haskell Wexler (\"Medium Cool\") traveled with the San Francisco delegation, photographing and conversing candidly with the participants. He has succeeded admirably in capturing the significance and drama of this historic trip.', 62, '0+', '1965-04-05', 'Documentary'),
(1062980, 'Maixabel', 'https://image.tmdb.org/t/p/original/7lOcGma9G2yak5qB6ITwg3j0PDm.jpg', 'In the year 2000, Maixabel Lasa’s husband, Juan Maria Jauregi, was killed by ETA. Eleven years later, she receives an incredible request: one of the men who killed Juan wants to meet with her in the Nanclares de la Oca prison in Araba (Spain), where he is serving his sentence after breaking ties with the terrorist group.  Despite her reservations and her immense pain, Maixabel Lasa agrees to meet face to face with those who ended the life of the person who had been her companion since she was 16 years old. ‘Everyone deserves a second chance’, she said, when asked why she was willing to confront the man who killed her husband.', 115, '0+', '2021-09-24', 'Drama'),
(1062981, 'Terrorgram', 'https://image.tmdb.org/t/p/original/nDXn5RW7ls7pFc69xv5MhK4S5Ad.jpg', 'Three horror stories linked by a sinister delivery boy. The stories are \"Heroine Overdose\", \"Pandora\" and \"Veteran\'s Day\".', 88, '0+', '1990-01-01', 'Fantasy/Horror/Thriller'),
(1062982, 'Desperate Souls', 'https://image.tmdb.org/t/p/original/oTaBK1AoCCWuq5zTXBxDBgSY4V8.jpg', 'Living in the endless void of the afterlife, Moira survives on the lust, despair and grief of men, an existence this enchantress has known for eons as a succubus. Using her exquisite beauty, she lures them with false hopes of relief from the mental pain before consuming their broken souls.  ​When Moira hears the cries of Devin, a man whose life dances on the edge of a razor blade, she’s drawn to a pain she’s never felt before. Discovering they both found what they have longed for, Moira is determined to keep them together and not let anyone stand in their way, no matter who she must kill.', 0, '0+', '2023-05-26', 'Horror/Romance'),
(1062983, 'Light of the World', 'https://image.tmdb.org/t/p/original/3vUqo90FCIHXPiXnQJEeqzg5EDV.jpg', 'It\'s 30 AD and everyone is expectantly awaiting the coming Messiah. While Jesus isn\'t exactly what they imagined, there is something special about this man. Soon, John, James, Andrew, Peter, and others begin to follow Jesus on an unexpected adventure. This beautifully animated story of Jesus is told through the eyes of his beloved young friend, the Apostle John.', 84, '0+', '2025-09-04', 'Animation/Fantasy/Drama/Music'),
(1062984, 'The Ordeal', 'https://image.tmdb.org/t/p/original/1NpjJ6eIoAGTsG9PVsTrEpF8vio.jpg', 'Sybil marries George Bruce, an alcoholic 20 years her senior, In order to provide for her crippled sister, Helen, and her brother, Geoffrey. Bruce becomes jealous of Sybil\'s attentions to young physician Robert Acton, and when Bruce suffers a heart attack and calls for digitalis, Sybil allows the vial to break and he dies.', 50, '0+', '1922-05-21', 'Drama'),
(1062985, 'April Apocalypse', 'https://image.tmdb.org/t/p/original/A9FB6gCQLpTKQFtI4SCSQbSeA0q.jpg', 'Artie is pure bred trailer trash. He has zero ambition, is everyone\'s favorite punching back at school and bears the burden of his virginity in silence. And then April moves out of the state. She\'s his best friend and support since kindergarten and the love of his life. Three years later Artie finally has the courage to take to the road and go see April to tell her how he feels about her. One car-crash later Artie wakes up in the middle of the zombie apocalypse. But this time he\'s not going to hide. Artie\'s love for April doesn\'t give him wings, but does give him the courage to hack, slash, punch and kick himself a part towards the girl he loves. Time is of the essence, because that bite on his hand will make the difference between a French kiss and a bite out of April\'s brains.', 84, '0+', '2013-10-12', 'Romance/Comedy/Horror'),
(1062986, 'Honeymoon Trio', 'https://image.tmdb.org/t/p/original', 'This Educational Comedies one-reeler is all about Walter Catlett in his obnoxious mode as he somehow imposes himself completely on Al St. John and Dorothy Granger as they go on their honeymoon. Dorothy never seems to notice anything odd about this situation -- which renders it all the funnier -- while Al St. John builds up quite a head of steam in what amounts to a ten-minute slow burn, worthy of Edgar Kennedy at his best.', 10, '0+', '1931-08-29', 'Comedy'),
(1062987, 'Joe', 'https://image.tmdb.org/t/p/original/2x4YCP8uV4cKOS5ZEKt1Cc1h4eF.jpg', 'After murdering his daughter\'s drug-dealing boyfriend, a wealthy ad executive stumbles into a bar and strikes up an uneasy alliance with Joe Curran, a drunken bigot with a bloodlust who works at a local factory.', 107, '0+', '1970-07-15', 'Drama/Crime'),
(1062988, 'José Rizal', 'https://image.tmdb.org/t/p/original/x2I1cdCmfSjzUoKaF1dC6lbHRoC.jpg', 'Accused of treason, Dr. Jose P. Rizal awaits trial and meets with his colonial government-appointed counsel, Luis Taviel de Andrade. The two build the case and arguments for the defense as significant events in the central figure\'s life prior to his incarceration unfold. Upon hearing Rizal\'s life story, Taviel begins to realize that the accused not just is innocent but exhibits in fact all the qualities of an extraordinary man. When the mock trial unreels, Taviel is all set to act as the prime advocate for his client as Rizal himself is about to give an earth-moving speech to defend his honor and address his countrymen. Meanwhile, the Spanish authorities have worked out the vast political machinery to ensure a guilty verdict. A revolution waits in the wings.', 178, '0+', '1998-12-25', 'Drama/History/War'),
(1062989, 'Feral', 'https://image.tmdb.org/t/p/original/aomgxCVKGUBjg0e9wpIRcIBfPw8.jpg', 'A homeless woman living in the tunnels below New York City survives on her own terms in the days leading up to a blizzard.', 74, '0+', '2019-04-07', 'Drama/Thriller'),
(1062990, 'Razem', 'https://image.tmdb.org/t/p/original/m52XidzKx94bKlToZfEXUnL3pdy.jpg', 'With a move to the countryside already testing the limits of a couple\'s relationship, a supernatural encounter begins an extreme transformation of their love, their lives, and their flesh.', 102, '0+', '2025-07-28', 'Horror/Romance'),
(1062991, 'Mandao Returns', 'https://image.tmdb.org/t/p/original/H81EYNPtU5PXVUTiegT01qMt7r.jpg', 'Jay Mandao is not your average hero. He’s an astral projecting time traveler who spends his days hanging with his adult nephew Jackson, crashing on his scheming cousin Andy’s couch, and riding with his cabbie friend Fer. In the days leading up to Christmas, Jay tries to make contact with his deceased father Raymond, but ends up contacting the ghost of B-movie star, Aura Garcia. Aura enlists the gang to astral project back in time to prevent her death. Jay quickly finds out that the more he messes with time, the more he falls down a rabbit hole of cults, conspiracies, and death. This Christmas is gonna kick astral! The sequel to Mandao of the Dead.', 71, '0+', '2020-12-15', 'Horror/Science Fiction/Comedy/Fantasy/Adventure'),
(1062992, 'Evasión', 'https://image.tmdb.org/t/p/original', 'Lost film. The director would comment on it: \"I did another one in \'72, which unfortunately was never shown. Rather, they kidnapped it and I never heard from it again...\"', 60, '0+', '1973-01-01', 'Documentary'),
(1062993, 'Czasy ostateczne: Pozostawieni', 'https://image.tmdb.org/t/p/original/b9Q2WR62yB5Aq0hd6kyRFS9cc3Y.jpg', 'A small group of survivors are left behind after millions of people suddenly vanish during the rapture and the world is plunged into chaos and destruction.', 110, '0+', '2014-10-03', 'Thriller/Action/Science Fiction'),
(1062994, 'Wild Beauty', 'https://image.tmdb.org/t/p/original/kQW2sYjCZrQPq1RSXa5PCvcu6UA.jpg', 'A soldier returns home from World War I with a beautiful black horse that he saved on the battlefield, and names Thunderhoof. He enters the horse in a local race, hoping to earn enough money to save the family ranch of the girl he loves. However, the crooks intent on taking the ranch manage to capture a notorious wild horse and enter it in the same race, believing that it can beat Thunderhoof and thereby ensure that they\'re able to take the ranch.', 65, '0+', '1927-11-27', 'Western'),
(1062995, '新・第三の極道XII 裏盃よ永遠に…', 'https://image.tmdb.org/t/p/original/eXYa0wVqaZtNkK0QEmtop0CHcYf.jpg', 'The army of backstory reunites in the evil of darkness that pollutes Jinyoshi for his own desires! The final 12th installment of the super popular series based on Kazuhiko Murakami! !! Masaki, the young head of the Todo group, tries to drop Nagoya via the Murota group as a stepping stone to conquer the whole country, but the members are killed in a series of mysterious accidents, and even the leader of the Murota group is finally assassinated.', 78, '0+', '2000-12-21', 'Drama/Crime'),
(1062996, 'The Phantom', 'https://image.tmdb.org/t/p/original/7Y4BV1xdUunmlEb8TnSmvhB6o8U.jpg', 'An eclectic group of people are stalked by a masked killer in an old mansion.', 61, '0+', '1931-11-01', 'Horror/Thriller/Mystery'),
(1062997, 'Tide', 'https://image.tmdb.org/t/p/original/47sKhC5xyh9oUYz4icO4MB8ern8.jpg', 'Four friends race against the tide in a bay famous for its quicksands, but a lurking threat will aggravate the situation.', 81, '0+', '2024-09-12', 'Horror'),
(1062998, 'Dastan', 'https://image.tmdb.org/t/p/original/myb1Ocmiy2uUZaLi2tyDjY0xGnF.jpg', 'Indira (Suraiya) is an orphan brought up the strict and uprighteous Rani (Veena). Indira grows up to be a beauty and is sought by three suitors Raj (Raj Kapoor), Kundan (Al Nasir), and Ramesh (Suresh). Rani does not like Indira to marry into her family as both Raj and Kundan are her brothers, and she wants Indira to marry Ramesh, and as such arranges a meeting with Ramesh\'s mom (Pratima Devi) and finalizes the marriage. Indira does not appreciate this and refuses to marry Ramesh. Raj speaks of his love with Rani, and Rani warns him that Indira is to marry Ramesh, but also has an on-going affair with his brother Kundan. Who does Indira really love? Will she ever marry her dream man?', 122, '0+', '1950-08-17', 'Drama/Family/Romance'),
(1062999, 'Głosy', 'https://image.tmdb.org/t/p/original/ncB9SvOclmXYALlcAsF1jRIuISl.jpg', 'An architect\'s desire to speak with his wife from beyond the grave using EVP (Electronic Voice Phenomenon), becomes an obsession with supernatural repercussions.', 101, '12', '2005-01-07', 'Drama/Horror/Thriller'),
(1063000, 'Possum', 'https://image.tmdb.org/t/p/original/dkS3Ypwin2i78X9cp4ReLWcPxYV.jpg', 'In a backwoods cabin, a boy called Little Man lives with his dad (a trapper), his older sister Missy, and his younger sister Kid, who is feral, spends most of her time under the table, and can imitate the sound of any animal. Their mother is dead. One day, while dad\'s in town selling skins, Missy teases Kid and gets bitten. There\'s Hell to pay when dad gets home, and Kid runs off into the night to spend it with her animal friends. Little Man, who narrates much of the story as well as his reflections in a whisper, must sort out loss and emptiness.', 19, '0+', '1997-01-01', 'Horror/Drama');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1063001, 'SLUGFEST', 'https://image.tmdb.org/t/p/original/mYG2iYfSi5GCHBOXOAE3Zq6yzo2.jpg', 'SLUGFEST emerges as a playful, engaging martial arts experience that delves into the \"inner-feminist struggles\" that have characterized recent years and decades. Yet, unlike narratives of division, this film champions the concept of unity, emphasizing the dire need for solidarity and deeper mutual respect within feminist discourse.  The film\'s central motif is a stylized, choreographed sparring training that, while aimed at empowerment and self-discovery, can sometimes escalate beyond control. This metaphorical approach isn\'t about antagonism but represents the passionate debates that fuel progress and understanding, even when they momentarily seem to get out of hand.  \"There is no losing in martial arts. Either you win or you learn.\" - as Karate Kid would say today.', 5, '0+', '2023-09-30', 'Action/Comedy'),
(1063002, 'The Womb', 'https://image.tmdb.org/t/p/original/Z9SC4KiyVkoFz66minanrBNo5Q.jpg', 'Sami, a deaf woman, survives alone in a suburban wasteland stalked by a terrifying presence beneath high-tension power lines. Her only warning of its approach is a faint hum detected by her cochlear implant. Clinging to the hope that her missing family will return, she refuses to leave her fortified home, even as the military prepares to destroy the entire area. When two mysterious intruders arrive claiming they can destroy the creature using a bomb “fueled by Hell,” Sami’s world begins to unravel. Childhood trauma resurfaces, memories shift, and her grip on reality weakens. In a climactic confrontation, Sami deploys the bomb and wakes in a hospital to a reunion with her long-lost family. But as buried truths surface, she realizes the reunion isn’t real.', 99, '0+', '2024-02-27', 'Thriller'),
(1063003, 'Zbuntowana', 'https://image.tmdb.org/t/p/original/pmuSQm8PCKrpG5PDWgL8hCw4ZgD.jpg', 'Beatrice Prior must confront her inner demons and continue her fight against a powerful alliance which threatens to tear her society apart.', 119, '12', '2015-03-18', 'Action/Science Fiction/Thriller'),
(1063004, 'Fantasmagoría', 'https://image.tmdb.org/t/p/original/7TA8HJFBZ5GBdiiH1lQ1co6TM5L.jpg', 'Professor Jorge Ollot and Dr. Iris de Miguel have gathered a group of people, carefully chosen, with whom they will be isolated for a week in a secluded house. Their intention? To demonstrate that the paranormal exists, but that it is our own mind that provokes it.', 0, '0+', NULL, 'Horror'),
(1063005, 'Daredevil Kate', 'https://image.tmdb.org/t/p/original/vbWQRjEkIfh8DrjMGNSv9QeT6Pl.jpg', 'Orphaned sisters Kate and Irene are separated as children, but each keeps half of their mother\'s wedding ring. Years later Irene marries John West, the head of a munitions camp. Kate, as fate would have it, happens to run the saloon in the camp and she and Irene become friends, but neither has any idea that the other is her long-lost sister. Matters take a turn for the worse, however, when Kate starts a romance with Cliff, Irene\'s adopted brother--a relationship that Irene strongly disapproves of. Complications ensue.', 60, '0+', '1916-08-21', 'Drama'),
(1063006, 'Desperate Situation', 'https://image.tmdb.org/t/p/original/w3vtOMdVkSnIkma802pZxn6RBdg.jpg', 'Recent widow Mandy is kidnapped and held for ransom. Her rich father-in-law is contacted for the money. Dressed only in a sheer nightgown, and bound and gagged, Mandy is forced to walk barefoot in the woods at night, is placed in the trunk of a car and is left in the shower to be drenched. And then, while waiting for the payment, the kidnapper begins to fall in love with the frightened girl. But that’s not all! He’s got a foot fetish that the girl tries to use to her advantage in an attempt to escape. And then his accomplice (Deana Enoches) comes between them. And the result is a deadly confrontation ending in murder!', 100, '0+', '1995-01-01', 'Thriller'),
(1063007, 'Bright Road', 'https://image.tmdb.org/t/p/original/QeFChSNW5Rtn1Hj1gFWOkgTlr6.jpg', 'Teachers at an all-black school fight to save a problem child.', 68, '0+', '1953-04-17', 'Drama/Music'),
(1063008, 'Good boy', 'https://image.tmdb.org/t/p/original/fYCxF8m0rkdmITKxcGahTVaMmQ8.jpg', 'A loyal dog moves to a rural family home with his owner Todd, only to discover supernatural forces lurking in the shadows. As dark entities threaten his human companion, the brave pup must fight to protect the one he loves most.', 73, '0+', '2025-10-01', 'Horror/Thriller'),
(1063009, 'Cowboy Poets', 'https://image.tmdb.org/t/p/original/sMaa4RbYP3NvRqwCi6aGO9lgwyS.jpg', 'American cowboys have been writing poetry for over a century. This little-known literary tradition both belies the macho image of the Western heroes and serves as an imaginative form of oral history. Cowboy Poets travels to the big sky country of Nevada, Montana, and Arizona to explore the tradition and to introduce three working cowboys, and the poetry they write about the lifestyle and land they love: Waddie Mitchell, Slim Kite, and Wally McRae.', 53, '0+', '1988-04-07', 'Documentary'),
(1063010, 'Stella Dallas', 'https://image.tmdb.org/t/p/original/spcGWnz05deoY7gAl0EvrBelzPa.jpg', 'After divorcing a society man, a small-town woman tries to build a better life for their daughter.', 106, '0+', '1937-08-06', 'Drama/Romance'),
(1063011, 'The Alternative', 'https://image.tmdb.org/t/p/original/3LBqba1kYeBmMpotXNTYtzNCfSp.jpg', 'Unmarried, beautiful and talented, Melanie Hilton discovers she is pregnant. The editor of a woman\'s magazine, she decides to have her baby and take leave from her job. Caught between her ex-lover and a colleague who wants to marry her, Melanie must find a solution or an alternative to her problem. When she falls in love with a woman, she questions the value of the traditional value unit.', 74, '0+', '1977-04-20', 'Drama/TV Movie'),
(1063012, 'Kaganiec', 'https://image.tmdb.org/t/p/original/7pXRA6HpxYjp3ISimzLqmH4ibGz.jpg', 'LAPD K-9 officer Jake Rosser has just witnessed the shocking murder of his dedicated partner by a mysterious assailant. As he investigates the shooter’s identity, he uncovers a vast conspiracy that has a choke-hold on the city in this thrilling journey through the tangled streets of Los Angeles and the corrupt bureaucracy of the LAPD.', 100, '0+', '2023-09-29', 'Action/Thriller'),
(1063013, 'Nieznajoma dziewczyna', 'https://image.tmdb.org/t/p/original/dUoTKphxbtKDJPGcubw6IP6D8w5.jpg', 'Jenny, a young doctor who feels guilty after a young woman she refused to see winds up dead a few days later, decides to find out who the girl was, after the police can\'t identify the young woman.', 106, '0+', '2016-10-05', 'Thriller/Drama/Crime'),
(1063014, 'Norymberga', 'https://image.tmdb.org/t/p/original/gOPHBaJJNpNDEnTHmDixg5JS8yp.jpg', 'In postwar Germany, an American psychiatrist must determine whether Nazi prisoners are fit to go on trial for war crimes, and finds himself in a complex battle of intellect and ethics with Hermann Göring, Hitler\'s right-hand man.', 148, '0+', '2025-11-06', 'History/Drama/Thriller/War'),
(1063015, 'Rozgrzeszenie', 'https://image.tmdb.org/t/p/original/gt70JOD9xsPlpJnuBJAWdOT4yRg.jpg', 'An aging ex-boxer gangster working as muscle for a Boston crime boss receives an upsetting diagnosis.  Despite a faltering memory, he attempts to rectify the sins of his past and reconnect with his estranged children. He is determined to leave a positive legacy for his grandson, but the criminal underworld isn’t done with him and won’t loosen their grip willingly.', 112, '0+', '2024-10-31', 'Action/Crime/Thriller/Mystery'),
(1063016, 'Kłamstwo', 'https://image.tmdb.org/t/p/original/xZPPnf68hP0JLIMyfvZb1TYeVVO.jpg', 'After a local woman is murdered, a group of teenage liars create a warning e-mail of a serial killer named “The Wolf”, coming on the next full moon. The teens describe each death method The Wolf uses, but when the described victims actually do start turning up dead, suddenly no one knows where the lies end and the truth begins.', 90, '0+', '2005-09-16', 'Horror/Thriller'),
(1063017, 'Jack i Sally Koszmar przed świętami', 'https://image.tmdb.org/t/p/original/buBoujM5PDuuA6ArKD80Mgl1kJX.jpg', 'Tired of scaring humans every October 31 with the same old bag of tricks, Jack Skellington, the spindly king of Halloween Town, kidnaps Santa Claus and plans to deliver shrunken heads and other ghoulish gifts to children on Christmas morning. But as Christmas approaches, Jack\'s rag-doll girlfriend, Sally, tries to foil his misguided plans.', 76, '7', '1993-10-09', 'Fantasy/Animation/Family'),
(1063018, 'Flow', 'https://image.tmdb.org/t/p/original/jAiMt4gKZIb9VaX7kx9cYUBanMq.jpg', 'A solitary cat, displaced by a great flood, finds refuge on a boat with various species and must navigate the challenges of adapting to a transformed world together.', 85, '0+', '2024-08-29', 'Animation/Adventure/Fantasy/Family'),
(1063019, '女囚さそり 第41雑居房', 'https://image.tmdb.org/t/p/original/mVmtfl3YJc04BJKy6PcFnol0RZG.jpg', 'After being used and betrayed by the detective she had fallen in love with, young Matsu is sent to a female prison full of sadistic guards and disobedient prisoners.', 90, '0+', '1972-12-30', 'Action/Crime/Drama'),
(1063020, 'Dobry nauczyciel', 'https://image.tmdb.org/t/p/original/kGQZQkqBajcI6oWHcIGcKJLIjJR.jpg', 'Julien, a young teacher, is wrongfully accused of sexual misconduct by a teenage girl from his class. As he faces mounting pressures from the girl’s older brother and her classmates, the situation spirals out of control. Allegations spread, the entire school is thrown into turmoil, and the teacher has to fight to clear his name.', 92, '0+', '2024-03-27', 'Drama/Thriller'),
(1063021, 'Harry Potter i Czara Ognia', 'https://image.tmdb.org/t/p/original/kRGddmzmxXcFZsJcEqVlgXUb29S.jpg', 'When Harry Potter\'s name emerges from the Goblet of Fire, he becomes a competitor in a grueling battle for glory among three wizarding schools—the Triwizard Tournament. But since Harry never submitted his name for the Tournament, who did? Now Harry must confront a deadly dragon, fierce water demons and an enchanted maze only to find himself in the cruel grasp of He Who Must Not Be Named.', 157, '16', '2005-11-16', 'Adventure/Fantasy'),
(1063022, 'Icefall', 'https://image.tmdb.org/t/p/original/AdOqoe8In6UDCkUOsAaR46IFML.jpg', 'A young Indigenous game warden arrests an infamous poacher only to discover that the poacher knows the location of a plane carrying millions of dollars that has crashed in a frozen lake. When a group of criminals and dirty cops are alerted to the poacher’s whereabouts, the warden and the poacher team up to fight back and escape across the treacherous lake before the ice melts.', 99, '0+', '2025-10-16', 'Action/Crime/Thriller'),
(1063023, 'CONFLICT 〜最大の抗争〜 第八章', 'https://image.tmdb.org/t/p/original/dPoOsGBbtMxxbT29ycxQJHdhFWU.jpg', 'The Nihon Tōgōsha continues to dismantle yakuza organizations across the country. To survive, Sankōkai Fourth-Generation Chairman Daiki Yabuta (Kenji Matsuda) plans to create a new yakuza group led by Okita Shōhei (Yasukaze Motomiyac) from Washio-gumi. This group aims to unify yakuza nationwide, similar to the former Tendokai under Kazuma Washio (Hitoshi Ozawa).  Meanwhile, within Nihon Tōgōsha, Kazuma Washio is expanding his influence, prompting the leader Tōjō (Kentarō Shimazu) to take action and plot Washio’s assassination. However, the plan leads to unexpected outcomes...  Additionally, a letter sent to Washio-gumi and other national yakuza organizations pushes Okita and the others into even greater peril.', 67, '0+', '2019-01-01', NULL),
(1063024, 'Nocny stróż', 'https://image.tmdb.org/t/p/original/hPWjid7yMatyIDHvku7lCMN7zSi.jpg', 'Hotel night clerk Bart Bromley is a highly intelligent young man on the Autism spectrum. When a woman is murdered during his shift, Bart becomes the prime suspect. As the police investigation closes in, Bart makes a personal connection with a beautiful guest named Andrea, but soon realises he must stop the real murderer before she becomes the next victim.', 90, '0+', '2020-02-19', 'Thriller/Crime/Drama'),
(1063025, 'Parasite', 'https://image.tmdb.org/t/p/original/ujWkLw5WkffXdt8DYlwM0acVOyr.jpg', 'All unemployed, Ki-taek\'s family takes peculiar interest in the wealthy and glamorous Parks for their livelihood until they get entangled in an unexpected incident.', 133, '16', '2019-05-30', 'Comedy/Thriller/Drama'),
(1063026, 'Epoka lodowcowa: Mamucia gwiazdka', 'https://image.tmdb.org/t/p/original/4dPI7xH3ANs1WPWHLVP6xwRIxOl.jpg', 'When Sid accidentally destroys Manny\'s heirloom Christmas rock and ends up on Santa\'s naughty list, he leads a hilarious quest to the North Pole to make things right and ends up making things much worse. Now it\'s up to Manny and his prehistoric posse to band together and save Christmas for the entire world!', 26, '7', '2011-11-24', 'Animation/Family/TV Movie'),
(1063027, 'Na Linii Wroga', 'https://image.tmdb.org/t/p/original/6eAMxsasHwJAraxAg9lwPdvBAWz.jpg', 'An ex-marine returns to Vietnam when he learns his former mercenary partner whom he thought was killed is being held by a sadistic general.', 89, '0+', '1997-05-23', 'Action/War'),
(1063028, 'Safe House', 'https://image.tmdb.org/t/p/original/peUlWeJaqTi0YnsM4L6gnWzz0Ko.jpg', 'Trapped in a high-security safe house after a terrorist attack in downtown Los Angeles, six government agents realize they must survive not just the enemy outside, but the potential traitor among them.', 90, '0+', '2025-10-30', 'Action/Thriller'),
(1063029, 'Silver Bears', 'https://image.tmdb.org/t/p/original/uaJgZ1IDZToI3mB9MqY80pQm9la.jpg', 'Financial wizard \"Doc\" Fletcher is sent by crime boss Joe Fiore to buy a bank in Switzerland in order to more easily launder their profits. When he arrives, Fletcher finds that the bank, acquired by his associate Prince di Siracusa, consists of some shabby offices above a restaurant. To make up for this, the Prince suggests that Fletcher invests in a silver mine owned by Shireen and Agha Firdausi. This solves one problem, but the mine also attracts the attention of some of the most powerful people in the silver business. Fletcher must pull out all his wheeler-dealing skills in order to keep hold of everything he\'s worked for, in the process romancing a banker\'s discontented wife.', 113, '0+', '1977-06-03', 'Comedy/Crime'),
(1063030, 'The Pier', 'https://image.tmdb.org/t/p/original/wvfIk4pgoGDMkWo5rtxKA1QlQa6.jpg', 'After 20 years of no contact with his father, Jack McCarthy (played by Hurley) travels from New York to his father Larry\'s death bed in Cork. Upon arrival he is furious to find his father alive and well and even more so when he then discovers he can\'t leave. Soon, father and son are forced to deal with a painful history. At the core of their conflict is Larry\'s denial about the death of his wife, Jack\'s mother. The story explores the difficult and painful, but often very hilarious ways they try to communicate. Forging a begrudging peace, the reality of life sets in when Larry discloses to Jack another truth that leads to a final reconciliation.', 84, '0+', '2011-07-04', 'Drama/Romance'),
(1063031, 'Avengers: Czas Ultrona', 'https://image.tmdb.org/t/p/original/nJqhqtWTzBR66hDWRO5gxDl4CUe.jpg', 'When Tony Stark tries to jumpstart a dormant peacekeeping program, things go awry and Earth’s Mightiest Heroes are put to the ultimate test as the fate of the planet hangs in the balance. As the villainous Ultron emerges, it is up to The Avengers to stop him from enacting his terrible plans, and soon uneasy alliances and unexpected action pave the way for an epic and unique global adventure.', 141, '16', '2015-04-22', 'Action/Adventure/Science Fiction'),
(1063032, 'Idle Tongues', 'https://image.tmdb.org/t/p/original/oMMlk2wenASjkno9wXGBqRHA7IC.jpg', 'After serving 5 years in prison for embezzling church funds, Dr. Ephraim Nye returns to Ostable and the scornful gossip of its residents, led by Althea Bemis. There is a typhoid epidemic, and Dr. Nye believes it to be caused by the water in a pond that Judge Copeland, the brother of Dr. Nye\'s dead wife, Fanny, wishes to use as the source of municipal water supply. Only Katherine Minot supports Dr. Nye, but biologists prove him correct; and Dr. Nye confronts Copeland with proof that he went to prison to protect Fanny, the actual criminal. Copeland finally consents to the marriage of his daughter, Faith, to Tom Stone, the son of his enemy; and Katherine spreads the news of her engagement to Dr. Nye through Althea.', 60, '0+', '1924-12-21', 'Drama'),
(1063033, 'Beatrice Fairfax', 'https://image.tmdb.org/t/p/original/1TshMLvwfVuOQc2NwvYOEhuHZS1.jpg', 'Beatrice Fairfax, the original advice-to-the-lovelorn reporter and her friend and not-so-secret admirer Jimmy Barton investigate calls for help and escape exotic perils and dangers. Episodes include exciting and fun stories of baby-napping, blackmail, jewel thievery, disguise, counterfeiting, and the long-unseen episode featuring entrancing cult starlet Olive Thomas and the real New York Yankees and Giants playing a game in the Polo Grounds.', 300, '0+', '1916-08-07', 'Action/Adventure'),
(1063034, 'Snow White', 'https://image.tmdb.org/t/p/original/eYiSyqi584AW9eKHPVYzME3cNTv.jpg', 'A young princess named Snow White is sent away from her palace to live in the woods due to the jealousy of her stepmother.', 46, '0+', '1995-04-27', 'Animation/Drama/Family/Fantasy/Music/Romance'),
(1063035, 'Halloween II', 'https://image.tmdb.org/t/p/original/xBbgAOmzoCcmnmacM13e2kvkeyx.jpg', 'Laurie Strode struggles to come to terms with her brother Michael\'s deadly return to Haddonfield, Illinois. Meanwhile, Michael prepares for another reunion with his sister.', 105, '0+', '2009-08-28', 'Horror'),
(1063036, 'Między nami żywiołami', 'https://image.tmdb.org/t/p/original/fv3idA7yYUP1jt6TYy6l6AlUdQR.jpg', 'In a city where fire, water, land and air residents live together, a fiery young woman and a go-with-the-flow guy will discover something elemental: how much they have in common.', 102, 'AL', '2023-06-14', 'Family/Fantasy/Comedy/Romance/Animation'),
(1063037, 'Jak wytresować smoka 3', 'https://image.tmdb.org/t/p/original/i2bSSOVmhJjBJt0ymResCmKoHT9.jpg', 'As Hiccup fulfills his dream of creating a peaceful dragon utopia, Toothless’ discovery of an untamed, elusive mate draws the Night Fury away. When danger mounts at home and Hiccup’s reign as village chief is tested, both dragon and rider must make impossible decisions to save their kind.', 104, 'b.o.', '2019-01-03', 'Animation/Family/Adventure'),
(1063038, 'Bharathan Effect', 'https://image.tmdb.org/t/p/original/hUnen0q1sk0nrTh5WKvbROpaYWK.jpg', 'One among the few sci-fi movies in Malayalam, \'Bharathan Effect\' tells the story of Bharathan (Biju Menon) who is a genius inventor struggling to make ends meet. His efforts are under appreciated by his wife Geetha (Geethu Mohandas) and causes constant conflict between them. After apparently seeing  an object float in air defying gravity; Bharathan gets obsessed by the whole idea. He tries to research the topic with the financial assistance of his landlord (Jagathy Sreekumar) despite the entire community branding him as a lunatic. The rest of the film deals with his quest to find the truth behind the strange phenomenon of anti-gravity that he witnesses.', 130, '0+', '2007-08-16', 'Science Fiction'),
(1063039, 'Iniemamocni', 'https://image.tmdb.org/t/p/original/qDRbpCiDtseCoz1NVSwYk4gC0Ye.jpg', 'Bob Parr has given up his superhero days to log in time as an insurance adjuster and raise his three children with his formerly heroic wife in suburbia. But when he receives a mysterious assignment, it\'s time to get back into costume.', 115, 'AL', '2004-11-05', 'Action/Adventure/Animation/Family'),
(1063040, 'Verdi Macbeth', 'https://image.tmdb.org/t/p/original/AiqFv5zA4rvgCqWxsj2sE1JIbr4.jpg', 'Claude D\'Anna\'s film of Verdi\'s Macbeth is a gloomy affair, stressing the descent into madness of the principal villains. It\'s acted by the singers of the Decca recording of the opera (with two substitutions of actors standing in for singers) and the lip-synching is generally unobtrusive. The musical performance is superb, conducted by Riccardo Chailly with admirable fire, and sung by some of the leading lights of the opera stages of the 1980s. Shirley Verrett virtually owned the role of Lady Macbeth at the time, and she delivers a terrific performance, the voice equal to the role\'s wide register leaps and it\'s suffused with emotion, whether urging her husband on to murder or maddened by guilt in the Sleepwalking Scene. Leo Nucci\'s resonant Macbeth may lack the ultimate in vocal color and steadiness (his last notes of the great aria Pietà, rispetto, amore are wobbly) but he compensates with intensity in both singing and acting.', 133, '0+', '1987-01-01', 'Music'),
(1063041, 'Eenie Meanie', 'https://image.tmdb.org/t/p/original/12Va3oO3oYUdOd75zM57Nx1976a.jpg', 'A former teenage getaway driver gets dragged back into her unsavory past when a former employer offers her a chance to save the life of her chronically unreliable ex-boyfriend.', 106, '0+', '2025-08-21', 'Thriller/Action/Comedy'),
(1063042, 'Chappie', 'https://image.tmdb.org/t/p/original/vcAa3RlVVEEAx01SjXNb6Maudp.jpg', 'Every child comes into the world full of promise, and none more so than Chappie: he is gifted, special, a prodigy. Like any child, Chappie will come under the influence of his surroundings—some good, some bad—and he will rely on his heart and soul to find his way in the world and become his own man. But there\'s one thing that makes Chappie different from any one else: he is a robot.', 120, '18', '2015-03-04', 'Crime/Action/Science Fiction'),
(1063043, 'Every Day', 'https://image.tmdb.org/t/p/original/bj1XvLeU087dSnTHuhPpRcyyLNy.jpg', 'Maddie was raped in high school at a party, but no one believed her when she reported it, causing her to become a social outcast, and crushing her dreams. Ten years later, as she tries to rebuild her life, she takes a job as a tutor to a wealthy family where, she meets Laurel, the family\'s nanny. The two become instant and close friends, too close according to her long time friends, Paige and James. They worry Laurel may have alternative motives and try to protect Maddie. Maddie is forced to decide between who she trusts more, Laurel or Paige and James.', 0, '0+', '2021-02-26', 'Drama'),
(1063044, 'Avatar', 'https://image.tmdb.org/t/p/original/6DfNtptjkIrevq4mDAB0XDXT0NO.jpg', 'In the 22nd century, a paraplegic Marine is dispatched to the moon Pandora on a unique mission, but becomes torn between following orders and protecting an alien civilization.', 162, '12', '2009-12-15', 'Action/Adventure/Fantasy/Science Fiction'),
(1063045, 'Smerfy. Wielki film', 'https://image.tmdb.org/t/p/original/iukMhsMUdq76BCTefQT1PUGBVod.jpg', 'When Papa Smurf is mysteriously taken by evil wizards, Razamel and Gargamel, Smurfette leads the Smurfs on a mission into the real world to save him. With the help of new friends, the Smurfs must discover what defines their destiny to save the universe.', 89, '7', '2025-07-05', 'Animation/Family/Fantasy'),
(1063046, 'Świąteczne Zaręczyny', 'https://image.tmdb.org/t/p/original/4yM1krPnjkWhIOmrY33mVQgSwXJ.jpg', 'Thirty-something Hillary Burns has spent her life trying to get the approval of her parents, in the shadow of her more successfully-attached siblings. So when Hillary\'s fiance, workaholic lawyer Jason King, dumps her because she isn\'t willing to relocate for his potential promotion, she panics because she had been promising to bring him home to meet her expectant family, whom she does not want to let down! As a last-minute idea, her best friend Sophie convinces her to actually hire someone to \"play the role\" of Jason for her return home on Thanksgiving.. leading to an interesting combination of sparks & revelations for all involved.', 92, '0+', '2011-11-28', 'Comedy/Romance/TV Movie'),
(1063047, 'Uszanować wroga', 'https://image.tmdb.org/t/p/original/bAtQu18vwiBwDjU4BKkYeGxM9aY.jpg', 'Based on a true story its the untold story of Italian World War II POW\"S in Jan 1946. Luca Zingaretti stars as one of over 50,000 Italian Prisoners of War detained at POW camps in the U.S. Roy Schneider stars as Colonel Gartner, the Commander of the camp. Things take a turn for the worse when Manin is brought back from his most recent escape by a patrol force, only to realize that the camp has been evacuated while he was gone. Gartner is forced to keep Manin at the camp until another patrol force can come pick him up. However, no one ever comes. The phone lines get cut, and the two men realize they are completely isolated from the outside world. It is up to each man now to escape the camp.An untold and rarely known fact of US held Italian POW\"S', 96, '0+', '2002-01-11', 'Drama/History/War'),
(1063048, 'Jack Reacher: Jednym strzałem', 'https://image.tmdb.org/t/p/original/6Shi6cqkSfuOo222hAOkjAAoXI2.jpg', 'One morning in an ordinary town, five people are shot dead in a seemingly random attack. All evidence points to a single suspect: an ex-military sniper who is quickly brought into custody. The interrogation yields one written note: \'Get Jack Reacher!\'. Reacher, an enigmatic ex-Army investigator, believes the authorities have the right man but agrees to help the sniper\'s defense attorney. However, the more Reacher delves into the case, the less clear-cut it appears. So begins an extraordinary chase for the truth, pitting Jack Reacher against an unexpected enemy, with a skill for violence and a secret to keep.', 130, '16', '2012-12-20', 'Crime/Drama/Thriller/Action'),
(1063049, 'Average Joe', 'https://image.tmdb.org/t/p/original/stuzJUtbqSrOrUdAsYYgmzKggnc.jpg', 'After a troubled childhood, a former Marine becomes a beloved high school football coach. However, his reputation comes under fire when he is fired for praying before each games.', 110, '0+', '2024-10-10', 'Drama'),
(1063050, 'Two Overcoats', 'https://image.tmdb.org/t/p/original', 'Solomon keeps a clothing store, he has in stock two overcoats of exactly the same make and pattern. Michael Gallagher, who is passing by and in need of an outer garment, notices Solomon\'s display and buys one of the coats. Shortly after the first sale, Peter Dempsey, a bachelor, happens along and takes quite a fancy to the remaining twin overcoat and Solomon makes another sale. Gallagher and Dempsey dine, at the same time, in the same restaurant. Finishing his meal, Gallagher leaves hurriedly and takes Dempsey\'s coat, quite naturally mistaking it for his own. When Dempsey is through with his meal, he puts on Gallagher\'s coat quite satisfied that it is his own. That night Dempsey goes to call on his sweetheart, who admires his new overcoat, and as she helps him off with it, a letter in a woman\'s hand-writing falls out of the pocket.', 6, '0+', '1911-06-24', 'Comedy'),
(1063051, 'HEARD', 'https://image.tmdb.org/t/p/original/4BZ1PB59Deg9ehdH3B6lYfRLv2.jpg', 'Samantha was left to carry the guilt and shame from an act that was out of her control. When she couldn’t find the words to speak, she reeled from the results of her choices — or lack thereof. Paralyzed by her trauma, Samantha spins at the thought of how to proceed. How does she move forward with this burden? And how big of a burden will it be? She is in agony as she tries to understand if speaking up would have made a difference, or if her voice was never meant to be HEARD', 0, '0+', '2021-10-12', 'Drama/Thriller'),
(1063052, 'Diamenty', 'https://image.tmdb.org/t/p/original/go0IdqMLj3KyJHClxSMbputDWs3.jpg', 'A film director gathers his favorite actresses, those he worked with and those he loved. He wants to make a film about women but he doesn’t reveal much: he observes them, takes cue, until his imaginary throw them into another era, in a past where the noise of the sewing machines fills a workplace handled and populated by women, where men have minor and marginal roles and cinema can be told from another point of view: the one of costume. Between loneliness, passions, anxieties, heartbreaking absence and unbreakable bonds, reality and fiction permeate, as well as the lives of the actresses and those of the characters, the competition and the sisterhood, the visible and the invisible.', 135, '0+', '2024-12-19', 'Comedy/Drama'),
(1063053, 'Pierwszaki', 'https://image.tmdb.org/t/p/original/k2ySukuAiAarLns0yttKS3jg85Y.jpg', 'Their first week of high school. The biggest party of the year. Mistakes will be made as four teenage boys navigate a night of mayhem and debauchery.', 92, '16', '2024-08-22', 'Comedy'),
(1063054, 'Opowieści z Narnii: Lew, Czarownica i stara szafa', 'https://image.tmdb.org/t/p/original/mLozkymFZgzkEyQhC8yAqcbYGaG.jpg', 'Siblings Lucy, Edmund, Susan and Peter step through a magical wardrobe and find the land of Narnia. There, they discover a charming, once peaceful kingdom that has been plunged into eternal winter by the evil White Witch, Jadis. Aided by the wise and magnificent lion, Aslan, the children lead Narnia into a spectacular, climactic battle to be free of the Witch\'s glacial powers forever.', 143, '12', '2005-12-07', 'Adventure/Family/Fantasy'),
(1063055, 'Surnuaiavahi tütar', 'https://image.tmdb.org/t/p/original/xhGN59yT3RORYvss6tyNzPURSOx.jpg', 'A snapshot of one segment of Estonian present-day life, shown through the eyes of a child: 8 years old Lucia is leading a jolly and naughty Pippi-Longstocking-style life in a small town in Estonia. Her father Kaido, a graveyard keeper, can hardly provide for the family, her mother Maria is a drunk. Then the family receives an unexpected invitation to spend a week in Finland, in the house of the female pastor Sipra. This week will change everybody\'s life in unexpected ways...', 100, '0+', '2011-02-25', 'Drama'),
(1063056, 'Willesden Confidential', 'https://image.tmdb.org/t/p/original/A9HEkFP6k4wdxiTKgLFWTREKzko.jpg', 'Dangerous Davies investigates the death of Geoff Fallon, a stock car driver who was killed during a race at the local stadium when his car exploded due to a leaky fuel line. There seemed to be a considerable animosity with his brother, also a stock car driver, but it turns that Fallon was convicted of killing a child with his car some years previously and the dead child\'s older brother was working at the stadium on the night in question. When a second person is killed, Davies determines that the case is far more complex than originally thought. Meanwhile, all of the officers at the local station are under investigation when information is leaked to the press.', 70, '0+', '2005-06-19', NULL),
(1063057, 'En mærkelig kærlighed', 'https://image.tmdb.org/t/p/original/pX1X2MfbqrFbCYO7uTrJ52df3VJ.jpg', 'A nouvelle vague-inspired film about young Danes, their struggles with love, and their philosophical discussions.', 67, '0+', '1968-08-19', 'Drama/Romance'),
(1063058, 'Sezon na króliki', 'https://image.tmdb.org/t/p/original/foVYnv4rV98B2DA0Znzk3Pbm0Mg.jpg', 'Elmer Fudd is hunting both Daffy Duck and Bugs Bunny again.', 7, '0+', '1952-09-20', 'Animation/Comedy'),
(1063059, 'Chata', 'https://image.tmdb.org/t/p/original/vLMcoRan9NmrHMulhpqFFl4pEJt.jpg', 'A grieving man receives a mysterious, personal invitation to meet with God at a place called \'The Shack\'.', 132, '12', '2017-03-03', 'Drama/Family'),
(1063060, 'Riding Waves', 'https://image.tmdb.org/t/p/original/a4KarXMUK2Yw7W3EdrNz2LTZwnS.jpg', 'In this soulful surf documentary, filmmaker Cyrus Sutton shadows five different surfers, capturing the ups and downs of their daily routines -- much like the ebb and flow of the waves they ride with such passion. Whether Sutton\'s lens is trained on Rob Machado, Joel Tudor, Donovan Frankenreiter, Dane Reynolds or John Peck, there\'s one theme that unifies them despite their differences when it comes to personal style: They all love what they do.', 0, '0+', '2008-01-01', NULL),
(1063061, 'Czerwona Planeta', 'https://image.tmdb.org/t/p/original/a6b7X1NGhbEGnyqFVw8C0iLCYZt.jpg', 'Astronauts search for solutions to save a dying Earth by searching on Mars, only to have the mission go terribly awry.', 106, '12', '2000-11-10', 'Thriller/Action/Science Fiction'),
(1063062, 'Freakshow', 'https://image.tmdb.org/t/p/original/rMx3EHvlwjETsSsmV6U1fBtAPCd.jpg', 'After being ditched by her cameraman because of her manipulative behavior at a murder scene, a reporter wanders through town looking for a phone she can use. She finds a small museum, where the proprietor invites her in to have a look around before leaving. In one room, she encounters a strange jar which causes her to have strange visions, visions that are supposedly drawn from her own mind. These \'visions\' make up the rest of this four- part anthology, which includes horror and suspense stories about a junkie chasing a dog for his runaway fix, a pizza delivery boy who gets a Halloween surprise, a living but paralyzed OD victim forced to undergo her own autopsy because everyone thinks she\'s dead, and a deal between a golf course owner and a gravedigger that has some unexpected consequences.', 97, '0+', '1989-01-06', 'Horror'),
(1063063, 'Klucz do Wieczności', 'https://image.tmdb.org/t/p/original/dwhUICKIlzCbij2VPAMAiLzt2uT.jpg', 'An extremely wealthy elderly man dying from cancer undergoes a radical medical procedure that transfers his consciousness to the body of a healthy young man but everything may not be as good as it seems when he starts to uncover the mystery of the body\'s origins and the secret organization that will kill to keep its secrets.', 117, '16', '2015-07-10', 'Science Fiction/Action/Thriller'),
(1063064, 'Meddling Women', 'https://image.tmdb.org/t/p/original/bc0YOYO2g5nD14Y0ouLJ7A9RP7F.jpg', 'Grace Ainsworth wants to return to her career as an opera singer, and her mother-in-law supports her. Grace\'s husband, Edwin, wants her to stay at home and to convince her, he relates the story of his latest play about a man who allows his wife to return to the stage. Edwin comes to believe that Grace is in love with Harold Chase, a manager, and the couple separates. Edwin has an affair with a dancer, Madeline, and he winds up in a fight with her dancing partner, Vincenti, which causes him to lose his memory.', 69, '0+', '1924-11-15', 'Drama'),
(1063065, 'Powrót do przyszłości', 'https://image.tmdb.org/t/p/original/2fEoQxuMRzebtqwHICuyM6B0HTH.jpg', 'Eighties teenager Marty McFly is accidentally sent back in time to 1955, inadvertently disrupting his parents\' first meeting and attracting his mother\'s romantic interest. Marty must repair the damage to history by rekindling his parents\' romance and - with the help of his eccentric inventor friend Doc Brown - return to 1985.', 116, '12', '1985-07-03', 'Adventure/Comedy/Science Fiction'),
(1063066, 'Gru i Minionki: Pod przykrywką', 'https://image.tmdb.org/t/p/original/92a2vvO8wysBryFlC8QgyX3CuJA.jpg', 'Gru and Lucy and their girls—Margo, Edith and Agnes—welcome a new member to the Gru family, Gru Jr., who is intent on tormenting his dad. Gru also faces a new nemesis in Maxime Le Mal and his femme fatale girlfriend Valentina, forcing the family to go on the run.', 94, 'AL', '2024-06-20', 'Family/Comedy/Animation/Science Fiction'),
(1063067, 'En la cuerda del hambre', 'https://image.tmdb.org/t/p/original/584V6TCu3aobDyG3LaOXmbSOA.jpg', 'Owners of two small farms try to move forward in life by wholesaling their own produce instead of relying on dishonest brokerages. When that doesn\'t work, they hatch a kidnapping scheme, and the movie shifts its focus to the rich people who have been profiting off their poverty.', 90, '0+', '1979-12-25', 'Drama'),
(1063068, 'Człowiek ringu', 'https://image.tmdb.org/t/p/original/hurKMKEk365RTEHo01uQhPuIKw0.jpg', 'The true story of boxer Jim Braddock who, following his retirement in the 1930s, makes a surprise comeback in order to lift his family out of poverty.', 144, '16', '2005-06-02', 'Romance/Drama/History'),
(1063069, 'Psych-Out', 'https://image.tmdb.org/t/p/original/gl0waHdQJkcP7TxjPl4V8jeduI4.jpg', 'Jenny, a deaf runaway who has just arrived in San Francisco\'s Haight-Ashbury district to find her long-lost brother, a mysterious bearded sculptor known around town as The Seeker. She falls in with a psychedelic band, Mumblin\' Jim, whose members include Stoney, Ben, and Elwood. They hide her from the fuzz in their crash pad, a Victorian house crowded with love beads and necking couples. Mumblin\' Jim\'s truth-seeking friend Dave considers the band\'s pursuit of success \"playing games,\" but he agrees to help Jennie anyway.', 101, '0+', '1968-03-06', 'Drama/Thriller/Music'),
(1063070, 'Obecność 3: Na rozkaz diabła', 'https://image.tmdb.org/t/p/original/1pVV7OOqTkQA0x6krvq2v3hjEn.jpg', 'Paranormal investigators Ed and Lorraine Warren encounter what would become one of the most sensational cases from their files. The fight for the soul of a young boy takes them beyond anything they\'d ever seen before, to mark the first time in U.S. history that a murder suspect would claim demonic possession as a defense.', 111, '18', '2021-05-25', 'Horror/Mystery/Thriller'),
(1063071, 'Madison County', 'https://image.tmdb.org/t/p/original/2zCC4BBXyxb9rsSfv1edBgfWXsO.jpg', 'A group of college kids travel to a small, mountain town called Madison County to interview the author of a tell-all book on the accounts of several grisly murders that happened there. But when the kids get to Madison County, the author is no where to be found and the towns people act like they haven\'t seen him in years. They also say that the killer never existed and the murders never happened. However, when the kids start digging around to get their own answers, they find out that the stories maybe more real than the townspeople are letting on!', 81, '0+', '2011-10-11', 'Horror/Mystery/Thriller'),
(1063072, 'The Convent', 'https://image.tmdb.org/t/p/original/ehDQuLqA0Lj03k4uM5MKzphbi0Y.jpg', 'A group of college students break into an abandoned convent and become possessed by demonic spirits.', 79, '0+', '2000-01-21', 'Horror/Action/Comedy'),
(1063073, 'Christmas Island', 'https://image.tmdb.org/t/p/original/Aw3ApBYlH0KIJ377vcUiqbPMth5.jpg', 'When a snowstorm diverts Kate\'s first private flight bound for Switzerland, to Christmas Island in Nova Scotia, she must team up with an air traffic controller to secure her dream job as the family\'s pilot.', 84, '0+', '2023-11-11', 'TV Movie/Comedy/Drama/Romance'),
(1063074, 'Antboy', 'https://image.tmdb.org/t/p/original/db8a23rqcErLLuU3TG5gJJNJCPH.jpg', '12-year-old Pelle accidentally gets bitten by an ant and develops unimaginable superpowers. With help from his friend, comic book nerd Wilhelm, Pelle creates a secret identity as the superhero Antboy. Slowly things start to happen in the surburban community, and when a scary and crazy supervillain, Flea, enters the scene, Antboy must step up to the challenge.  The first Danish superhero-movie. Based on the books by Kenneth Bøgh Andersen.', 77, '0+', '2013-09-07', 'Comedy/Adventure/Family'),
(1063075, 'Bagno', 'https://image.tmdb.org/t/p/original/h70gDIHVJ1uKoUVjyaaCeX0txPW.jpg', 'A look behind the curtain of Washington politics following three \"renegade\" Republican Congressmen as they bring libertarian and conservative zeal to champion the President’s call to “drain the swamp.”', 114, '0+', '2020-08-04', 'Documentary'),
(1063076, 'Pray Away', 'https://image.tmdb.org/t/p/original/1wikrtZZZoThwnHulB7klQek4Ai.jpg', 'In the 1970s, five men struggling with being gay in their Evangelical church started a bible study to help each other leave the \"homosexual lifestyle.\" They quickly received over 25,000 letters from people asking for help and formalized as Exodus International, the largest and most controversial conversion therapy organization in the world. But leaders struggled with a secret: their own “same-sex attractions” never went away. After years as Christian superstars in the religious right, many of these men and women have come out as LGBTQ, disavowing the very movement they helped start. Focusing on the dramatic journeys of former conversion therapy leaders, current members, and a survivor, PRAY AWAY chronicles the “ex gay\" movement’s rise to power, persistent influence, and the profound harm it causes.', 101, '16', '2021-06-16', 'Documentary'),
(1063077, 'Kapitan Ameryka. Nowy wspaniały świat', 'https://image.tmdb.org/t/p/original/aZC3z3y13QM6C711gtObszm2fcw.jpg', 'After meeting with newly elected U.S. President Thaddeus Ross, Sam finds himself in the middle of an international incident. He must discover the reason behind a nefarious global plot before the true mastermind has the entire world seeing red.', 119, '0+', '2025-02-12', 'Action/Thriller/Science Fiction'),
(1063078, 'Ebb Tide', 'https://image.tmdb.org/t/p/original/h64z46Zt0muicBoK1S5WBx5bRaR.jpg', 'In 1890, two British expatriates, Robert Herrick and Huish, and German Captain Jakob Thorbecke, are commissioned to sail a Yankee schooner called The Golden State , whose captain and crew have died of smallpox. From Tehua in the South Seas to Australia, they are to deliver a cargo of champagne. Thorbecke decides to head for Peru, however, so he can sell the merchandise and pocket the money. While sailing, Faith Wishart, daughter of the deceased captain, comes out of her hiding place on board and, by briefly holding Thorbecke at gunpoint, demands he make the delivery.', 94, '0+', '1937-10-14', 'Adventure'),
(1063079, 'Confidence', 'https://image.tmdb.org/t/p/original/1B23YrveO15iNklqxGmWDvvlwcm.jpg', 'The animals on Oswald the Rabbit\'s farm couldn\'t be happier with their work. The hens, in particular, enjoy their jobs as egg producers. True, a hen gets a bit anxious when her egg is too small or when she can\'t lay anything. But on the whole, times are good. That changes when a specter by the name of Depression rises from the dump and travels the globe spreading fear and panic. The Great Depression has begun and has poisoned the entire country, including Oswald\'s farm. Now, the roosters are listless and the chickens flop around in a daze. Oswald runs to the doctor for help. But Dr. Pill points to a poster of the President, Franklin Delano Roosevelt. \"There\'s your doctor!\" he declares. Soon, Oswald is in the White House, knocking down the Vice President in his haste to see FDR. Roosevelt sings \"Confidence\" and gives the rabbit a generous supply.', 7, '0+', '1933-07-31', 'Animation'),
(1063080, 'แม่ซื้อ', 'https://image.tmdb.org/t/p/original/e8NefV41e0xxJYBFnqSPDB4QAHc.jpg', 'Ing is sent to Pinijkhun Reform School, an all-girls facility on a remote island. The only rule here is that everyone must obey orders.', 125, '0+', '2025-10-09', 'Horror'),
(1063081, 'Robinson Crusoe', 'https://image.tmdb.org/t/p/original/93uRPzVpf4ZVjDfswmpsrAmBS4w.jpg', 'Robinson Crusoe flees Britain on a ship after killing his friend over the love of Mary. A fierce ocean storm wrecks his ship and leaves him stranded by himself on an uncharted island. Left to fend for himself, Crusoe seeks out a tentative survival on the island, until he meets Friday, a tribesman whom he saves from being sacrificed. Initially, Crusoe is thrilled to finally have a friend, but he has to defend himself against the tribe who uses the island to sacrifice tribesman to their gods. During time their relationship changes from master-slave to a mutual respected friendship despite their difference in culture and religion.', 92, '16', '1997-06-11', 'Action/Adventure/Drama'),
(1063082, 'Rosa Mistica', 'https://image.tmdb.org/t/p/original/yfOABfBSLpRxRY4mLBMCD5yZH5U.jpg', 'A Filipino fantasy/horror anthology starring Snooky Serna. In \"Mga Puting Rosas ni Rosalie\", Rosalie dies in a freak accident on the day of her wedding to Mike, who\'s only after her money. With the help of the white rose, she comes back to earth to correct what is wrong. In \"Mga Pulang Rosas ni Rosanna\", Rosanna is the daughter of a mausoleum caretaker who happens to be the soulmate of the mysterious heir, Ramil, the victim of a curse of Satan\'s disciple, Lucila. In \"Mga Dilaw Rosas ni Rosario\", Rosario or Osang, a maid with an ugly facade, falls in love with a man named Dio.', 116, '0+', '1987-03-03', 'Horror/Fantasy'),
(1063083, 'Occasional, Strong', 'https://image.tmdb.org/t/p/original', 'A man signs up as a driver for a group of criminals on a dangerous job. On the way to the hit the man hears the lottery numbers and realises he\'s got the winning ticket on him. However the job goes badly and the lottery ticket is collected as litter by a street cleaner. The leader of the gang goes after the cleaner while on a picnic with his daughter to get the ticket back.', 12, '0+', '2002-12-12', 'Crime'),
(1063084, 'Operacja Avalanche', 'https://image.tmdb.org/t/p/original/3ngw7s1fa0eJL19fJ6Jw0bTQg3n.jpg', 'In 1967, four undercover CIA agents were sent to NASA posing as a documentary film crew. What they discovered led to one of the biggest conspiracies in American history.', 94, '0+', '2016-09-16', 'Thriller/Mystery/Comedy/Drama'),
(1063085, 'Beat Street', 'https://image.tmdb.org/t/p/original/cn0gXtGgQXT7EVVXKJRhK4E1nOc.jpg', 'An aspiring DJ, from the South Bronx, and his best friend, a promoter, try to get into show business by exposing people to hip-hop music and culture.', 105, '0+', '1984-06-08', 'Drama/Music'),
(1063086, 'Zerowy czerwca', 'https://image.tmdb.org/t/p/original/u4lgTJ9wNb3umR4vsj0gHCsGbbm.jpg', 'Israel, 1961. Nazi war criminal Adolf Eichmann, responsible for organizing the extermination of European Jews, is sentenced to death.', 106, '0+', '2023-09-08', 'Drama/History'),
(1063087, 'The Mutation', 'https://image.tmdb.org/t/p/original/inorTD5FpesgGfono5S6tVyu8XD.jpg', 'A mutated rat has been let loose in a city.', 87, '0+', '2021-08-04', 'Horror'),
(1063088, 'Freedom Radio', 'https://image.tmdb.org/t/p/original/pRNp9klF2pQEY8sRM1PF9iYSgL8.jpg', 'Hitler\'s doctor is gradually realising that the Nazi regime isn\'t as good as it pretends to be when his friends start to \"disappear\" into the camps. His wife is courted by the party and accepts a political post in Berlin. Meanwhile Dr Karl decides to try to do something to counteract the Nazi propaganda and with the help of an engineer and a few friends he sets up the Freedom Radio to counteract the Nazi propaganda.', 95, '0+', '1941-02-04', 'Drama/War'),
(1063089, 'Amityville Exorcism', 'https://image.tmdb.org/t/p/original/9hqGKcQ1XNhKzc2gDiEPbO9gh4S.jpg', 'A family must put faith in a mysterious priest when an demonic force, connected to a decades-old murders in their home, possesses their daughter.', 77, '0+', '2017-01-03', 'Horror'),
(1063090, 'Macbeth', 'https://image.tmdb.org/t/p/original/pHWfFhwG2sTKFQBSx9z8lwDMsPV.jpg', 'Entirely shot on green screen, Shakespeare’s Macbeth has been reinvented by director Kit Monkman (The Knife That Killed Me) in an exciting new film adaptation. Starring Mark Rowley, (The Last Kingdom, Luther). Monkman’s unique adaptation successfully bridges the gap between theatre and film to create a wholly new type of imaginative space. This radical new adaptation puts the audience’s engagement with the story centre-stage, amplifying the theatrical context of the original and creating truly innovative and thrilling cinematic vistas, whilst maintaining the language and themes of Shakespeare’s original play. Using background matte painting and computer modelling to generate the world in which the action plays out, the green screen allows Monkman to create his vision of a multi-tiered globe in which the characters play out their various fates.', 121, '0+', '2018-03-13', 'Drama'),
(1063091, 'Montańska opowieść', 'https://image.tmdb.org/t/p/original/hglc2z9WFJD6hdYUwNvYEKNaIa5.jpg', 'Two estranged siblings return home to the sprawling ranch they once knew and loved in order to care for their ailing father.', 113, '0+', '2022-05-13', 'Drama/Western'),
(1063092, 'All I Need for Christmas', 'https://image.tmdb.org/t/p/original/qH9VoUVO2rOVT3BrzP2SHOHtwrL.jpg', 'Struggling singer/songwriter Maggie is worried she\'s unable to compete with such a tech-savvy world. Upon returning home to help her parents on their farm she meets Archer, an entrepreneur who has come back to town to spend the holidays alone.', 84, '0+', '2024-12-12', 'TV Movie/Comedy/Romance'),
(1063093, 'Tatranská romance', 'https://image.tmdb.org/t/p/original', 'In Slovakia’s Tatra mountains, ironsmith Pavel lives with his son Janko and orphan Anuška, who are close. Janko spends summer pasturing sheep, while Anuška deals with Jura’s advances. Janko meets Soňa Varenová, a city woman seeking peace, and becomes her guide, causing village gossip. At a festival, Janko ignores Anuška for Soňa, angering Pavel. Pavel asks Soňa to leave Janko for Anuška, and she agrees despite her feelings. Janko seeks Anuška’s forgiveness, but she’s in the mountains. He follows her, and they reconcile by lighting a large fire.', 81, '0+', '1935-01-04', 'Drama/Romance'),
(1063094, 'W ukryciu', 'https://image.tmdb.org/t/p/original/mPuaHaczkoJDzlYD9GyXiDjMXig.jpg', 'A family takes refuge in a fallout shelter to avoid a dangerous outbreak.', 83, '0+', '2015-09-15', 'Thriller/Horror'),
(1063095, 'Brainstorm', 'https://image.tmdb.org/t/p/original/6k80yVsymeT0Ap1xVdA4OweTdcT.jpg', 'Scientist Jim Grayam saves his boss\' wife from suicide but then falls in love with her.', 105, '0+', '1965-05-05', 'Thriller');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1063096, 'Sojusznicy', 'https://image.tmdb.org/t/p/original/f3ni3vH2eC1DI7ANZ1WBRzI9g9o.jpg', 'The UK Prime Minister and US President have a public rivalry that risks their countries\' alliance. But when they become targets of a powerful enemy, they\'re forced to rely on each other as they go on a wild, multinational run. Allied with Noel, a brilliant MI6 agent, they must find a way to thwart a conspiracy that threatens the free world.', 117, '0+', '2025-06-24', 'Action/Thriller/Comedy'),
(1063097, 'Colorado Sunset', 'https://image.tmdb.org/t/p/original/fhqzs2v3qdK2TdQm9jayl6foua2.jpg', 'When his well-meaning sidekick (Smiley Burnette) buys a cow farm instead of a cattle ranch, singing cowpoke Gene Autry prepares to embrace the dairy business. But with a corrupt association bent on driving up milk prices, it\'s up to newly elected Sheriff Gene to clean up the mess. Country music icon Patsy Montana sings \"I Want to Be a Cowboy\'s Sweetheart,\" while radio crooners the Texas Rangers perform alongside Autry.', 65, '0+', '1939-07-30', 'Western'),
(1063098, 'Radio America', 'https://image.tmdb.org/t/p/original/2CB6cjjKSTIv0fOK4azVaOkqiw6.jpg', '\"After being discovered at a music competition, two young famers find themselves living the rock star life. As their national tour becomes a massive success, they begin to lose track of their true selves until a tragic accident brings everything back into focus.\"', 102, '0+', '2015-10-01', NULL),
(1063099, 'Crimson Mask', 'https://image.tmdb.org/t/p/original', 'Crimson Mask is a documentary film by Marco Eisenbarth, that follows German \'Ultra Violence Wrestler\' Thumbtack Jack a.k.a. Alexander Bedranowsky in and outside of the wrestling ring.  Being much more than a simple career review, the film gives a deep insight beyond the mask of this seemingly violent and insane character that is Thumbtack Jack, who mutilates his opponents with thumbtacks, barbed wire, syringes and even fire. Crimson Mask shows the man on the other side.  From his career high in the USA to his feud with arch enemy Drake Younger all the way to his very last \'Death-Match\' against long time friend and mentor \'Hate\', the filmmaker never leaves Thumbtack Jack\'s side. But then fate strikes and changes Alexander Bedranowsky\'s life forever...', 73, '0+', '2012-03-22', 'Documentary'),
(1063100, 'Duchy kanionu', 'https://image.tmdb.org/t/p/original/9Ep7FDFaG31sNduhSxLF9yWGMCz.jpg', 'A family returns from a Grand Canyon vacation with a supernatural presence in tow.', 92, '0+', '2016-05-13', 'Horror/Thriller'),
(1063101, 'Pluto matką', 'https://image.tmdb.org/t/p/original/uMkc6iEPSkRuV8dc1HjVncHNea4.jpg', 'Pluto accidentally hatches a bunch of chickens and looks after them until the hen returns.', 8, '0+', '1936-11-14', 'Animation'),
(1063102, 'Probation', 'https://image.tmdb.org/t/p/original/ckpDEx2ciy0rLfgsRlPKKy52CVM.jpg', 'Janet Holman is suspicious of her fiancé, Allen Wells, after he kisses her best friend Gwen when the lights are turned out during a party. Allen leaves early, purportedly for business reasons, but in reality, he is going to visit his secret girl friend, seventeen-year-old Ruth Jarrett. When Ruth\'s neighbor and landlady, Mrs. Humphries, overhears her talking to Allen on the phone, she becomes morally outraged and calls the police. Ruth is taken away to juvenile hall, and when Ruth\'s older brother Nick comes home to celebrate Ruth\'s birthday, Mrs. Humphries explains that Ruth has been seeing an older, wealthy man who has been leading her astray, and that she sent her away for her own good. Nick is saddened that he has failed to keep Ruth on the right track, and when he returns to his apartment, he becomes enraged to see Allen there. When Allen claims ignorance of Ruth\'s age, Nick hits him, and they engage in a brawl.', 67, '0+', '1932-03-15', 'Drama'),
(1063103, 'Silent Dust', 'https://image.tmdb.org/t/p/original/zU2Fj3dzewKsjZ33T7lYk61qLS0.jpg', 'A wealthy blind man is determined to build a cricket pavilion as a memorial to his dead son, who was killed in battle in World War II. Not long before the dedication ceremony is to be held, the son shows up; it turns out that he wasn\'t killed in battle but deserted, and has become a blackmailer and a killer. He wants to get some money to \"start a new life\", but his blind father senses that something is wrong and sets out to find out what\'s going on.', 82, '0+', '1949-02-01', 'Drama'),
(1063104, 'Atmósfera', 'https://image.tmdb.org/t/p/original/3BYOSyh7Ln8pPZcUFAfINfRh6uZ.jpg', 'Cecilia, Alberto, and Felipe live through a strange epidemic that plagues the abandoned streets of a coastal town. Suddenly, an uncontrollable desire forces them to leave in search of the sea.', 20, '0+', '2010-03-10', 'Science Fiction'),
(1063105, 'Magic Spot', 'https://image.tmdb.org/t/p/original/jRRXpBoaXQHILBUgqcykNAYEo8W.jpg', 'Two cousins use a magic spot in the local woods that acts as a time travel portal to both assist their dead uncle and to rekindle an old romance.', 87, '0+', '2022-05-13', 'Comedy/Fantasy'),
(1063106, 'Matrix', 'https://image.tmdb.org/t/p/original/xiCMLkZOVlxFbvWJMHuf4FJvnuX.jpg', 'Set in the 22nd century, The Matrix tells the story of a computer hacker who joins a group of underground insurgents fighting the vast and powerful computers who now rule the earth.', 136, '16', '1999-03-31', 'Action/Science Fiction'),
(1063107, 'Blind Hearts', 'https://image.tmdb.org/t/p/original/zQlvdNAvJ2ZDGjMDwveQ75Xig3o.jpg', 'In 1898 friends John Thomas and Lars Larson travel to the Yukon with their wives to make their fortunes. While in Alaska Thomas\' wife gives birth to a boy, and Larson\'s wife has a girl, Julia. However, Larson spots a birthmark on his daughter\'s shoulder that resembles one on Thomas\' shoulder, and he begins to suspect that he may not actually be the girl\'s father. Over the next 20 years the two become millionaires, but Larson\'s wife dies. Julia and Thomas fall in love and wish to marry, but Larson is determined to oppose it.', 60, '0+', '1921-10-03', 'Drama'),
(1063108, 'The Unseen', 'https://image.tmdb.org/t/p/original/66BAwSfIef99UztzXgVBt8sNR4W.jpg', 'A trio of female reporters find themselves staying overnight in a house occupied by a hostile being lurking in the basement', 94, '0+', '1980-09-01', 'Horror'),
(1063109, 'fff －フォルティッシッシモ－ / シルクロード～盗賊と宝石～', 'https://image.tmdb.org/t/p/original/whLtg5AuoVJ1BAdS1D8lpwZhvfh.jpg', 'FFF - Ludwig van Beethoven instigated a musical revolution of such historical proportions that we still know his name today. And yet the man bearing that name was visited by misfortune of all kinds: lost love, loneliness, hearing loss... Even so, he was able to produce his Ninth Symphony featuring the singing of \"Ode to Joy.\" But how?  Silk Road - From west to east, from east to west, the Silk Road, a trade route carrying culture, civilization, and people, connected Western Europe with Asia over land and sea.  A bandit preying on merchants traveling the route obtains a blue diamond. However, it is in fact the lost eye of the Indian goddess Sita. The jewel has changed hands on countless occasions, at times bringing good fortune to its owner, at other times tragic doom. Having roamed the Silk Road since the long distant past, the Eye of Sita invites the bandit on a journey through the copious memories dwelling behind its dazzling facets.', 158, '0+', '2021-04-20', NULL),
(1063110, 'Vishwas', 'https://image.tmdb.org/t/p/original/s62iZFuYkQzgAcQoJCSqO893dzr.jpg', 'Neena lives a poor lifestyle along with her parents. Her marriage is arranged with a wealthy male, but the marriage could not take place as her parents are unable to provide enough dowry. Ramnath Kapoor steps in, gets married to Neena and she re-locates to live a poor lifestyle with him. She is overly ambitious and superficial, and starts to live a parallel life. Even after the birth of a son, Ravi, she continues to enjoy her life, and neglects both her husband and son. Then one day she steals a necklace and lets Ramnath take the blame, and as a result he is arrested and imprisoned. When Ramnath returns, there is no trace of Neena, and he undertakes to look after Ravi on his own. 15 years later Ravi has grown up, and is a Forest Ranger in Uttar Pradesh.', 0, '0+', '1969-02-05', 'Family/Drama/Romance'),
(1063111, 'The Draft', 'https://image.tmdb.org/t/p/original', 'In Shannon Airport, American military planes off-load a mysterious cargo destined for a secret location in Ireland. En route, one of the military trucks drops its package amongst the treacherous hillsides of Cavan. The box smashes, releasing a silver canister that ends up on \'Makeout Point\', killing two young lovers in their car. From here, all hell breaks loose – Who is the mysterious Professor Wigand, and what is his role in these ghastly events? Can our young hero, Garda Cormac McKee, crack the case and save his girl, the beautiful but challenged Katie Hamelton? What has the sinister General Earl McCarthy got in store for our heroes? And just what in the hell is \'The Draft\'?', 15, '0+', '2006-10-08', 'Horror/Comedy'),
(1063112, 'The Temp', 'https://image.tmdb.org/t/p/original/87h7OsuTWZURTZ1oSNfLl8bqfbO.jpg', 'A series of mysterious accidents at a food company lead a manager to suspect his impressive new temporary secretary.', 99, '0+', '1993-02-12', 'Drama/Mystery/Thriller/Horror'),
(1063113, 'Kung Fu Panda 4', 'https://image.tmdb.org/t/p/original/kDp1vUBnMpe8ak4rjgl3cLELqjU.jpg', 'Po is gearing up to become the spiritual leader of his Valley of Peace, but also needs someone to take his place as Dragon Warrior. As such, he will train a new kung fu practitioner for the spot and will encounter a villain called the Chameleon who conjures villains from the past.', 94, '0+', '2024-03-02', 'Animation/Family/Action/Comedy/Adventure/Fantasy'),
(1063114, 'Gun Runner', 'https://image.tmdb.org/t/p/original/5Jwnsw33jcmorUWFQj9o3J7cIsr.jpg', 'Kate Diamond owns the Roaring Falls Trading Post from where she directs her gang\'s gun-smuggling to the Indians. After she short-changes smuggler Stacey, his men attempt to steal the hidden guns, and attack her foreman Nebraska, but he is saved by Jimmy and \"Cannonball\" on their way to file a homestead claim at Canyon City. Jimmy renews a long acquaintance with Sheriff Harris and his daughter Jessica. The sheriff is wounded by half-breed Danny when he finds a rifle hidden in the latter\'s wagon, but Jimmy captures the outlaw, a go-between for Kate and the Indians.Wounded and in bed, Sheriff Harris ask Jimmy not to tell Jessica that she is only adopted and that Nebraska is really her father, although he believes her to be dead.', 54, '0+', '1949-01-30', 'Western'),
(1063115, 'Fatalna namiętność', 'https://image.tmdb.org/t/p/original/uT8GeRam6ZSX0spNZBFCvqTdilo.jpg', 'An American attorney on business in China, ends up wrongfully on trial for murder and his only key to innocence is a female defense lawyer from the country.', 122, '16', '1997-10-30', 'Crime/Drama/Thriller'),
(1063116, 'Head Space', 'https://image.tmdb.org/t/p/original', 'Spectacle is proud to present HEAD SPACE, a showcase of animated works exploring dimensions both interior and outlying. Featuring an extremely talented and creative group working in a diverse array of styles, the shorts wander through strange and sometimes sketchy landscapes, including alternate-universe appliance stores, the ramblings of Charles Manson, environmental catastrophes in the Dutch style of painting, and a houseplant’s musings. Some, like Sally Cruikshank’s Make Me Psychic, are established classics; others feature newer animators working in looping GIF format, presented away from the small screen’s momentary pleasures to fully appreciate the art that it is. Occasionally gross, often beautiful, and always interesting, HEAD SPACE is a sampler of the thoughts happening inside and out of each frame.', 66, '0+', '2015-05-09', 'Animation'),
(1063117, 'Whisky Galore!', 'https://image.tmdb.org/t/p/original/4qz5Oc3hgXx4eBx7vkqLfG58J9X.jpg', 'Based on a true story. The name of the real ship, that sunk Feb 5 1941 - during WWII - was S/S Politician. Having left Liverpool two days earlier, heading for Jamaica, it sank outside Eriskay, The Outer Hebrides, Scotland, in bad weather, containing 250,000 bottles of whisky. The locals gathered as many bottles as they could, before the proper authorities arrived, and even today, bottles are found in the sand or in the sea every other year.', 82, '0+', '1949-06-16', 'Comedy/Crime'),
(1063118, 'Peter Grimes', 'https://image.tmdb.org/t/p/original/5ZroI3m5EENQZuBmZcwiO1Upp9F.jpg', 'Based on a poem published in 1810 with more ethnographic than dramatic focus, Britten constructed a sombre parable about the conflict between the masses and the individual. The maritime atmosphere, the crudity of people’s lives and passions, and the complex, impenetrable personality of the protagonist come together in a tragedy which ferments and explodes in the din of silence and hearsay.  New production of the Teatro Real, in co-production with the Royal Opera House Covent Garden of London, the Opéra national of Paris and the Teatro dell’Opera of Rome', 225, '0+', '2021-05-07', 'Music'),
(1063119, 'Peter Grimes', 'https://image.tmdb.org/t/p/original/9QWUGDmUa46Vp0ANp4rn1z2jEFu.jpg', 'This 1969 BBC production is about as close as we can get to a definitive version of Benjamin Britten\'s PETER GRIMES, one of the greatest 20th Century operas. The story of the individualistic fisherman hounded by his neighbors who believe he murdered his young apprentice packs tremendous emotional power. The compelling narrative is richly enhanced by its subtexts: the lone outsider versus the conformist mob; the dreamer of improbable dreams that lead to tragedy; the artist (dreamer) versus the Philistines, and the homosexual overtones of Grimes\' abuse of his child apprentices. Britten is conductor of his work and tenor Peter Pears is Grimes, 25 years after he created the title role at the opera\'s premiere. As the widow Ellen Orford, soprano Heather Harper is magnificent. Best of all, the sea is an ever-present actor here. When we don\'t see it in the background it exerts its presence in the abundant visual references to nets, barrels, and other paraphernalia of a seaside fishing village.', 142, '0+', '1969-11-02', 'Music'),
(1063120, 'Project Nim', 'https://image.tmdb.org/t/p/original/bKvxfhFK4hSgY19ObJ30bQYtyli.jpg', 'From the team behind Man on Wire comes the story of Nim, the chimpanzee who in the 1970s became the focus of a landmark experiment which aimed to show that an ape could learn to communicate with language if raised and nurtured like a human child. Following Nim\'s extraordinary journey through human society, and the enduring impact he makes on the people he meets along the way, the film is an unflinching and unsentimental biography of an animal we tried to make human. What we learn about his true nature - and indeed our own - is comic, revealing and profoundly unsettling.', 93, '0+', '2011-07-08', 'Documentary'),
(1063121, 'Kaiju No. 8: Mission Recon', 'https://image.tmdb.org/t/p/original/aOjVfu8F5mPuamhi38t1IX9r1fa.jpg', 'In a Kaiju-filled Japan, Kafka Hibino works in monster disposal. After reuniting with his childhood friend Mina Ashiro, a rising star in the anti-Kaiju Defense Force, he decides to pursue his abandoned dream of joining the Force, when he suddenly transforms into the powerful \"Kaiju No. 8.\" An action-packed recap of the first season of Kaiju No. 8 and a new original episode, Hoshina\'s Day Off.', 110, '12', '2025-03-28', 'Animation/Action/Science Fiction'),
(1063122, 'Harry Potter i Komnata Tajemnic', 'https://image.tmdb.org/t/p/original/mFeZBqgKQqTuk2R67IfmfQP62nj.jpg', 'Cars fly, trees fight back, and a mysterious house-elf comes to warn Harry Potter at the start of his second year at Hogwarts. Adventure and danger await when bloody writing on a wall announces: The Chamber Of Secrets Has Been Opened. To save Hogwarts will require all of Harry, Ron and Hermione’s magical abilities and courage.', 161, '12', '2002-11-13', 'Adventure/Fantasy'),
(1063123, 'Primrose', 'https://image.tmdb.org/t/p/original/6xEyh3BIrwOwA03AQCbSs1AHFqo.jpg', 'A cross-species love affair plays out against the Alaskan wilderness.', 5, '0+', '2015-03-14', 'Comedy'),
(1063124, 'Superman', 'https://image.tmdb.org/t/p/original', 'In this Indian take on the classic superhero story, a young baby from the doomed planet Krypton is sent to Earth, where he is adopted by an elderly couple in India who name him Shekhar. After growing to an adult and learning about his origins and powers, he goes to the city in search of his school sweetheart, Gita, who has become a newpaper reporter. At the same time, Verma, Shekhar\'s rival for Gita\'s affection in their school days, has gone on to become a crime lord and general super-villain. Verma has hatched at plan to become rich by devastating part of India with natural disasters, then buying up all of the abandoned land. Will Superman/Shekhar be able to put a stop to Verma\'s evil plan? Will he win Gita\'s heart? Will he keep his double identity a secret?', 124, '0+', '1987-12-31', 'Action/Adventure/Science Fiction'),
(1063125, 'Lenny', 'https://image.tmdb.org/t/p/original/Avhk4pGdz3YQrzqLU65icjnE6vn.jpg', 'The story of acerbic 1960s comic Lenny Bruce, whose groundbreaking, no-holds-barred style and social commentary was often deemed by the establishment as too obscene for the public.', 111, '0+', '1974-11-10', 'Drama'),
(1063126, 'Knysna', 'https://image.tmdb.org/t/p/original/dHDE7qPWFjHwnE6pALqGZN49WhY.jpg', 'Dolf is a regular guy from a modest background in Knysna. He is content with his normal small town existence, his group of friends and his eccentric grandparents. His life is thrown upside down when he falls for a beautiful stranger Stephanie, a somewhat wealthy visitor to the sleepy coastal resort. What she has not been honest about, is that she is engaged to the Prince of Lichtenstein, but has a cold feet, and is hiding out in Knysna. Stephanie is drawn to the simplicity of Dolf\'s life and yearns for her own to be as uncomplicated and away from the limelight. When the lie becomes apparent, Dolf is conflicted. He is in love with Stephanie, but also feels an inferiority complex come to the fore. She is just a girl wanting a guy to love her and for her to love him back.', 104, '0+', '2014-12-25', 'Comedy'),
(1063127, 'Ruby Gentry', 'https://image.tmdb.org/t/p/original/bFFDqnL6mK2epcaFb1BNInKpq8N.jpg', 'A sexy but poor young girl marries a rich man she doesn\'t love, but carries a torch for another man.', 82, '0+', '1952-12-25', 'Drama/Romance'),
(1063128, 'Perjamuan Iblis', 'https://image.tmdb.org/t/p/original/rVzvYb1PLXEz83A8Jpi9YkcqlQ0.jpg', 'Kala and Radit are a husband and wife who live happily and feel perfect with their only child named Bima. One day, this happiness slowly disappeared after they had to go to Radit\'s old house because their long-lost mother was found to have mysteriously committed suicide in Radit\'s old house. The death of the grandmother made this family experience a lot of terror by creatures beyond reason in the house. And strangely, all the terror was aimed at their only child, Bima. Kala and Radit decided to leave that place. They thought leaving that place was the best way to save Bima, however, they never thought that it was just the beginning of a series of nightmares that would soon happen, and the dark secret behind their grandmother\'s death was related to with the rise of a demonic figure.', 115, '0+', '2023-11-16', 'Horror'),
(1063129, 'Zimowe zapasy', 'https://image.tmdb.org/t/p/original/8wypzIyM5DCZUWeeBaSqYkr5zom.jpg', 'It\'s October 7th and Chip is working industriously to store enough acorns in the tree for the winter. Dale would rather sleep in his matchbox, but an angry kick from Chip gets him working furiously. But there\'s only so much they can do. Their tree is nearly out of acorns. Luckily, the two semi-intelligible chipmunks happen to see the half-unintelligible Donald Duck, a park ranger, planting acorns. They immediately set to steal his bag of the precious nuts. Donald soon realizes what they are up to, and sets out a box propped up with a stick. It\'s a crude trap, with an acorn as bait; but it\'s not too crude to fool Dale, who upsets it and traps Chip. Soon, Donald finds he can have fun instigating a fight between these two quarrelsome chipmunks, but he underestimates their friendship and their ability to work as a team against a common enemy: in this case, a bad-tempered duck.', 7, '0+', '1949-06-03', 'Animation/Comedy'),
(1063130, 'Licorice Pizza', 'https://image.tmdb.org/t/p/original/k3Jk0b9nA7vbUYY7VcbfwVXPpro.jpg', 'The story of Gary Valentine and Alana Kane growing up, running around and going through the treacherous navigation of first love in the San Fernando Valley, 1973.', 133, '12', '2021-11-26', 'Drama/Comedy/Romance'),
(1063131, 'Spiando Marina', 'https://image.tmdb.org/t/p/original/e0C6tkKajFSVOdqVtyELanfqyCc.jpg', 'Mark, a hitman haunted by his past as a corrupt Miami cop and the death of his wife and son,  prepares for his next killing. Gradually he becomes fascinated by the beautiful prostitute who lives in the next apartment and they embark on a passionate affair. Their dreams of a life together are complicated by her pimp being a drugs baron; before they can escape he must die, but things are never that simple...', 86, '0+', '1992-05-23', 'Thriller'),
(1063132, 'As Good as Dead', 'https://image.tmdb.org/t/p/original/qqQPxxRQqfLrq0ubfDQCwhJHZ91.jpg', 'An ex-cop in self-imposed witness protection in Mexico becomes a target when a fight video of his apprentice goes viral.', 88, '0+', '2022-12-16', 'Action/Crime'),
(1063133, 'Sindak', 'https://image.tmdb.org/t/p/original/4l3NeVQNcjkHOQCYurHvKWaqDbM.jpg', 'Sindak is a movie about four guys, security guards by night, sex maniacs by day, and in weekends, regular dudes who like to shoot the shit with gin and pulutan (gleaned from their weekend monkey-hunting trips). Unbeknownst to them, they live in a world of sin and extraordinary inexplicable weirdness (inexplicable because the movie doesn\'t put any effort in explaining a lot of things), made apparent when a man they killed—whom they suspect of being a serial murderer—comes back to haunt them one by one. Once they start dying, they start seeing the infidelity, the incest, and the debauchery around them, and soon they disintegrate under the pressure of the seedy world around them.', 98, '0+', '1999-12-15', 'Thriller'),
(1063134, 'Aswang', 'https://image.tmdb.org/t/p/original/882p5QzYEzFnpwbVKomKFvJ8l0S.jpg', 'This Filipino vampire film co-directed by Peque Gallaga and Lore Reyes tells the story of an aswang, the traditional shape-shifting creature of local legend. Here, the vampire makes appearances as a giant snake, a young woman (Alma Moreno), and a withered old hag (Lilia Cuntapay). The aswang has a lengthy cinematic history, having been the subject of the first sound film ever produced in the Philippines (1932\'s Ang Aswang) and migrating, in somewhat altered form, to films in Hong Kong, India, Japan, and, in 1994, to the United States. Aiza Seguerra co-stars with Janice de Belen, Aljon Jimenez, John Estrada, and Alma Moreno.', 125, '0+', '1992-05-22', 'Horror/Comedy'),
(1063135, 'Dynamite Chicken', 'https://image.tmdb.org/t/p/original/6JQfxYbGW5PvWWfCMju6GCFjRr.jpg', 'A collection of subversive comedy sketches and routines relating to the peace movement.', 76, '0+', '1971-01-20', 'Comedy'),
(1063136, 'Frameup', 'https://image.tmdb.org/t/p/original/xxEbhuPsB5bydYYynDFegJJvVqU.jpg', 'Ricky, a dim-witted ex-con, meets Beth, a dim-witted waitress, in an Idaho diner. They take off in his car to Washington and begin an affair. Beth, a lonely romance-novel addict, is hopelessly enamored; Ricky is just in it for the (constant) sex. Beth\'s longing to visit California and Ricky\'s longing for quick cash leads them into a desperate situation. Director Jost uses a variety of avant-garde visual and narrative techniques, such as montage, collages, split screens and lengthy, tongue-in-cheek monologues to tell the tragicomic story of two complete losers in love.', 91, '0+', '1993-01-19', 'Romance/Crime/Drama'),
(1063137, 'Frankenstein \'80', 'https://image.tmdb.org/t/p/original/3Q8XEYoWCGMuywyqS0WBOKbjIAS.jpg', 'A mad scientist creates a monster called \"Mosaico,\" who breaks out of the laboratory to hunt down and kill beautiful women.', 85, '0+', '1972-12-12', 'Horror/Science Fiction'),
(1063138, 'En cada puerto un amor', 'https://image.tmdb.org/t/p/original', 'An inveterate sailor renounces love because of his passion for the sea. It is the Spanish-language version of Way for a Sailor (Wood, 1930).', 91, '0+', '1931-03-27', NULL),
(1063139, 'CONFLICT 〜最大の抗争〜 第六章', 'https://image.tmdb.org/t/p/original/7wRWgeSRc2N5oeDNs5R7TdKLu3j.jpg', 'To revive Tendokai, Okita (Yasukaze Motomiya) and Kurata (Yoshiyuki Yamaguchi) form the Washio-gumi, recruiting former members like Murata (Shunsaku Kudo) and Yagi (Yudai Uenishi). They are warned by retired Kozo Otani (Shun Suda) about an impending police raid on their organization. Despite Kurata\'s questioning, Otani remains vague. Meanwhile, Akinari Myojin (Kaneko Sho) discovers that Jinseikai was being controlled by Prime Minister Anan (Ikki Hankai).  Before they can act, Jinseikai\'s headquarters is destroyed by a \"mysterious man.\" Hozumi (IZAM) of the police suspects Washio-gumi is behind it, but Okita and Kurata are uncertain. Hozumi suggests the conspiracy may be tied to Kazuma Washio\'s (Hitoshi Ozawa) past, prompting them to investigate.  Okita visits arms dealer Genkichi Hyuga (Masataka Naruse), who holds crucial information that leads Okita to a shocking truth…', 70, '0+', '2019-01-01', NULL),
(1063140, 'Mufasa: Król Lew', 'https://image.tmdb.org/t/p/original/qeBl1XFXDEYKIOUDPT3tLnCEsV1.jpg', 'Mufasa, a cub lost and alone, meets a sympathetic lion named Taka, the heir to a royal bloodline. The chance meeting sets in motion an expansive journey of a group of misfits searching for their destiny.', 118, '0+', '2024-12-18', 'Adventure/Family/Animation'),
(1063141, 'Misled', 'https://image.tmdb.org/t/p/original/usDfphGSWsoGo1YGrLQ92zUHbGN.jpg', 'Two brothers from southwest Detroit struggle to improve their lives. Unable to afford college and faced with expulsion - and meanwhile supporting his mother - Jason turns to stripping which turns to prostitution, posing a huge dilemma since he has just begun the first true love relationship of his life. Bobby\'s own drug habit spirals him down into a darker and darker place, exasperated by the re-emerging memory of the horrible childhood secret he shares with Jason.', 90, '0+', '2015-02-28', 'Crime/Drama'),
(1063142, 'Killer High', 'https://image.tmdb.org/t/p/original/m4idaPFZUCNeDWjxxwenCKtLEM1.jpg', 'Sabrina\'s perfectly planned high school reunion goes south when a monster keeps killing all the guests.', 87, '0+', '2018-10-20', 'Horror/Comedy/TV Movie'),
(1063143, 'Back Trail', 'https://image.tmdb.org/t/p/original/ANW57hALLt3PWKg4e9usFQVvF.jpg', 'Back Trail is one of the livelier entries in Monogram\'s Johnny Mack Brown western series. Brown rides into a small town where he becomes embroiled in a blackmail scheme. The town\'s banker (Ted Adams), a pillar of respectability, once served a jail term. Outlaw leader Pierce Lyden threatens to reveal Adams\' secret if the banker doesn\'t let him know in advance when the gold shipments are going through. Adams tearfully tells Brown the whole story, whereupon Johnny rides shotgun on the next shipment himself. Back Trail was one of the last films directed by workhorse Christy Cabanne, whose career stretched all the way back to the D.W. Griffith days.', 57, '0+', '1948-07-18', 'Western'),
(1063144, 'The Vampire', 'https://image.tmdb.org/t/p/original', 'Guy Temple, as \"the fool there was\" marries his brother\'s ward, his boyhood sweetheart, Emily. The young husband becomes ensnared in the toils of the Vampire (a destroyer of souls). Clandestine meetings are arranged and the cunning, unscrupulous, satanic actions of the Vampire compels the poor weakling, Temple, to falter and fall before her charms. John Temple, the other brother, determines to save the young husband when he discovers his perfidy, and to recover the jewels given the Vampire by Guy.', 0, '0+', '1910-11-10', NULL),
(1063145, 'Far North', 'https://image.tmdb.org/t/p/original/d31sugp9MHWv7YHGxgM5iYQVmXB.jpg', 'In the arctic, as Saiva is being born, a shaman declares that she is evil and will bring harm to all who become involved with her. Saiva is cast out of her tribe of herders and grows up to live a nomadic existence with Anja, a young woman she adopts as an infant. Then Loki, an injured and starving soldier, stumbles into their isolated lives. The women nurse him back to health, but treachery, violence and doom await them all.', 89, '0+', '2008-10-09', 'Drama/Thriller/Romance/Crime'),
(1063146, 'Eliza Fraser', 'https://image.tmdb.org/t/p/original/tZLCrDEb2VUOVAaOB3ZaKZHaTtf.jpg', 'An old captain &amp; his young wife share a lot of adventures after they\'re shipwrecked and captured by Aborigines on an island near Australia.', 130, '0+', '1976-12-16', 'Adventure/Comedy/Drama'),
(1063147, 'Without Mercy', 'https://image.tmdb.org/t/p/original/e76gKEjCDNSxP0EEZsr5dkx7z8V.jpg', 'After terrorizing the people of Nodaway County and repeatedly escaping justice for years, the town bully finally meets his demise at the hands of the townspeople of Skidmore, Missouri. Immediately, law enforcement at all levels mount an intense investigation to find and arrest the shooters. But the townspeople refuse to cooperate, even defiantly challenging the FBI to make good on their threats to arrest every adult male in town for murder and conspiracy.', 113, '0+', '2005-01-01', 'Horror'),
(1063148, 'Inspiration', 'https://image.tmdb.org/t/p/original/bpgVGXftTyIdICxDBlTxT1hCFy0.jpg', 'Gina, a pleasant and witty young lady and Danny a suave, attractive young lad live parallel lives nurtured by single parents. In a series of events, their parents meet and fall in love. Though despising each other completely, Gina and Danny are determined to separate their parents in the desire to win back their parents attention. Despite their efforts, their parents marry leaving Gina and Danny to live under one roof. Will this wreak havoc in the new household or will they learn to grow fond of each other?', 0, '0+', '1972-05-27', 'Drama/Romance'),
(1063149, 'Going Back', 'https://image.tmdb.org/t/p/original', 'A remote stone house nestles peacefully on the edge of the Yorkshire moors. In the garden. Faith Armstrong describes the flowers and the late afternoon skies to Jack, her blind husband. \"The sun is almost setting. The sky is blue, with ... those little puffy clouds like meringues. There are still leaves on the trees. Oh . quite a few birds are gathering . \" All is peaceful. As they talk, a small figure appears walking towards the cottage on the moorland road. Slowly it becomes recognisable as the Armstrong\'s son David. David\'s arrival is unexpected. He left home three years ago, and Faith and Jack have heard nothing from him until now. Things at home have changed a lot in those three years. His father has gone blind, and his brother Malcolm is now engaged \'to Heather. David\'s former girlfriend. The family are curious. Why has David suddenly decided to return home? How long is he staying? Is he in trouble?', 56, '0+', '1979-07-24', NULL),
(1063150, 'Sędzia', 'https://image.tmdb.org/t/p/original/fyjDCr4ZKOoD7kLfmOJPNVDe54s.jpg', 'A successful lawyer returns to his hometown for his mother\'s funeral only to discover that his estranged father, the town\'s judge, is suspected of murder.', 141, '0+', '2014-10-08', 'Drama'),
(1063151, 'Piraci z Karaibów. Skrzynia umarlaka', 'https://image.tmdb.org/t/p/original/bzxQf3bPoEbPjsBj6MTSOjM7zxz.jpg', 'Captain Jack Sparrow races to recover the heart of Davy Jones to avoid enslaving his soul to Jones\' service, as other friends and foes seek the heart for their own agenda as well.', 151, '12', '2006-07-06', 'Adventure/Fantasy/Action'),
(1063152, 'Ted', 'https://image.tmdb.org/t/p/original/tZPTcdGTpxq4yJx1YxqBl0gthNz.jpg', 'John Bennett, a man whose childhood wish of bringing his teddy bear to life came true, now must decide between keeping the relationship with the bear or his girlfriend, Lori.', 107, '12', '2012-06-29', 'Comedy/Fantasy'),
(1063153, 'Dhyanu Bhagat', 'https://image.tmdb.org/t/p/original/goGR7iTOBuCulLH1XgHVzc2sAMJ.jpg', 'Shunned by his parents, brought up by a Poojary, nursed by a cow, Dhyanu Bhagat grows up performing miracles, curing the ill, and singing the praise of Devi Maa Durga. He faces many opponents, including Satish, who believes that Dhyanu is wooing his fiancée, Paro. After witnessing Mughal troops\' desecration of the Devi\'s Mandir, Dhyanu\'s biggest challenge will come from none other than Shahenshah Akbar himself who will ask him to convert to Din-i-Ilahi.', 0, '0+', '1978-01-01', 'History/Adventure/Drama'),
(1063154, 'Tarot Curse', 'https://image.tmdb.org/t/p/original/gAUyxtELzgi1HrcGTHMyqgMkErK.jpg', 'After a Tarot reading in New Orleans, a group of students are horrified to realize the cards are predicting their gruesome deaths one by one.', 90, '0+', '2025-02-21', 'Horror/Mystery'),
(1063155, 'Ujeżdżanie Barbie', 'https://image.tmdb.org/t/p/original/kDmRRbaKgsdWbAqM1LxRysE5CsI.jpg', 'A Tinder date gone astray leaves famous fitness selfie queen, Barbi, lost in the wilderness trying to survive despite Homeland Security, alien death rays and zero cell service.', 90, '0+', '2019-02-15', 'Comedy/Science Fiction'),
(1063156, 'Nightmare', 'https://image.tmdb.org/t/p/original/iyrWn77rfUBd05HkYRozwJtM4RC.jpg', 'A young student is haunted by recurring dreams of her mother murdering her father, but her nightmare is just beginning as she tries to prove to her loved ones that she is not insane.', 83, '0+', '1964-02-28', 'Thriller/Horror/Mystery'),
(1063157, 'Mutant 3: Obrońca', 'https://image.tmdb.org/t/p/original/vNAwfgBPZXprxfgx7cF5Cji4be1.jpg', 'A man enclosed in a plastic bubble, his sister, and their best friend must defend an apartment complex from the mutant Judas Breed insects.', 77, '0+', '2003-04-14', 'Horror/Science Fiction/Thriller'),
(1063158, 'Robinson Charley', 'https://image.tmdb.org/t/p/original/cqDNfh4umcYwRFeIi9R1rV3VPVR.jpg', 'No man is an island, but Charley represents his nation in this economical cartoon tale of Britain’s economics.', 11, '0+', '1948-07-16', 'Animation'),
(1063159, 'Crash Drive', 'https://image.tmdb.org/t/p/original', 'Paul Dixon (Dermot Walsh) is a fiercely competitive racing driver whose meteoric career is cut short after he is paralyzed in a collision. Ann, Paul\'s conflicted, estranged wife (Wendy Williams), tries to help her husband overcome his self-pity to become productive once again. Paul\'s perception of himself as a cripple is challenged by his new friend, a former dancer (Anton Rodgers), who urges Paul to strive for rehabilitation and new goals. [Netflix]', 0, '0+', '1959-11-13', NULL),
(1063160, 'Shrek', 'https://image.tmdb.org/t/p/original/o04jZs5SXhbvhqO4981W7KJXOWZ.jpg', 'It ain\'t easy bein\' green -- especially if you\'re a likable (albeit smelly) ogre named Shrek. On a mission to retrieve a gorgeous princess from the clutches of a fire-breathing dragon, Shrek teams up with an unlikely compatriot -- a wisecracking donkey.', 90, '7', '2001-05-18', 'Animation/Comedy/Fantasy/Adventure/Family'),
(1063161, 'V/H/S/Halloween', 'https://image.tmdb.org/t/p/original/bvMKSZtN8KAdtlKoYbEi1Zhyaou.jpg', 'A collection of Halloween-themed videotapes unleashes a series of twisted, blood-soaked tales, turning trick-or-treat into a struggle for survival.', 115, '0+', '2025-09-19', 'Horror/Thriller'),
(1063162, 'Little Boxes', 'https://image.tmdb.org/t/p/original/2MARwPALPBlLUN9OyBqvDdeSenQ.jpg', 'It\'s the summer before 6th grade, and Clark is the new-in-town biracial kid in a sea of white. Discovering that to be cool he needs to act \'more black,\' he fumbles to meet expectations, while his urban intellectual parents Mack and Gina also strive to adjust to small-town living. Equipped for the many inherent challenges of New York, the tight-knit family are ill prepared for the drastically different set of obstacles that their new community presents, and soon find themselves struggling to understand themselves and each other in this new suburban context.', 84, '0+', '2017-04-14', 'Comedy/Drama'),
(1063163, 'Fast Romance', 'https://image.tmdb.org/t/p/original/flommTAjfAY5G8R6A2vL8B1mz32.jpg', 'The interweaving stories of seven very different people in the cosmopolitan city of Glasgow who decide that, in their pursuit of love, it is time to try something new. Little do they know that after one night of speed dating their lives will take dramatic new twists - and we\'ll be there to witness each and every one of them.', 97, '0+', '2011-02-10', 'Comedy/Romance'),
(1063164, 'The Palace', 'https://image.tmdb.org/t/p/original/4fYrhAupTYH9I0vYMzxVITpjVJv.jpg', 'A comedy set on New Year’s Eve 1999 in a luxurious hotel in the Swiss Alps where the lives of various guests and those who work for them intersect.', 100, '16', '2023-09-28', 'Comedy/Drama'),
(1063165, 'Alleluja', 'https://image.tmdb.org/t/p/original/tplgL2sRXigiz7vINH8kwsbwo8L.jpg', 'Michel, a murderous womanizer, meets introverted Gloria online and treats her to a whirlwind one-night-stand. Offering herself as an accomplice in his seductive crimes, the unhinged lovers embark on a deadly odyssey amplified by wild sex, unbridled jealousy, and passionate forays into the dark arts. This smart and gory shocker breathes new life into the lovesick horror genre to serve up a chilling tale of white-hot desperation and terrifying devotion.', 93, '0+', '2014-11-26', 'Horror/Drama/Thriller'),
(1063166, 'Flight Angels', 'https://image.tmdb.org/t/p/original/mYpq6aOX9CIFCQehi3HQPYZvmMk.jpg', 'Federal Airlines ace pilot Chick Faber is grounded by Flight Superintendent Bill Graves when a doctor says his eyesight is failing. Aided by Mary Norvell and Nan Hudson, Graves persuades Chick to take a job as teacher in the school for airline hostesses, and Chick and Mary get married. He learns that the Army is going to test a stratosphere plane that he and Artie Dixon designed and feels that he should make the first flight but permission is refused.', 74, '0+', '1940-05-18', 'Drama'),
(1063167, 'ConMom', 'https://image.tmdb.org/t/p/original/7ZfQiEOSmF0xtkSLqGImkjcNHgo.jpg', 'After separating from an abusive husband, a former theater actress resorts to using disguises in a desperate attempt to spend time with her only child.', 112, '0+', '2025-05-21', 'Comedy'),
(1063168, 'Titanic', 'https://image.tmdb.org/t/p/original/9xjZS2rlVxm8SFx8kPC3aIGCOYQ.jpg', '101-year-old Rose DeWitt Bukater tells the story of her life aboard the Titanic, 84 years later. A young Rose boards the ship with her mother and fiancé. Meanwhile, Jack Dawson and Fabrizio De Rossi win third-class tickets aboard the ship. Rose tells the whole story from Titanic\'s departure through to its death—on its first and last voyage—on April 15, 1912.', 194, '0+', '1997-11-18', 'Drama/Romance'),
(1063169, 'Cape Forlorn', 'https://image.tmdb.org/t/p/original/pl304cmcNFrB4qdeoMxrhSUizTx.jpg', 'William Kell, the keeper of a lighthouse on a lonely stretch of coastline, marries cabaret dancer Eileen. His young wife, however, goes on to have an affair with Henry Cass, the handsome assistant later taken on by her husband; when she then begins to flirt with a stranger who is rescued from the wreck of a motor-launch, a chain of shocking events is set in motion...', 82, '0+', '1931-01-08', 'Drama'),
(1063170, 'Tron', 'https://image.tmdb.org/t/p/original/zwSFEczP7AzqugAHHIX3zHniT0t.jpg', 'When brilliant video game maker Flynn hacks the mainframe of his ex-employer, he is beamed inside an astonishing digital world...And becomes part of the very game he is designing. In his mission through cyberspace, Flynn matches wits with a maniacal Master Control Program and teams up with Tron, a security measure created to bring balance to the digital environment.', 95, '12', '1982-07-09', 'Science Fiction/Action/Adventure'),
(1063171, 'Twoje imię.', 'https://image.tmdb.org/t/p/original/yLglTwyFOUZt5fNKm0PWL1PK5gm.jpg', 'High schoolers Mitsuha and Taki are complete strangers living separate lives. But one night, they suddenly switch places. Mitsuha wakes up in Taki’s body, and he in hers. This bizarre occurrence continues to happen randomly, and the two must adjust their lives around each other.', 106, '0+', '2016-08-26', 'Animation/Romance/Drama'),
(1063172, 'Curtains', 'https://image.tmdb.org/t/p/original/jpMClX0G1Gsia1Dn1HaFGPXqjd0.jpg', 'Six young actresses auditioning for a movie role at a remote mansion are targeted by a mysterious masked murderer.', 89, '0+', '1983-03-04', 'Horror/Thriller'),
(1063173, 'Det brinner!', 'https://image.tmdb.org/t/p/original/km2hDCIfw0T4qst2CtUrRAGwHX1.jpg', 'Two girls think that maybe they burned down an old house in the forest, when they secretly went to smoke a cigarette, but what does the burned house have to do with a madman named Reine and a dragon? Maybe there is more to this mystery than the girls know.', 81, '0+', '2002-01-17', 'Drama/Crime/Family'),
(1063174, 'The Dancers', 'https://image.tmdb.org/t/p/original/BevR0iovcSgbrmkpWgnyOSkS9h.jpg', 'Young Tony, unable to make a living in crowded and fast-paced London, goes to South America in search of his fortune. He soon becomes the owner of a saloon and dance hall. One of the dancers in his place, Maxine, falls in love with him, but Tony is still in love with his childhood sweetheart Una, although Una is now a \"party girl\" back in London and has forgotten about Tony. However, Tony comes into an unexpected inheritance, along with a title, and returns to London for Una. Although disappointed with Una\'s current lifestyle, he asks her to marry him despite her \"indiscretions\". However, the night before they are to be married Una confesses a deep, dark secret to Tony that could change their lives forever.', 70, '0+', '1925-01-04', 'Drama'),
(1063175, 'Piła II', 'https://image.tmdb.org/t/p/original/mmwzmgpuCfmE3JNDy4N682I62Zi.jpg', 'The chilling and relentless Jigsaw killer returns to terrorize the city once again. When a gruesome murder victim emerges with unmistakable traces of Jigsaw\'s sinister methods, Detective Eric Matthews is thrust into a high-stakes investigation. To his surprise, apprehending Jigsaw seems almost too easy, but what he doesn\'t realize is that being caught is merely another piece of Jigsaw\'s intricate puzzle.', 93, '18', '2005-10-28', 'Horror'),
(1063176, 'En perfekt gentleman', 'https://image.tmdb.org/t/p/original', 'Social comedy-drama. Aristocrat\'s boredom in marriage of convenience and sacrif ice of self on behalf of wife\'s lover.', 105, '0+', '1927-12-27', 'Drama'),
(1063177, 'Historia małżeńska', 'https://image.tmdb.org/t/p/original/a41H1hHn8KXg5aRPjnfBYVuDTZc.jpg', 'A stage director and an actress struggle through a grueling, coast-to-coast divorce that pushes them to their personal extremes.', 137, '16', '2019-09-28', 'Drama'),
(1063178, 'Melody', 'https://image.tmdb.org/t/p/original/8UoL2IkDnDqT9pvUk5HA2LQmvji.jpg', 'Two youngsters declare to their parents that they want to get married. Not sometime in the future but as soon as possible.', 103, '0+', '1971-03-28', 'Comedy/Drama/Romance'),
(1063179, 'Chermin', 'https://image.tmdb.org/t/p/original/wsqqlk8kOMMTgzT6bTao6Xw7MHE.jpg', 'The story is about a girl name Nasrin who got herself into a tragic car accident. Her face is ruined. Her mother discovers an antique mirror. The mirror is not an ordinary mirror, a spirit trapped inside it makes the mirror able to reflect what Nasrin wants to see. Nasrin becomes obsessed with the mirror. On a quest to regain her past beauty, Nasrin submits herself to the mirror spirit by satisfying the mirror’s need for blood and revenge.', 100, '0+', '2007-03-22', 'Horror'),
(1063180, 'Frances Ha', 'https://image.tmdb.org/t/p/original/jrq1NoKvsxWCcffVOjegiYwloFN.jpg', 'An aspiring dancer moves to New York City and becomes caught up in a whirlwind of flighty fair-weather friends, diminishing fortunes and career setbacks.', 86, '12', '2013-05-17', 'Comedy/Drama'),
(1063181, 'The Quare Fellow', 'https://image.tmdb.org/t/p/original/qUOePJEJBoNIVEpJZ9JGaTWwsi4.jpg', 'Thomas Crimmins is a new warder, or guard, in an Irish prison. He is young, naive, and idealistic, determined to serve his country by his part in meting out justice to criminals. His superior, Regan, however, realizes that even prisoners are human beings, and Regan is sick of the eye-for-an-eye attitude that leads the state to execute condemned men, or \"quare fellows.\" Crimmins begins to see that not all is black and white in his new world, and when he becomes involved with Kathleen, the wife of one of the condemned men, his attitude begins to change. When new evidence arises to suggest that Kathleen\'s husband may not deserve his fate, Crimmins is torn between his duty and his humanity.', 85, '0+', '1962-10-02', 'Drama'),
(1063182, 'Terrifier 3', 'https://image.tmdb.org/t/p/original/ju10W5gl3PPK3b7TjEmVOZap51I.jpg', 'Five years after surviving Art the Clown\'s Halloween massacre, Sienna and Jonathan are still struggling to rebuild their shattered lives. As the holiday season approaches, they try to embrace the Christmas spirit and leave the horrors of the past behind. But just when they think they\'re safe, Art returns, determined to turn their holiday cheer into a new nightmare. The festive season quickly unravels as Art unleashes his twisted brand of terror, proving that no holiday is safe.', 125, '0+', '2024-10-09', 'Horror/Thriller'),
(1063183, 'Totally Baked', 'https://image.tmdb.org/t/p/original/rKEbJbLZA4W5Zr6FBgad9DLOUEi.jpg', 'Meet Dave Bertman, a tightly wound 37 year-old father of one. Bertman\'s \"higher\" education begins when medical marijuana activists wielding \"loaded\" weapons interrupt a planned reunion barbecue with college debate chums. When his teenage daughter Gina Marie unexpectedly arrives with a joint found in her pocket, Bertman assumes the worst. Only after he faces his own hypocrisies, can he have the open and honest discussion needed for father and daughter to understand each other and reconnect.', 88, '0+', '2007-04-20', 'Comedy'),
(1063184, 'Trzy kamelie', 'https://image.tmdb.org/t/p/original/kWtJ1C98fQB1fUDSfqb1NGBPPK8.jpg', 'A woman suffers a nervous breakdown and an oppressive mother before being freed by the love of a man she meets on a cruise.', 117, '0+', '1942-10-22', 'Romance/Drama'),
(1063185, 'Red Rocket', 'https://image.tmdb.org/t/p/original/345gLhiNpItU1ICx8OxJQwjgPmH.jpg', 'After hitting rock bottom in Los Angeles, former porn star Mikey Saber returns to his hometown in Texas to stay with his estranged wife and mother-in-law. Just as tensions begin to ease, he becomes infatuated with a young doughnut shop worker named Strawberry.', 130, '16', '2021-12-10', 'Drama/Comedy'),
(1063186, 'Zmierzch', 'https://image.tmdb.org/t/p/original/4F1VuNijOZsY4sGjWSdianHYcOQ.jpg', 'When Bella Swan moves to a small town in the Pacific Northwest, she falls in love with Edward Cullen, a mysterious classmate who reveals himself to be a 108-year-old vampire. Despite Edward\'s repeated cautions, Bella can\'t stay away from him, a fatal move that endangers her own life.', 122, '16', '2008-11-20', 'Fantasy/Drama/Romance'),
(1063187, 'Rytuał', 'https://image.tmdb.org/t/p/original/uubL8yvtEBjz3V7DFQHjCuSQO8w.jpg', 'Two priests, one in crisis with his faith and the other confronting a turbulent past, must overcome their differences to perform a risky exorcism.', 98, '0+', '2025-04-18', 'Horror/Drama/Thriller'),
(1063188, 'Dziewczyna z marzeniami', 'https://image.tmdb.org/t/p/original/iRUviw0Dxs0FZI1IcSDYFX02i8s.jpg', 'In Bodeen, Texas, an indie-rock loving misfit finds a way of dealing with her small-town misery after she discovers a roller derby league in nearby Austin.', 111, '0+', '2009-04-09', 'Drama'),
(1063189, 'Tyrannosaurus Azteca', 'https://image.tmdb.org/t/p/original/dFdEkhljyVJfjSqbf7qTGqdpyKO.jpg', 'The Aztecs summoned a Tyrannosaurus Rex to keep Cortes and his army out of Mexico. Now they need the Conquistadors\' help to stop the T-Rex from killing them all.', 86, '0+', '2007-05-05', 'Adventure/Action'),
(1063190, 'Hopeless Romantic', 'https://image.tmdb.org/t/p/original/1Els0XqRXicIooZ9nYa6zJfZJwQ.jpg', 'Everyone has a different story to tell, especially when it comes to relationships. Lynda Boyd stars as Anna, a recently widowed cardiologist facing romantic challenges. While attending a wedding, Anna discovers she is not alone and bonds with six other women as they each share their unique stories of navigating the complex world of relationships. This anthology film weaves through the love lives of these women, charting their ups and downs in romance and rejection.', 85, '0+', '2018-09-15', 'Romance'),
(1063191, 'Harry Potter i Zakon Feniksa', 'https://image.tmdb.org/t/p/original/7SusRCFTH01GtGVlKjFY0xZWCx5.jpg', 'Returning for his fifth year of study at Hogwarts, Harry is stunned to find that his warnings about the return of Lord Voldemort have been ignored. Left with no choice, Harry takes matters into his own hands, training a small group of students to defend themselves against the dark arts.', 138, '16', '2007-07-08', 'Adventure/Fantasy');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1063192, 'Człowiek przyszłości', 'https://image.tmdb.org/t/p/original/wrs23eO0VEWwOQpXoOasMnlW9Y4.jpg', 'Richard Martin buys a gift, a new NDR-114 robot. The product is named Andrew by the youngest of the family\'s children. \"Bicentennial Man\" follows the life and times of Andrew, a robot purchased as a household appliance programmed to perform menial tasks. As Andrew begins to experience emotions and creative thought, the Martin family soon discovers they don\'t have an ordinary robot.', 131, '0+', '1999-12-17', 'Science Fiction/Drama'),
(1063193, 'Zaginiony autokar', 'https://image.tmdb.org/t/p/original/uOjaSXIUoQ2RXiSW61vnZSjaY8s.jpg', 'A determined father risks everything to rescue a dedicated teacher and her students from a raging wildfire.', 130, '12', '2025-09-19', 'Drama/Mystery/Thriller'),
(1063194, 'Projekt Almanach: Witajcie we wczoraj', 'https://image.tmdb.org/t/p/original/9u5Rb0e7mx8qOO7zj39KnIRWClr.jpg', 'A group of teens discover secret plans of a time machine, and construct one. However, things start to get out of control.', 106, '0+', '2015-01-28', 'Science Fiction/Thriller'),
(1063195, 'Remembering Agatha', 'https://image.tmdb.org/t/p/original/3OyPXX5qu7JlRzyc7Z3vs1WakvX.jpg', 'For Agatha, Christmas triggers sadness. She yearns for freedom laced with imagination, when magical creatures were part of a game played with friends in the forest. The death of her parents after a 1978 Christmas Party still haunts Agatha. She sees similarities between her parents\' unhappy marriage and her own. The Black Madonna statue from her childhood visits Agatha, escalating her anxiety and goading her towards change. The discovery of a mysterious portal offers Agatha the possibility of resolving her grief and saving her crumbling marriage.', 30, '0+', '2017-10-10', 'Animation/Drama'),
(1063196, 'Critically Acclaimed', 'https://image.tmdb.org/t/p/original/djO46r10LsoYqU5kFMXzjjX8ViB.jpg', '\"Critically Acclaimed\" is a movie featuring the world\'s greatest surfers. Two years in the making and a trip around the world Critically Acclaimed brings the most exotic surf locations and exciting surfers into your living room. Featuring exclusive free surfing sections of Joel Parkinson, Mick Fanning, Dane Reynolds, Geoff Brack, Dean Morrison, Jamie O\'Brien, Chris Ward, Bruce Irons, Andy Irons, Tim Curran, Kelly Slater. Filmed on Location in Tahiti, Australia, France, Hawaii, California, East Coast', 0, '0+', '2006-01-01', NULL),
(1063197, 'Holiday', 'https://image.tmdb.org/t/p/original/ew4gt1IYriNJiUbdnC3O9nWj2BY.jpg', 'Two women, one American and one British, swap homes at Christmastime following bad breakups. Each woman finds romance with a local man but realizes that the imminent return home may end the relationship.', 136, '16', '2006-12-05', 'Comedy/Romance'),
(1063198, 'Wyrok skazujący', 'https://image.tmdb.org/t/p/original/rUxznyFz7D0HgC5zcYigzP1XUi4.jpg', 'When Betty Anne Waters\' older brother Kenny is arrested for murder and sentenced to life in 1983, Betty Anne, a Massachusetts wife and mother of two, dedicates her life to overturning the murder conviction. Convinced that her brother is innocent, Betty Anne puts herself through high school, college and, finally, law school in an 18 year quest to free Kenny. With the help of best friend Abra Rice, Betty Anne pores through suspicious evidence mounted by small town cop Nancy Taylor, meticulously retracing the steps that led to Kenny\'s arrest. Belief in her brother - and her quest for the truth - pushes Betty Anne and her team to uncover the facts and utilize DNA evidence with the hope of exonerating Kenny.', 107, '0+', '2010-10-15', 'Drama'),
(1063199, 'W głowie się nie mieści', 'https://image.tmdb.org/t/p/original/hf0z2LV69XedGf2RAGfOtgLaIo.jpg', 'When 11-year-old Riley moves to a new city, her Emotions team up to help her through the transition. Joy, Fear, Anger, Disgust and Sadness work together, but when Joy and Sadness get lost, they must journey through unfamiliar places to get back home.', 95, 'AL', '2015-06-17', 'Animation/Family/Adventure/Drama/Comedy'),
(1063200, 'Aufzug', 'https://image.tmdb.org/t/p/original/6Js91MFnkgMDmQZIo2GaaNE0391.jpg', 'The story is set some time in the past, or maybe some time in the future. Given a time-frame, we would say somewhere between the American moonwalk, and Coca- Cola\'s serious ambition to turn the moon into an advertising logo. Our central character, the young lift operator, is formed by experience into cynicism, detachment, and apathy. The story builds to its crescendo: of public outrage and state crackdown; the banality of commercial interest and the monumental rape of nature. Set in a large newspaper office, the Lift is a place of relative safety. But floor by floor, with each passenger in his or her tableau, the atmosphere of mayhem seeps in. Finally our young character leaves the situation, far-gone in hopelessness and disinterest.', 16, '0+', '2012-02-07', NULL),
(1063201, 'Paradox', 'https://image.tmdb.org/t/p/original/bEvWTCEZUIqSJ12n4mOVAxid0x3.jpg', 'A loud poem. A whimsical western tale of music and love.', 73, '0+', '2018-03-15', 'Music/Fantasy'),
(1063202, 'Crimson Peak. Wzgórze krwi', 'https://image.tmdb.org/t/p/original/x9muLnNZz8JotCOSyY29wBy3DUB.jpg', 'In the aftermath of a family tragedy, an aspiring author is torn between love for her childhood friend and the temptation of a mysterious outsider. Trying to escape the ghosts of her past, she is swept away to a house that breathes, bleeds… and remembers.', 119, '16', '2015-10-13', 'Horror/Mystery/Romance'),
(1063203, 'Rest Area', 'https://image.tmdb.org/t/p/original/zSYFVNZ2QqzqEBgLD2btALCkMGu.jpg', 'Five crazy rich people are stranded at a remote rest area during their nighttime journey. What was supposed to be a stopover turns into a nightmare when they are attacked by the Kresek Ghost, a wandering spirit with a face covered in black plastic, seeking revenge for past sins. One by one, they begin to lose control, terrorized relentlessly in every dark corner. The dark secrets they have been hiding are slowly revealed. What fatal mistake have they committed? And… can they survive the revenge that comes from beneath the ground?', 79, '0+', '2025-10-02', 'Horror/Thriller'),
(1063204, 'Krwawa Profesja', 'https://image.tmdb.org/t/p/original/y24hmSGT2mf2gInEemKX8F1Voi1.jpg', 'Still recovering from a heart transplant, a retired FBI profiler returns to service when his own blood analysis offers clues to the identity of a serial killer.', 110, '0+', '2002-08-09', 'Thriller/Crime/Action/Mystery'),
(1063205, 'Sezon na Zabijanie', 'https://image.tmdb.org/t/p/original/zTodeBysPUQdwsSNrZAgfWycB5A.jpg', 'Two veterans of the Bosnian War, one American, one Serbian, clash in the remote Smoky Mountain wilderness.', 91, '0+', '2013-07-12', 'Action/Thriller'),
(1063206, 'Mother Mountain', 'https://image.tmdb.org/t/p/original/gGMArd48cG3vbku9LRLQ8y8hMzZ.jpg', 'A young, restless Jewish mother and her family move to an idyllic country property at the base of a mystical and sacred Aboriginal mountain (Gulaga, or “Mother Mountain”), with the hope of starting a new life. Still haunted by a marriage break-up and a strained relation with her parents, she struggles to find a meaningful connection with her new partner. When her daughter is bullied at the local school, an enigmatic Indigenous boy Ren comes to her aid and opens her eyes to the magic of the mountain and its bucolic surrounds. But an unexpected visit from her parents reopens old wounds, with unexpected consequences.', 105, '0+', '2022-04-28', 'Drama'),
(1063207, 'Bohaterowie legendy Kondora: Szlachetni mężowie', 'https://image.tmdb.org/t/p/original/xZmUHiZlzuU3FuD9EE5wdZpNc95.jpg', 'Under Genghis Khan, the Mongolian army pushes west to destroy the Jin Dynasty, setting its sights on the Song Dynasty next. Amid internal conflicts among martial arts schools, Guo Jing unites the Central Plains\' warriors to defend Xiangyang, embodying courage and loyalty in the fight for the nation.', 147, '0+', '2025-01-29', 'Action/Drama/History'),
(1063208, 'Bu Feng Zhui Ying', 'https://image.tmdb.org/t/p/original/o25Tk1FYQi2BLk0OEAvx2h69QvB.jpg', 'Macau Police brings the tracking expert police officer out of retirement to help catch a dangerous group of professional thieves.', 142, '0+', '2025-08-16', 'Action/Crime/Thriller'),
(1063209, 'Generation', 'https://image.tmdb.org/t/p/original/nZWhaC43RILv8k7X4diw13HUWmV.jpg', 'Futuristic prospective series pilot, a distant cousin the 1975 theatrical violent sport movie \"Rollerball,\" revolves around a turn-of-the-millennium family on the Great Eve (the night before the year 2000 begins) planning for a reunion. Son Richard Beymer is an inventor working with prosthetic devices to help young athlete brother Drake Hogestyn perfect his game of combat hockey to maintain his skills as a national hero, and Cristina Raines is a socially conscious doctor who wants nothing to do with their prideful father, Bert Remsen, to the distress of their loving mother, Priscilla Pointer.', 96, '0+', '1985-05-24', 'Crime/Drama/Science Fiction/Thriller/TV Movie'),
(1063210, 'Stridulum', 'https://image.tmdb.org/t/p/original/nO6pEHO2bewFPgDxxdRI2taKLir.jpg', 'An ancient intergalactic warrior arrives on Earth to put a stop to a demonic child\'s plot to reproduce Satan\'s next generation of evil.', 109, '0+', '1979-03-22', 'Horror/Science Fiction'),
(1063211, 'Flight 7500', 'https://image.tmdb.org/t/p/original/8lz7vt9Rcdb7xvR2A8P2GlFit2O.jpg', 'Flight 7500 departs Los Angeles International Airport bound for Tokyo. As the overnight flight makes its way over the Pacific Ocean during its ten-hour course, the passengers encounter what appears to be a supernatural force in the cabin.', 79, '0+', '2014-05-16', 'Thriller/Horror/Mystery'),
(1063212, 'Christmas Crash', 'https://image.tmdb.org/t/p/original/cN1CeIyQ3xGBTgYLD8UZlMJqN43.jpg', 'A husband, wife and their two daughters take a Christmas break at a lodge in the woods. There\'s evident tension between the couple. He\'s pulled by attention to his corporation and negotiations about a merger. Even on their vacation he\'s on the phone. She\'s feeling abandoned. He takes her on a light plane flight to a cabin across the lake, but their plane suddenly loses altitude. They crash into the lake before they can notify anyone. The husband is more seriously hurt but with his wife\'s assistance they navigate cross-country towards a distant highway.. While they struggle to cross a ridge, the husband\'s business partner moves behind the scenes to sell the company to raiders, apparently assuming Frank is dead. Attacked by rogue wolves, the husband and wife are rescued in the nick of time. The FAA begins an investigation of the plane crash while the family begins to heal the emotional and physical wounds.', 96, '0+', '2009-01-01', 'Drama'),
(1063213, 'Wybrańcy', 'https://image.tmdb.org/t/p/original/wtw4jMMKz5CfB4H408XGAa87XHp.jpg', 'In a 1940s New York, two Jewish teenage boys are determined to remain friends despite the deep differences between their two families.', 105, '0+', '1981-08-20', 'Drama'),
(1063214, 'Zabójczy koktajl', 'https://image.tmdb.org/t/p/original/rDD5Fn0BtGxSL0hlNpE1KRCanB4.jpg', 'To protect an 8-year-old girl, a dangerous assassin reunites with her mother and her lethal associates to take down a ruthless crime syndicate and its army of henchmen.', 114, '16', '2021-07-14', 'Action/Crime/Thriller'),
(1063215, 'Glória', 'https://image.tmdb.org/t/p/original/3DbCa4IqgS0oDvgld7I5R19eKCM.jpg', 'Gloria is set against the backdrop of a rural landscape slowly disappearing in modern Portugal. The small border town of Vila de Santiago, once a booming trade center for illegal trafficking, is about to become a ghost town, as a new motorway is to bypass the city and the railway station is being closed. Its stationmaster, Vincente, is preparing to retire. Many young people have moved out, leaving the children to be brought up by the elderly, including thirteen-year-old Glória and her friend Ivan. Glória\'s life suddenly changes with the arrival of Vincente\'s younger brother, Mauro, who has just come out of prison and has some old issues to settle. Mauro begins to charge around the station on his motorbike, while Glória\'s friendship with Ivan is put to test on account of her attraction to older Mauro.', 102, '0+', '1999-11-03', 'Drama'),
(1063216, 'Abduction', 'https://image.tmdb.org/t/p/original/6wr5AWNoyXM08Q3NoQXJ3JWCuYP.jpg', 'A horror comedy spoofing conspiracy theory moves, girl victim films, and Alien Grey abduction movies.  Melissa rescues a young woman from a mental hospital where no-one believes she is a victim of abduction by aliens. She and a colleague try to prevent the aliens from taking her but a government agent seems to be hot on her trail, and the Alien Greys and their powerful leader, The Hive Queen have no intention of being stopped. An outrageous mix of graphic horror and dark twisted humor.', 90, '0+', '2017-06-28', 'Fantasy/Drama'),
(1063217, 'Ekstaza', 'https://image.tmdb.org/t/p/original/mZjkgA9eh1SXJRHC7sx9uTQTdUB.jpg', 'Eva has just gotten married to an older gentleman, but discovers that he is obsessed with order in his life and doesn\'t have much room for passion. She becomes despondent and leaves him, returning to her father\'s house. One day while bathing in the lake, she meets a young man and they fall in love. The husband has become grief stricken at the loss of his young bride, and fate brings him together with the young lover that has taken Eva from him.', 89, '0+', '1933-01-20', 'Drama/Romance'),
(1063218, 'Theatre Royal', 'https://image.tmdb.org/t/p/original/fCMNoPNbKPu4LRm8nAwiW9YzBzX.jpg', 'The Theatre Royal is a struggling London venue battling to keep its doors open. When the bank threatens to close it, the workers fear that they will soon be forced out of their jobs. The Royal\'s property master, Bob Parker (Bud Flanagan), recruits the rest of the staff to stage a benefit gala. They hope their show, featuring songs and dances, can raise enough cash to stave off the end. Meanwhile, they seek investors who can keep the Theatre Royal and its staff in business permanently.', 101, '0+', '1943-07-26', 'Comedy'),
(1063219, 'Utopians', 'https://image.tmdb.org/t/p/original/uw0EC3viEhFg8WC2xEDeHGCxO42.jpg', 'Told through memory and metaphor, Utopians is a dark and subtly comic character study of three people on the edge: of society, of control, and of collapse. Roger is a yoga teacher. His daughter Zoe returns home from the military and to Rogers dismay resumes her relationship with her allegedly schizophrenic girlfriend Maya. Opposed to Zoe\'s pursuit of Maya but eager to be a part of his daughters life, Roger becomes entangled in the ups and downs of their relationship. Increasingly late and obviously distracted during his yoga classes, his few remaining students begin to lose patience. When Rogers well-meaning friend Morris offers them a live-in renovation job in an upscale Brooklyn home, the three of them move in and start a job they are not exactly qualified for. Living rent-free provides them with a respite from the responsibilities and expectations of the outside world. Together they try to find comfort in their new reality while being revisited by their troubled pasts.', 84, '0+', '2011-02-11', NULL),
(1063220, 'Dziki robot', 'https://image.tmdb.org/t/p/original/FTd11HGc8FfkBChRCrFAxtjJJm.jpg', 'After a shipwreck, an intelligent robot called Roz is stranded on an uninhabited island. To survive the harsh environment, Roz bonds with the island\'s animals and cares for an orphaned baby goose.', 102, '7', '2024-09-12', 'Animation/Science Fiction/Family/Drama'),
(1063221, 'The Wolves', 'https://image.tmdb.org/t/p/original/fzZ8JbGHfx13kkioYPc1oXqqJ3F.jpg', 'Left quad. Right quad. Lunge. A girls indoor soccer team warms up. From the safety of their suburban stretch circle, the team navigates big questions and wages tiny battles with all the vim and vigor of a pack of adolescent warriors. The Wolves is a portrait of life, liberty, and the pursuit of happiness for nine American girls who just want to score some goals.', 90, '0+', '2021-07-22', 'Drama/TV Movie'),
(1063222, 'Madras Cafe', 'https://image.tmdb.org/t/p/original/4xF2CXNDhiPtnVDPLbGENS9lIrt.jpg', 'An Indian intelligence agent journeys to a war-torn coastal island to break a resolute rebel group and meets a passionate journalist.', 130, '0+', '2013-08-23', 'Thriller/Drama/Action'),
(1063223, 'Gen', 'https://image.tmdb.org/t/p/original/aqSTTHj98cIdAfJWsXkOkke0Xu8.jpg', 'A suicide case is informed to the police from a mental hospital in a rocky district. Two policemen comes to hospital to investigate the case. In the same morning, Dr. Deniz comes to hospital as the new psychiatrist. Because of the heavy rain and landslide the only road and telephone connections that provide access to hospital from the city are damaged.There is no transportation to hospital and none can leave hospital. During three days, three patients are killed wildly in the hospital. Everyone becomes anxious. The police deepen the investigation. A mystical patient attracts attention.', 105, '0+', '2006-04-07', 'Thriller'),
(1063224, 'Running Out', 'https://image.tmdb.org/t/p/original/wYQK2u7X2equ5VIYkHbbKZyUetX.jpg', 'A young woman, unable to handle the stress of raising a family, runs out on her husband and young daughter. 12 years later, she returns in hopes of rekindling a bond with them.', 100, '0+', '1983-01-26', 'Drama/TV Movie'),
(1063225, 'Megalodon Rising', 'https://image.tmdb.org/t/p/original/vWeWU43mNVzpAnjgzxnvi9xgo9d.jpg', 'When history’s greatest aquatic predator returns, the armada of modern warships sent to destroy it has no chance at all.', 86, '0+', '2021-08-27', 'Action/Science Fiction'),
(1063226, 'Niezniszczalni', 'https://image.tmdb.org/t/p/original/A7sKWXg62vxILBQ1PBHrepCg6Na.jpg', 'Barney Ross leads a band of highly skilled mercenaries including knife enthusiast Lee Christmas, a martial arts expert Yin Yang, heavy weapons specialist Hale Caesar, demolitionist Toll Road, and a loose-cannon sniper Gunner Jensen. When the group is commissioned by the mysterious Mr. Church to assassinate the dictator of a small South American island, Barney and Lee visit the remote locale to scout out their opposition and discover the true nature of the conflict engulfing the city.', 103, '16', '2010-08-07', 'Thriller/Adventure/Action'),
(1063227, 'Murewa', 'https://image.tmdb.org/t/p/original/visGIEONtvyWJZoR9qJe0j45ffV.jpg', 'In the quiet seaside town of Worthing, Marlon and Murry (Murewa) form a deep friendship, bonding over skateboarding, photography and the carefree adventures of youth. But as they grow older, their lives take different turns. Marlon leaves for university in London, while Murry, facing mounting pressure at home, makes choices that lead to prison. Through years of home video, Murewa reflects on the complexities of growing up, and how opportunity and circumstance shape the futures of young people in ways they don’t fully grasp at the time. Intimate and deeply personal, the film explores boyhood, belonging and the lingering question of what might have been.', 14, '0+', '2025-03-09', 'Documentary'),
(1063228, 'Władca Pierścieni: Powrót króla', 'https://image.tmdb.org/t/p/original/75KNIheWdy7eLe4RWsbJmVjvJPU.jpg', 'As armies mass for a final battle that will decide the fate of the world--and powerful, ancient forces of Light and Dark compete to determine the outcome--one member of the Fellowship of the Ring is revealed as the noble heir to the throne of the Kings of Men. Yet, the sole hope for triumph over evil lies with a brave hobbit, Frodo, who, accompanied by his loyal friend Sam and the hideous, wretched Gollum, ventures deep into the very dark heart of Mordor on his seemingly impossible quest to destroy the Ring of Power.​', 201, '16', '2003-12-17', 'Adventure/Fantasy/Action'),
(1063229, 'Olvídame', 'https://image.tmdb.org/t/p/original/sKluEL7DnWsMIpxsrQSi6GcfrwF.jpg', 'Víctor Terx is a young, attractive, and mysterious man, preacher and leader of a spiritualist sect. He compulsively murders his occasional partners with cruelty. Ámbar Atlas is a young stripper at a brothelly nightclub, her beauty is unconventional and her sexuality exultant and perturbing. Christlike, she uses sex as a vehicule to her own destruction due to her inevitable death drive. Ámbar and Víctor will fall in love viscerally and passionately while they become aware of the proximity of an ineluctable danger that preys on them both. Together they will tortuously travel an esoteric underworld of mediums, witches and false shamans in the search for Ámbar\'s miraculous \"cure\".', 110, '0+', '2013-10-31', 'Thriller'),
(1063230, 'Po Katastrofie', 'https://image.tmdb.org/t/p/original/25oWTCGqIik4gUTMidx3L8DI4Bt.jpg', 'A fatal plane crash changes the lives of Roman and Jake forever. Roman loses his wife and daughter in the accident, while Jake loses his mind—as he happens to be the air traffic controller who failed to avert the nightmare. Rage and revenge engulfs Roman and Jake finds himself swamped with guilt and regret.', 92, '0+', '2017-02-28', 'Drama/Thriller'),
(1063231, 'The Lost', 'https://image.tmdb.org/t/p/original/7umv0xy6252iBzQz4OgbII8xnQw.jpg', 'A charismatic psycho suspected of killing two innocent campers in a cold-blooded double homicide grows increasingly unstable as his suburban empire starts to crack at the foundations.', 119, '0+', '2006-03-11', 'Crime/Drama/Thriller'),
(1063232, 'Cisza', 'https://image.tmdb.org/t/p/original/lTVOquzxw2DPF3MKuYd1ynz9F6H.jpg', 'With the world under attack by deadly creatures who hunt by sound, a teen and her family seek refuge outside the city and encounter a mysterious cult.', 90, '16', '2019-05-16', 'Horror/Drama/Thriller/Fantasy'),
(1063233, '周处除三嗨', 'https://image.tmdb.org/t/p/original/kiEEwMmWCngrjNmGfQ6CFt69Hn0.jpg', '', 0, '0+', '2024-04-11', NULL),
(1063234, 'Bitwa o Ziemię', 'https://image.tmdb.org/t/p/original/o2d6vVpNDeTYRCVhf0YgdsBZKW9.jpg', 'In the year 3000, man is no match for the Psychlos, a greedy, manipulative race of aliens on a quest for ultimate profit. Led by the powerful Terl, the Psychlos are stripping Earth clean of its natural resources, using the broken remnants of humanity as slaves. What is left of the human race has descended into a near primitive state. After being captured, it is up to Tyler to save mankind.', 119, '0+', '2000-05-12', 'Science Fiction/Action/Adventure'),
(1063235, 'La Bohème', 'https://image.tmdb.org/t/p/original/x552eYl5Hj1Rs2c8TnAiZScIUng.jpg', 'In the 50\'s, in Paris, the neighbors Rodolfo and Mimi meet each other when Mimi\'s candle blows out in a cold and dark night. They immediately fall in love for each other, in times of financial difficulties in the post-war. Rodolfo introduces Mimi to his close friends Marcello and his beloved Musetta; Colline; and Schaunard and together they have a good-time in Café Momus. Some time later, Mimi tells Marcello that she can not support the jealousy of Rodolfo any longer and when Marcello discuss with Rodolfo, Mimi overhears the real reason for the behavior of her beloved Rodolfo.', 112, '0+', '1994-06-08', 'Romance/Music/Drama/TV Movie'),
(1063236, 'Sin City - Miasto grzechu', 'https://image.tmdb.org/t/p/original/lmUFPB8B6oT7KKVgDPFmhVaQRm9.jpg', 'Welcome to Sin City. This town beckons to the tough, the corrupt, the brokenhearted. Some call it dark… Hard-boiled. Then there are those who call it home — Crooked cops, sexy dames, desperate vigilantes. Some are seeking revenge, others lust after redemption, and then there are those hoping for a little of both. A universe of unlikely and reluctant heroes still trying to do the right thing in a city that refuses to care.', 124, '18', '2005-04-01', 'Crime/Thriller'),
(1063237, 'Mass Appeal', 'https://image.tmdb.org/t/p/original/kyZ5dQzPmh47jaBUJI5s6p8vJwv.jpg', 'A young seminarian rattles the established order at a Catholic parish run by an older pastor.', 99, '0+', '1984-12-14', 'Comedy/Drama'),
(1063238, 'Carnival Nights', 'https://image.tmdb.org/t/p/original/vqpHzMqL6An9Fn2uYg0C01ExgnL.jpg', 'Jack Benny presents a variety hour with a carnival theme that stars Lucille Ball, Johnny Carson, Ben Blue, and Paul Revere and The Raiders. Cameos by The Smothers Brothers (as Joe-Joe, the two-headed boy), George Burns (as Martine, the Bearded Lady), and Dean Martin (as Rip Van Rinkle, the sleeping man). Songs include Lucille Ball singing \"It\'s So Nice To Have a Man Around the House\" and \"Cleo\" (to the tune of \"Mame\"), \"Too Much Talk\" and \"Him or Me\" sung by Paul Revere and The Raiders.', 60, '0+', '1968-03-20', 'Comedy/Music'),
(1063239, 'Marked Cards', 'https://image.tmdb.org/t/p/original', 'Ellen Shannon, the daughter of self-made Irish politician Pat Shannon, is engaged to Ted Breslin, but because Pat began his career as a menial laborer, Ted\'s mother, Mrs. J. De Barth Breslin, refuses to sanction the marriage. Heartbroken, Ted takes up drinking and gambling with \"Poker\" LeMoyne and Don Jackson, while Ellen attends a finishing school hoping to improve herself. While trying to elude her chaperone, Ellen unwittingly dashes into a man\'s hotel room, and from the window, she witnesses Don and \"Poker\" playing cards, while Ted lies unconscious from too much drink. When the two gamblers quarrel, Don kills \"Poker,\" but Ted is accused of the crime.', 50, '0+', '1918-07-14', 'Drama'),
(1063240, 'Rosso sangue', 'https://image.tmdb.org/t/p/original/flV61iFguBws7oJfuROczStdSE5.jpg', 'A priest-doctor chasing a man with supernatural regenerative abilities, who has recently escaped from a medical lab, reaches a small town where the mutant goes on a killing spree.', 94, '0+', '1981-10-01', 'Horror'),
(1063241, 'Mary Lou', 'https://image.tmdb.org/t/p/original/lQ0j5jpyZLFCsiUkdWDLOnSh9WZ.jpg', 'Airline hostess Ann Parker is fired for being undignified when she sang to calm the passengers during a storm. Mike Connors, publicity man for Frankie Carle\'s orchestra, invites her to try out as the band\'s vocalist since the regular singer, Mary Lou, had just quit the band on the eve of an engagement at a swanky New York night club. Encouraged by her boyfriend, Steve Roberts, Ann lands the job and assumes the name of \"Mary Lou\", a trademark almost for Frankie Carle singers. But the departed Mary Lou shows up and threatens to sue if she is not rehired. Ann returns to her former job. Meanwhile, Steve locates the woman who was the original Mary Lou with the band, and urges Mike to keep the current Mary Lou off the bandstand until he can return with Ann.', 65, '0+', '1948-01-23', 'Music'),
(1063242, 'Monster', 'https://image.tmdb.org/t/p/original/wlbfha5H94ohwaiq7zbn4sAls5m.jpg', 'An emotionally scarred highway drifter shoots a sadistic trick who rapes her, and ultimately becomes America\'s first female serial killer.', 110, '-', '2003-12-24', 'Crime/Drama'),
(1063243, 'Annabelle', 'https://image.tmdb.org/t/p/original/1uJhc3DIWP3GFlrDbKYfWi1hKQ3.jpg', 'A couple begins to experience terrifying supernatural occurrences involving a vintage doll shortly after their home is invaded by satanic cultists.', 99, '18', '2014-10-01', 'Horror'),
(1063244, 'The Runaway', 'https://image.tmdb.org/t/p/original/azTRoB7QKdNojw6yhazIwFE779X.jpg', 'The adventures of a young boy who runs away from an orphanage on a search to find his father.', 62, '0+', '1961-01-01', 'Drama'),
(1063245, 'Traps', 'https://image.tmdb.org/t/p/original/ApanSNxT55tWdLS7eYi7HEKppSa.jpg', 'Working for the first time with sound, I made TRAPS, a film scripted in jail on hearing of an acquaintance’s suicide, and LEAH. Both are “portraits” of alienated young women. TRAPS is harsh in both form and content, with long takes speaking to the camera juxtaposed against long silent sequences as, in an argument by accretion, the grounds for alienation are piled up. Ostensibly a “documentary self-portrait” made by the woman of the film, TRAPS’ seemingly uncohesive segments crystallize only at the last moment when the neutral narrator (and alleged “editor” ) informs the viewer that the woman committed suicide.', 22, '0+', '1967-09-01', NULL),
(1063246, 'Zabójca', 'https://image.tmdb.org/t/p/original/6mKqWM7KETGPqdlpWfuu96Ekyqs.jpg', 'After a fateful miss, an assassin battles his employers, and himself, on an international manhunt he insists isn\'t personal.', 118, '16', '2023-10-25', 'Crime/Thriller'),
(1063247, 'Zakręcony piątek 2', 'https://image.tmdb.org/t/p/original/dRTHA5ZFwrVAGKwpRmIOE4tyCVp.jpg', 'Years after Tess and Anna endured an identity crisis, Anna now has a daughter of her own and a soon-to-be stepdaughter. As they navigate the myriad challenges that come when two families merge, Tess and Anna discover lightning might indeed strike twice.', 111, '0+', '2025-08-06', 'Comedy/Fantasy/Family'),
(1063248, 'Die Nylonschlinge', 'https://image.tmdb.org/t/p/original/y7fcdbonbVp19Jdd9Cummr6z0KR.jpg', 'A company\'s stockholders hold their meeting at a lonely mansion. A mad doctor conducting experiments in the mansion starts to strangle them one at a time with a nylon noose. The survivors must figure out a way to stop him.', 81, '0+', '1963-07-30', 'Crime'),
(1063249, 'Pojedynek', 'https://image.tmdb.org/t/p/original/s9sPhcfD4LtrIGwix11bKtl9VLR.jpg', 'In 1800, as Napoleon Bonaparte rises to power in France, a rivalry erupts between Armand and Gabriel, two lieutenants in the French Army, over a perceived insult. For over a decade, they engage in a series of duels amidst larger conflicts, including the failed French invasion of Russia in 1812, and shifts in the political and social systems of Europe.', 100, '12', '1977-08-31', 'Drama/War'),
(1063250, 'I że ci nie odpuszczę', 'https://image.tmdb.org/t/p/original/wFhak2L1nJizhhvJeBdzubZA95J.jpg', 'A spoiled, wealthy yacht owner is thrown overboard and becomes the target of revenge from his mistreated employee.', 112, '16', '2018-04-13', 'Romance/Comedy'),
(1063251, 'Jurassic World', 'https://image.tmdb.org/t/p/original/rhr4y79GpxQF9IsfJItRXVaoGs4.jpg', 'Twenty-two years after the events of Jurassic Park, Isla Nublar now features a fully functioning dinosaur theme park, Jurassic World, as originally envisioned by John Hammond.', 124, '16', '2015-06-06', 'Action/Adventure/Science Fiction/Thriller'),
(1063252, 'Maakohus', 'https://image.tmdb.org/t/p/original/2NizFQqZd7lG4Qh2WB9TAEeSkXe.jpg', 'An absurdist court drama where a mother and a father, ex-spouses, fight over the custody of their 5-year old son. However, the whole process takes place in the middle of a grain field instead of the classic court room. On that field the courtroom has no boundaries much like the mother and father whose actual goal is to exact vengeance on each other with no regard to the means used, forgetting their child entirely.', 14, '0+', '2021-11-12', 'Drama'),
(1063253, 'Hit Man', 'https://image.tmdb.org/t/p/original/ubDQYlzYEvqRH9Ae2kVt2GeJYFV.jpg', 'A mild-mannered professor moonlighting as a fake hit man in police stings ignites a chain reaction of trouble when he falls for a potential client.', 116, '0+', '2024-05-16', 'Comedy/Romance/Crime'),
(1063254, 'Świat triasu', 'https://image.tmdb.org/t/p/original/u7IgMjhZnegiAcyibs0NEKp12CW.jpg', 'In the future, scientists found a way to grow human organs inside dinosaurs to harvest them for profit. But when the dinosaurs break out, the scientists that created them have to find ways undo the terrible mistakes they have done.', 90, '0+', '2018-06-19', 'Action/Horror/Science Fiction'),
(1063255, 'Une conquête', 'https://image.tmdb.org/t/p/original/kwAPsIwx7iyva6TvyWA2Jfwg5Qv.jpg', 'George, passing a pretty woman in the street, has recourse to that old-time trick of dropping his own handkerchief and hurrying after her, making believe that he thinks it is hers. On examining the handkerchief, the beauty returns it, telling George that it does not belong to her. He then confesses that he knows very well that it is not her property, as it happens to be his own, and his offering it to her was only an excuse to make her acquaintance, so struck was he by her beauty. Upon this frank declaration the young woman draws herself up haughtily, but George is not to be discouraged, but follows closely behind her, ready to be of any assistance on the slightest pretext. We therefore see him arriving at the lady\'s house laden down with such articles as a lampshade, a statuette, a bunch of roses, a bundle of dress goods, and, in addition, leading an enormous dog on a leash, against whose attacks he is endeavoring to protect himself.', 4, '0+', '1909-10-22', NULL),
(1063256, 'The Aerodrome', 'https://image.tmdb.org/t/p/original/jDm8fWvgkqU4HZHyY0LXqdQylsR.jpg', 'In the future England is ruled by a fascist government, and one day the leaders begin the construction of a heavily guarded, mysterious airport. BBC adaptation of  Rex Warner\'s 1941 novel of the same name. A stereotypical village in a somewhat alternative England is taken over wholesale by \'The Air Force.\' Living in the village is young Roy, who has just learned he is not who he thought he was. Attempting to forge a new sense of identity, he joins the dashing Air Force, seduced by its dynamism and direct and brutal ways.', 91, '0+', '1983-12-13', 'Drama/Science Fiction/TV Movie'),
(1063257, 'Plan wycieczki', 'https://image.tmdb.org/t/p/original/5XfKg0ddStt7tpjVZpKCG9Ve933.jpg', 'Dan Morgan is many things: a devoted husband, a loving father, a celebrated car salesman. He\'s also a former assassin. And when his past catches up to his present, he\'s forced to take his unsuspecting family on a road trip unlike any other.', 118, '12', '2023-12-14', 'Action/Comedy/Family'),
(1063258, 'Flying Colors', 'https://image.tmdb.org/t/p/original/vJNzxWZaJwlDeyGCeafNQvm1CLN.jpg', 'Brent Brewster, formerly a Yale athlete known for his pole vaulting prowess, is unsuccessful in business. When his wealthy relatives send him out to fend for himself, Brent joins a detective agency. After Craig Lansing, a family friend, hires Brent to investigate the numerous jewel thefts in Poughkeepsie, Brent works undercover at Lansing\'s house party and recognizes Captain Drake, an English crook. Although Brent temporarily forgets detective work when he meets Ann, the beautiful sister of Lansing\'s wife Ruth, Ann\'s remark that $40,000 a year would be enough for her to live on brings Brent back to the job.', 50, '0+', '1917-09-23', 'Drama'),
(1063259, 'Jujutsu Kaisen 0: The Movie', 'https://image.tmdb.org/t/p/original/9WrgbeYF9CFUfHems0RvkG1vRTY.jpg', 'Yuta Okkotsu is a nervous high school student who is suffering from a serious problem—his childhood friend Rika has turned into a curse and won\'t leave him alone. Since Rika is no ordinary curse, his plight is noticed by Satoru Gojo, a teacher at Jujutsu High, a school where fledgling exorcists learn how to combat curses. Gojo convinces Yuta to enroll, but can he learn enough in time to confront the curse that haunts him?', 105, '0+', '2021-12-24', 'Animation/Action/Fantasy'),
(1063260, 'Dorwać Gunthera', 'https://image.tmdb.org/t/p/original/emGIqWk6v9q4t9o5k8wDw3jDJHk.jpg', 'A group of eccentric assassins are fed up with Gunther, the world\'s greatest hitman, and decide to kill him – but their plan turns into a series of bungled encounters as Gunther seems to always be one step ahead.', 93, '0+', '2017-09-22', 'Action/Comedy'),
(1063261, 'Silver Range', 'https://image.tmdb.org/t/p/original/yXqXNcZjlHe7BMoAp9JVGih8C7j.jpg', 'Veteran cowboy star Johnny Mack Brown plays a cattle buyer turned prairie sleuth in this low-budget oater from Monogram, which co-stars perennial old-timer Raymond Hatton as a retired U.S. Marshal assigned to investigate the mysterious disappearance of a rancher. As the two old friends soon learn, a gang of smugglers headed by the town\'s banker (Frank LaRue) needs the use of the Flying Arrow Ranch for their nefarious purposes.', 53, '0+', '1946-11-16', 'Western/Action'),
(1063262, 'In Embryo', 'https://image.tmdb.org/t/p/original/8IA7M8yNgyjcX1QEvYr8dKMfqzp.jpg', 'Sean lives a harsh but successful life as a criminal in Los Angeles\'s rough suburbs. He has, in spite of a chaotic and violent childhood, created some order in his life. As long as order is maintained, he - along with his partner in crime Peter - can ensure that his criminal life does not fall apart. But like in any Greek tragedy, things are doomed to go wrong when he one day falls in love with the waitress Lilly. Sean thinks he can bring order to her life too, but the all-consuming heroin addiction can not be tamed so easily.', 105, '0+', '2016-06-16', 'Drama/Romance'),
(1063263, 'Więzy krwi', 'https://image.tmdb.org/t/p/original/gvP6R6juhe2IpCG7QGDgjyUvm0g.jpg', 'Based on the true life experiences of poet Jimmy Santiago Baca, the film focuses on half-brothers Paco and Cruz, and their bi-racial cousin Miklo. It opens in 1972, as the three are members of an East L.A. gang known as the \"Vatos Locos\", and the story focuses on how a violent crime and the influence of narcotics alter their lives. Miklo is incarcerated and sent to San Quentin, where he makes a \"home\" for himself. Cruz becomes an exceptional artist, but a heroin addiction overcomes him with tragic results. Paco becomes a cop and an enemy to his \"carnal\", Miklo.', 180, '0+', '1993-02-05', 'Crime/Action/Drama/Thriller'),
(1063264, 'Rollover', 'https://image.tmdb.org/t/p/original/fJEBWDpN4O5Nb2kueroLSzx3BI0.jpg', 'An Arab oil organization devises a plan to wreck the world economy in order to cause anarchy and chaos.', 116, '0+', '1981-10-11', 'Drama/Mystery/Romance/Thriller'),
(1063265, 'Caramelo', 'https://image.tmdb.org/t/p/original/c4ZEAah5a01cu27w7vT2IAoFogk.jpg', 'After a life-changing diagnosis, a promising chef finds hope and humor with the help of a fur-midable dog friend.', 101, '0+', '2025-10-07', 'Comedy/Drama'),
(1063266, 'Madame DuBarry', 'https://image.tmdb.org/t/p/original/pO2Ls6xcqW3CoyJI5MGHU8suv9F.jpg', 'The story of Madame du Barry, the mistress of Louis XV of France, and her loves in the time of the French revolution.', 114, '0+', '1919-09-18', 'Drama/History'),
(1063267, 'Power Dive', 'https://image.tmdb.org/t/p/original/9pgc8pEiHij3ZiaK7pyBf47eFLc.jpg', 'The story concentrated on a group of test pilots, busily experimenting with a revolutionary all-plastic airplane. Ace flyboy Brad Farrell (Richard Arlen) is determined to prove the practicality of the new aircraft, designed by Professor Blake (Thomas Ross), father of Brad\'s sweetheart Carol (Jean Parker). Back on solid ground, Brad must vie for Carol\'s attentions with his own brother, engineer Doug Farrell (Don Castle).', 68, '0+', '1941-06-04', 'Action/Drama'),
(1063268, 'Areola 51', 'https://image.tmdb.org/t/p/original/ArXHRijfHgZPpWgW4Yu12R3BKn4.jpg', 'A beautiful grad student named Tara Simmons is abducted by aliens in a flying saucer. Four days later she finds herself back on earth at the top secret government facility Areola 51, which documents sexual encounters with aliens. She remembers everything and recounts the story of her pleasant abduction in sensuous detail to an eager but reserved government agent. Tara describes being bound and bathed by the humanoid aliens, and later being probed by their hands and instruments. She also tells of having various types of sex with the aliens and of having to train them in the ways of sensual pleasure since the alien race had lost their sexuality. As Tara continues, the agent loses interest in taking notes, and becomes aroused and eager to hear more. She also reports that the aliens made her own sexual fantasies seem real as a way to study sex and to reward her. Finally, Tara seduces the agent, but may have an ulterior motive.', 74, '0+', '2008-12-10', 'Science Fiction'),
(1063269, 'Bulletproof', 'https://image.tmdb.org/t/p/original/9CFBGwHbutAFiABPMVwlkp7o3Y5.jpg', 'Young Benny Jackson is in danger of losing the beloved family business, Bulletproof Jackson\'s Saloon to an avaricious developer. In his quest, Benny stumbles across a journal that belonged to his great great grandfather, the famous gunslinger Bulletproof Jackson. Benny opens the journal and we are brought back to the wild west where we learn the true legend of Bulletproof and perhaps the secret that will save the Saloon. But for Benny, the journal holds many more questions than answers...', 35, '0+', '2013-02-13', 'Comedy/Western/Drama'),
(1063270, 'Noc Oczyszczenia', 'https://image.tmdb.org/t/p/original/4BOiXhQN52QzAzFVDzS79QpKqSM.jpg', 'Given the country\'s overcrowded prisons, the U.S. government begins to allow 12-hour periods of time in which all illegal activity is legal. During one of these free-for-alls, a family must protect themselves from a home invasion.', 85, '16', '2013-05-31', 'Science Fiction/Horror/Thriller'),
(1063271, 'Darling Mine', 'https://image.tmdb.org/t/p/original/gcvctjxuSXeHdvC5RfLGbCUjymT.jpg', 'Persuaded by a letter from her Aunt Agnes in America, Kitty McCarthy ( Olive Thomas ) travels from Ireland to New York City, there she meets Gordon Davis, a successful playwright, who directs her to her aunt\'s address on the East Side. Kitty soon discovers her aunt living in a tenement, a confirmed alcoholic. Through her niece\'s care, Agnes is cured, and one day Davis appears and offers Kitty a part in a comedy that he has written. She accepts, and once backstage meets Vera Maxwell, the victim of an unhappy affair with Oscar Savoy. Kitty brings the lovelorn couple back together but is unsuccessful in arranging her own romance with Davis\' nephew Roger until Davis finally intervenes, and a happy ending prevails for all.', 50, '0+', '1920-08-16', 'Drama'),
(1063272, 'De Sade', 'https://image.tmdb.org/t/p/original/thvrilDY8XBOmCpvovVBBsYcwZv.jpg', 'The 18th-century French marquis recalls his sadomasochistic experiments and goes to jail for lewd behavior.', 113, '0+', '1969-08-27', 'Drama/History/Thriller'),
(1063273, 'Skarbiec', 'https://image.tmdb.org/t/p/original/pWrgTpUVJdjDxpWKZLKMDJ5ilsf.jpg', 'A pair of cops investigating a drug invasion stumble upon a mysterious bank vault.', 93, '0+', '2016-04-29', 'Thriller/Drama/Crime/Action/Comedy/Mystery'),
(1063274, 'Zombie Nightmare', 'https://image.tmdb.org/t/p/original/4jC4ghLWYnnmh5auuY0Hj90288c.jpg', 'Tony Washington is killed in a hit-and-run after saving the local bodega clerk from robbers. Molly Mokembe is a Haitian voodou practitioner who brings him back as a zombi from a debt owed by Tony\'s late dad in an act of sacrifice that saved her. Jimbo, the kid that iced Tony, is embracing some new sadistic feelings. What follows is a revenge that can only be sated once all of those who were with Jimbo that night have had their due.', 89, '0+', '1987-10-13', 'Horror'),
(1063275, 'Uneasy Payments', 'https://image.tmdb.org/t/p/original', 'Bee Haven, a little country girl from Missouri, wins a Charleston contest and goes to New York to pursue a theatrical career, accompanied by Charlie Ross, a bucolic sheik. Her country attire merely amuses the stage managers, but Tom Gatesby, a backer, persuades Bozoni, a cabaret owner, to give her a job. She innocently accepts money from Bozoni to furnish a luxury apartment; and when disillusioned Bozoni cancels the payments for her furniture and new clothes, Bee tries to avoid the gown-collectors, but they retrieve her gown and fur coat. In desperation, she joins a revue chorus, doing a lingerie number that results in a fight with Valentia, the star of the show. Tom rescues Bee from her precarious position, and all ends happily.', 50, '0+', '1927-05-04', 'Comedy'),
(1063276, 'Rajat Jayanti', 'https://image.tmdb.org/t/p/original/vqNelf1X4SP9cStlcDDS3dCpRJY.jpg', 'The simple-minded Rajat (Barua) loves neighbour Jayanti (Menaka Devi). He is advised on how to court her by his streetsmart cousin Bishwanath (Sanyal) and Bishwanath\'s friend Samir (Bannerjee). Bishwanath and Samir try to get Rajat\'s miserly guardian Bagalcharan (Choudhury) to loan them money so that Samir can make a \'European-style art film\'. The guardian is admitted to the clinic of a doctor Gajanan where he falls into the clutches of two professional crooks Natoraj (Indu Mukherjee) and Supta (Molina Devi). Supta wants Rajat and they try to kidnap her...', 0, '0+', '1939-01-31', NULL),
(1063277, 'Brudny szmal', 'https://image.tmdb.org/t/p/original/zIhjkkkox2hyb8XClY9XSYKe6eQ.jpg', 'Bob Saginowski finds himself at the center of a robbery gone awry and entwined in an investigation that digs deep into the neighborhood\'s past where friends, families, and foes all work together to make a living - no matter the cost.', 106, '16', '2014-09-12', 'Drama/Crime'),
(1063278, 'Wow', 'https://image.tmdb.org/t/p/original/kXShuB1qDA8stuJkXVcNHRylBhL.jpg', 'In this French Canadian film, the lives of teenagers are examined in fantasy sequences and through the use of documentary interviews.  Prompted by the filmmaker, nine teenagers individually act out their secret dreams and, between times, talk about their world as they see it. The fantasy sequences make creative use of animation, unusual film-development techniques, and stills. Babette conceives of herself as an abbess defending her fortress, a convent; Michelle is transported in a dream of love where all time ceases; Philippe is the revolutionary, defeating all the institutions that plague him, and so on, through all their fantasies. All the actual preoccupations of youth are raised: authority, drugs, social conflict, sex. Jutra\'s style in \"Wow\" exhibits his innovative approach to storytelling and filmmaking, showcasing his talents as a director during that period. With English subtitles.', 94, '0+', '1970-03-25', 'Documentary'),
(1063279, 'Shera', 'https://image.tmdb.org/t/p/original/qI6TKB6u8g0ZbncKGIaRtxAQzUH.jpg', 'Jai is a peaceful man and doesn\'t partake in violence. However, when the drug mafia kills his sister, he is left with no choice but to defend himself and his family.', 0, '0+', '1999-01-01', NULL),
(1063280, 'Up Periscope', 'https://image.tmdb.org/t/p/original/1t0Zo7y4L7PSJV1T5K5JM8HFQqw.jpg', 'Lieutenant Braden discovers that Sally, the woman he\'s been falling in love with, has actually been checking out his qualifications to be a U.S. Navy frogman. He must put his personal life behind him after being assigned to be smuggled into a Japanese-held island via submarine to photograph radio codes.', 112, '0+', '1959-03-04', 'War/Adventure/Action'),
(1063281, 'The Shadow', 'https://image.tmdb.org/t/p/original', 'Driven to desperation by the enmity of Jane, her step-daughter, Sarah, Dean\'s second wife, turns to Ware, a friend of the family and a former suitor, for advice. Jane learns that her stepmother has gone to call upon Ware. Realizing the unhappiness her conduct has caused, the girl is stricken with remorse. Knowing that her father would misconstrue Sarah\'s visit to Ware, the girl hastens to the man\'s home to meet her stepmother. Sarah is fallen aback when Jane finds her with Ware, but is filled with happiness when the girl announces her desire for a reconciliation.', 20, '0+', '1914-02-23', 'Drama'),
(1063282, 'Emergency', 'https://image.tmdb.org/t/p/original/xAr6uivPtFjupLrU4gtBBI9QQZo.jpg', 'When a little girl is knocked down it is discovered that there are only three donors of the right blood type to help with a life-saving operation. One is a murderer awaiting execution, one an atomic scientist selling secrets, and one an international footballer about to get his hundreth cap.', 63, '0+', '1962-03-02', 'Drama'),
(1063283, 'Sisu 2', 'https://image.tmdb.org/t/p/original/kiVSRymeEmXspPvs1KJM5aeWi81.jpg', 'Returning to the house where his family was brutally murdered during the war, \'the man who refuses to die\' dismantles it, loads it on a truck, and is determined to rebuild it somewhere safe in their honor. When the Red Army commander who killed his family comes back hellbent on finishing the job, a relentless, eye-popping cross-country chase ensues — a fight to the death.', 89, '0+', '2025-10-21', 'Action/War'),
(1063284, 'Dziwne dni', 'https://image.tmdb.org/t/p/original/rY5BrDRcYAKE0BYmmT66YG6Uy5Q.jpg', 'Former policeman Lenny Nero has moved into a more lucrative trade: the illegal sale of virtual reality-like recordings that allow users to experience the emotions and past experiences of others. While they typically contain tawdry incidents, Nero is shocked when he receives one showing a murder.', 145, '16', '1995-10-13', 'Crime/Drama/Science Fiction/Thriller'),
(1063285, 'O Fabulă', 'https://image.tmdb.org/t/p/original/Akbmaawhwz89C9ZqJSYrmUoIZZT.jpg', 'In \"Spaces #2\", 7 internationally acclaimed directors shot, after commissioning by the Thessaloniki International Film Festival, a short film at home, making their own timely comment on the new reality that we live in. The project is inspired by the book \"Species of Spaces\" by the French novelist, filmmaker, documentalist, and essayist, Georges Perec and the days of quarantine. The idea is to create a film at home, using the environment, the people or the animals in that space. The only outdoor areas that may be used are outdoor living spaces, such as the terrace, the garden, the balcony and the stairwell. \"A Fable\" is Radu Jude\'s submission.', 3, '0+', '2020-04-21', NULL),
(1063286, 'Eurynomé tánca', 'https://image.tmdb.org/t/p/original', 'Dancing eurynome (Mytho-Clip) is dedicated to the Greek goddess Eurynome, the child of Oceanus and Tethys. She was the mother of the Graces and of the river-god Aesopus. Eurynome dances on water - and to the music of der Plan. Astrological symbols (an egg, a bird and the suchlike) are added to the image of her mythical dance. In Mytho-Clip (as in Philo-Clip and Lyric-Clip), Bódy exploits video\'s considerable potential to transform the image.', 4, '0+', '1985-01-01', 'Music');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1063287, '封神第二部：战火西岐', 'https://image.tmdb.org/t/p/original/5bBgvH3hTxlANUsLP1ov0lEKmJp.jpg', 'Taishi Wen Zhong led the army of Shang Dynasty including Deng Chanyu and four generals of the Mo Family to Xiqi. With the help of Kunlun immortals such as Jiang Ziya, Ji Fa led the army and civilians of Xiqi to defend their homeland.', 145, '0+', '2025-01-29', 'Action/Fantasy/War'),
(1063288, 'Sayang', 'https://image.tmdb.org/t/p/original/mLLcT8U3YEVrA3SqDwUQQNSO0gj.jpg', 'The film narrates Datin Zaharah had two sons, Herman and Noni, studying in a college. Herman always concerned about her sister Noni. The girl was not allowed to mix freely and attend social functions.  Herman not only act as red but also as head of the house after his father\'s death a year ago. Noni, through kawawn class, Eda, can get acquainted with Don have agreed to attend a birthday party with their classmates Hussein.  Don tries to seduce Noni but the girl refused, Hamzah has warned Don not to be friends with her sister again.', 105, '0+', '1987-01-01', 'Romance'),
(1063289, 'Revival', 'https://image.tmdb.org/t/p/original/1XiRapIjZwJBOVj2ZH3kx74jyVb.jpg', 'Two robbers on the run end up in the clutches of a doctor who experiments on people to navigate the afterlife. What seems to be an innocuous foray into a scientific and existential revolution for humanity soon takes a turn for the worse.', 97, '0+', '2024-11-28', 'Horror/Thriller/Science Fiction'),
(1063290, 'Mary Shelley', 'https://image.tmdb.org/t/p/original/gKHJTsrfxJtfFNPQJn2hDNEMtFf.jpg', 'The love affair between poet Percy Shelley and Mary Wollstonecraft Godwin resulted in the creation of an immortal novel, “Frankenstein; or, The Modern Prometheus.”', 120, '0+', '2017-08-06', 'Romance/Drama'),
(1063291, 'Sun Dogs', 'https://image.tmdb.org/t/p/original/hiEHsguMwMyZMRXgjgQaB2Vpbzj.jpg', 'A man eager to serve his country but rejected by the Marines pairs up with a young runaway to form an unlikely team on a misguided adventure.', 93, '0+', '2017-06-18', 'Drama/Comedy'),
(1063292, 'Knife', 'https://image.tmdb.org/t/p/original', 'Set in rural Texas the story chronicles an unnamed man with a broken spirit. In the beginning we see him returning to his family. Where he’s been is unknown. Wherever it was – prison, maybe war – the years have not been kind to him. In spite of his family’s warm welcome the man can’t shake an anger that builds in him so he must leave them again. This time to return to the land that was once theirs, a land that had been in the family for generations, a land that has been stolen, plundered, and sewn with seeds of greed. There’s a force at work, a corruption that destroys homes, nature, families, and memories. The Man decides to lay his stakes down and pits himself against it all. He is on a ruinous mission to sate the hatred in his heart with the knife he carries in his hand.', 13, '0+', '2011-12-31', 'Drama'),
(1063293, 'Ang Panday', 'https://image.tmdb.org/t/p/original/wYWTkXgVomL3OLUjSB2BvCXyLDz.jpg', 'Long ago, the evil wizard Lizardo sent an army of monsters to subjugate the land and its people. Lizardo succeeded, but a prophecy tells of a comet that will fall to Earth, and a man who will wield a weapon that will free the people from Lizardo\'s tyranny. Flavio is a blacksmith content with living a quiet, uneventful life in a town mostly untouched by Lizardo\'s evil. But when the comet of prophecy lands on the outskirts of town, Flavio\'s destiny is immediately made clear. Around the peace-loving but brave Flavio. His arch-enemy Lizardo attempts to ruin the peace and harmony of their dwelling place, affecting the inhabitants. Moreover, the evil warlord challenges Flavio by capturing his beautiful lady love Maria. A series of events take place, bringing the blacksmith (panday) at the forefront of a full-blown war against Lizardo\'s troops.', 110, '0+', '2009-12-25', 'Science Fiction/Action/Fantasy'),
(1063294, 'Król Dawid', 'https://image.tmdb.org/t/p/original/pFdaND8Dl4yLGvzIBlahiqAaec3.jpg', 'This is a movie about the life of Israel\'s king David.', 114, '0+', '1985-03-29', 'Action/Adventure/History/Drama'),
(1063295, 'Heretyk', 'https://image.tmdb.org/t/p/original/4rE9jJtLqS3OwKOPCebo2yQ3YyU.jpg', 'Two young missionaries are forced to prove their faith when they knock on the wrong door and are greeted by a diabolical Mr. Reed, becoming ensnared in his deadly game of cat-and-mouse.', 111, '0+', '2024-10-31', 'Horror/Thriller'),
(1063296, 'AEW x NJPW: Forbidden Door - Zero Hour', 'https://image.tmdb.org/t/p/original/1AHuU0ZNqcbQuGVGSVWPxfGmg1K.jpg', 'AEW x NJPW: Forbidden Door - Zero Hour served as the pre-show to the larger AEW x NJPW: Forbidden Door 2025 pay-per-view (PPV) featuring a collaboration between All Elite Wrestling (AEW) and New Japan Pro-Wrestling (NJPW).', 90, '0+', '2025-08-24', NULL),
(1063297, 'The Suburbanite', 'https://image.tmdb.org/t/p/original', 'A family moves out to the \'peaceful\' suburbs where everything goes wrong, including the mother-in-law moving in.', 9, '0+', '1904-11-12', 'Comedy'),
(1063298, 'ಕಾಂತಾರ: ಅಧ್ಯಾಯ - ೧', 'https://image.tmdb.org/t/p/original/ehQPboTPaIMkMUOoNOh8e7pZ5Rp.jpg', 'During the Kadamba reign, King Vijayendra, the ruler of the fictional feudatory land of Bangra, meets his final fate while venturing into the mystical forest of Kantara. Witnessing this, his son Rajashekara seals the borders of their realm. Later, Prince Kulashekara reopens them through a brutal massacre. The protagonist, Berme, in search of prosperity, crosses the divide and ignites a conflict of faith, power, and destiny between the Kingdom and Nature.', 165, '0+', '2025-10-01', 'Action/Drama/Fantasy'),
(1063299, 'Enna Nu Rehna Sehna Ni Aaunda', 'https://image.tmdb.org/t/p/original/gm0BcnnxiHVGgnO5xczlyp5mXCw.jpg', 'Kiran lives in a quiet Canadian neighborhood with her family until some fun-loving international students move in next door.', 131, '0+', '2025-08-22', 'Comedy'),
(1063300, 'Osiris', 'https://image.tmdb.org/t/p/original/3YtZHtXPNG5AleisgEatEfZOT2w.jpg', 'Special Forces commandos on a mission are abducted mid-operation by a mysterious spacecraft. Upon waking aboard, they find themselves prey to a relentless alien race in a fight for survival.', 108, '0+', '2025-07-25', 'Science Fiction/Action/Horror'),
(1063301, 'Hagedorn', 'https://image.tmdb.org/t/p/original/lsxyp5TIqfGH03YHg9HlXVXTYed.jpg', 'A biopic movie based on the titular figure.', 114, '0+', '1996-01-09', 'Action/Drama'),
(1063302, 'Becoming Blond', 'https://image.tmdb.org/t/p/original/cF6shPfs1Ty6nR6Q2YcRxASClix.jpg', 'Sebastian works for the lazy combo of frienemies Rosetta (Reno) and Professor Morey (Mink Stole) translating dead romance languages. He lives with his roommate Ida, a cyber-chick agoraphobic nudist who realizes Hippo, a Boy George look-alike she\'s only ever met online. Ida\'s Aunt Gertrude, misunderstanding their BFF relationship, wills the house to Ida and her \"husband\" Sebastian. Not actually being married, Ida discovers she could lose her home to Noodles the poodle; her grandmother\'s dog!!! She decides to seek out the exotic Hippo whom she has only seen in the pictures Meanwhile, Sebastian offers to sacrifice his gayness by marrying Ida.', 78, '0+', '2012-10-16', 'Comedy'),
(1063303, 'I, Philip', 'https://image.tmdb.org/t/p/original/a0zqFDxWJvRfwJFPakazbtqLHJP.jpg', 'A Virtual Reality Movie - In early 2005, David Hanson, an American robotics, is developing its first android human. His name is Phil and it is simply the copy of the famous science fiction author Philip K. Dick. In a few weeks Phil became famous on the Web and in the author\'s fan circles. It is presented in several conferences around the world. In late 2005, the head of the android disappeared during a flight America West Airlines between Dallas and Las Vegas. Through the memories of the android and those of the author, the film offers an interpretation of Phil\'s life.', 14, '0+', '2016-02-01', 'Science Fiction'),
(1063304, 'Avatar: Ogień i popiół', 'https://image.tmdb.org/t/p/original/m0UoNRK2H2TsR1EbzgngF4vlOsU.jpg', 'In the wake of the devastating war against the RDA and the loss of their eldest son, Jake Sully and Neytiri face a new threat on Pandora: the Ash People, a violent and power-hungry Na\'vi tribe led by the ruthless Varang. Jake\'s family must fight for their survival and the future of Pandora in a conflict that pushes them to their emotional and physical limits.', 192, '0+', '2025-12-17', 'Science Fiction/Adventure/Fantasy'),
(1063305, 'Bikini Planet', 'https://image.tmdb.org/t/p/original/7nYM6ENPUNAhYsoNQukGxfxLxCF.jpg', 'When a new planet is discovered in Earth\'s solar system, Capt. Flash Rogers is picked to head a team to investigate. They find that high levels of silicon in the atmosphere has created a society of gorgeous, large-breasted women--but things start to go south when Flash discovers that these Amazonian babes are planning to take over the Earth in order to replenish their shrinking supplies of silicon.', 80, '0+', '2002-01-01', 'Science Fiction/Comedy'),
(1063306, 'Tajemnicza wyspa', 'https://image.tmdb.org/t/p/original/lqLIpwISJEvERlS5fSWe8xbQDFf.jpg', 'During the US Civil War, Union POWs escape in a balloon and end up stranded on a South Pacific island, inhabited by giant plants and animals. They must use their ingenuity to survive the dangers, and to devise a way to return home. Sequel to \'20,000 Leagues Under the Sea\' .', 101, '0+', '1961-12-19', 'Adventure/Science Fiction'),
(1063307, 'Spaceways', 'https://image.tmdb.org/t/p/original/e4pPxnO5JfBrYZDej0ObVTNpX0l.jpg', 'A rocket engineer, responsible for sending a satellite into space, is accused of committing the most extraordinary crime.', 77, '0+', '1953-08-07', 'Drama/Science Fiction/Thriller'),
(1063308, 'Ginący świat', 'https://image.tmdb.org/t/p/original/gydw7e4QCWrp5qExSJSvzyPJ42E.jpg', 'An unlikely team of activists and innovators hatches a bold mission to save endangered species.', 90, '0+', '2015-01-24', 'Adventure/Documentary'),
(1063309, 'En borgerpligt', 'https://image.tmdb.org/t/p/original', 'The wife is unhappy that her husband has not registered with the Home Guard like the other men.', 1, '0+', '1953-12-13', 'Documentary'),
(1063310, 'Cross-Roads', 'https://image.tmdb.org/t/p/original/yhlC7DhL3LoizCPinIeX27jZ39N.jpg', 'A ghost returns from the grave to seek revenge.', 19, '0+', '1955-02-01', 'Horror/Drama'),
(1063311, 'Skateboard Party', 'https://image.tmdb.org/t/p/original/8Yhchgbwoo6J7wMAsGsNNvft0vu.jpg', 'Skateboard Party is a collection of skate footage from the 2004 Red Dragons (RDS) skate tour, making up the second skateboarding video from RDS. It\'s a mix of awesome skate clips and partying. It opens with Tom Green trashing a mirrored closet door and they guys smack him around over it. I didn\'t know he still had a career... interesting. Aboard two boats the team go to an island, with a lot of beer, to celebrate the finish of their 2004 tour.', 33, '0+', '2005-09-07', 'Documentary'),
(1063312, 'Coyotes', 'https://image.tmdb.org/t/p/original/fSzs9ZXYcrln0FRrjGIPCjuB6En.jpg', 'Trapped in their Hollywood Hills home, a family fights for survival when caught between a raging wildfire and a pack of savage coyotes. As the city loses power and chaos spreads, nature turns feral - and what starts as isolated attacks escalates into a terrifying siege they may not all survive.', 91, '0+', '2025-10-02', 'Horror/Comedy'),
(1063313, 'The Plan', 'https://image.tmdb.org/t/p/original/yvsnHWBmRKHMcClEGOkgmGunGtF.jpg', 'The Plan - youth centric, high energy, prison break, suspense thriller, social and political film treated on world cinema treatment. The film is portrayed on a canvas of a prison amidst of a dense forest. Where, in, trapped lives, battling between Rage, Fear, Revenge and deceit that finally unfolds in to a climax that reflects the ugliness of the social face today\'s world... It talks about the friendship of four guys, how they live life and a moment of thoughtlessness changes their lives and they find themselves in prison.. What happens next forms the crux of the story.', 124, '0+', '2015-11-27', 'Thriller/Mystery/Crime'),
(1063314, 'Rabia', 'https://image.tmdb.org/t/p/original/u6kcdyG06mbvWgH3LC3dVmqlyBo.jpg', 'A romantic thriller about a construction worker in hiding for killing his foreman who hides in the mansion where his girlfriend works as a maid.', 89, '0+', '2009-08-12', 'Drama/Thriller/Romance'),
(1063315, 'Nieuchronna Sprawiedliwość', 'https://image.tmdb.org/t/p/original/g5WeIWEHcMprqgrmJlOHU1pRD1N.jpg', 'After returning home from a traumatic tour of duty in Iraq, John finds himself struggling with PTSD. What little peace he had managed to build around him is shattered one fateful day when he rescues a local call girl from a group of violent Aryan Brotherhood pimps. Having killed several of the high-ranking brotherhood during the rescue, John and his family are now the prime targets of Hollis, the ruthless criminal leader of the group.', 96, '0+', '2014-08-04', 'Action/Drama'),
(1063316, 'Peddinti Alludu', 'https://image.tmdb.org/t/p/original/jVn88yjvi5ItDqINvveHz1KjyHx.jpg', 'Raja (Suman) is an unemployed educated guy, his mother (Dubbing Janaki) is a serious heart patient and requires a major operation. But due to poverty, Raja decides to shift to Hyderabad for his mother\'s treatment and search of a job. On the way, he meets a retired music teacher Srinivasa Rao (Babu Mohan) on a train who is traveling going to join as a tuition master Island Estate for Rs. 3000 salary monthly. While alighting with the suitcases of Raja & Srinivasa Rao interchanges. After reaching the room, Raja finds the appointment letter and address cover of Srinivasa Rao. Due to the critical situation of his mother, Raja joins the post as a disguise old man.', 0, '0+', '1991-01-01', NULL),
(1063317, 'Rocketman', 'https://image.tmdb.org/t/p/original/f4FF18ia7yTvHf2izNrHqBmgH8U.jpg', 'The story of Elton John\'s life, from his years as a prodigy at the Royal Academy of Music through his influential and enduring musical partnership with Bernie Taupin.', 121, '16', '2019-05-17', 'Music/Drama'),
(1063318, 'State Trooper', 'https://image.tmdb.org/t/p/original/A6g8RtrxtfEOM1uIDAksDPGtzQM.jpg', 'Mike Rolph quits his job, seemingly, as a highway patrolman and takes the position of the Police Chief of W. J. Brady\'s oil refinery. He is also romantically involved with Brady\'s daughter, June. It appears that some highly-placed employee has sold out to the opposition refinery people, and much sabotage and havoc is being caused.', 61, '0+', '1933-02-10', 'Action/Crime'),
(1063319, 'Dwunastu odważnych', 'https://image.tmdb.org/t/p/original/pxMeYLOJcMqPJsH4AwzLiKvolQd.jpg', 'A team of special forces head into Afghanistan in the aftermath of the September 11th attacks in an attempt to dismantle the Taliban.', 130, '0+', '2018-01-18', 'War/Drama/Action/History'),
(1063320, 'アジア三面鏡2018 Journey', 'https://image.tmdb.org/t/p/original/k4b6A74qqzciNUSK7IStTaNpkJp.jpg', 'This omnibus film consists of three films made by three directors from three countries. With “Journey” as the theme, each of these films tells about a journey. “The Sea” is a film by Degena Yun (China), telling about mother and child’s trip to the sea from Beijing. “Hekishu,” a film by Daishi Matsunaga (Japan), tells about the journey of a Japanese businessman involved in infrastructure development in Yangon. The film depicts the entrepreneur’s emotional feelings in the face of Yangon residents who lost their homes due to the construction of the new infrastructure. The last is a film titled “Variable No. 3” by Edwin (Indonesia), which tells the story of a couple’s journey to Tokyo. There they meet a mysterious man. The man who works as a tour guide and rents out the inn, gives a strange advice to the husband and wife.', 83, '0+', '2018-10-26', 'Drama'),
(1063321, 'U-Turn', 'https://image.tmdb.org/t/p/original/axgqQUSgtRnzjiOYJkwAEjtbTs.jpg', 'In this Canadian romance, Scott (David Selby) was so smitten by the looks of a pretty girl that he spends years looking for her. He keeps his searches a secret from his live-in lover, whom he stays with the entire while. When Scott actually meets the girl, he discovers that she has been similarly motivated, even though she is married and has had two children in the meantime. They share a romantic assignation and discover that the ideal figure they were each searching for is absent.', 99, '0+', '1973-08-15', 'Drama'),
(1063322, 'Terrorise', 'https://image.tmdb.org/t/p/original/ayvBxUnhKipIbEej70e4Kmb8FrS.jpg', 'Quaid and Kurk escape from prison and kidnap a pretty woman to ensure their protection. Kurk dislikes the way Quaid treats her, and the two begin a deadly cat-and-mouse game with two corrupt police officers Doug & Charles hot on their trail.  Terrorise is the ultimate & Final Cut of the cult exploitation film Tortured. It has been remastered from the original camera tapes, re-cut, re-graded, re-scored, new and alternate footage all to create the directors closest vision.', 77, '0+', '2024-01-13', 'Horror'),
(1063323, 'Breakdance Academy', 'https://image.tmdb.org/t/p/original/a0QEH1bduaRQwHh8K0s71lotmEB.jpg', 'In this hilarious send-up of boy bands, teen movies and dance movies, the audience gets a guarantee of something that will make you laugh -- whether it’s mom remembering the days of NSYNC, or little Lisa fantasizing about the Biebs, or your sexually-ambiguous nephew who thinks Channing rocks a sailor suit! Our story follows Brad, a jock who decides he\'s more than just a meathead women pine for, so he joins the dance club, a rap group, metal mania and more, before creating the perfect boy band with the help of the local Zen master. Watch out, high school will never be the same!', 90, '0+', '2010-06-04', 'Comedy/Music'),
(1063324, 'Hollywood Dirt', 'https://image.tmdb.org/t/p/original/3mhv9gjqFJscFM14rRSPsM9d1UW.jpg', 'Hollywood arrives in force to Quincy, the small town where the secret Crown Cola billionaire\'s live. They want to film about the billionaire\'s and how they made their fortunes. Summer Jenkins, who was the town pariah, joins forces with the scout, Ben, and finds filming locations, extras, lessons with the town officials and house owners, etc. When Cole Masten arrives, they hate each other, but sparks fly. Cole is running from a nasty divorce, yet is captivated by Summer. Summer is dying to leave town to get away from the gossip. This is a great story about Southern customs, a Southern girl, and a Hollywood star who finds his lady.', 121, '0+', '2017-09-01', 'Drama/Romance'),
(1063325, 'Raton Pass', 'https://image.tmdb.org/t/p/original/baB6FNYcL6cmF41BXUi4PUSBab9.jpg', 'Raton Pass is a curious western based on the rules of Community Property. Dennis Morgan and Patricia Neal portray a recently married husband and wife, each of whom owns half of a huge cattle ranch. Neal is a tad more ambitious than her husband, and with the help of a little legal chicanery she tries to obtain Morgan\'s half of the spread. He balks, so she hires a few gunslingers to press the issue. In a 1951 western, the greedy party usually came to a sorry end; Raton Pass adheres strictly to tradition.', 84, '0+', '1951-04-07', 'Western'),
(1063326, 'Pacific High', 'https://image.tmdb.org/t/p/original/wIeNsf8auCzaiyISMiqm0bGeD2o.jpg', 'In April 1978, the annual Ensenada Yacht Race from Newport Beach, California, to Ensenada, Mexico, occurred over the course of twenty-four hours. More than 600 yachts and sailboats competed in the 200-mile race. In the final stretch into Ensenada Harbor, the winds calmed, leaving the boats moving slowly to the finish line.', 0, '0+', '1980-01-01', 'Documentary'),
(1063327, 'Dzika orchidea', 'https://image.tmdb.org/t/p/original/6UfS8J9Ixn0BAv1aeuAFWom5YEk.jpg', 'A woman lawyer becomes mesmerized by a self-made millionaire during an encounter in Rio setting off a series of erotic encounters.', 105, '0+', '1989-12-22', 'Drama/Romance'),
(1063328, 'Gorgo', 'https://image.tmdb.org/t/p/original/fC27POiM5HB08oDxVedPNkGAKUj.jpg', 'Greedy sailors capture a giant lizard off the coast of Ireland and sell it to a London circus. Then its mother shows up.', 78, '0+', '1961-02-02', 'Science Fiction/Action/Horror'),
(1063329, 'Road House', 'https://image.tmdb.org/t/p/original/fDEdtS4P0gJsxHDIt8dG8TR5dx1.jpg', 'Ex-UFC fighter Dalton takes a job as a bouncer at a Florida Keys roadhouse, only to discover that this paradise is not all it seems.', 121, '0+', '2024-03-08', 'Action/Thriller'),
(1063330, 'The Catcher', 'https://image.tmdb.org/t/p/original', 'A trapeze instructor encounters the supernatural while trying to enjoy a beautiful summer day.', 13, '0+', '2005-04-16', 'Drama'),
(1063331, 'Venom 3: Ostatni taniec', 'https://image.tmdb.org/t/p/original/yOQAyQAka0h2Hl9sLnCS9wpLHjl.jpg', 'Eddie and Venom are on the run. Hunted by both of their worlds and with the net closing in, the duo are forced into a devastating decision that will bring the curtains down on Venom and Eddie\'s last dance.', 109, '12', '2024-10-22', 'Action/Science Fiction/Adventure'),
(1063332, 'Valhalla: Mroczny wojownik', 'https://image.tmdb.org/t/p/original/7LBMcAx6XHwEduIsBYipvUke9n.jpg', 'Scandinavia, 1,000 AD. For years, One Eye, a mute warrior of supernatural strength, has been held prisoner by the Norse chieftain Barde. Aided by Are, a boy slave, One Eye slays his captor and together he and Are escape, beginning a journey into the heart of darkness. On their flight, One Eye and Are board a Viking vessel, but the ship is soon engulfed by an endless fog that clears only as the crew sights an unknown land. As the new world reveals its secrets and the Vikings confront their terrible and bloody fate, One Eye discovers his true self.', 93, '0+', '2009-09-04', 'Adventure/Drama/Action/Fantasy'),
(1063333, 'Harry Potter i więzień Azkabanu', 'https://image.tmdb.org/t/p/original/sR7uC42HHb7qj1ndLBgBXii0quX.jpg', 'Year three at Hogwarts means new fun and challenges as Harry learns the delicate art of approaching a Hippogriff, transforming shape-shifting Boggarts into hilarity and even turning back time. But the term also brings danger: soul-sucking Dementors hover over the school, an ally of the accursed He-Who-Cannot-Be-Named lurks within the castle walls, and fearsome wizard Sirius Black escapes Azkaban. And Harry will confront them all.', 141, '12', '2004-05-31', 'Adventure/Fantasy'),
(1063334, 'Doom', 'https://image.tmdb.org/t/p/original/oUe0yqgGj11RFgqSXqeUEVQAlt.jpg', 'A team of space marines known as the Rapid Response Tactical Squad, led by Sarge, is sent to a science facility on Mars after somebody reports a security breach. There, they learn that the alert came after a test subject, a mass murderer purposefully injected with alien DNA, broke free and began killing people. Dr. Grimm, who is related to team member Reaper, informs them all that the chromosome can mutate humans into monsters -- and is highly infectious.', 105, '16', '2005-10-20', 'Action/Horror/Science Fiction'),
(1063335, 'Brooding Eyes', 'https://image.tmdb.org/t/p/original', 'Slim Jim Carey, the leader of a criminal gang, is in reality a nobleman called Lord Talbois, and his daughter is the rightful heir to the family estate. When \"Slim Jim\"\'s gang finds out about this, they conspire to cheat her out of her inheritance by passing off one of the gangster\'s girlfriends as the real daughter. Unbeknownst to the gang, however, their leader isn\'t dead and finds out what they\'re up to. Complications ensue.', 60, '0+', '1926-03-15', 'Crime'),
(1063336, 'Baza księżycowa', 'https://image.tmdb.org/t/p/original/3N8qqiFzvSJh0XWHu6bDztABPAT.jpg', 'The most dangerous criminals in the universe escape from the Off-World Penitentiary and stow away to the quiet Moonbase Waste Disposal Plant. Hidden beneath the lunar surface lies an arsenal of nuclear warheads- the inmates\' passport home to earth. Moonbase Commander John Russell launches a desperate fight to save his crew from a force capable of laying waste to an entire planet.', 90, '0+', '1997-12-06', 'Science Fiction'),
(1063337, 'The Graduates', 'https://image.tmdb.org/t/p/original/yZAN6amO7HhzzfTLEMgmUdM12hq.jpg', 'Follows a group of young adults as they navigate life after college.', 112, '0+', '1986-04-03', 'Comedy/Romance'),
(1063338, 'Czerwona jedynka', 'https://image.tmdb.org/t/p/original/8xfBpl0zisD9wgEvJ1o1egHx5Ep.jpg', 'After Santa Claus (codename: Red One) is kidnapped, the North Pole\'s Head of Security must team up with the world\'s most infamous tracker in a globe-trotting, action-packed mission to save Christmas.', 124, '12', '2024-10-31', 'Action/Comedy/Fantasy'),
(1063339, 'Wielkie polowanie', 'https://image.tmdb.org/t/p/original/2sK0wjqW9XtBNIsK16691MDTBkh.jpg', 'Daffy Duck and Bugs argue back and forth whether it is duck season or rabbit season. The object of their arguments is hunter Elmer Fudd.', 7, '0+', '1951-05-19', 'Animation/Comedy'),
(1063340, 'Mamma Mia!', 'https://image.tmdb.org/t/p/original/mugycW3U8TT2tK58rrljffjQrvz.jpg', 'A spirited young bride-to-be living with her single mother on a small Greek island secretly invites three of her mother\'s ex-boyfriends in hope of finding her biological father to walk her down the aisle.', 108, '12', '2008-07-03', 'Comedy/Romance'),
(1063341, 'Rajakiya Chadurangam', 'https://image.tmdb.org/t/p/original/yi8jgCTXqF6wLWu9Wdocir8BZpl.jpg', 'The story begins with formation of the new government when an honest person, Satya Murthy (Akkineni Nageswara Rao) becomes Chief Minister of Andhra Pradesh. After that, he forms his government by selecting people with a clean image in his cabinet and brings out several revolutionary changes in the state. This overshadows Joginatham (Kota Srinivasa Rao), who is another strong aspirant for the chairs of CM and his group. They all conduct a secret meeting along with Contractor Papa Rao (Prabhakar Reddy), a political lobbyist and decide to assassinate CM Satya Murthy. Papa Rao contacts a Professional Killer Narang (Charan Raj) to kill CM and he keeps deadline till 1 November. Through the intelligence bureau, Police Department gets secret information regarding it. Here they specially appoint a powerful Police officer, S. P. Pratap (Krishna) for C.M.\'s protection. The rest of the story is how S. P. Pratap protects CM from the secret killer', 0, '0+', '1988-01-14', NULL),
(1063342, 'Siostry', 'https://image.tmdb.org/t/p/original/c7JoUa6DDoHkR5ubRdCgnpwGUE5.jpg', 'Tired of their mother\'s alcoholism and a string of her abusive boyfriends, two sisters plot to kill her.', 100, '0+', '2014-04-08', 'Thriller/Drama/Crime'),
(1063343, 'Kto pod kim dołki kopie ...', 'https://image.tmdb.org/t/p/original/o2Dm2mcE1qW8vT0bpsJO5OMBbqa.jpg', 'After being wrongfully convicted for stealing a pair of shoes, Stanley Yelnats is sent away to Camp Green Lake, a boys detention facility where inmates are forced to dig holes all day in the hot desert sun as a form of character building. But Stanley and the other boys start to unravel a mystery, linked with the camps tough-as-nails warden —and possibly Stanley’s family itself.', 117, '7', '2003-04-18', 'Adventure/Family/Drama/Comedy'),
(1063344, 'Zombie Nightmare', 'https://image.tmdb.org/t/p/original', 'A mad scientist! Four beautiful women! A sex-starved zombie! Lethal experiments! All this and more add up to Zombie Nightmare where helpless victims die, not once, but twice! In his desperate attempt to revive his cancer ridden wife from suspended animation, a deranged scientist abducts four innocent women and subjects them to lethal experiments! Will his wife live again at the expense of the other women?', 90, '0+', '1993-01-01', 'Horror'),
(1063345, 'Niezniszczalni 4', 'https://image.tmdb.org/t/p/original/o4oEqbmZcBwhsVJ1qhlwOF4asVO.jpg', 'Armed with every weapon they can get their hands on and the skills to use them, The Expendables are the world’s last line of defense and the team that gets called when all other options are off the table. But new team members with new styles and tactics are going to give “new blood” a whole new meaning.', 103, '16', '2023-09-15', 'Action/Adventure/Thriller'),
(1063346, 'Europa Europa', 'https://image.tmdb.org/t/p/original/eRrtlpJbQPUShcDv9Z7huG3Tw4m.jpg', 'A Jewish boy separated from his family in the early days of WWII poses as a German orphan and is taken into the heart of the Nazi world as a \'war hero\' and eventually becomes a Hitler Youth.', 112, '0+', '1990-11-14', 'History/Drama/War'),
(1063347, 'Die Möwe', 'https://image.tmdb.org/t/p/original', '', 0, '0+', '1963-07-09', 'Drama'),
(1063348, 'Boogie Nights', 'https://image.tmdb.org/t/p/original/wnE24UPCPQsQnbBOu4zVE2qaDNm.jpg', 'Set in 1977, back when sex was safe, pleasure was a business and business was booming, idealistic porn producer Jack Horner aspires to elevate his craft to an art form. Horner discovers Eddie Adams, a hot young talent working as a busboy in a nightclub, and welcomes him into the extended family of movie-makers, misfits and hangers-on that are always around. Adams\' rise from nobody to a celebrity adult entertainer is meteoric, and soon the whole world seems to know his porn alter ego, \"Dirk Diggler\". Now, when disco and drugs are in vogue, fashion is in flux and the party never seems to stop, Adams\' dreams of turning sex into stardom are about to collide with cold, hard reality.', 156, '0+', '1997-10-10', 'Drama'),
(1063349, 'Bambi: The Reckoning', 'https://image.tmdb.org/t/p/original/8oBbWxWDJrrDtNkmd0OzZpPFFUR.jpg', 'After a mother and son get in a car wreck, they soon become hunted by Bambi, a mutated grief-stricken deer on a deadly rampage seeking revenge for the death of his mother and wife.', 80, '0+', '2025-07-11', 'Horror/Thriller'),
(1063350, 'Tension', 'https://image.tmdb.org/t/p/original/9xhArxwGLDQyEccn7vmBT5BJc0C.jpg', 'Warren Quimby manages a drugstore while trying to keep his volatile wife, Claire, happy. However, when Claire leaves him for a liquor store salesman, Warren can no longer bear it. He decides to assume a new identity in order to murder his wife\'s lover without leaving a trace. Along the way, his plans are complicated by an attractive neighbor, as well as a shocking discovery that opens up a new world of doubts and accusations.', 95, '0+', '1949-11-25', 'Thriller/Crime'),
(1063351, 'Blow', 'https://image.tmdb.org/t/p/original/yYZFVfk8aeMP4GxBSU9MTvqs9mJ.jpg', 'A boy named George Jung grows up in a struggling family in the 1950\'s. His mother nags at her husband as he is trying to make a living for the family. It is finally revealed that George\'s father cannot make a living and the family goes bankrupt. George does not want the same thing to happen to him, and his friend Tuna, in the 1960\'s, suggests that he deal marijuana. He is a big hit in California in the 1960\'s, yet he goes to jail, where he finds out about the wonders of cocaine. As a result, when released, he gets rich by bringing cocaine to America. However, he soon pays the price.', 124, '18', '2001-04-04', 'Crime/Drama'),
(1063352, 'Haruo', 'https://image.tmdb.org/t/p/original/eqhSVOU80GBmKroubY9vJYHOFjN.jpg', 'A Yakuza member seeking to lead a new life in Manila. A morbid turn of events brings Haruo (Jacky Woo) to the squalor of Manila. A prized asset of the feared Yakuza in Tokyo, Haruo, aka Tadano Hayashi, escapes the criminal syndicate with bountiful cash, a helpless Filipina bar girl (Nina Kodaka) – and tragic consequences. Now solitary, he has uprooted himself to the railside slums of the metropolis, wistfully fending for himself. Still hiding from his past, he rents out a small room, seemingly lost in the clutter of wandering souls desperate for survival. There, he spends his days anonymously roaming the congested streets selling food, and even giving them away for the hungry. But he mostly keeps to himself, even to the inquisitive Edna (Rosanna Roces), an aging bar girl with whom he occasionally shares his bed.', 0, '0+', '2011-12-17', 'Drama'),
(1063353, 'Człowiek ze stali', 'https://image.tmdb.org/t/p/original/qj40hZtRF8T98NANC9zsrDQHf3v.jpg', 'A young boy learns that he has extraordinary powers and is not of this earth. As a young man, he journeys to discover where he came from and what he was sent here to do. But the hero in him must emerge if he is to save the world from annihilation and become the symbol of hope for all mankind.', 143, '16', '2013-06-12', 'Action/Adventure/Science Fiction'),
(1063354, 'Pszczelarz', 'https://image.tmdb.org/t/p/original/zUijwnrcMD8ml643ueggHiIjCz8.jpg', 'One man\'s campaign for vengeance takes on national stakes after he is revealed to be a former operative of a powerful and clandestine organization known as Beekeepers.', 106, '0+', '2024-01-08', 'Action/Crime/Thriller'),
(1063355, 'Prorok', 'https://image.tmdb.org/t/p/original/nc0tQUBWxPOuVakRnCcMBD2b8jA.jpg', 'Sentenced to six years in prison, Malik El Djebena is alone in the world and can neither read nor write. On his arrival at the prison, he seems younger and more brittle than the others detained there. At once he falls under the sway of a group of Corsicans who enforce their rule in the prison. As the \'missions\' go by, he toughens himself and wins the confidence of the Corsican group.', 155, '0+', '2009-08-26', 'Crime/Drama'),
(1063356, 'Bezlitosny morderca', 'https://image.tmdb.org/t/p/original/bh6wHjHxmuSyYL8jSFqtLlzMSGq.jpg', 'Seattle, 1974. Ted Bundy gives into his violent passions and embarks on a cross country killing spree, leaving a trail of raped, tortured, murdered, dismembered, and defiled corpses in his wake…', 99, '0+', '2002-08-02', 'Crime/Horror'),
(1063357, 'Second Chorus', 'https://image.tmdb.org/t/p/original/qo20sq732j5dIbgmNYveJITwvna.jpg', 'Danny O\'Neill and Hank Taylor are rival trumpeters with the Perennials, a college band, and both men are still attending college by failing their exams seven years in a row. In the midst of a performance, Danny spies Ellen Miller who ends up being made band manager. Both men compete for her affections while trying to get the other one fired.', 84, '0+', '1941-01-03', 'Music/Comedy/Romance'),
(1063358, 'Balahibong Pusa', 'https://image.tmdb.org/t/p/original/46LcxNYZS4QcEeq4ZDuWyVuqN7W.jpg', 'Details Here', 0, '0+', '2025-11-28', 'Drama/Romance'),
(1063359, 'Spider-Man: Bez drogi do domu', 'https://image.tmdb.org/t/p/original/1Pb65hcIv4ymPBbH7ycRM2UUcga.jpg', 'Peter Parker is unmasked and no longer able to separate his normal life from the high-stakes of being a super-hero. When he asks for help from Doctor Strange the stakes become even more dangerous, forcing him to discover what it truly means to be Spider-Man.', 148, '16', '2021-12-15', 'Action/Adventure/Science Fiction'),
(1063360, 'Testamentet', 'https://image.tmdb.org/t/p/original/bJT8ZlqEl0Lxtnv5bI5uOqyDf8y.jpg', 'FRAGMENT | A man lies on his deathbed and shows his will to his carer. After his death, a grieving man and woman come in. The scene changes and we find ourselves on a beach in the company of two couples. They’re about up to fight on a cliff, and one of the men plummets to his death. Then the scene changes again to a living room with a sobbing woman. (Stumfilm.dk)', 7, '0+', '1908-01-07', 'Drama'),
(1063361, 'Gambit, czyli jak ograć króla', 'https://image.tmdb.org/t/p/original/aXr4pIIjrBevMkBotpzkieAJskO.jpg', 'An art curator decides to seek revenge on his abusive boss by conning him into buying a fake Monet, but his plan requires the help of an eccentric and unpredictable Texas rodeo queen.', 89, '0+', '2012-04-25', 'Comedy/Crime'),
(1063362, 'Krwawy koszmar', 'https://image.tmdb.org/t/p/original/mFzyMEQvKwf2rXxB1GsSocJfL11.jpg', 'Audra\'s graduation gift is her dream house, but it soon becomes a living nightmare when some uninvited guests come to her homecoming party who aren\'t very subtle about the fact they don\'t approve of the home\'s new owner.', 100, '0+', '2023-04-28', 'Horror'),
(1063363, 'Sweet Genevieve', 'https://image.tmdb.org/t/p/original/4O94MmuUMhOg8kDy6M8bZ12imk2.jpg', 'The biggest town problem is worrying whether the high school basketball team will win the championship...until racketeers move into town and the kids begin to bet on horses, become overly fond of stripped-down racing cars, and Genevieve Rogers (Jean Porter) suspects her father of being too fond of the school principal\'s secretary. Town nerd Bill Kennedy (Jimmy Lydon) invents a new fuel amidst rumors that - horrors - the basketball game might be fixed. River City is not the only town that has trouble starting with a \"T\" and there\'s not a pool hall in sight.', 68, '0+', '1947-10-23', 'Comedy'),
(1063364, 'Animals', 'https://image.tmdb.org/t/p/original/hARdyUbYerEwOj3iOXFN9oVmdIm.jpg', 'Pol is a teenager with a seemingly calm life: he lives with his brother and is still in high school. However, Pol has a secret: Deerhoof, a cuddly teddy bear who thinks, moves around and with whom he shares his best moments. Life goes on as normal until the arrival of Ikari, an enigmatic student who seems to be hiding something. Pol is fascinated by his new classmate and attracted to the dark side he harbors. An inexplicable death and a series of strange events will transform the meek student\'s routine into a fantastic adventure which will take over their lives. Animals is a story of teenage love, of sacrifice, of the tragedy of two clashing worlds. A Tale in which the power of imagination blurs its borders with reality and where death turns out to be an ending as tempting as inevitable.', 95, '0+', '2012-10-26', 'Drama/Fantasy'),
(1063365, 'Miasto Złodziei', 'https://image.tmdb.org/t/p/original/6JrbfnR1NqmU5pEQm8ADwcUWman.jpg', 'Doug MacRay is a longtime thief, who, smarter than the rest of his crew, is looking for his chance to exit the game. When a bank job leads to the group kidnapping an attractive branch manager, he takes on the role of monitoring her – but their burgeoning relationship threatens to unveil the identities of Doug and his crew to the FBI Agent who is on their case.', 125, '16', '2010-09-15', 'Crime/Drama/Thriller'),
(1063366, 'Atak rekinów', 'https://image.tmdb.org/t/p/original/g3xlaPOkt1vFkJqxA32LnudEqrG.jpg', 'When an accidental death verdict is given on discovery of the remains of a top scientist, within the stomach of a hammerhead shark his closest friend Marine Biologist Steven McRay is not happy with the explanation and travels to investigate further, where he discovers that his friend\'s death was not an isolated incident, and that the local population have been terrorised by a rash of shark attacks.Developments in scientific technology had allowed experts to predict the pattern and likelihood of Shark Attacks, but now it seems that they may also be able to actually control these factors, rendering at their disposal the ultimate Killing machine.Enjoy the water... you may never want to go in the sea again!', 95, '0+', '1999-11-09', 'Horror/TV Movie'),
(1063367, 'Oh Boy!', 'https://image.tmdb.org/t/p/original/pOcEBHkCAXBPPTVWFfNoMd9Ebm0.jpg', 'George elopes with Lou Ellen, a judge\'s daughter, against the wishes of both their families. Simultaneously, George\'s friend Jim is in love with Jackie, an actress who gets into trouble for punching a bumbling constable at a raided party. George foolishly allows Jackie to hide in his home, leading to a series of comedic complications as he tries to keep her presence a secret from his new wife, her parents (especially her strict judge father), and his Quaker aunt.', 60, '0+', '1919-06-22', 'Comedy'),
(1063368, 'The Remains', 'https://image.tmdb.org/t/p/original/k76aHHeRgqZsdjcSvkzq2KBQLj4.jpg', 'After a family moves into an old Victorian home, they discover a chest in the attic containing antiques tainted by a malevolent spirit. As the antiques slowly possess each family member, the spirit grows stronger, hellbent on kidnapping the children.', 85, '0+', '2016-08-05', 'Horror/Thriller'),
(1063369, 'Tycho', 'https://image.tmdb.org/t/p/original', 'The year 1601: At the funeral of the eccentric yet brilliant astronomer Tycho Brahe, an illustrious group of mourners congregate to receive their parts of the inheritance. When the Holy ...   »', 0, '0+', NULL, NULL),
(1063370, 'The Snob', 'https://image.tmdb.org/t/p/original/qGzgKoxjl3bz7Zv5oug4y8lDzIz.jpg', 'Two schoolteachers, married for love, are parted by the husband\'s obsessive desire for wealth and social position.', 70, '0+', '1924-11-10', 'Drama'),
(1063371, 'High Explosive', 'https://image.tmdb.org/t/p/original/Jn4E9vwSH0EeBi97MIQtYz0JFu.jpg', 'Mike Douglas (Barry Sullivan), owner of a nitroglycerin concern hires his old friend \"Buzz\" Mitchell (Chester Morris), a race-driver of midget-auto cars who has been banned from racing, to go to work hauling nitro. \"Buzz\" makes a play for Connie Baker (Jean Parker), Mike\'s secretary and girlfriend, and also for Doris Lynch (Barbara Lynn), fiancée of Connie\'s younger brother, Jimmy (\'Rand Brooks\'), and gets Jimmy to replace him on a dangerous nitro haul and Jimmy, of course, has an accident and gets killed. But \"Buzz\" finds a way to redeem himself. The hard way.', 63, '0+', '1943-03-27', 'Action/Drama'),
(1063372, 'International Settlement', 'https://image.tmdb.org/t/p/original/nxLCLBGY6YDOiN1ilsA1TFEIG5N.jpg', 'In Shanghai amidst Sino-Japanese warfare an adventurer (Sanders) collecting money from gun suppliers falls in loves with a French singer (Del Rio).', 75, '0+', '1938-02-04', 'Adventure'),
(1063373, 'Lost Angels', 'https://image.tmdb.org/t/p/original/ft5cZbnfJVLwn2kgggD1HIuy9ZK.jpg', 'Lost Angels is a music/drama set to the soulful sounds of Oliver Pigott, the contestant Canadian Idol judges stated was perhaps the most talented person to ever audition for the show. Other name talent include, Alimi Ballard (NUMBERS, The Fast Five) and Robert Pralgo (The Vampire Diaries). Hollywood has always held a universal fascination for audiences but rarely is its true nature honestly exposed. Lost Angels pulls no punches in revealing the unique and treacherous world that has no rules except those created by the power players within.', 90, '0+', '2014-08-23', 'Drama/Music'),
(1063374, 'Eskimo Nell', 'https://image.tmdb.org/t/p/original/rjWzhLCnjPypZFym7H3c8OPKFjh.jpg', 'Three young men, a scriptwriter, a producer and a director are called in by Benny U Murdoch, an exotic movie producer. He wants to make a new erotic movie starring a big woman - the \"Eskimo Nell\" of the title. However problems start from the beginning, the scriptwriter is a virgin, a lover of penguins and hasn\'t a clue on how to write an erotic movie, each of the three main backers want a different type of movie - a western, an erotic and a kung-fu movie with different people in the main part. However problems really start for the three when Benny runs off with all the money and they have to make three different versions of the same film and try not to let the backers and stars know what has happened. And this is made harder when there is a clean-up-filth society breathing down their necks....', 85, '0+', '1975-01-17', 'Comedy'),
(1063375, 'Double Wedding', 'https://image.tmdb.org/t/p/original/76A4FIQuX4gbKVUDtVHkKvcTunY.jpg', 'A bohemian free spirit helps meek Waldo win back his fiancée and falls in love with her over-controlling sister in the process.', 87, '0+', '1937-10-15', 'Comedy/Romance'),
(1063376, 'Droga bez powrotu', 'https://image.tmdb.org/t/p/original/nufVcdQyJgAwIq3jusdRzXavPCU.jpg', 'Chris crashes into a carload of other young people, and the group of stranded motorists is soon lost in the woods of West Virginia, where they\'re hunted by three cannibalistic mountain men who are grossly disfigured by generations of inbreeding.', 84, '18', '2003-05-30', 'Horror/Thriller'),
(1063377, 'Wielka Szóstka', 'https://image.tmdb.org/t/p/original/erRGYVt8N4rlg79IBywqp8HLmmk.jpg', 'A special bond develops between plus-sized inflatable robot Baymax, and prodigy Hiro Hamada, who team up with a group of friends to form a band of high-tech heroes.', 102, 'AL', '2014-10-24', 'Adventure/Family/Animation/Action/Comedy'),
(1063378, 'Spiders', 'https://image.tmdb.org/t/p/original/vuF1EopyrrtRvVPsAsFBAThcWIT.jpg', 'After a Soviet space station crashes into a New York City subway tunnel, a species of venomous spiders is discovered, and soon they mutate to gigantic proportions and wreak havoc on the city.', 89, '0+', '2013-02-08', 'Science Fiction/Thriller'),
(1063379, 'Kopciuszek', 'https://image.tmdb.org/t/p/original/clDFqATL4zcE7LzUwkrVj3zHvk7.jpg', 'Cinderella, an orphaned girl with an evil stepmother, has big dreams and with the help of her Fabulous Godmother, she perseveres to make them come true.', 113, '7', '2021-09-03', 'Fantasy/Romance/Comedy'),
(1063380, 'The Fan', 'https://image.tmdb.org/t/p/original/uBUfrSpgQacEnjcMjpDszQTTqsL.jpg', 'A record store clerk is an obsessed fan of an actress of stage and screen. However, when faced with rejection, the fan strikes out in increasingly violent ways.', 95, '0+', '1981-05-15', 'Drama/Horror/Thriller'),
(1063381, 'Tatsumi', 'https://image.tmdb.org/t/p/original/iZOc4CM6y9uxENQp7G871AYG1zE.jpg', 'Animated film based on the life and stories of Manga writer Yoshihiro Tatsumi who revolutionised the art form with darker, more adult stories. The film animates several of his stories.', 94, '0+', '2011-09-15', 'Animation/History/Drama'),
(1063382, 'Fenomen', 'https://image.tmdb.org/t/p/original/roUYK9EXmgyDO48Qje7rZI4Qgav.jpg', 'An ordinary man sees a bright light descend from the sky, and discovers he now has super-intelligence and telekinesis.', 123, '0+', '1996-07-05', 'Drama/Romance/Science Fiction/Fantasy'),
(1063383, 'Nigdy więcej', 'https://image.tmdb.org/t/p/original/wV4kj1ovmLYRY6Voqru0WCyT13S.jpg', 'Working-class waitress Slim thought she was entering a life of domestic bliss when she married Mitch, the man of her dreams. After the arrival of their first child, her picture perfect life is shattered when she discovers Mitch\'s hidden possessive dark side, a controlling and abusive alter ego that can turn trust, love and tranquility into terror. Terrified for her child\'s safety, Slim flees with her daughter. Relentless in his pursuit and enlisting the aid of lethal henchmen, Mitch continually stalks the prey that was once his family.', 114, '18', '2002-05-21', 'Drama/Thriller'),
(1063384, 'Spirited Away: W krainie Bogów', 'https://image.tmdb.org/t/p/original/gSqglWhte6Q3zT71ovD1Ww4ckzd.jpg', 'A young girl, Chihiro, becomes trapped in a strange new world of spirits. When her parents undergo a mysterious transformation, she must call upon the courage she never knew she had to free her family.', 125, '12', '2001-07-20', 'Animation/Family/Fantasy'),
(1063385, 'North Mountain', 'https://image.tmdb.org/t/p/original/6YW5EEUE2CSpv8vvZ5nAMa8JfxS.jpg', 'Wolf, a young métis hunter living on the mountain. While hunting deep in the woods he discovers Crane, an older man with a mysterious past and the scars to prove it. Wolf nurses him back to health. Over time their bond gets deeper and they fall in love. When outsiders begin to show up looking for Crane, blood begins to flow. Cornered by an army of crooked cops, Wolf and Crane work together to boobie trap the mountain, taking them out one at a time until they come face-to-face with the man who pulls the strings…. Bretten Hannam’s debut feature is an ambitious action/thriller with outstanding performances from Justin Rain (Defiance) and Festival favourite Glen Gould (Rhymes for Young Ghouls, Charlie Zone).', 78, '0+', '2015-09-23', 'Thriller'),
(1063386, 'Harvey', 'https://image.tmdb.org/t/p/original/dgd82hYmpiXDM1G867HqNaWe8wj.jpg', 'The story of Elwood P. Dowd who makes friends with a spirit taking the form of a human-sized rabbit named Harvey that only he sees (and a few privileged others on occasion also.) After his sister tries to commit him to a mental institution, a comedy of errors ensues. Elwood and Harvey become the catalysts for a family mending its wounds and for romance blossoming in unexpected places.', 104, '0+', '1950-12-04', 'Comedy/Fantasy'),
(1063387, 'Radio Pirates', 'https://image.tmdb.org/t/p/original/qIQ43Xb49sLPSIwzG7RSgoQeuZe.jpg', 'Three unlikely people set up a pirate radio station in this musical comedy.', 89, '0+', '1935-08-18', 'Comedy/Music'),
(1063388, 'Dead Lenny', 'https://image.tmdb.org/t/p/original/s22d6o0SPaon75ONrn3LCK7Mi7H.jpg', 'A local New York City mobster named Tony Thick is expecting $5 million in cash to be delivered by Lenny Long from Los Angeles. Soon enough he realizes Lenny is missing, and it\'s unknown whether he is dead or he stole the money and ran away. Thick sends Shady, his made man, to L.A. to look for the missing cash. In his search, Shady meets Lenny\'s baby-desperate wife Sally, his ditsy mistress Eve, his muscle headed brother Louis, his quirky neurosurgeon Dr. Hooker, and a crew of other nut jobs.  None of them know where Lenny is or what happened to him, but they all know that Lenny promised them a share of the money. With Lenny discovered in the San Fernandino hospital, drifting in and out of a coma, Shady has to discover where the money is.', 89, '0+', '2007-01-25', 'Comedy'),
(1063389, 'Class Dismissed', 'https://image.tmdb.org/t/p/original', 'It\'s official; class is back! Riots on the street, old-Etonians in government, a workforce on strike, \"Downton Abbey\", \"The King\'s Speech\", the royal wedding and vajazzling. In this one-off special, Frank Skinner is joined by comedians Micky Flanagan, Roisin Conaty and Miles Jupp to assess whether class is still relevant in the 21st century. Probing analysis meets comedy chat, as our comics become intrepid reporters, examining the subject through their own unorthodox reports.', 30, '0+', '2011-12-14', 'Comedy');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1063390, 'Ocalić Nowy Jork', 'https://image.tmdb.org/t/p/original/hg2R1TllSeXGeHYJjIqWuIJ6SKF.jpg', 'Cold War tensions climb to a fever pitch when a U.S. bomber is accidentally ordered to drop a nuclear warhead on Moscow.', 86, '0+', '2000-04-09', 'Drama/Thriller/TV Movie'),
(1063391, 'Niebezpieczne zwierzęta', 'https://image.tmdb.org/t/p/original/oQJ1PKLIE2gF5cr3xwjLCvv4jcU.jpg', 'A savvy and free-spirited surfer is abducted by a shark-obsessed serial killer. Held captive on his boat, she must figure out how to escape before he carries out a ritualistic feeding to the sharks below.', 98, '0+', '2025-06-05', 'Horror/Thriller'),
(1063392, 'Schulmädchen-Report 5. Teil: Was Eltern wirklich wissen sollten', 'https://image.tmdb.org/t/p/original/yARD8zy28uJEzitUGD5mxyvU8yl.jpg', 'Seven more first-hand accounts of sexual awakening amongst school girls in the early Seventies.', 86, '0+', '1973-04-13', 'Drama/Romance'),
(1063393, 'Hunting Season', 'https://image.tmdb.org/t/p/original/aOWGN74O8FJzs45LlXENcinpo6Q.jpg', 'When two campers on a peaceful weekend excursion are suddenly confronted, harassed, and molested by a pack of heavily armed outdoorsman, a brutal series of events ensues. A struggle for survival and sanity drives the surviving victim into a bloody vendetta of rage. The hunters become the hunted in a malicious game of cat and mouse.', 90, '0+', '2000-01-01', 'Horror'),
(1063394, 'The Hustle', 'https://image.tmdb.org/t/p/original/dZRvLYqjl5QLPpYAjArHrw2aolz.jpg', 'What do you do when your biggest dream is just an arms reach away. Tre-Dog and C-Note long for the day to be the biggest rap stars in the city of Ft. Lauderdale but don\'t have the dough or the connections to get there. When a bogus record label offers to sign them if they can come up with their own promotion money, the hustle is on. The two rappers scam their way into raising 20,000 dollars the fast way, stealing it. Now two be wannabee rap stars are on the run from one of the hood\'s most dangerous drug ealers. Is their dream worth dying for or can they hustle their way out of this one? The Hustle is definitely a slap your knee, gut busting comedy about two hustlers who find themselves getting hustled.', 93, '0+', '2003-11-25', 'Comedy'),
(1063395, 'La madre', 'https://image.tmdb.org/t/p/original/sR7yrYPY0zpggsJmR0MGZCsN5Z5.jpg', 'Miguel is a 14-year-old kid about to go back to a centre for minors. His mother, out of work and with an unstable personal life, is incapable of taking care of him. This is why Miguel lives in a state of constant urgency, doing the housework, selling Kleenex or stealing from supermarkets. All this ends when Social Services come for him again, and his mother makes him seek refuge in the house of Bogdan, a Rumanian ex-lover of hers who lives in a nearby town. At the same time, María, the owner of a bar, sympathizes with the boy and gives him the virtually maternal treatment that he does not get in his own home. However, everything is thrust forward when the mother suddenly disappears', 89, '0+', '2016-10-28', 'Drama'),
(1063396, 'Fall Creek', 'https://image.tmdb.org/t/p/original/76D1EJzcMBdTPHl4Fa0vfjmB1Gn.jpg', 'A homage to nature and a plea for a careful approach to it. In one of his early films, Jon Jost shows impressions of a stream in the forest and a couple streaming through the forest: direct looks into the camera, cross-fades, multiple exposures, playing with sunlight, shadows and shapes. At the end, the appeal of a Wintu indigenous man who condemns the reckless treatment of the whites with nature is faded in.', 14, '0+', '1970-01-01', NULL),
(1063397, 'Obietnica', 'https://image.tmdb.org/t/p/original/7MEeXccpbNHB17mfVZRhRB6ZrtC.jpg', 'A police chief about to retire pledges to help a woman find her daughter\'s killer.', 124, '16', '2001-01-19', 'Crime/Drama/Mystery/Thriller'),
(1063398, 'Pentecost', 'https://image.tmdb.org/t/p/original/5xCV8ytQjSHOaezRJ7JUtxYBp9Y.jpg', 'Ireland 1977. Eleven-year-old Damian Lynch (Scott Graham) is called in at the last moment to serve as an altar boy at an important mass in his local parish. Following his last appearance as an altar boy when he knocked Father O\'Toole off the altar, Damien is serving a 3 month ban from his only passion in life...football. To make matters worse, Damian\'s team, Liverpool FC, are playing in their first European cup final in two weeks time. Damien\'s father (Michael McElhatton) offers him a reprieve and crucially a chance to see the European cup final if he serves the mass correctly. Damien now faces a choice: either conform to the status quo or never watch his beloved Liverpool play again...', 11, '0+', '2010-11-01', 'Comedy'),
(1063399, 'Ninja Warriors', 'https://image.tmdb.org/t/p/original/ddNOt9GA87HK7YltiYwITIsyLmJ.jpg', 'Steve is a Ninja. He\'s been called in by the police to help them in their investigations. He\'s to work with Kevin, a police lieutentant. They are investigating the break-in at the Federal Research Institute, where despite heavy security, 7 Ninja warriors manage to steal a vital document.  Well pleased with their night\'s work, they return to their master, Kurodo, who finds they only have a half of the information they need.  The police capatain wants results. Kevin suspects that a Japanese Garden he visited once with Steve could be the headquarters of Kurodo and his Ninja\'s and goes in search of proof. He\'s caught spying and is tortured and killed.  After the disappearance of Kevin, Steve opens his Ninja box. He breaks the seal of his Katana and starts the Mantra.  He attacks the Japanese Garden, eliminates the Ninja warriors and after recovering the documents and blowing up the laboratory, finally meets Kurodo, there can only be one victor...', 90, '0+', '1985-06-01', 'Action'),
(1063400, 'Finding Faith', 'https://image.tmdb.org/t/p/original/jzZMtGktGqC2z9jjHiQTpMZkVa7.jpg', 'The Garretts are the envy of most families in their small town. But when their 14-year-old daughter falls victim to a skillful online predator, the family\'s strength is tested as they search with Sherriff Brown and the Internet Crimes Against Children task force to find their missing child.', 111, '0+', '2013-01-15', 'Thriller/Drama'),
(1063401, 'Never Land', 'https://image.tmdb.org/t/p/original/fvBQIo4SQzatndo2ib2Y8H6wvNt.jpg', 'Aimee Dent had to grow up fast. She is raising her little brother all on her own. But her life is changed forever when she meets a teenage boy who gives her a taste of what it\'s like to be a kid again. However, Aimee soon finds out that the boy, Peter, isn\'t everything he appears to be or as young. She learns that Peter will never be able to grow up, because he\'s a vampire.', 39, '0+', '2010-09-09', NULL),
(1063402, 'Moe', 'https://image.tmdb.org/t/p/original/fhgJMBJfxnGKrPtPKhY2TP7snyU.jpg', 'Moe, a fun-loving theater artist working on a one woman show, finds out that he is dying from an AIDS related illness. Naturally, his response is to invite his closest friends over for a “going away for good” party as one last big celebration of his life. His plans go awry when his best friend, and his ex, decide to crash the party, despite 15 years without communication between them. Alternating between the painful reality of his current situation and scenes featuring his alter ego, a torch-singing drag queen who wants to take him for “the ride of his life,” MOE is an often light-hearted film that also packs a serious emotional punch.', 80, '0+', '2023-06-04', NULL),
(1063403, 'Moja wina, Londyn', 'https://image.tmdb.org/t/p/original/pGEs2gyhKKe5bYfIyI1CML75iX2.jpg', '18-year-old Noah moves from America to London, with her mother who\'s recently fallen in love with William, a wealthy British businessman. Noah meets William’s son, bad-boy Nick, and soon discovers there is an attraction between them neither can avoid. As Noah spends the summer adjusting to her new life, her devastating past will catch up with her while falling in love for the first time.', 118, '0+', '2025-02-12', 'Romance/Drama'),
(1063404, 'The Jailhouse', 'https://image.tmdb.org/t/p/original/5thdKJOzBX49FByo9J6fU9aVWbd.jpg', 'Small town, the American dream. A blue-collar family living the idyllic rural lifestyle. Nothing is out of place save for the lacking white picket fence - and the old JAIL that occupies the 2nd floor of their century-old home. Seth Delray knew the possibilities before he moved his wife and two kids into the old jailhouse, but the Sheriff assured him that it would take an act of God to put that place back into service. Times were tight, and it was just too good of a deal to refuse. That is, until the county jail caught fire. The Sheriff\'s hands were tied and he had to put displaced inmates anywhere he could find iron bars with a locking door. The Delray house was his only option. For Seth the worst wasn\'t the criminals locked like animals in the soiled cages above his living room. It was the mortal fear in his children\'s eyes, it was the piercing cold looks from his wife. It was that deep..', 86, '0+', '2009-05-01', 'Thriller/Horror/Mystery'),
(1063405, 'Quick Millions', 'https://image.tmdb.org/t/p/original/2NDXUrJzSOtn3v8rhLkTi6mXoN5.jpg', 'A truck driver \"too lazy to work and too nervous to steal\" gets mixed up in racketeering. Naturally his underhanded business practices make him a pillar of the community.', 72, '0+', '1931-04-17', 'Crime/Drama'),
(1063406, 'Nebo sateliti', 'https://image.tmdb.org/t/p/original/tbWB2ouDBYBZ9w36PykLw8YJDtg.jpg', 'When two enemy sides ex-change the captives in the middle of a minefield, a nameless man without identity and memory, subsequently named Jakov, leaves the column unnoticed and wanders around in order to minimize other people\'s sufferings. On his dangerous journey, he meets a female first-fighter who runs an orphanage, a commander who got back from Foreign legion and runs a defense line from a disco club, and goes through many other adventures only to end up in the endless backwaters of the Neretva river where war threats to arrive.', 81, '0+', '2000-01-01', 'Drama/War/Fantasy'),
(1063407, 'Without Love', 'https://image.tmdb.org/t/p/original/54ayABmVMl9YVbURzShhRDLXrNQ.jpg', 'In World War II Washington DC, scientist Pat Jamieson\'s assistant, Jamie Rowan, enters a loveless marriage with him. Struggles bring them closer together.', 111, '0+', '1945-03-22', 'Romance/Comedy'),
(1063408, 'Nędzne psy', 'https://image.tmdb.org/t/p/original/2EQbuv5A9st3gRWTQTvNkDuCNjo.jpg', 'A young couple moves to a quaint southern town. Soon their perfect getaway turns out to become a living hell when dark secrets and lethal passions spiral out of control.', 110, '18', '2011-09-16', 'Drama/Thriller'),
(1063409, 'Trust', 'https://image.tmdb.org/t/p/original/n9GS1mUAVMiC3gBn9rb8jrDoK4D.jpg', 'A Hollywood starlet seeks refuge in a secluded Airbnb following a high-profile scandal, only to find herself at the mercy of hardened criminals on the hunt for a score.', 86, '0+', '2025-08-22', 'Thriller'),
(1063410, 'Comic Aid', 'https://image.tmdb.org/t/p/original', 'Shot live at the one off Comic Aid benefit gig at London’s Carling Apollo – which sold out in just three and a half minutes of tickets being put on sale – the DVD features the entire uncut show for all those unfortunate enough to have missed out on tickets.  The 3 hour show sees Jonathan Ross, Jack Dee, Graham Norton, Julian Clary, and Lily Savage host a stellar comic line-up that includes; Lee Evans, Dawn French, Jimmy Carr, Ardal O’Hanlon, Johnny Vegas, Bill Bailey, Bo’ Selecta! star The Bear, Jo Brand, Jon Culshaw, Omid Djalili, Otis Lee Crenshaw, Eddie Izzard, The League Of Gentlemen with Miranda Richardson, Alistair McGowan, Dylan Moran, Dave Spikey, Simon Pegg & Jessica Stevenson. Psychological illusionist Derren Brown and international percussion sensation Stomp also present their own unique blend of stage entertainment.', 167, '0+', '2005-03-02', 'Comedy/TV Movie'),
(1063411, 'Say Less', 'https://image.tmdb.org/t/p/original/afW2lDdemCVcNlkQF4aIfoB7CAR.jpg', 'Teen siblings Cassie and Max find themselves home alone for the weekend after their parents leave town. Cassie hopes to invite her crush, Blake, over for a study date, while Max plans an intimate evening with his girlfriend, Sky. However, tensions rise when Blake doesn’t respond to Cassie’s texts, and Max taunts her about having no friends. Determined to prove him wrong, Cassie invites Oliver, a boy she previously ignored, to join the group. Cassie’s actions turn Max’s romantic plans into a chaotic double date, setting the stage for a night full of conflict and unexpected discoveries that might tear the family apart forever.', 81, '0+', NULL, 'Comedy/Drama/Romance'),
(1063412, 'The Struggle', 'https://image.tmdb.org/t/p/original/16JxxqssKHzxZ4Fu9UaXvsRn0MR.jpg', 'In The Struggle (Broncho, 1913) a prospector and his son Bob depart from home in the morning, while the wife, at home, offers food to a passing stranger. His shifting eyes reveal his nature; he assaults her, and although her husband and son return in time to save her, the father is killed in the ensuing fight. The stranger gets away, but five years later Bob, now a government scout, recognizes the stranger just as he is accused of cheating at cards.', 24, '0+', '1913-01-20', 'Western'),
(1063413, 'CONFLICT 〜最大の抗争〜 第一章 勃発編', 'https://image.tmdb.org/t/p/original/AhyEfjBAG4GvL7T7Co2xoxPUX6N.jpg', 'The Hyodo-gumi boss—part of Tendokai, Japan’s largest yakuza syndicate—has been brutally murdered.  Kazuma Washio (Hitoshi Ozawa), the head of the Washio-gumi and Tendokai’s wakagashira (underboss), is convinced that Yoshinari Myojin (Sho Aikawa), a former Tendokai wakagashira-hosa now running Tokyo’s underworld of thugs and mafia, is behind the killing.  Around the same time, Tendokai\'s 5th-generation chairman Katsushige (Hakuryu) orders Washio to secure a woman named Nagi Toyama (Akane Hotta).  Washio sets out with his men, Okita (Yasukaze Motomiya) and Date (Hideo Nakano), but they’re ambushed by a group of heavily armed youths.  Barely escaping, they manage to bring Nagi to their hideout—only to discover she’s a key player in a power struggle over the Tokyo Casino Project.  And so begins the greatest conflict yet, entangling yakuza, mafia, street gangs, the police, and even the state itself—', 79, '0+', '2016-05-28', 'Crime/Action/Drama'),
(1063414, 'Christmas Joy', 'https://image.tmdb.org/t/p/original/nyBL0NqfIgMrtAGTp7W2ilosvpz.jpg', 'Joy Holbrook, is a corporate market researcher, gunning for a promotion within her firm. Just as her company\'s CEO is taking notice, Joy finds out her Aunt Ruby has broken her ankle and will be undergoing surgery. Despite the less than opportune timing, Joy makes her way back home to Crystal Falls, NC to be with her Aunt. Stars seem to be aligned as Joy sees her former crush, Ben Andrews, while at the hospital. At first, Joy is focused solely on helping her Aunt heal; even taking over her position as chair of the local Cookie Crawl competition. Eventually, she begins to let Ben in and remembers there\'s no place like home for the holidays. The pair work together on the Cookie Crawl to make the event a success.', 84, '0+', '2018-11-03', 'Family/TV Movie/Romance'),
(1063415, 'Mad Love', 'https://image.tmdb.org/t/p/original/lDD8pKd6jSrFLV3RvE0eDGGGxR0.jpg', 'An insane surgeon\'s obsession with an actress leads him to replace her wounded pianist husband\'s hands with those of a knife-throwing murderer.', 68, '0+', '1935-07-12', 'Horror/Romance'),
(1063416, 'Noc zombie', 'https://image.tmdb.org/t/p/original/iS1tYFialjnYQ1pDLYN7gX3TG0J.jpg', 'Zombies come out at night and two families must survive until morning.', 88, '0+', '2013-10-08', 'Horror'),
(1063417, 'Niebo', 'https://image.tmdb.org/t/p/original/xPdtOuGtcQt655uRrmIdBkSRmVx.jpg', 'Cate Blanchett stars as Philippa, a British teacher living in Turin, Italy, who has seen many friends, including her husband, fall victim to drug overdoses. Philippa has repeatedly contacted the police with information about Turin\'s biggest drug dealer but, complicit in his dealings, they have completely ignored her. So Philippa decides to dole out her own form of justice with a homemade bomb -- setting her off on a journey from young widow to fugitive on the run.', 96, '16', '2002-02-06', 'Drama/Thriller/Romance/Crime'),
(1063418, 'Spider-Man: Poprzez multiwersum', 'https://image.tmdb.org/t/p/original/aSQijwZ3o2qtUczdhFHdqtp9NZm.jpg', 'After reuniting with Gwen Stacy, Brooklyn’s full-time, friendly neighborhood Spider-Man is catapulted across the Multiverse, where he encounters the Spider Society, a team of Spider-People charged with protecting the Multiverse’s very existence. But when the heroes clash on how to handle a new threat, Miles finds himself pitted against the other Spiders and must set out on his own to save those he loves most.', 140, '7', '2023-05-31', 'Animation/Action/Adventure/Science Fiction'),
(1063419, 'Ernani - ROMA', 'https://image.tmdb.org/t/p/original/5QJy521xikwiWZAG62tEtCMWVKL.jpg', 'Ernani is a love story about a young woman, Elvira, caught between three men: her lover, the nobleman-turned-outlaw Ernani; her guardian, the rich, elderly de Silva, who wants her for himself; and Don Carlo, the King of Spain who also has his eye on Elvira. Given the number of protagonists, it is also the story of a tragedy.  Only 14 years after the premiere of Hernani, Giuseppe Verdi adapted Victor Hugo’s play into an opera to premiere at La Fenice, Venice in 1844. Ernani was an immediate and lasting triumph for the young Verdi, marking his prowess at adapting an historical event (the crowning of Charles V as emperor at Aachen Cathedral) to a psychologically convincing musical drama. The backdrop of three men paying court to one woman was the perfect foil for Verdi to explore the expressive qualities of three types of male voice. The tenor, the bass and the baritone.', 0, '0+', '2022-07-29', NULL),
(1063420, 'Mr. Horn', 'https://image.tmdb.org/t/p/original/qGnr6FjXH4Rsbk6QYo1WB7a1mIp.jpg', 'Western saga based on the legend of frontier folk hero Tom Horn, including his role in the trackdown of Geronimo in the 1880s with his mentor and pal, Al Sieber, the fabled Indian scout, his later days as a Pinkerton detective, and the way he was used by both sides in turn-of-the-century cattle wars, leading to his tragic death.', 180, '0+', '1979-02-01', 'Western'),
(1063421, 'The Strangler', 'https://image.tmdb.org/t/p/original/dnttPCxSz367Ue2htpedKXSnAWx.jpg', 'An overweight lab technician with low self esteem, brought on by his dominant mother, becomes a serial killer of female nurses.', 89, '0+', '1964-04-01', 'Horror'),
(1063422, 'Jesus', 'https://image.tmdb.org/t/p/original/gf8mntERjDLRrULnsCOoumeWSRp.jpg', 'Michel Auder’s Jesus – in which underground NY artists and Warhol superstars openly discuss their beliefs. Jesus – which premiered as a screening at The Kitchen in 1980 – mixes documentary elements such as footage of evangelical TV programs, books, cartoons, paintings, and other Jesus related imagery – with performances including Taylor Mead as a priest in the West Village and Florence Lambert playing a crucified Jesus. Also, intercut throughout are surprisingly candid interviews with Auder’s friends, family, and people he approaches on New York City streets about their faith and relationship to the world’s most famous person. Among those interviewed are Diego Cortez, Jackie Curtis, Gerard Malanga, Alice Neel (Andrew Neel’s grandmother), Larry Rivers, and Viva.', 59, '0+', '1979-01-01', 'Documentary'),
(1063423, 'Szpiedzy', 'https://image.tmdb.org/t/p/original/rgBGZ2XuVSxRxG5MGuOv3eLUk25.jpg', 'When intelligence agent Kathryn Woodhouse is suspected of betraying the nation, her husband – also a legendary agent – faces the ultimate test of whether to be loyal to his marriage, or his country.', 94, '0+', '2025-03-12', 'Drama/Mystery/Thriller'),
(1063424, 'Bizet: Carmen', 'https://image.tmdb.org/t/p/original/me0J21ZQt3cQEEvx8EqIhsg2igO.jpg', 'Richard Eyre’s stunning new production of Bizet’s opera was the talk of the town when it was unveiled on New Year’s Eve 2009. Elīna Garanča leads the cast as the iconic gypsy of the title—a woman desired by every man but determined to remain true to herself. Roberto Alagna is Don José, the soldier who falls under her spell and sacrifices everything for her love, only to be cast aside when the toreador Escamillo (Teddy Tahu Rhodes) piques Carmen’s interest. With dances created by star choreographer Christopher Wheeldon and conducted by rising maestro Yannick Nézet-Séguin, this Carmen brings every aspect of Bizet’s tale to thrilling life, from its lighthearted beginning to its inevitably tragic climax.', 166, '0+', '2010-01-15', 'Music/Drama'),
(1063425, 'Mandarin Peel', 'https://image.tmdb.org/t/p/original/31o7DhvYCSY90c207hz3JL8Zgaj.jpg', 'Mandarin Peel is a haiku. Through a lens of memory and dreams, two girls explore their friendship and the joy of a juicy mandarin in the dry Australian landscape. An evocative montage, the film evokes tactile experiences and revels in the visceral. It\'s a musing on childhood, kinship, instincts, violence and forgiveness. The children of Mandarin Peel serve as metaphors for Australia itself, its exploration of identity, forging relationships, inventing history and future.', 5, '0+', '2009-08-09', 'Drama'),
(1063426, 'Twisted Desire', 'https://image.tmdb.org/t/p/original/u5oYWIKUxSM20xKQsjG5gfX0JKq.jpg', 'A teenage girl convinces a young, love-struck ex-con that the only way they can be together is to do away with her domineering parents.', 96, '0+', '1996-05-13', 'Crime/Drama/TV Movie'),
(1063427, 'Zróbmy zemstę', 'https://image.tmdb.org/t/p/original/a3YlA239OK0OippgHZcURSeJq0s.jpg', 'A dethroned queen bee at a posh private high school strikes a secret deal with an unassuming new student to enact revenge on one another’s enemies.', 118, '0+', '2022-09-14', 'Comedy/Thriller/Romance'),
(1063428, 'Broken Hallelujah', 'https://image.tmdb.org/t/p/original/hDGbcxG3Ind1W6hIKuJhi5hH4IO.jpg', 'The best of plans can be thwarted and, when the pressure comes on, the cracks begin to show. As the incidents in their worlds play out, three families bound by love and broken by betrayal, find their lives unknowingly touch one another, and then a final single event brings them together. This is not a love story but a story about love; three loves, three lies and one more chance.', 135, '0+', '2014-02-06', 'Drama'),
(1063429, 'Borrowed Finery', 'https://image.tmdb.org/t/p/original', 'Dress model Sheila Conroy loses her job after ruining a gown she borrowed from her employer. Harlan, a criminal posing as a government agent, offers Sheila work as his assistant. She accepts for the sake of her brother-in-law, Billy, who embezzled money from his firm and is in danger of discovery. Her assignment is to obtain the necessary \"evidence\" on Mrs. Bordon, a wealthy widow who smuggled a valuable jewel into the country. Channing Maynard, a real government agent, reveals the truth to Sheila, and after they bring Harlan to justice, Channing takes Sheila for his bride.', 69, '0+', '1925-10-01', 'Drama'),
(1063430, 'The Awakened', 'https://image.tmdb.org/t/p/original/h9tDLNxO1BigDS1DrkEiIVbz2DI.jpg', 'Five friends have a party to ride out a hurricane in Miami. As if it were not bad enough being trapped inside the house while natural forces wreak havoc outside, something is trapped inside with them. The storm is the least of their worries trying to make it through the night.', 90, '0+', '2012-09-08', NULL),
(1063431, 'Cocote', 'https://image.tmdb.org/t/p/original/5aobAPTPLFsXyN6sPm0l9nwapLH.jpg', 'A rapturous crime fable set in the Dominican Republic, Nelson Carlo De Los Santos Arias’ COCOTE follows Alberto, a kind-hearted gardener returning home to attend his father’s funeral. When he discovers that a powerful local figure is responsible for his father’s death, Alberto realizes that he’s been summoned by his family to avenge the murder. It’s an unthinkable act — especially for him, an Evangelical Christian. But as pressure mounts, he sees few ways out. Questions of faith, tradition and honor course through this electrifying film, which, seemingly at the speed of thought itself, jumps between film formats, colors, and aspect ratios, radically envisioning a community torn asunder by senseless violence.', 106, '0+', '2017-08-21', 'Drama'),
(1063432, 'Wojownicze Żółwie Ninja', 'https://image.tmdb.org/t/p/original/mWAK5vtjMKaKQB9c3iHiCQbVxVd.jpg', 'When a kingpin threatens New York City, a group of mutated turtle warriors must emerge from the shadows to protect their home.', 101, '12', '2014-08-07', 'Science Fiction/Action/Adventure/Comedy'),
(1063433, 'Freedom Besieged', 'https://image.tmdb.org/t/p/original/vaV7nbnux8mOGCcSkkrzDVjXlb3.jpg', 'Freedom Besieged is a feature-length documentary concerning the economic and political climate of Greece and specifically how such has impacted the development and psychology of the nation\'s youth. Treading fearlessly into what has been called a \"humanitarian catastrophe\", the film explores the pursuits of Greek youth living within the country\'s crisis. Freedom Besieged is an intimate portrait of a young Greek generation who serve as the focal point for the future of European youth today.', 98, '0+', '2017-01-27', 'Documentary'),
(1063434, 'The Finale', 'https://image.tmdb.org/t/p/original/9WOGqHUuwcfpnZdA9iMLVn6pxDF.jpg', 'Sagan Riley is a triple threat who has her sights set on Broadway. When she’s accepted to the legendary Stage Left Theater Camp, she thinks her dreams are within reach. Sagan spends her days singing, dancing, acting, and dreaming of love. But soon the Stage Left instructors and Sagan’s fellow campers start dying off one by one. Now, Sagan will have to survive rehearsal and discover the killer, if she’s ever gonna make it.', 132, '0+', '2023-07-28', 'Horror/Thriller'),
(1063435, 'Talking Head', 'https://image.tmdb.org/t/p/original/qkeChq01PeK3KM31PcmpVzlMI62.jpg', 'An elusive actor is a rarity. Talking Head is about the actor Dhritiman Chaterji. In October 1970, Pratidwandi (The Adversary) one of Satyajit Ray’s most political films was released. It was a film about the time; the moment of anger, disenchantment, strikes, injustice and unemployment among the young. It was a film about angry youth and it introduced Dhritiman Chaterji, into film acting. A new actor in Bengali cinema, Dhritiman Chaterji acted in few of the most prominent films of the decade', 94, '0+', '2020-12-17', 'Documentary'),
(1063436, 'Ratownicy z Malibu', 'https://image.tmdb.org/t/p/original/7pWOciZg6BsZytgV63oReKoHbWs.jpg', 'When a long list of shenanigans lands Tyler in hot water, he’s forced to suit up and spend his summer training for an elite junior lifeguard program.', 69, '0+', '2019-05-13', 'Action/Comedy/Family'),
(1063437, 'Billy Madison', 'https://image.tmdb.org/t/p/original/sOdgtJdFalL9kRKaeJItARLTAEq.jpg', 'Billy Madison is the 27 year-old son of Bryan Madison, a very rich man who has made his living in the hotel industry. Billy stands to inherit his father\'s empire, but only if he can make it through all 12 grades, 2 weeks per grade, to prove that he has what it takes to run the family business.', 90, '0+', '1995-02-10', 'Comedy'),
(1063438, 'Secuestro diabolico', 'https://image.tmdb.org/t/p/original/79p4HPAGQrCmVaPpq5rIwJ5mptf.jpg', 'Second film in the Tigres del ring series.', 87, '0+', '1957-01-01', 'Crime/Drama'),
(1063439, 'Następcy 2', 'https://image.tmdb.org/t/p/original/qWQL4Zp4XMl4mneCidjkwwLiyD9.jpg', 'When the pressure to be royal becomes too much for Mal, she returns to the Isle of the Lost where her archenemy Uma, Ursula\'s daughter, has taken her spot as self-proclaimed queen.', 111, '12', '2017-07-21', 'Family/Fantasy/TV Movie/Adventure/Music'),
(1063440, 'Kings Ransom', 'https://image.tmdb.org/t/p/original/uAYsPWIER2xyRX2voaXdifZcZox.jpg', 'On August 9, 1988, the NHL was forever changed with the single stroke of a pen. The Edmonton Oilers, fresh off their fourth Stanley Cup victory in five years, signed a deal that sent Wayne Gretzky, a Canadian national treasure and the greatest hockey player ever to play the game, to the Los Angeles Kings in a multi-player, multi-million dollar deal. As bewildered Oiler fans struggled to make sense of the unthinkable, fans in Los Angeles were rushing to purchase season tickets at a rate so fast it overwhelmed the Kings box office. Overnight, a franchise largely overlooked in its 21-year existence was suddenly playing to sellout crowds and standing ovations, and a league often relegated to “little brother” status exploded from 21 teams to 30 in less than a decade.', 53, '0+', '2009-09-13', 'Documentary'),
(1063441, 'Kolizja', 'https://image.tmdb.org/t/p/original/k4KWmmV51Cc7bIFbaS4jzz9PYGf.jpg', 'Over the course of one fateful day, a corrupt businessman and his socialite wife race to save their daughter from a notorious crime lord.', 99, '0+', '2022-06-16', 'Thriller/Crime/Drama'),
(1063442, 'Mściciel z Hongkongu', 'https://image.tmdb.org/t/p/original/3AaPWvywczDIeGFCjUvohBIMzJL.jpg', 'A casino security guard is forced into violence from when the Hong Kong mob threatens his friends.', 90, '0+', '1982-07-30', 'Action/Adventure/Thriller/Drama'),
(1063443, 'Heavy Vinyl', 'https://image.tmdb.org/t/p/original/xHBGmvW21q2IuWLGfkWQdwpioa4.jpg', 'Denny and Jeremy love Heavy Metal and old school vinyl records, especially those rumored to have Subliminal Backwards Messages. When they find a copy of Sealed Fayte\'s infamous, banned and out-of-print debut album, they can\'t get it on the turntable fast enough - and that\'s when the s--t hits the fan leaving only them and Denny\'s sister, Hallie, to figure out how to save the world from the terror unleashed on 180gram heavy vinyl.', 17, '0+', '2023-01-13', 'Horror'),
(1063444, 'Stam', 'https://image.tmdb.org/t/p/original/dlRRBwvnnL9Rty6VeFkGsmSqflp.jpg', 'In a small section of inner-city Cape Town, Chantal, a fugitive addict loses track of her child, Jona, when she leaves him behind all alone to turn one final trick. Dawid, a frustrated cop faces up to the demons from a traumatic childhood. Samiah, a young nurse clings to a disintegrating bubble of fantasy that shields her from facing life on life’s terms. Aphiwe, an up-and-coming art director in a crumbling relationship, is confronted by his fear of connection as he looks for salvation beyond his impenetrable personal boundaries. In a city wracked by conflict, contradiction and harsh battles for survival, the four main characters each discover surprising and profound truths about their purposes as human beings through their inextricable connections to others. Fear meets hope. Anger meets love. Loss meets meaning. One night, one city, four lives changed forever and bound together by the unblinking gaze of an innocent child.', 75, '0+', '2020-09-04', NULL),
(1063445, 'Nemo', 'https://image.tmdb.org/t/p/original', 'The wind swirls up dust in a desert landscape. The picture is followed by images of clouds racing over the skyline of a city, of reflections on an expanse of water, of waves breaking over an embankment and of row upon row of burning candles. Then, gradually, music sets in: It initially accompanies the images, supports the patterns of movement in their characteristic style, pushes them ahead and enhances their drama. In Nemo, named after the captain in Jules Vernes «Twenty Thousand Leagues under the Sea», Morrison utilizes images of nature and natural phenomena to compose a cinematic poem about time and transience. (Claudia Slanar)', 6, '0+', '1995-04-04', NULL),
(1063446, 'Bloodlines', 'https://image.tmdb.org/t/p/original/tbMdk4b2riDwfYbhXXWxah3JaCj.jpg', 'Based on one of the most famous mysterious disappearances in the world, Richard John Bingham, the Seventh Earl of Lucan, was accused of the murder of 29-year-old nanny Sandra Rivett on 7 November 1974, at his family home at 46 Lower Belgrave Street, in London. Three days later, police found his borrowed Ford Corsair abandoned some 16 miles away near the docks of Newhaven. Since then there have been many reported \'sightings\' of Lord Lucan around the globe viz. Africa, Australia, the Netherlands, Ireland and Sicily.', 110, '0+', '2004-11-08', 'Mystery'),
(1063447, 'Evangelion: 3.0+1.01 Od–nowa', 'https://image.tmdb.org/t/p/original/wEtHaLIpe1FxMBOhZ7HzCmtYb8j.jpg', 'In the aftermath of the Fourth Impact, stranded without their Evangelions, Shinji, Asuka and Rei find refuge in one of the rare pockets of humanity that still exist on the ruined planet Earth. There, each lives a life far different from their days as an Evangelion pilot. However, the danger to the world is far from over. A new impact is looming on the horizon—one that will prove to be the true end of Evangelion.', 155, '0+', '2021-03-08', 'Animation/Action/Science Fiction/Drama'),
(1063448, 'All Wrong', 'https://image.tmdb.org/t/p/original/gkhVbkzGl1JN3SoyXlofCflBnuB.jpg', 'Salesman Warren Kent develops the idea of \"The Unending Courtship\" and manages to convince his new wife Betty of his theory, which entails their living separately and only meeting on Wednesday evenings, as they did while they were engaged. Warren\'s boss, however, who was never enamored of the idea, fires him when he bungles an account and loses the company a large order. On top of that, through a series of misunderstandings Warren comes to believe that his wife is pregnant and his mother-in-law believes that Warren is having an affair with Betty\'s friend Ethel. Things go downhill for Warren from there.', 30, '0+', '1919-06-01', 'Comedy'),
(1063449, 'Paris Calling', 'https://image.tmdb.org/t/p/original/c9r525MMoHmQcKHUbOQyVXdywDg.jpg', 'Marianne Jannetier, a well-to-do Parisian, engaged to Andre Benoit, a high-ranking government official, flees the city when the goose-stepping Nazi storm-troopers arrive. When her mother dies on the road to Bordeaux as a result of Nazi bombing, she returns to Paris and joins the underground movement. Nicholas Jordan, an American member of the RAF, stranded in Paris after the evacuation is also working with the Paris underground. Marianne kills her former fiancée, a pro-Nazi informant, for the traitorous state papers he is carrying, and she and Jordan try to flee over a French seaport...', 95, '0+', '1941-12-04', 'Action/Adventure/Romance/War/Thriller'),
(1063450, 'Pink Tights', 'https://image.tmdb.org/t/p/original/8IIXaaXoG0ISoO4BdEfkAV8PHJv.jpg', 'When a circus troupe comes to a small, extremely conservative New England town, the residents go to their minister to have him protest the scandalous fact that the female tightrope walker wears a pair of pink tights. When she has an accident and is forced to recuperate at the minister\'s house, he has to hide her in order to avoid even more of a scandal. Mazie Darton, a high-wire performer with a traveling circus, longs for a peaceful country life. Forced to stay in a small town while laid up with an injury, Darton is spurned by the conservative townspeople. Rev. Jonathon Meek, the local parson, befriends the circus troupe, especially Darton. But he, too, opens himself to criticism from his flock, who protest his closeness with the show people. Eventually, Darton\'s boyfriend arrives and the pair become closer. The parson fades from the scene as a possible mate for Darton, who ends up winning the hearts of the townspeople.', 50, '0+', '1920-09-25', 'Comedy'),
(1063451, 'Dziedzictwo', 'https://image.tmdb.org/t/p/original/rEpfvgTQsc768zNND0SjMelbnLH.jpg', 'The patriarch of a wealthy and powerful family suddenly passes away, leaving his wife and daughter with a shocking secret inheritance that threatens to unravel and destroy their lives.', 110, '0+', '2020-04-30', 'Drama/Mystery/Thriller'),
(1063452, 'The Plant', 'https://image.tmdb.org/t/p/original/tCoDiOj8HnoJlsbrbygJnM38pxc.jpg', 'In a garden in a London suburb, corpses sprout out of the earth on during a live television gardening programme called Down to Earth. However, it soon appears that these human bodies are not dead people, they are grown there, like plants. The question is who is growing these bodies and for which purpose.', 84, '0+', '1995-01-20', 'Science Fiction/Drama/Romance/TV Movie'),
(1063453, 'Liberty', 'https://image.tmdb.org/t/p/original/pY0BAsoeiUWbQDNd6qGK8VMRulX.jpg', 'Liberty, a thriller, tells the story of Matt Robinson, a young Animal Park Guide who feels a deep connection with nature and the local wildlife where he lives. He takes tourists on day excursions to discover the beauty of the land around them and the animals who live freely on it. But our young hero is also an idealist, an activist for animal rights, in conflict with man, who locks up and imprisons animals for commercial and entertainment purposes. His deep love for animals and dedication to helping free those in captivity leads him to make impulsive and illegal actions.', 101, '0+', '2023-11-21', 'Thriller'),
(1063454, 'Paperman', 'https://image.tmdb.org/t/p/original/9tvF744hwTm2Bn9hkDjMfEsysKz.jpg', 'An urban office worker finds that paper airplanes are instrumental in meeting a girl in ways he never expected.', 7, '0+', '2012-11-02', 'Animation/Family/Romance'),
(1063455, 'Wrogie przejęcie', 'https://image.tmdb.org/t/p/original/vntwlS3CAKfoLTs90GaoK6lymBC.jpg', 'Follows Pete, a professional hitman, as he faces a group of assassins after the boss of a crime syndicate suspects disloyalty due to his attendance at Workaholics Anonymous meetings.', 89, '0+', '2025-08-08', 'Action/Comedy/Thriller'),
(1063456, 'The End of Evangelion', 'https://image.tmdb.org/t/p/original/yBanOpNIccxjZlH4QH7ag4ojWOI.jpg', 'SEELE orders an all-out attack on NERV, aiming to destroy the Evas before Gendo can advance his own plans for the Human Instrumentality Project. Shinji is pushed to the limits of his sanity as he is forced to decide the fate of humanity.', 87, '16', '1997-07-19', 'Animation/Science Fiction/Action/Drama'),
(1063457, 'Tolkien', 'https://image.tmdb.org/t/p/original/iiqSG5XRSfEyMC7T4lt7jpyktFD.jpg', 'England, early 20th century. The future writer and philologist John Ronald Reuel Tolkien (1892-1973) and three of his schoolmates create a strong bond between them as they share the same passion for literature and art, a true fellowship that strengthens as they grow up, but the outbreak of World War I threatens to shatter it.', 112, '12', '2019-05-03', 'War/Drama/Romance'),
(1063458, 'The Chaperone', 'https://image.tmdb.org/t/p/original/aoLPq6a1zy3ED7aHAfmQ4ensqQO.jpg', 'Extremely rare roughie in the vein of LAST HOUSE ON THE LEFT. A group of young hippies go camping accompanied by an uptight, sexually repressed, middle-aged chaperone. The chaperone is envious of the youngster\'s liberated ways and doesn\'t trust one of the young men. Then the group is plagued by a series of vicious knife murders. Directed by Israeli-born Jourdan Alexander (as \"Jaacov Jaavoci\") and written by Svetlana, both of whom would make a name for themselves in hardcore porn, this one\'s nearly impossible to track down nowadays. The only known home video release occurred in Australia on the King of Video / Video Budget label and their release is reduced down to just 70 minutes from the original 87.', 87, '0+', '1974-10-18', 'Thriller/Horror'),
(1063459, 'Secret Society', 'https://image.tmdb.org/t/p/original/sZ4HeEoyOkzmv6848exsbDfsNVJ.jpg', 'Daisy is the love of Ken\'s life - she is also large... and very pretty... and on the dole. But Ken is a dreamer, all his dreams to make a fast buck ending up where they started - as dreams. With the rent unpaid, the bailiffs at the door and Ken\'s dreams in tatters, Daisy sets out to bring home the bacon and gets a job in the local factory. There she meets Marlene and half a dozen other large women who are all united in a secret passion - Sumo wrestling! Ken doesn\'t know what\'s hit him.', 92, '0+', '2000-10-29', 'Comedy/Drama/Romance'),
(1063460, 'Towarzysz', 'https://image.tmdb.org/t/p/original/lvuMjzIvVGINolbO66kdcukMKVq.jpg', 'During a weekend getaway at a secluded lakeside estate, a group of friends finds themselves entangled in a web of secrets, deception, and advanced technology. As tensions rise and loyalties are tested, they uncover unsettling truths about themselves and the world around them.', 97, '0+', '2025-01-22', 'Horror/Science Fiction/Thriller'),
(1063461, 'Uwaga, spoiler!', 'https://image.tmdb.org/t/p/original/m6FQtqoIP7JUqc9hRwQQfuYG2kz.jpg', 'Journalist Michael Ausiello embarks on a rollercoaster ride of emotions when Kit Cowan, his partner of 14 years, is diagnosed with terminal cancer.', 110, '0+', '2022-12-02', 'Romance/Comedy/Drama'),
(1063462, 'Krwawe igrzyska', 'https://image.tmdb.org/t/p/original/hDZzETrYegrB6pYpHKKzdwux6Km.jpg', 'Jane is a beautiful but troubled American girl backpacking through Japan, when her raw street fighting skills draw the attention of Oshima, Japanese karate champion, who recruits and trains her to fight in the vicious, all-female, underground martial arts tournament known as \"The Kumite\". After months of rigorous preparation, Jane is ready to face off against the deadliest female fighters in the world, including Ling, the Chinese apprentice of Oshima\'s nemesis. But other nefarious forces lie in the shadows, and Jane and Ling will have to unite on a journey that will take them from the gritty underworld of Hong Kong to the glitz of Macao, before deciding who really is the best female fighter on the planet.', 97, '0+', '2016-11-11', 'Action/Thriller'),
(1063463, 'Traveling Light', 'https://image.tmdb.org/t/p/original/4DpvHJAF64oGMWd97U86b4vMIkn.jpg', 'On May 30th, 2020, Uber and delivery driver Caddy searches for his missing son who has been living on the Los Angeles streets during the early days of the pandemic. Along the way, his path crosses that of Harry, a cult leader who is holding a bizarre ceremony up on Mulholland Drive. All the while, news of the horrific murder of George Floyd reverberates around the city and the social fabric collapses.', 90, '0+', '2021-10-10', 'Drama'),
(1063464, 'Hobbit: Niezwykła podróż', 'https://image.tmdb.org/t/p/original/z8QVNWqPxJQtOUIz5zEZBIJ28cF.jpg', 'Bilbo Baggins, a hobbit enjoying his quiet life, is swept into an epic quest by Gandalf the Grey and thirteen dwarves who seek to reclaim their mountain home from Smaug, the dragon.', 169, '16', '2012-12-12', 'Adventure/Fantasy/Action'),
(1063465, 'Halloween', 'https://image.tmdb.org/t/p/original/6BBb3uvJ5rl8Jq4CytiG9n1OLTq.jpg', 'The early years of young Michael Myers and the events leading up to his fateful Halloween night murder rampage in the quiet town of Haddonfield, Illinois.', 110, '0+', '2007-08-31', 'Horror'),
(1063466, 'On Broadway', 'https://image.tmdb.org/t/p/original/6E2yKuVxaN6GLe540sAoD5ypjkU.jpg', 'An all-star cast tells the inside story of the Broadway theater, and how it came back from the brink thanks to innovative work, a new attention to inclusion and a sometimes uneasy balance between art and commerce. Legends of the stage and screen—including Helen Mirren, Christine Baranski, August Wilson, James Corden, Alec Baldwin, John Lithgow, Viola Davis, Hugh Jackman and Ian McKellen—take us behind the scenes of Broadway\'s most groundbreaking and beloved shows, from A Chorus Line to Hamilton. Iconic performances by Lin Manuel Miranda, Patti LuPone, Bernadette Peters, James Earl Jones and Mandy Patinkin lead the way on a hurly burly ride through Times Square, once again the main street of American show business in this documentary directed by Academy-Award nominee Oren Jacoby.', 84, '0+', '2019-10-12', 'Documentary'),
(1063467, 'Mega Piranha', 'https://image.tmdb.org/t/p/original/vZB82Iqg28c5UxY3maGg1gGr3yF.jpg', 'When a science experiment goes horribly wrong, gigantic fish gain appetites for human flesh.', 92, '0+', '2010-04-10', 'Action/Adventure/Science Fiction'),
(1063468, 'The Queens', 'https://image.tmdb.org/t/p/original/5rbZULs1ZoJVuC9kEHky4xJufD4.jpg', 'This documentary chronicles over two years in the heels of four of the world’s most famous drag queens including former RuPaul’s Drag Race winners Jinkx Monsoon and Sharon Needles, former All Stars champion Alaska Thunderf*ck and season 7 and All Stars 2 contestant Katya Zamolodchikova. From performing across world stages to winning (and losing) Drag Race or dealing with major tragedies, The Queens lifts the lace front, giving an insight into one of the most fascinating and quickly ascending entertainment artforms.', 92, '0+', '2019-09-13', 'Documentary'),
(1063469, 'Milt & Honi', 'https://image.tmdb.org/t/p/original/qWcDO7JOufzyejiaMILHB6dxFGs.jpg', 'The story of legendary jazz bassist Milt Hinton and tap dancer Charles \"Honi\" Coles offers a front row seat to the creation of Jazz History. The film includes rehearsals, practice sessions, photographs, historical film footage, as well as a lunch break interview at New York\'s China Song restaurant in which the artists discuss everything from the mathematical principles of music to the dance acts who played the Apollo. The film also features a special appearance by choreographer/tap dancer Brenda Bufalino.', 98, '0+', NULL, NULL),
(1063470, 'Champion', 'https://image.tmdb.org/t/p/original/oCy74z0ipr3SiodWGOz21b4pBGt.jpg', 'In the supercharged world of dirt track racing, a single mistake causes the lives of two men to change forever. One must fight for his family, the other must fight to forgive.', 116, '0+', '2017-05-19', 'Drama'),
(1063471, 'The Current', 'https://image.tmdb.org/t/p/original/Nlrf6mEU2HAxmcEgiFl3gipykf.jpg', 'Arriving on a cruise ship as though pulled by an invisible string, senior citizen Donald discovers an apparent murder scene. While searching for answers, he finds a second body, and an emergency is declared.  When it becomes clear that the murderer is not of flesh and blood, that Donald is next in line to be killed and that the ship’s captain is a ferryman carrying his passengers to the afterlife, he and the other elderly tourists decide to make a break for it.', 14, '0+', '2024-11-26', 'Comedy'),
(1063472, 'Infernal', 'https://image.tmdb.org/t/p/original/9ahimn1talePzdiOhgRrEClp0BP.jpg', 'In a forsaken, dilapidated town, four inseparable friends long for a brighter future and unwittingly forge a sinister bargain with the devil to transform their destinies. This ill-fated agreement leads to a fiendish pact where they must relinquish their souls in return for their most profound desires. When the friends resist, the devil presents them with an insurmountable task: unravel an enigmatic riddle within a mere 24 hours or endure eternal damnation. As the friends race against time to decipher the conundrum, they soon discover that the devil has even more nefarious schemes in store.', 0, '0+', '2025-04-25', 'Horror'),
(1063473, 'Laura\'s Toys', 'https://image.tmdb.org/t/p/original/rqzupBGrChmHG5Wl6wy5vI0V3Vz.jpg', 'Archaeologist Walter and his wife Laura are working at a dig on a small island off the coast of Sweden. One day Laura catches Walter having a go at it with his sexy assistant, Anna. Laura calls in her old friend--and former lesbian lover--Hanni to help get her revenge on Walter by having she and Hanni seduce Anna.', 103, '0+', '1975-01-01', 'Drama'),
(1063474, 'Wilk z Wall Street', 'https://image.tmdb.org/t/p/original/eQTzLZ8szPpQuxKsxvUDUEq74nd.jpg', 'A New York stockbroker refuses to cooperate in a large securities fraud case involving corruption on Wall Street, corporate banking world and mob infiltration. Based on Jordan Belfort\'s autobiography.', 180, '16', '2013-12-25', 'Crime/Drama/Comedy'),
(1063475, '101 dalmatyńczyków', 'https://image.tmdb.org/t/p/original/9RbmY9zUcS3h2BMTMxWRj9nEklk.jpg', 'An evil, high-fashion designer plots to steal Dalmatian puppies in order to make an extravagant fur coat, but instead creates an extravagant mess.', 103, 'AL', '1996-11-27', 'Family/Comedy'),
(1063476, 'Sarraounia', 'https://image.tmdb.org/t/p/original/4rnY3S4XpirMeFTx5mJSYFSQ50O.jpg', 'On 2 January 1899, starting from the French Sudan, a French column under the command of the captains Voulet and Chanoine is sent against the black Sultan Rabah in what is now the Cameroon. Those captains and their African mercenary troops destroy and kill everything they find on their path. The French authorities try to stop them sending orders and a second troop but the captains kill the emissaries who reach them. Sarraounia, queen of the Aznas, have heard about the exactions. Clever in war tactics and in witchcraft, she decides to resist and stop those mad men.', 120, '0+', '1986-07-01', 'War/Drama/History'),
(1063477, 'Agenci bardzo specjalni', 'https://image.tmdb.org/t/p/original/aHTUpo45qy9QYIOnVITGGqLoVcA.jpg', 'Two FBI agent brothers, Marcus and Kevin Copeland, accidentally foil a drug bust. To avoid being fired they accept a mission escorting a pair of socialites to the Hamptons--but when the girls are disfigured in a car accident, they refuse to go. Left without options, Marcus and Kevin decide to pose as the sisters, transforming themselves from black men into rich white women.', 109, '0+', '2004-06-23', 'Comedy/Crime');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1063478, 'Paradistorg', 'https://image.tmdb.org/t/p/original/gMF5FG141ItdIbx5AvoKHmhhXyi.jpg', 'Conventions of civility among family members are severely strained by the very real breakup of the bonds between them. During a few days at a vacation home, Katha, a woman in late middle age, tries to cope with an influx of discontented, disconnected relatives. Her divorced daughter brings all sorts of people to the house, including a woman-friend accompanied by her psychotic son; the grandfather of the house is convinced he is dying and is satisfied by nothing; and some friends drop off their angry teenage son to stay with her, while they go on a long trip abroad. Her friend Emma doesn\'t help much with keeping a lid on things, as she is a social worker who is fascinated by the awfulness of these situations.', 113, '0+', '1977-04-27', 'Drama'),
(1063479, 'Three Rogues', 'https://image.tmdb.org/t/p/original/a93Y0XGy516ntHbucL9hbvzCbzK.jpg', 'In 1877, thieves Ace Beaudry, Bronco Dawson and Bull Stanley head West together after having each been betrayed by a woman. They come across a wagon train bound for the town of Custer, where hundreds of people are gathering for a land rush in the Dakotas, which President Ulysses S. Grant has opened to settlers thanks to a treaty with the Sioux Indians. After the three rogues ride off, they spy a lone wagon with a tempting string of thoroughbreds. Before they can steal the horses, however, the wagon is attacked by a gang led by Layne Hunter, a shifty saloon owner from Custer. The trio chase off the gang, and as they are about to abscond with the horses, they find pretty Lee Carleton, whose father was killed in the attack.', 70, '0+', '1931-03-08', 'Western'),
(1063480, 'Amerykańskie graffiti', 'https://image.tmdb.org/t/p/original/1tjLivPad2PX8FAzWko7FPIb8d2.jpg', 'A couple of high school graduates spend one final night cruising the strip with their buddies before they go off to college.', 110, '0+', '1973-08-11', 'Comedy/Drama'),
(1063481, 'Cynicy i praktycy', 'https://image.tmdb.org/t/p/original/hUpYDriYa5YkwwxeafUsowTweBg.jpg', 'A Democratic political consultant helps a retired Marine colonel run for mayor in a small, conservative Wisconsin town.', 101, '0+', '2020-07-01', 'Comedy/Drama'),
(1063482, 'Pociąg', 'https://image.tmdb.org/t/p/original/bzgPLB7efMohled42PIn6CcOTnO.jpg', 'As the Allied forces approach Paris in August 1944, German Colonel Von Waldheim is desperate to take all of France\'s greatest paintings to Germany. He manages to secure a train to transport the valuable art works even as the chaos of retreat descends upon them. The French resistance however wants to stop them from stealing their national treasures but have received orders from London that they are not to be destroyed. The station master, Labiche, is tasked with scheduling the train and making it all happen smoothly but he is also part of a dwindling group of resistance fighters tasked with preventing the theft. He and others stage an elaborate ruse to keep the train from ever leaving French territory.', 133, '0+', '1964-09-24', 'War/Thriller'),
(1063483, 'Adventure', 'https://image.tmdb.org/t/p/original/iPnrJhEf8jtLgE0p2CtkmRbg1hG.jpg', 'David Sheldon owns a plantation in the Solomon Islands. Many of his field hands die of blackwater fever, and then he becomes sick himself. Joan Lackland, a female soldier of fortune, arrives by schooner in the islands. With the help of her Kanaka crew, she protects David from an attack by the natives who are led by Googomy. Joan nurses David back to health and becomes his business partner, protecting his mortgaged property from two avaricious moneylenders. Seeking vengeance, the moneylenders incite the natives to revolt.', 70, '0+', '1925-04-26', 'Drama/Adventure'),
(1063484, 'Tranzyt', 'https://image.tmdb.org/t/p/original/2YGo85qQ8zoLTKBZJ3yRiyfSJHp.jpg', 'In an attempt to flee Nazi-occupied France, Georg assumes the identity of a dead author but soon finds himself stuck in Marseilles, where he falls in love with Maria, a young woman searching for her missing husband.', 102, '0+', '2018-04-05', 'Drama/Romance'),
(1063485, 'The Invisible Life of Addie Larue', 'https://image.tmdb.org/t/p/original/d5lv1Jd1o8KSCUEZUGzhnlBE5KI.jpg', 'A film based on the novel of the same name. Follows a woman who makes a Faustian bargain to live forever. But in return, she’s cursed to be forgotten by everyone she meets. That all changes 300 years later, when Addie LaRue stumbles upon a man who remembers her name.', 0, '0+', NULL, 'Fantasy/Drama'),
(1063486, 'Siegfried', 'https://image.tmdb.org/t/p/original/3IulABKIGo4IUOQ9lVoRM9s8P0j.jpg', 'Der Ring des Nibelungen in a production of the Zürich opera house, recorded 2024. \"Dramatic music-making at its finest\". In the hands of General Music Director Gianandrea Noseda and Stage Director Andreas Homoki, Wagner\'s myth is represented as \"a dysfunctional family of gods\" (The Independent) in a polished yet unpretentious production that underscores the humanity of the characters, who are performed by the same exceptional cast of singers across all four operas.', 251, '0+', '2024-05-24', 'Music'),
(1063487, 'golden love', 'https://image.tmdb.org/t/p/original/cyR7dTxez6RkZuz3TBC9RV9DGZF.jpg', 'Golden Love is a tender and heartwarming short film that explores the enduring bond between an elderly couple, Amos and Anna, and their mischievous yet lovable cat. Set against the quiet rhythms of their everyday life, the film beautifully captures moments of love, nostalgia, and the unspoken connection that binds them together.', 22, '0+', '2024-12-21', 'Drama/Romance/Adventure'),
(1063488, 'A Falecida', 'https://image.tmdb.org/t/p/original/qhNI3ldWsrj4YKTASOTjQoA14o1.jpg', 'After visiting a fortune teller, Zulmira is informed that a blonde woman will threaten her peace. After talking to her husband Toninho, she suspects that her cousin Glorinha may be that blonde.', 96, '0+', '1965-09-22', 'Drama'),
(1063489, 'Strange Fruit', 'https://image.tmdb.org/t/p/original/kfQdLSyX1gExHj5oXazJYC4C8w2.jpg', 'In 1937, after seeing a photo depicting the lynching of a black man in the south, Bronx-born high school teacher Abel Meeropol wrote a poem entitled \"Strange Fruit\" that begins with the words: \"Southern trees bear a strange fruit / Blood on the leaves and blood at the root.\" He set the poem to music and a few years later convinced Billy holiday to record it in a legendary heartbreaking performance. Intertwining jazz genealogy, biography, performance footage, and the history of lynching, director Joel Katz fashions a fascinating discovery of the lost story behind a true American classic. Written by Excerpted from Coolidge Corner Theatre Program Update', 57, '0+', '2002-05-20', 'Music/Documentary'),
(1063490, 'Cowardice Court', 'https://image.tmdb.org/t/p/original/pNyjDqiLlAcKPxNlEuigBkQScdw.jpg', 'A feud in the Adirondack Mountains develops when Randolph Shaw will not give up a shack and its acreage adjoining the estate of Lord Cecil Bazelhurst, whose wife, the former Evelyn Banks of Jersey City, married him for his title and now wants to get rid of Randolph\'s ugly shack. When Randolph meets Cecil\'s sister Penelope, a romance begins which is furthered after one of the Bazelhurst servants shoots Randolph in the arm for trespassing and Penelope, who earlier had looked upon the feud as a joke, runs away to Randolph\'s house and accepts his engagement proposal. Cecil and his men pursue Penelope, but are frightened away by Randolph\'s men and are forced to spend a miserable stormy night in the woods. The next day everyone becomes reconciled when Lady Evelyn realizes that the desired property will now be in the family, and Randolph offers Cecil and his men dry, if ill-fitting, garments to wear.', 50, '0+', '1919-06-15', 'Romance/Drama'),
(1063491, 'The Accused', 'https://image.tmdb.org/t/p/original/u6JOf3UMYjZ6XnYw7Z4ObP9IAHW.jpg', 'Simone is the owner of a strip club. She believes that her new hostess, Sharon has been stealing from her. So she lures the unsuspecting girl to her place under false pretenses. Simone convinces Sharon that she needs her to be her new magician\'s assistant for a charity event. But what Sharon doesn\'t know is that it\'s all a ruse to get the girl tied up and helpless. But a twist will have Simone sorry she ever kidnapped the girl!', 45, '0+', '2007-01-01', 'Thriller'),
(1063492, 'Assault Platoon', 'https://image.tmdb.org/t/p/original/uBsqrAaUVxmT7qMM04EJcpiHtnU.jpg', 'In 1973 Vietnam, gas bombs are dropped on villages, killing men, women, and children. Two downed American pilots, accused of the bombings, are captured and tortured. Both men give name, rank, and serial number but neither one confesses. Elsewhere, a team of seven diverse individuals is hired to rescue the two pilots. These individuals manage to free the pilots from the river-cages where they\'ve been imprisoned, (with water up to their shoulders), but the Vietnamese counterattack proves deadly. Only one rescuer survives and he\'s burdened by the knowledge that the U.S. Government wanted the pilots rescued and then silenced to order to conceal their role in dropping gas-bombs.', 92, '0+', '1990-01-01', NULL),
(1063493, 'Francisca', 'https://image.tmdb.org/t/p/original/tOmNwF8R8aAoNLiLMqAzQHWOTjE.jpg', 'The life of a young man, son of an English officer who lets himself become a prisoner of love resulting in fatalism and disgrace.', 166, '0+', '1981-12-03', 'Drama/Romance'),
(1063494, 'Cappuccino', 'https://image.tmdb.org/t/p/original', 'Victor is a journalist, his wife Vanessa is in health care writing a thesis on how some women use sex to get what they want. One morning she tells him he\'s stopped listening to her, stopped trying to figure out her needs, and hasn\'t satisfied her for months. At a bar two hours later, a seductive married women, whom he nicknames Cappuccino, comes onto him, inviting him to play a game. She gives him a phone number missing the last digit, meets him in an abandoned house, appears in his shower while Vanessa\'s at work: soon he\'s obsessed even as Vanessa tries to regain his attention. When Cappuccino shows up with a black eye, Victor decides her abusive husband must be stopped', 98, '0+', '1998-07-09', 'Thriller'),
(1063495, 'Splettrhex', 'https://image.tmdb.org/t/p/original/3OTuNQEFXbhAYHjmSAswsTDUJU7.jpg', 'Imagine this: Jim Button, Vincent Price, and Sam Raimi sitting together over a beer after work. Over the course of the evening, they decide they should do something together... But since such a meeting never took place, the young Berlin puppet maker Florian Moch took it upon himself to combine the relevant influences in a film. The result is probably the world\'s first puppet splatter horror film. It bears the meaningful title \"Splettrhex.\"', 0, '0+', '2010-04-01', 'Horror/Comedy'),
(1063496, 'Układ', 'https://image.tmdb.org/t/p/original/2DeptED3bbdHS2ww5BcvjoCs6F2.jpg', 'A high-profile terrorism case unexpectedly binds together two ex-lovers on the defense team - testing the limits of their loyalties and placing their lives in jeopardy.', 96, '0+', '2013-08-28', 'Mystery/Drama/Crime/Thriller'),
(1063497, 'Aberdeen', 'https://image.tmdb.org/t/p/original/qC3Dd0FLzwHDJStRZPNNjp68PM1.jpg', 'An idyllic childhood with her mooshum and kookum, or grandparents, in her community of Peguis First Nation dissipates as Aberdeen’s hard-partying and absentee parents distances her from that haven.  Now an adult, sleeping on public benches, Winnipeg-based Aberdeen is in survival mode. The last remaining stable parts of her life begin slipping away — her reliable brother Boyd is ill and gives up Aberdeen’s grandkids to the foster care system. Then she loses her ID.', 83, '0+', '2024-09-06', 'Drama'),
(1063498, 'Homecoming', 'https://image.tmdb.org/t/p/original/wV9EPHz9R2FRiW2Qi2rLjnlCenU.jpg', 'When Nina Patel is nominated to represent her eighth grade class at Homecoming, she\'s thrilled. However, Nina\'s traditional Indian parents refuse to let her assimilate to such an American tradition. Nina gets the answer she expects, but decides to ask her father one last time. Only when she shows up at his office unannounced, she discovers him in a compromising position with his secretary. Trying to shake the thoughts of a broken home, Nina flees the scene.', 25, '0+', '2011-10-15', 'Drama'),
(1063499, 'Oppenheimer', 'https://image.tmdb.org/t/p/original/8Gxv8gSFCU0XGDykEGv7zR1n2ua.jpg', 'The story of J. Robert Oppenheimer\'s role in the development of the atomic bomb during World War II.', 181, '12', '2023-07-19', 'Drama/History'),
(1063500, 'Schoolboy Father', 'https://image.tmdb.org/t/p/original/rZPZULZQtSELzSYe7cykigxPuDz.jpg', 'High school senior discovers his summer girlfriend has given birth to his child, and decides to fight for custody.', 45, '0+', '1980-10-15', 'Drama/TV Movie'),
(1063501, 'T2: Trainspotting', 'https://image.tmdb.org/t/p/original/xlbpCwa9OXXIiNgXcwuompHFIk9.jpg', 'After 20 years abroad, Mark Renton returns to Scotland and reunites with his old friends Sick Boy, Spud and Begbie.', 117, '18', '2017-01-27', 'Drama/Comedy/Crime'),
(1063502, 'Witch Hunt', 'https://image.tmdb.org/t/p/original/dmOXxbrAN013vKE2BJXIyl46hLL.jpg', 'Magic and murder connect an actress, a private eye, a senator and a witch in 1950s Hollywood.', 100, '0+', '1994-12-10', 'TV Movie/Comedy/Fantasy/Horror'),
(1063503, 'Senor Daredevil', 'https://image.tmdb.org/t/p/original/oZWKyLUAKU6SbhUKPmOdT6U0rnX.jpg', 'Don Luis O\'Flagherty (Ken Maynard), a daredevil comes to the rescue of his long-lost father, \"Tiger\" O\'Flagherty (George Nichols), the supervisor of a supply-wagon train destined for the miners in Sonora. Tiger is being terrorized by Jesse Wilks (J.P. McGowan), who hopes to starve the miners out of their claims. Falling in love with Tiger\'s ward, Sally (Dorothy Devore), Don Luis manages to turn the tables on Wilks, who is killed attempting to rob the supply train.', 70, '0+', '1926-08-01', 'Action/Western/Romance/Adventure'),
(1063504, 'Catfish', 'https://image.tmdb.org/t/p/original/mXNxee2ix6Ke0bSIqFST0UhbVLR.jpg', 'Nev, a 24-year-old New York-based photographer, has no idea what he\'s in for when Abby, an eight-year-old girl from rural Michigan, contacts him on Facebook, seeking permission to paint one of his photographs. When he receives her remarkable painting, Nev begins a friendship and correspondence with Abby\'s family. But things really get interesting when he develops a cyber-romance with Abby\'s attractive older sister, Megan, a musician and model. Prompted by some startling revelations about Megan, Nev and his buddies embark on a road trip in search of the truth.', 87, '0+', '2010-09-17', 'Documentary'),
(1063505, 'ALWAYS 続・三丁目の夕日', 'https://image.tmdb.org/t/p/original/wPTi4F9YKFHZQpK9HsS83sQhNEC.jpg', 'Would-be writer Ryunosuke Chagawa is still living across the street from Norifumi Suzuki and his auto repair shop, though now he shares his home with Junnosuke, an orphan he\'s taken under his wing at the urging of pretty Hiroi, who continues to manage a nearby tavern. Chagawa dreams of publishing a successful novel and settling down with Hiroi and Junnosuke, but his day job running the candy store keeps him busy, and Hiroi mistakes his tight schedule for a lack of interest in her. Hiroi has also embarked on a secret career as a burlesque dancer, which isn\'t doing much to improve her opinion of men. At the Suzuki household, seven-year-old Ippei isn\'t happy to be sharing the house with a guest, his distant cousin Mika who is the same age but far more demanding. Mutsuko, the apprentice female auto mechanic, is still staying with the Suzukis, and she\'s becomes the object of the affections of Takeo, a downbeat young man who is studying cooking.', 146, '0+', '2007-11-03', 'Comedy/Drama'),
(1063506, 'Bright Lights', 'https://image.tmdb.org/t/p/original/uPbyvD8VGiEttygnEOZbruPw13W.jpg', 'Tom loves Patsy, but she lives in the city while he is every bit the country bumpkin. When an invention of his sells, he decides to take the money and go to the city. There he will show Patsy that he can be just what he thinks she wants: a city slicker. But Patsy yearns for the simple pleasure of her country boy, Tom, and is shocked at what shows up at her door.', 70, '0+', '1925-11-15', 'Comedy/Romance'),
(1063507, 'Graduation Day', 'https://image.tmdb.org/t/p/original/bbNtkM0oFTCnFfblOzeEuaDUaZB.jpg', 'After the death of a high school track star during a race, a mysterious killer in a fencing mask begins murdering her friends and teachers.', 96, '0+', '1981-05-01', 'Horror'),
(1063508, 'Za linią wroga', 'https://image.tmdb.org/t/p/original/vG8qBkByy9naORB6zahcntIC2N.jpg', 'In the frozen, war torn landscape of occupied Poland during World War II, a crack team of allied commandos are sent on a deadly mission behind enemy lines to extract a rocket scientist from the hands of the Nazis.', 92, '16', '2020-04-24', 'War/Drama'),
(1063509, 'Just Tom', 'https://image.tmdb.org/t/p/original/8G6idUXrUmcb2bQZZ0kEaYQWQL8.jpg', 'Tom Lessard, a 30-year-old depressed watch salesman from Newark, NJ, is disappointed to learn that not only must he attend a three-day watch sales convention in Charlotte, NC, but he must do so with his rambunctious co-worker, Ralph. Miserable at the convention, Tom\'s luck turns around when he meets April, a bartender at the hotel lobby bar. She convinces him to leave the convention and they find themselves exploring Charlotte. The two spend the day in and out of museums, parks, and pubs. Aided by April\'s free spirit, Tom is able to take a closer look at himself and the choices he\'s made to get him where he is. His passions, fears, and outlook are all exposed by April. The question is, will he do anything about it?', 86, '0+', '2014-01-13', 'Drama/Comedy'),
(1063510, 'Rocky II', 'https://image.tmdb.org/t/p/original/nMaiiu0CzT77U4JZkUYV7KqdAjK.jpg', 'After Rocky goes the distance with champ Apollo Creed, both try to put the fight behind them and move on. Rocky settles down with Adrian but can\'t put his life together outside the ring, while Creed seeks a rematch to restore his reputation. Soon enough, the \"Master of Disaster\" and the \"Italian Stallion\" are set on a collision course for a climactic battle that is brutal and unforgettable.', 120, '0+', '1979-06-15', 'Drama'),
(1063511, 'Psycholka', 'https://image.tmdb.org/t/p/original/jO5x1YmnRoGpbWWwz8Ptu28Gbpe.jpg', 'Frida is different. Self chosen different. Marius, on the other hand is the most perfect boy in class, and likes to show off. When they have to work together at school, it\'s the start of a turbulent and challenging relationship. Generation Achievement meets impossible love.', 109, '0+', '2019-01-11', 'Drama'),
(1063512, 'Forever Home', 'https://image.tmdb.org/t/p/original/quYaRZFAMFpc5JXeyZnNvhUeCus.jpg', 'Forever HOME  follows a young couple’s dream to provide the best possible life for rescued farm animals by rethinking the concept of “home.” At their refuge, they base their designs on the needs of the individual animals, replacing conventional barns with customized homes. Paul, an architect, calls it \"animal centered design.\" With empathy and boundless imagination, they’re bringing architectural design to the world of animal care and providing a blueprint for a compassionate, sustainable future. This unique film is a celebration of life and creativity!', 56, '0+', '2025-01-03', 'Documentary'),
(1063513, 'Oddział wyrzutków', 'https://image.tmdb.org/t/p/original/yKTFCdZjocd4kFwVkhBoKFokWzY.jpg', 'A rag tag unit of misfits known as the War Pigs must go behind enemy lines to exterminate Nazis by any means necessary.', 92, '0+', '2015-08-03', 'War/Action'),
(1063514, 'Śmiertelna gorączka', 'https://image.tmdb.org/t/p/original/93JnJZPRRj2w9pRTSAVcDy5hS0o.jpg', 'While staying at a remote cabin for a week-long vacation, a group of five college friends succumb to an infectious, flesh-eating disease.', 99, '0+', '2016-02-12', 'Horror'),
(1063515, 'SHINE 62', 'https://image.tmdb.org/t/p/original/6Z8Wy4vKrMDnOsXkTYOnJvy7nhk.jpg', 'WWN & SHINE Wrestling present  SHINE 62,  Woodside, NY,  11/9/2019. Matches include:  Six Woman War! – All SHINE Championships Are On The Line!  SHINE Champion Allysin Kay & BTY of Marti Belle & Jayme Jameson vs. SHINE Nova Champion Shotzi Blackheart & SHINE Tag Team Champions Triple Aye of Aja Perera & Big Swole w/ Ayla  • Rematch from SHINE 61!  Brandi Lauren vs. Alex Gracia  • Natalia Markova vs. Double D’Rose  • Tag Team Triple Threat Match  Team Sea Stars of Ashley Vox & Delmi Exo vs. Avery Taylor & Brittany Blake vs. Rainbow Bright of Luscious Latasha & Gabby Gilbert  • Candy Cartwright vs. Notorious Nadi  • Tina San Antonio vs. Vanity  • Madi Maxx vs. Savannah Evans.', 98, '0+', '2019-11-09', NULL),
(1063516, 'Pierwszy reformowany', 'https://image.tmdb.org/t/p/original/8HKA3Hwf8jQWy8TCYWr7C8Wft23.jpg', 'A pastor of a small church in upstate New York starts to spiral out of control after a soul-shaking encounter with an unstable environmental activist and his pregnant wife.', 113, '16', '2018-05-18', 'Drama'),
(1063517, 'En mand kommer hjem', 'https://image.tmdb.org/t/p/original/wTnLpUbIcat5ZOSibSmjkbaSAiu.jpg', 'A small provincial town is buzzing with excitement: the town´s most illustrious son, a world-famous opera singer, is coming home. Meanwhile, Sebastian, a kitchen boy who is as good as married, falls head over heels in love with the new maid, Maria. Their love affair, along with rumours that the opera singer and the kitchen boy are related, turns the town upside down, threatening to ruin everyone´s high expectations and the opera singer´s triumphant return.', 100, '0+', '2007-09-14', 'Comedy'),
(1063518, 'Barbie', 'https://image.tmdb.org/t/p/original/iuFNMS8U5cb6xfzi51Dbkovj7vM.jpg', 'Barbie and Ken are having the time of their lives in the colorful and seemingly perfect world of Barbie Land. However, when they get a chance to go to the real world, they soon discover the joys and perils of living among humans.', 114, '12', '2023-07-19', 'Comedy/Adventure'),
(1063519, 'Arizona Bound', 'https://image.tmdb.org/t/p/original/4KVWIcGSzGlIZxPWHXRFDXBuUzV.jpg', 'Dave Saulter, a rambling young cowboy drifts into a small western town the day a big gold shipment is leaving by stagecoach. Two different people plan to rob the stagecoach...Buck O\'Hara, the driver who is very trusted, and a stranger, Texas Jack. Dave gets involved and is accused of being one of the robbers.', 53, '0+', '1927-04-09', 'Western'),
(1063520, 'CBeebies Musical: The Great Ice Cream Hunt', 'https://image.tmdb.org/t/p/original/hwAeaDz4sex9SSYcZg4KgylO8sp.jpg', 'When all the ice creams go missing, Lolly the cow and Pinecone the hedgehog team up for a musical road trip to save the Empress of Storyland\'s Summer Send-Off!', 56, '0+', '2025-07-11', 'Family/Music'),
(1063521, 'La Finale', 'https://image.tmdb.org/t/p/original/9KYEVSiRf6qWYO94NNfOw1BvO2x.jpg', 'A rebellious teenager must travel the country with his sick grandpa to get to his basketball game.', 85, '0+', '2018-03-21', 'Comedy'),
(1063522, 'Królewna Śnieżka', 'https://image.tmdb.org/t/p/original/s6fI8ZQzl4u6vdnyboXubD1eMv9.jpg', 'After she spends all her money, an evil enchantress queen schemes to marry a handsome, wealthy prince. There\'s just one problem - he\'s in love with a beautiful princess, Snow White. Now, joined by seven rebellious dwarves, Snow White launches an epic battle of good vs. evil...', 106, '0+', '2012-03-15', 'Adventure/Comedy/Family/Fantasy'),
(1063523, '24 Godziny', 'https://image.tmdb.org/t/p/original/qDnxF0DmlUKBtuTSCCJLF6rVhso.jpg', 'When their daughter is abducted by experienced kidnappers, the Jennings turn the tables on their seemingly fool-proof plan.', 106, '0+', '2002-09-20', 'Thriller/Crime'),
(1063524, 'Unknown World', 'https://image.tmdb.org/t/p/original/gjF34MepQwZBGuc3mumLwmjeCo3.jpg', 'With the cyclotram, an atomic-powered rock-boring vehicle, Dr. Jerimiah Morley leads an expedition into a subterranean world.', 74, '0+', '1951-10-26', 'Adventure/Science Fiction'),
(1063525, 'Střevíčky', 'https://image.tmdb.org/t/p/original', 'It\'s a crisp autumn morning. Marta prepares breakfast and goes to work. Little Jenda has a sore throat, so she has to go to her grandfather\'s to look after the boy. On the way to work, she reflects on the monotony of her life and marriage, and doubts whether her husband Karel still loves her. She spots a beautiful pair of Indian shoes in a fashion shop and shows them to Karel during her lunch break. He just runs his eyes over them and tells Marta to buy them. Martha is touched by his indifferent words. In the afternoon, encouraged by her colleague, she decides to buy the shoes. She is unlucky, however, as they have already been sold in the meantime. In the evening, Marta dresses for the theatre without any mood. In her wardrobe she discovers a box containing Indian slippers. Her face brightens with a smile and she goes to sew a button to Karl\'s white shirt without speaking. Suddenly the couple are close again.', 0, '0+', '1961-01-01', 'Romance'),
(1063526, 'The Misadventures of Fanny Starr Chapter 4: Case of the Deadly Twins', 'https://image.tmdb.org/t/p/original', 'At the end of Chapter 3, Fanny Starr (Deana) found herself sinking in a quicksand bog. Learn how she escapes in Chapter 4.  Fanny then seeks out Kraven, only to be captured by him and confronted with her arch-enemy, Vanessa Krueger (Clancey McCauley). Vanessa wants her body back and she plans to use Annie (Clancey McCauley) as leverage. Rita (Dawn Murphy) appears out of nowhere to help Fanny escape. Fanny learns that she’s not the only person with a twin, as Tina Krause appears as Kristen, who’s out for revenge for her sister’s death! Catfights abound as Tina faces off against Dawn and Deana and Deana faces off against Clancey.', 95, '0+', NULL, 'Horror/Thriller'),
(1063527, 'Blind Trust', 'https://image.tmdb.org/t/p/original/v5wUsnkw1yP9Z8YxAly3YurQN77.jpg', 'An immigration lawyer is unwittingly entangled in a money-laundering scheme where his only chance to survive is to confront the same people who set him up.', 87, '0+', '2021-09-22', 'Thriller/Drama'),
(1063528, 'Impossible Catherine', 'https://image.tmdb.org/t/p/original/4jt3KrCkFyyF7f2mv8KAvT6XbvR.jpg', 'The head of the Kimberly household rules it with an iron fist. Unfortunately the head of the Kimberly household isn\'t Grant (J.H. Gilmore), the father and wealthy Wall Street magnate -- it\'s his spoiled, headstrong daughter Catherine (Virginia Pearson). She is so willful that she has earned the name \"Impossible Catherine,\" and her whole focus in life is to prove women\'s superiority over the masculine gender.', 50, '0+', '1919-10-05', 'Comedy/Drama'),
(1063529, 'The Landlord', 'https://image.tmdb.org/t/p/original/DoDKRMIRki2ft2D9bZGa1zzgVx.jpg', 'At the age of twenty-nine, Elgar Enders \"runs away\" from home. This running away consists of buying a building in a black ghetto in the Park Slope section of Brooklyn. Initially, his intention is to evict the black tenants and convert the building into a posh flat. But Elgar is not one to be bound by yesterday\'s urges, and soon he has other thoughts on his mind.', 112, '0+', '1970-05-20', 'Comedy/Drama'),
(1063530, 'Fall Away', 'https://image.tmdb.org/t/p/original/8ZcfgoKBZLZgQhmVKgzoh1GHlyT.jpg', 'On the verge of being discovered, the secretly gay lead singer for up-and-coming country folk band \"65 Home\" dies violently in a back alley. We follow the friends and lovers of \'Handsome Jake\' as they try to come to terms with the singer\'s untimely death. As the band travels to Nashville to honor his passing, we discover that there are many Jake\'s - the brother, the lover, the poet, the liar and the cruel manipulator. As the band members cross the Midwest with Jake\'s ashes on board their Winnebago, they must now struggle to regroup, understand what happened, and find a way to move on. But can they do it without Jake?', 91, '0+', '2011-08-21', 'Drama'),
(1063531, 'SHINE 27', 'https://image.tmdb.org/t/p/original/bc9F5f2OKfiXExcmgoD4ojfzSj3.jpg', 'SHINE Wrestling presents  SHINE 27,  Ybor City, FL,  5/15/2015. Matches include:  • SHINE Championship Match  Santana defends vs. Mia Yim  • Anything Goes Match  Jessicka Havok vs. Su Yung w/ April Hunter  • SHINE Tag Team Championship Match  The Kimber Bombs of Kimber Lee & Cherry Bomb defend vs. Legendary of Brandi Wine & Malia Hosaka w/ Leilani Kai  • Brass Knuckles On A Pole Match  La Rosa Negra vs. Taylor Made w/ April Hunter  • Leah Von Dutch vs. Thunderkitty w/ Leilani Kai  • Valifornia of Andrea & Jayme Jameson w/ So Cal Val vs. Crazy Mary Dobson & Kimberly w/ Daffney  • Allysin Kay w/ April Hunter vs. Tracy Taylor  • Amber Gallows vs. Xandra Bale  • Leva vs. Tessa Blanchard w/ April Hunter.', 158, '0+', '2015-05-15', NULL),
(1063532, 'En Marche vers l\'Effondrement !', 'https://image.tmdb.org/t/p/original/5naoUQMRbmbANCTKQ8ZwP0ECt0t.jpg', 'Disappointed by leftists politics this last few years, PAP\'40 of the Church of the Holy $aint Con$umption decide to run for presidential election of 2022 to fix the country. He meets his electorate and other candidates to spread the word : Work, Obey, Consume !', 86, '0+', '2023-03-08', 'Comedy/Documentary'),
(1063533, 'Projekt - M', 'https://image.tmdb.org/t/p/original/ef6Y3ttcuX0yHnwZoizATLooAkX.jpg', 'Four astronauts have to stay 1000 days in a space station around Earth in order to prove that a trip to Europa, one of Jupiter\'s moon, is possible. The experience goes well until something happens on earth.', 98, '0+', '2014-09-20', 'Science Fiction/Drama'),
(1063534, 'Dancing Days', 'https://image.tmdb.org/t/p/original', 'Despite the fact that he has a beautiful wife who loves him and a good home, gold-digger Lillian Loring discovers that Ralph Hedman is a pushover for her winsome wiles and ways. Ralph\'s wife, Alice, becomes suspicious when she sees them together at lunch one day. He asks for a divorce but Alice says she wants to keep the marriage going for at least a year, for appearances sake, and says she will agree to a divorce then if he still wants it. Alive stays home alone for three months while Ralph is living it up as a full member of the Jazz Age. He gets sick and Alice invites Lillian to come over and help get him well. Lillian decides that lots of saxophone playing and wild dancing is the best cure. Alice takes all she can stand, leaves a note for Ralph and departs the premises. Ralph also takes his own departure, after leaving a note for Alice. Lillian keeps on partying. Alice and Ralph, driving their respective cars into an intersection, have a collision.', 65, '0+', '1926-09-27', 'Drama/Romance'),
(1063535, 'Czas patriotów', 'https://image.tmdb.org/t/p/original/rDwIvZU63NKsm8LgvmZp1JYB4hb.jpg', 'When CIA Analyst Jack Ryan interferes with an IRA assassination, a renegade faction targets Jack and his family as revenge.', 117, '0+', '1992-06-04', 'Drama/Action/Thriller/Crime'),
(1063536, 'Yimingjingren 一鳴驚人', 'https://image.tmdb.org/t/p/original', 'Anatole France\'s The Man Who Married a Dumb Wife has been adapted into three different Hong Kong films in the 1950s alone. These two adaptations stray from the source material considerably in genre, characterisation and plot, turning a farce about married life into localised romantic comedies that emphasise family values.  The Beauty and the Dumb follows the couple from their meet-cute to the misunderstandings they encounter before the inevitable happy ending. The heir of a bank (Huang He) falls in love at first sight with one of the employees\' daughter (Li Lihua), but their burgeoning relationship is nearly derailed when the girl\'s father intervenes to help his dumb daughter land a rich husband.', 93, '0+', '1954-12-18', 'Romance/Comedy'),
(1063537, 'Robinson Crusoe', 'https://image.tmdb.org/t/p/original/y0kesJcTKzZ7eDrI4ROMBmyFdXS.jpg', 'On a tiny exotic island, Tuesday, an outgoing parrot lives with his quirky animal friends in paradise. However, Tuesday can\'t stop dreaming about discovering the world. After a violent storm, Tuesday and his friends wake up to find a strange creature on the beach: Robinson Crusoe. Tuesday immediately views Crusoe as his ticket off the island to explore new lands. Likewise, Crusoe soon realizes that the key to surviving on the island is through the help of Tuesday and the other animals. It isn\'t always easy at first, as the animals don\'t speak \"human.\" Slowly but surely, they all start living together in harmony, until one day, when their comfortable life is overturned by two savage cats, who wish to take control of the island. A battle ensues between the cats and the group of friends but Crusoe and the animals soon discover the true power of friendship up against all odds (even savage cats).', 90, '0+', '2016-02-04', 'Animation/Adventure/Comedy/Family'),
(1063538, 'Dweller', 'https://image.tmdb.org/t/p/original/zKqUEdvL5a0Tjib3h6qdYA743no.jpg', 'After a perfect bank heist, three criminals high-tail it to an old cabin in the woods to split the $100,000 they stole.  Little do they know that an alien being from a crashed saucer is prowling the woods for food.  The suspense tightens as greed, fear, and paranoia split the group apart as the hungry creature closes in on them.  Terror and shock in the usual Polonia Brothers tradition!', 71, '0+', '2001-08-04', 'Horror/Science Fiction'),
(1063539, 'Metal Lords', 'https://image.tmdb.org/t/p/original/r97txZRmBb75SGsIAWqmplWJnO3.jpg', 'For teenage misfits Hunter and Kevin, the path to glory is clear: Devote themselves to metal. Win Battle of the Bands. And be worshipped like gods.', 97, '0+', '2022-04-08', 'Comedy/Drama/Music'),
(1063540, 'The Janitor', 'https://image.tmdb.org/t/p/original/wmkaFm6tmOKjKon5Ab9cCJS3MzC.jpg', 'Crisanto Espina, a cop on suspension and under investigation, is tasked to eliminate the suspects involved in a bank robbery/massacre that shocked the whole nation.', 112, '0+', '2014-08-01', 'Drama/Action/Crime'),
(1063541, 'Służąca', 'https://image.tmdb.org/t/p/original/nICx2UzZFL2Qv0szfl6ZaKhzWQ8.jpg', '1930s Korea, in the period of Japanese occupation, a new girl, Sookee, is hired as a handmaiden to a Japanese heiress, Hideko, who lives a secluded life on a large countryside estate with her domineering Uncle Kouzuki. But the maid has a secret. She is a pickpocket recruited by a swindler posing as a Japanese Count to help him seduce the Lady to steal her fortune.', 145, '16', '2016-06-01', 'Thriller/Drama/Romance'),
(1063542, 'Winning London', 'https://image.tmdb.org/t/p/original/2wzA0yGuwpoIjduC6OoTXigWtMg.jpg', 'When Chloe and Riley Lawrence are invited to London to participate in the international Model U.N. competition, they enjoy seeing the sights and head over heals romance with cute british boys of course.', 93, '0+', '2001-03-27', 'Comedy/Family/Adventure'),
(1063543, 'Schumacher', 'https://image.tmdb.org/t/p/original/ArpeW9q7rEwWyzZ3SZbBRsuvFPZ.jpg', 'Through exclusive interviews and archival footage, this documentary traces an intimate portrait of seven-time Formula 1 champion Michael Schumacher.', 112, '16', '2021-09-14', 'Documentary'),
(1063544, 'Wolf Man', 'https://image.tmdb.org/t/p/original/wpSDzTBfF0Eeo5lzu2w9FTujGqd.jpg', 'With his marriage fraying, Blake persuades his wife Charlotte to take a break from the city and visit his remote childhood home in rural Oregon. As they arrive at the farmhouse in the dead of night, they\'re attacked by an unseen animal and barricade themselves inside the home as the creature prowls the perimeter. But as the night stretches on, Blake begins to behave strangely, transforming into something unrecognizable.', 102, '0+', '2025-01-15', 'Horror/Thriller'),
(1063545, 'Tosca', 'https://image.tmdb.org/t/p/original/uwk9i72NNrVjafVWZ9jWGW2DnZd.jpg', 'A stellar cast brings Puccini’s spellbinding opera to life, seizing every opportunity to thrill the audience. Luciano Pavarotti is Cavaradossi, the painter and political revolutionary in love with the beautiful and famous singer Tosca (the riveting Shirley Verrett). Rome’s diabolical chief of police, Baron Scarpia (Cornell MacNeil), wants Tosca for himself—but he underestimates the fury of a woman in love. With torture, murder, and a suicide in its final moments, Tosca packs more dramatic punches than most other operas—and this classic telecast captures them all. James Conlon conducts in a production by the incomparable Tito Gobbi, one of the great Scarpias of the 20th century.', 124, '0+', '1978-11-27', 'Music'),
(1063546, 'Gorąca linia', 'https://image.tmdb.org/t/p/original/EbhlsXivZlvj2Y6WpQTS5P9s9l.jpg', 'A provocative and edgy radio host must play a dangerous game of cat and mouse with a mysterious caller who\'s kidnapped his family and is threatening to blow up the whole station.', 104, '0+', '2022-10-31', 'Thriller/Drama'),
(1063547, 'Trujacy bluszcz', 'https://image.tmdb.org/t/p/original/3pYkklZMMD00B00jDT5PHvN0Dhm.jpg', 'A seductive teen befriends an introverted high school student and schemes her way into the lives of her wealthy family.', 92, '0+', '1992-05-08', 'Thriller/Drama'),
(1063548, 'Mały Nikita', 'https://image.tmdb.org/t/p/original/xdzugDI6avIlba05pstUFqh2mI2.jpg', 'An FBI agent works to uncover an all-American family as Soviet sleeper agents, and gets caught up in friendship with their oblivious teenage son.', 98, '0+', '1988-03-17', 'Drama/Action/Thriller'),
(1063549, 'Szybcy i wściekli 10', 'https://image.tmdb.org/t/p/original/3sFkBUkZtGb7bhVMi5uv1MdKlis.jpg', 'Over many missions and against impossible odds, Dom Toretto and his family have outsmarted, out-nerved and outdriven every foe in their path. Now, they confront the most lethal opponent they\'ve ever faced: A terrifying threat emerging from the shadows of the past who\'s fueled by blood revenge, and who is determined to shatter this family and destroy everything—and everyone—that Dom loves, forever.', 142, '12', '2023-05-17', 'Action/Crime/Thriller/Adventure/Mystery'),
(1063550, 'Sand Castle', 'https://image.tmdb.org/t/p/original/aw2K9mV3DE4ez3glmKmBxpzrDPQ.jpg', 'Set during the occupation of Iraq, a squad of U.S. soldiers try to protect a small village.', 113, '0+', '2017-04-21', 'War/Action/Drama'),
(1063551, 'The Freemason', 'https://image.tmdb.org/t/p/original/aCbVK0C5TVMB5Sp1zFbdRKXGSam.jpg', 'A wealthy banker lies brutally murdered. The bankers daughter and only heir, Rana (Alex McKenna) calls upon Cyrus (Randy Wayne) a brilliant but eccentric freelance writer, to assist in the investigation. Teaming up with homicide detective, Leon Weed (Sean Astin), Cyrus and Leon are quickly thrust into the cryptic world of Freemasonry, pursuing a legendary relic. They begin by interviewing Grandmaster Sheldon Lombard (Richard Dutcher) and a 32nd Degree Freemason named Jericho Beck (Joseph James). As the evidence leads them to a few select members of the bankers inner circle, the duo is forced to examine elements beyond their natural senses- and must do so quickly before the killer strikes again!', 95, '0+', '2013-12-07', 'Thriller/Crime'),
(1063552, 'Tyler Rake 2', 'https://image.tmdb.org/t/p/original/gvMVRNDZIUGHRoZcasIOT923psf.jpg', 'Back from the brink of death, highly skilled commando Tyler Rake takes on another dangerous mission: saving the imprisoned family of a ruthless gangster.', 122, '16', '2023-06-09', 'Action/Thriller/Crime'),
(1063553, 'Kevin sam w Nowym Jorku', 'https://image.tmdb.org/t/p/original/nml7EGnUFNYeWyZtGDQfyrS5xjB.jpg', 'Instead of flying to Florida with his folks, Kevin ends up alone in New York, where he gets a hotel room with his dad\'s credit card—despite problems from a clerk and meddling bellboy. But when Kevin runs into his old nemeses, the Wet Bandits, he\'s determined to foil their plans to rob a toy store on Christmas Eve.', 120, '12', '1992-11-15', 'Comedy/Family/Adventure'),
(1063554, 'Brettkontroll', 'https://image.tmdb.org/t/p/original/aPZEZSDYdfQDrKAL2xLyaA9gDhY.jpg', 'From 1978 to 1989 skateboarding was illegal in Norway, as the only country in the world it was not legal to sell, buy or use skateboard in this period. The film follows two generations of skaters - from the underground culture in the late 70s, with skating on secret locations in the forest around Oslo, to the commercial explosion when skating was legalized in 1989. The film says something about the Norwegian governments overprotective policy, but it also shows the paradox of how the prohibition led to a unique and creative environment.', 28, '0+', '2006-11-18', 'Documentary'),
(1063555, 'Isleen Pines', 'https://image.tmdb.org/t/p/original/cNCWhIj7C6c7RZJHTqHqJNhMOK7.jpg', 'A group of friends get together for the annual Halloween party, but are interrupted by mysterious visitors.', 84, '0+', '2023-10-28', 'Horror/Science Fiction/Comedy'),
(1063556, 'The Whirled', 'https://image.tmdb.org/t/p/original/lKMEjIBynuWU2NfMal1oJTiNCXO.jpg', 'Ken Jacobs writes: \"The first two sections were shot around Jack\'s loft on Reade Street on two 100\' 16 mm rolls. Sunday morning, following Saturday\'s sacrifice, I saw there was another 50 feet left. In an impromptu way, very different from my initial fastidious art-film approach, I quickly filmed Jack on the roof alongside his loft. The results had us falling onto the floor and I would never be an art-film true-believer again. After years of shooting my raging epic STAR SPANGLED TO DEATH starring Jack as The Spirit Not of Life But of Living, and after a few months of being on the outs with each other, we got together -- summer of \'61 in Provincetown -- for one last stab at friendship and the making of a film. In 1963, a snatch of Saturday Afternoon Blood Sacrifice was shown on TV. I had somehow been invited to participate in a TV quiz program called Back Your Hunch. (Or was it Hunch Your Back?)\"', 21, '0+', '1961-02-15', NULL),
(1063557, 'Dui Purush', 'https://image.tmdb.org/t/p/original/5fXmQSBMh7AjXL530YKQP7OoaTW.jpg', 'One of the early films of Chhabi Biswas featuring him as a leading man, before he came to be associated with the dominating patriarch roles that have become iconic in Bengali cinema, the film is a tale of the love, relationships and ideals of two generations. Nutubihari is an idealist who has given up his love for Kalyani  for the sake of his beliefs. He marries Bimala and becomes a lawyer, fighting for the rights of the poor against the feudal lords. Meanwhile, Kalyani comes to ask refuge after she becomes a widow and is inexplicably accepted by Bimala with a lot of warmth. As the years pass Kalyani\'s daughter Mamata and Nutu\'s oldest son Arun fall in love and wish to get married. However, the new-found fame and fortune turns his head and Nutu begins to resemble all the ideals and vices that he had always despised. On the other hand in an ironical turn of events, Arun comes to occupy the position once held by his father, highlighting the generational conflict of ideals.', 110, '0+', '1945-08-30', 'Family/Drama'),
(1063558, 'Pięć koszmarnych nocy 2', 'https://image.tmdb.org/t/p/original/g8y7bdjTa95XBxR5B4dMAdz5MqV.jpg', 'One year since the supernatural nightmare at Freddy Fazbear\'s Pizza, the stories about what transpired there have been twisted into a campy local legend, inspiring the town\'s first ever Fazfest. With the truth about what transpired kept from her, Abby sneaks out to reconnect with Freddy, Bonnie, Chica, and Foxy, setting into motion a terrifying series of events that will reveal dark secrets about the true origin of Freddy\'s, and unleash a long-forgotten horror hidden away for decades.', 104, '16', '2025-12-03', 'Horror/Thriller'),
(1063559, 'Memphis \'69', 'https://image.tmdb.org/t/p/original/1B0K0xyNhkJFhSwDIkwQQ226lD8.jpg', 'It’s the Summer of 1969. The temperature hovers around 105 degrees on a humid weekend in Memphis, Tennessee. It’s only been a year since the assassination of Dr. Martin Luther King Jr. But on this particular weekend, everyone in town, all races, creeds and colors have come out for the Fourth Annual Memphis Country Blues Festival. The lineup is the most ambitious in years, welcoming blues masters like Bukka White, Sleepy John Estes, Furry Lewis and the 106 year-old Nathan Beauregard, coupled with more notable headliners like Rufus Thomas & The Bar-Kays, John Fahey and rocker Johnny Winter. One attendee that year was Gene Rosenthal, who brought along a couple of cameras, a small crew and left with 40,000 feet of color film that was left untouched for nearly 50 years….until now. ‘Memphis 69’ is a time capsule. If you’re a blues enthusiast, watching this film feels like you’ve opened up a treasure chest and discovered that you’ve hit the motherload.', 72, '0+', '2019-01-28', 'Documentary/Music'),
(1063560, 'Crossroads - Dogonić marzenia', 'https://image.tmdb.org/t/p/original/prdFY9Bc28frBhhWl7mPSr7JmFp.jpg', 'After eight years apart, three childhood friends - Lucy, Kit, and Mimi - rediscover their friendship on a cross-country trip. With barely a plan, practically no money but plenty of dreams, the girls catch a lift with Mimi\'s handsome friend Ben in his convertible. Along the way they not only gather experiences that will change their lives, but they also discover how important it is to hold onto their hearts\' desires.', 93, '16', '2002-02-15', 'Drama/Romance/Comedy'),
(1063561, 'Arabskie noce', 'https://image.tmdb.org/t/p/original/w5ZurZi5LEyY9sGsl5iKzaCyEeC.jpg', 'Two half brothers battle each other for the power of the throne and the love of sensual, gorgeous dancing girl Scheherazade.', 86, '0+', '1942-12-25', 'Action/Adventure'),
(1063562, 'Trust Me', 'https://image.tmdb.org/t/p/original/aJe82MUVi8UNmZOm8iuXaKnT9Mx.jpg', 'An art dealer murders one of his artists in the hopes of increasing the market value of his work.', 104, '0+', '1989-11-10', 'Thriller/Comedy/Crime'),
(1063563, 'American Beast', 'https://image.tmdb.org/t/p/original/ivQ9rzNV3HzGlwbWNS6bavjsOJk.jpg', 'After a confrontation, a group of women are taken by a presence.', 92, '0+', '2014-10-21', 'Fantasy/Thriller'),
(1063564, 'The Ring', 'https://image.tmdb.org/t/p/original/AeRpUynJKDpJveklBJipOYrVxCS.jpg', 'Rachel Keller is a journalist investigating a videotape that may have killed four teenagers. There is an urban legend about this tape: the viewer will die seven days after watching it. Rachel tracks down the video... and watches it. Now she has just seven days to unravel the mystery of the Ring so she can save herself and her son.', 115, '18', '2002-10-18', 'Horror/Mystery'),
(1063565, 'The Transgressor', 'https://image.tmdb.org/t/p/original', 'A story of Puritan village life. The son of a minister wins a girl away from her devoted fisherman. Orphaned, she is adopted by the minister, and when her child is born refuses to reveal the father\'s name. She is cast out by the minister and scorned by the people. When her child is dying the fisherman comes back to her with unfaltering love, and the minister\'s son meets a tragic death at the hands of the Indians.', 0, '0+', '1913-06-25', 'Drama'),
(1063566, 'Micro Men', 'https://image.tmdb.org/t/p/original/n42Ngra1KKY4nU1pE08qeemHdl.jpg', 'In 1979 Clive Sinclair, British inventor of the pocket calculator, frustrated by the lack of home investment in his project,the electric car, also opposes former assistant Chris Curry\'s belief that he can successfully market a micro-chip for a home computer. A parting of the ways sees Curry, in partnership with the Austrian Hermann Hauser and using whizz kid Cambridge students, set up his own, rival firm to Sinclair Radionics, Acorn. Acorn beat Sinclair to a lucrative contract supplying the BBC with machines for a computer series. From here on it is a battle for supremacy to gain the upper hand in the domestic market.', 84, '0+', '2009-10-08', 'Drama'),
(1063567, 'Black Oasis', 'https://image.tmdb.org/t/p/original', 'Shut out, left alone… which way will Emily turn? This drama gets to the heart of difficulties that many post-modern teens are dealing with today: Peer pressure, cutting, suicide, divorced parents. In this story, we meet Emily, a girl struggling with the pain of her parents’ failed marriage and the dark temptations of a new friend.  This is an authentic, hard-hitting and ultimately compassionate story about the forces that tear at today’s families. The intense emotion of Emily’s journey will motivate discussion on a wide range of issues relevant to today’s teens and parents.', 26, '0+', '2005-10-28', 'Drama'),
(1063568, 'Bliźniaczki', 'https://image.tmdb.org/t/p/original/u0q8wf74ON9p2J9SZOIhfQc7hst.jpg', 'Tess loves her mom Patricia and the horse ranch she was raised on, but she’s ready for the next chapter. Attending her college orientation weekend, she gets the surprise of a lifetime when she’s approached by Sammy Crain, who happens to be her identical twin sister! After learning the story of how they were separated at birth, Tess is excited to connect with Sammy, but when Sammy’s adoptive parents turn up dead and Tess is mistaken for her sister, she realizes she’s been duped by her twin as part of Sammy’s devious plan to steal Tess’s identity, take the family fortune and get away with murder.', 88, '0+', '2020-05-16', 'TV Movie/Thriller'),
(1063569, 'Opus', 'https://image.tmdb.org/t/p/original/m0du9dsiOVeb0SgfqR8ZAEPRxww.jpg', 'A young writer is invited to the remote compound of a legendary pop star who mysteriously disappeared thirty years ago. Surrounded by the star\'s cult of sycophants and intoxicated journalists, she finds herself in the middle of his twisted plan.', 104, '0+', '2025-03-13', 'Horror/Mystery/Thriller');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1063570, 'The Skyrocket', 'https://image.tmdb.org/t/p/original/adJvMBTMkyk4KwYFrQ6ehGWJwsp.jpg', 'In the prologue Sharon Kimm and Mickey Reid are childhood friends in a tenement neighborhood but are separated when Sharon is placed in an orphanage. In the story we see Sharon as a young Hollywood star whose quick rise to fame leaves her self-centered, superficial, and a spendthrift. Ironically, the film that skyrocketed her to fame was written by Mickey. But her success is brief; and when it comes crashing to earth, Mickey is there to pick up the pieces.', 80, '0+', '1926-02-14', 'Drama/Romance'),
(1063571, 'Očovské pastorále', 'https://image.tmdb.org/t/p/original/vVR16KPm1ZWkK7c8Gz4B99XzWje.jpg', 'The story of a peasant whose harshness and bluntness only provoke disputes and anger, and his honesty and sense of truth and honor in conjunction with the previous qualities only exacerbate these disputes. The Slovak village with its collective farming, confronted with the habits of a square nature, raised by private farming, creates the main plot and conflict. In parallel, there is a lyrical motif of the young generation, whose love relationships do not care about the old ridiculous anger of the old generation.', 0, '0+', '1973-11-23', 'Drama'),
(1063572, 'Pięć koszmarnych nocy', 'https://image.tmdb.org/t/p/original/njcmQGiH38aljwWOD16eQa73BAP.jpg', 'Recently fired and desperate for work, a troubled young man named Mike agrees to take a position as a night security guard at an abandoned theme restaurant: Freddy Fazbear\'s Pizzeria. But he soon discovers that nothing at Freddy\'s is what it seems.', 110, '16', '2023-10-25', 'Horror/Thriller'),
(1063573, 'วิญญาณเลขที่ 13', 'https://image.tmdb.org/t/p/original/beBUaewkS1ytANQJ5F2UXIo0Wty.jpg', 'Bussaba, a volleyball player who enjoyed bullying others, was found dead by hanging in a gym, causing chaos and horror among other team members.', 106, '0+', '2025-06-13', 'Horror/Thriller'),
(1063574, '南京照相馆', 'https://image.tmdb.org/t/p/original/lwrANgpPEBmYZ59oExpCiuv34Ou.jpg', 'In the Nanjing Massacre of 1937, in order to save his life, postman A Chang pretended to be a photo developer in a photo studio and developed photos for the Japanese army. He also took in a group of Chinese soldiers and civilians, turning the studio into a temporary shelter. However, in the face of the Japanese army\'s cruel atrocities, A Chang risked his life to safely transfer the refugees and exposed the evidence of the massacre to the public.', 137, '0+', '2025-07-19', 'Drama/War/History'),
(1063575, 'Hellions', 'https://image.tmdb.org/t/p/original/hFIimZOCMyoQvbGnz0gntgcbYVm.jpg', 'A teen faces a night of terror when three malevolent trick-or-treaters come knocking at her door.', 80, '16', '2015-09-25', 'Horror'),
(1063576, 'Eksperymentator', 'https://image.tmdb.org/t/p/original/kMTLGbekuHkpw4M8XKdN2d7n2aF.jpg', 'Yale University, 1961. Stanley Milgram designs a psychology experiment that still resonates to this day, in which people think they’re delivering painful electric shocks to an affable stranger strapped into a chair in another room. Despite his pleads for mercy, the majority of subjects don’t stop the experiment, administering what they think is a near-fatal electric shock, simply because they’ve been told to do so. With Nazi Adolf Eichmann’s trial airing in living rooms across America, Milgram strikes a nerve in popular culture and the scientific community with his exploration into people’s tendency to comply with authority. Celebrated in some circles, he is also accused of being a deceptive, manipulative monster, but his wife Sasha stands by him through it all.', 97, '0+', '2015-10-16', 'Drama/History'),
(1063577, 'Twist', 'https://image.tmdb.org/t/p/original/tw7lgyrQpEVXuwjsx94brDSRIFZ.jpg', 'A Dickens classic brought thrillingly up to date in the teeming heartland of modern London, where a group of street smart young hustlers plan the heist of the century for the ultimate payday.', 92, '0+', '2021-01-22', 'Crime/Drama/Action'),
(1063578, 'Blue Moon', 'https://image.tmdb.org/t/p/original/tDkegNhdXIqJPhuJhcypzaUFvko.jpg', 'Corazon (Boots Anson Roa), an old Filipina who lives in Boston, wrote to each Manuel Pineda in her home a letter. She hopes to find her love again. In the Philippines experiences of the old Manuel Pineda (Eddie Garcia), meanwhile, that he has cancer and has only months to live. He goes in search of his Corazon.There were two Corazons in his life: before the Second World War, he spent (Mark Herras) and his buddy Domingo (Polo Ravales) a lot of time with the shy \"Cora\" (Jennylyn Mercado) and the lively \" Azon \"(Pauline Luna).', 107, '0+', '2006-01-01', 'Romance/Drama'),
(1063579, 'Götterdämmerung', 'https://image.tmdb.org/t/p/original/nC53MwfA1gELEElmBwN1sHhonf2.jpg', 'Gathered at the foot of the rock where Siegfried and Brünnhilde have come together, three Norns weave the fate of the world. Past, present and future are interwoven in their rope; when it breaks unexpectedly, the fates still have one oracle: the twilight of the gods is imminent! Götterdämmerung has more than one ending: Siegfried falls victim to intrigue and to his own innocence, Valhalla goes up in flames, Brünnhilde sacrifices herself to return the ring to the Rhinemaidens. Alliances are forged and immediately broken again, magical potions and helmets create painful confusions, and generational traumas result in general destruction. Everything familiar to humans and gods collapses.', 266, '0+', '2025-02-23', 'Music/Drama'),
(1063580, 'Dracula 3000', 'https://image.tmdb.org/t/p/original/ucrvSJIoxw1D2SZ2p6J9EIHzFPg.jpg', 'In the year 3000, the deep space salvage ship Mother III locates the vanished starship Demeter in the Carpathian System. Captain Abraham Van Helsing and his crew composed of the blonde assistant Aurora Ash; the crippled navigator Arthur \"The Professor\" Holmwood, who believes that he is a genius; the strong and dumb Humvee; the intern Mina Murry; and the drug addicted 187, decide to claim the possession of Demeter. While exploring the spacecraft, they see a tape of fifty years ago of Captain Varna telling that he was locked in his cabin since his crew was acting weird after getting a cargo of coffins in Transylvania station. When 187 decides to search in the coffins for some possible hidden dope, he cuts his hand and his blood awakes Count Orlock, a.k.a. Count Dracula. When Aurora discloses who Dracula is, the survivors try to find a way to destroy the vampire.', 87, '0+', '2004-08-09', 'Horror/Science Fiction'),
(1063581, 'Porwanie', 'https://image.tmdb.org/t/p/original/wbgvZSSvQyp1ZJGCZqXyTymJDu8.jpg', 'A female FBI agent is offered millions to help a thief escape from a hijacked airplane.', 86, '0+', '2017-04-14', 'Action/Thriller'),
(1063582, 'Kara no Kyōkai: Mirai Fukuin - Extra Chorus', 'https://image.tmdb.org/t/p/original/d2plsuUbqVPOwdA1We9kbBTtltl.jpg', 'Mikiya Kokutou gives Shiki Ryougi a cat to watch, as he will be away for a little while. Though Shiki protests, he leaves the cat anyway, and Shiki is stuck trying to understand her new feline companion. But as luck would have it, the cat seems to have taken a liking to Mikiya and misses him. Later in another part of the city, Ririsu Miyazuki visits the place where her dear friend committed suicide. She intends to end her life as well, but she meets Fujino Asagami, a blind classmate with a traumatic past. Though the two girls don\'t have much in common, Asagami reminds Miyazuki of her lost friend and helps her understand her pain. Two months later, Mikiya elects to celebrate New Year\'s with Shiki instead of his family, which makes his sister Azaka very upset, leading to her spending the holiday with her school friends. As the snow begins to fall, Mikiya reflects on what he wishes for most of all: that Shiki\'s life be filled with happiness.', 32, '0+', '2013-09-28', 'Animation/Science Fiction/Fantasy/Drama'),
(1063583, 'Iron Man 2', 'https://image.tmdb.org/t/p/original/6WBeq4fCfn7AN0o21W9qNcRF2l9.jpg', 'With the world now aware of his dual life as the armored superhero Iron Man, billionaire inventor Tony Stark faces pressure from the government, the press and the public to share his technology with the military. Unwilling to let go of his invention, Stark, with Pepper Potts and James \'Rhodey\' Rhodes at his side, must forge new alliances – and confront powerful enemies.', 124, '12', '2010-04-28', 'Adventure/Action/Science Fiction'),
(1063584, 'Cabinet Confidential', 'https://image.tmdb.org/t/p/original/eg6AtVQegELm0FpfNfcw0H6bWdO.jpg', 'A revealing one-off documentary that provides an inside view of how Tony Blair and former prime ministers - including Harold Wilson, Margaret Thatcher and John Major - have run their cabinet, the highest decision-making body in the land. Through candid interviews, rare archive footage and filming inside No 10, presenter Michael Cockerell opens the door to the Government\'s own chamber of secrets as he seeks the answer to the question: is the notion of cabinet government an obsolete concept?', 60, '0+', '2001-11-17', 'Documentary/TV Movie'),
(1063585, 'Homecoming', 'https://image.tmdb.org/t/p/original/lCanG5y42qrd1dVgslXoyaBlHA.jpg', 'The movie tells the story of Abigael Edades who returns to her Philippine hometown from her five-year stint as a nurse in Canada. Her town mates rousingly welcome her as a hero, the crass moniker ascribed by the government to hundreds of thousands of Filipinos working abroad. She finds her family in tatters, her parents estranged and living apart and her brother Jepoy living the life of drugs. But she basks in the welcome of her mother and youngest brother Noel and the devotion of her boyfriend, who proposes marriage. Her happiness is short-lived. She is diagnosed with SARS and contaminates Noel. They cause a national scare, are quarantined in Manila and are shunned by their own townspeople and the municipal government. Even her boyfriend leaves her. The hero becomes a heel. \"Just a month after my return, my views on life and the people around me have irrevocably changed,\" she says at the start of the movie.', 110, '0+', '2003-12-25', NULL),
(1063586, 'Blitz', 'https://image.tmdb.org/t/p/original/qjqmhhc7uLub22mhu4V6DjOBwXM.jpg', 'A tough cop is dispatched to take down a serial killer who has been targeting police officers.', 97, '0+', '2011-05-20', 'Crime/Action/Thriller'),
(1063587, 'Traceroute', 'https://image.tmdb.org/t/p/original/oDelXRjk8DBPdmjr5gcXr8ulJBr.jpg', 'Artist and life-long nerd Johannes Grenzfurthner is taking us on a personal road trip from the West Coast to the East Coast of the USA, to introduce us to places and people that shaped and inspired his art and politics. Traceroute wants to chase and question the ghosts of nerddom\'s past, present and future. An exhilarating tour de farce into the guts of trauma, obsession and cognitive capitalism.  Features interviews with Matt Winston, Sandy Stone, Bruce Sterling, Jason Scott, Christina Agapakis, Trevor Paglen, Ryan Finnigan, Kit Stubbs, V. Vale, Sean Bonner, Allison Cameron, Josh Ellingson, Maggie Mayhem, Paolo Pedercini, Steve Tolin, Dan Wilcox, Jon Lebkowsky, Jan \"Varka\" Mulders, Adam Flynn, Abie Hadjitarkhani, Kelly Poots...', 120, '0+', '2016-04-28', 'Comedy/Documentary'),
(1063588, 'Nevada Smith', 'https://image.tmdb.org/t/p/original/j6z17RwIBg0wLrFxVZ4T4PU00rJ.jpg', 'Nevada Smith is the young son of an Indian mother and white father. When his father is killed by three men over gold, Nevada sets out to find them and kill them. The boy is taken in by a gun merchant. The gun merchant shows him how to shoot and to shoot on time and correct.', 128, '0+', '1966-06-10', 'Western'),
(1063589, 'Prawdziwe wyznania', 'https://image.tmdb.org/t/p/original/qwTwHKesH4QcvSBkS1dE89AIFst.jpg', 'A cop clashes with his priest brother while investigating the brutal murder of a young prostitute.', 108, '0+', '1981-09-25', 'Crime/Drama'),
(1063590, 'Zemsta po Latach', 'https://image.tmdb.org/t/p/original/z4nTYj3JZ5jWAhDgrmEhW2GRAzb.jpg', 'After a tragic event happens, composer John Russell moves to Seattle to try to overcome it and build a new and peaceful life in a lonely big house that has been uninhabited for many years. But, soon after, the obscure history of such an old mansion and his own past begin to haunt him.', 105, '0+', '1980-03-28', 'Horror'),
(1063591, 'Culture Shock', 'https://image.tmdb.org/t/p/original/g12GgEf9WXS8Ww0UbDpMH5NeVbI.jpg', 'A young Mexican woman crosses the border in search of the American dream, only to instead find her worst nightmare lying within.', 91, '0+', '2019-07-04', 'Horror/Thriller/TV Movie'),
(1063592, 'El rey', 'https://image.tmdb.org/t/p/original/ajpFRYkrKRqbu64MBTFtpR6XnPz.jpg', 'Spain, June 2014. King Juan Carlos I abdicates after forty years on the throne. The historical cycle that began in 1978 has ended. It is the beginning of a new era. Felipe VI is the new king and the future is uncertain.', 82, '0+', '2018-12-05', 'Drama/History'),
(1063593, 'Meri Bhabhi', 'https://image.tmdb.org/t/p/original/a3MkmMn3mXyQmdfpLYOyvH42U4d.jpg', 'A simple-minded, yet loving young couple, Rajoo (Sunil Dutt), and his wife Maya, who allow their child to be adopted by Rajoo\'s sister-in-law/Bhabhi, Shanti (Kamini Kaushal). Shanti\'s child was still-born after an accident. But Shanti does not know this, and believes the child to be her own. She is misled and misguided by Gangajali (Lalita Pawar), and as a result Rajoo and Maya are humiliated, not allowed to come near the child, asked to leave the house, and ultimately are charged with kidnapping the child. Rafi\'s joyful song \"Aaj mera haal na poocho...\"; and Lata\'s lullaby \"Sohya mera pyar aanchal me pehli bar...\", are still popular on radio.', 0, '0+', '1969-01-15', 'Drama/Family'),
(1063594, 'Xreens', 'https://image.tmdb.org/t/p/original', 'A documentary about Malga Kubiak and her team. It\'s not only a movie about her, but also about the situation of independent, lesbian and queer cinema in Poland, Europe and all over the world. Malga is a director, activist, mother, daughter and grandmother. Her family is constantly engaged in her work. She made over 40 movies about such queer icons as Pasolini, Annemarie Schwarzenbach, F.G. Lorca, Andy Warhol or Lizzie Siddal, the muse of Pre-Raphaelites.', 187, '0+', '2020-04-10', NULL),
(1063595, 'Od góry do dołu', 'https://image.tmdb.org/t/p/original/odrpUIIs4Ay9Fu9Hio9MEyIR8Ot.jpg', 'When a titan music mogul, widely known as having the \"best ears in the business\", is targeted with a ransom plot, he is jammed up in a life-or-death moral dilemma.', 133, '16', '2025-08-14', 'Thriller/Crime/Drama'),
(1063596, 'Whirlwind Raiders', 'https://image.tmdb.org/t/p/original/rpff7qtuRMJi6eptIXQ5tenAaxX.jpg', 'It\'s 1873 and the disbanded Texas Rangers have been replaced by the corrupt Texas State Police. Steve Lanning arrives posing as a wanted outlaw to get in with them in his attempt to have them replaced. His inside work helps the Durango Kid break up the State Police raids but he is in trouble when his secret identity as Durango becomes known to them.', 54, '0+', '1948-05-12', 'Western'),
(1063597, 'Sweet Virginia', 'https://image.tmdb.org/t/p/original/qTch1l0ZMU4MiOBDEJ14jVmANVC.jpg', 'A former rodeo star, now a motel manager, meets a young man who is responsible for the violence that suddenly has seized his small town.', 94, '0+', '2017-11-17', 'Drama/Thriller'),
(1063598, 'Ibiza', 'https://image.tmdb.org/t/p/original/xm0QJ3eumZ5LSewpYKQe6KfwWRW.jpg', 'She could do the responsible thing. Or she could go to Ibiza with her best friends to chase down a hot DJ. Easy choice.', 94, '16', '2018-05-25', 'Comedy/Romance'),
(1063599, 'Ucieczka Gangstera', 'https://image.tmdb.org/t/p/original/7cHWJOIceeRdXtmAMMqhEfZLr0N.jpg', 'A recently released ex-convict and his loyal wife go on the run after a heist goes wrong.', 123, '0+', '1972-12-13', 'Action/Crime/Thriller'),
(1063600, 'Sri Menanti', 'https://image.tmdb.org/t/p/original/wj2yxO6vfkrrG4Cj9rmvESs4Qu4.jpg', 'Adapted from an original novel titled Fatimah《花蒂玛》by Chua Boon Hean, \'Sri Menanti\' is a poignant portrayal of an intercultural romance inhibited by racial prejudice and segregation, religious conservatism, and repressive social mores. The film stars Malay actress Zaiton and Hong Kong actor Paul Chang as the star-crossed lovers who seek in the Other not only connection and acceptance but also escape and freedom. Released in both Malay and Mandarin-dubbed versions, the film was unprecedented in the Singapore film industry for casting both local Malay and Hong Kong Chinese film stars.', 104, '0+', '1958-01-01', 'Drama/Romance'),
(1063601, 'Thrillkill', 'https://image.tmdb.org/t/p/original/bXhQkG2SzZPcVH20OtepR37Dkkf.jpg', 'Karlie Kendall\'s job is to write computer games - but in her spare time she hacks bank accounts. With 5 million dollars gathered, she wants to retire to Brazil - unaware that her secret partner Adrienne intends to keep all the money. Moreover, Karlie\'s boss Julien has got to know of her doing and has hired villains to get hold of the treasure. Only after Karlie\'s death they realize that she has hidden the money well inside the computer game \"Thrillkill\" - leaving the single clue to her sister, stewardess Bobbie.', 96, '0+', '1984-12-14', 'Horror/Thriller/Crime'),
(1063602, 'Apache Woman', 'https://image.tmdb.org/t/p/original/dM1PVRNIOlozVSx69P7NgrLO9sC.jpg', 'A government agent ventures west to look into reports that Apaches are behind a recent wave of frontier attacks. Begins to suspect a set-up.', 79, '0+', '1955-09-15', 'Western'),
(1063603, 'En el corazón de la Decimotercera', 'https://image.tmdb.org/t/p/original/Hmolhjm1mxhyc5aPi4qPO5DhhP.jpg', '', 0, '0+', '2018-09-17', 'Documentary'),
(1063604, 'Snatched', 'https://image.tmdb.org/t/p/original/9KGWBUBaE2VHSohwGeFz9Bd5aVJ.jpg', 'The wives of three wealthy men are kidnapped and held for a $3 million ransom, but one of the men doesn\'t want to pay his share.', 73, '0+', '1973-01-31', 'Crime/Drama/Thriller/TV Movie'),
(1063605, 'Telenowela', 'https://image.tmdb.org/t/p/original/9Hiq0x0uX5HbhwJkximg0am11ua.jpg', '32-year-old Charlotte could have it all, but she doesn\'t want any of it. When she moves away from her boyfriend, she happens to become the upstairs neighbour of a trans woman Veronica. Veronica prefers to keep to herself with her little dog and a romantic soap show on TV, while Charlotte gets through the nights with one-night stands. An assault, a new bed and some white curtains bring the two of them together.', 105, '0+', '2006-04-07', 'Comedy/Drama'),
(1063606, 'Mr. Hush', 'https://image.tmdb.org/t/p/original/l4EmuVuKdw968CRxQvC4zOjrOHG.jpg', 'What is the ultimate horror? For Holland Price, it is losing everything he loves. Holland is a devoted family man whose life is turned upside-down by a horrifying figure one Halloween night.  Holland spends ten years searching the country, filled with self-torment and suffering, as he is haunted by his nightmares of that terrible night. He is drawn back to the small town of Layton, PA where he finds work in a restaurant owned by his friend, Mac. There he meets Debbie and begins to regain stability and peace in his life. But once his life adjusts to normal, Mr. Hush and his henchman, Stark, arrive. Driven by a lifetime of hatred toward the Price family, Mr. Hush continues to taunt Holland. But why? Follow our hero on his emotional rollercoaster ride as he descends into a dank and villainous world to see the face of darkness for what it is the face of Mr. Hush.  Two men, fueled by love lost, collide in this chilling battle of good vs. evil.', 88, '0+', '2010-10-23', 'Horror'),
(1063607, 'Brighton Storeys', 'https://image.tmdb.org/t/p/original', 'In Brighton on the South coast of England, sharpened by the sting of sea spray, and mellowed by numinous light, a tight-knit community of oddballs and heart-felts live together in a tatty old mansion, the Fletcher Apartments. When a golden feather, the priceless antique mascot of the building, unexpectedly disappears, the residents have a mystery to solve. Will they find the talisman that previously bound them together, or will their community, now divided against itself, irrevocably unravel?', 0, '0+', NULL, 'Comedy'),
(1063608, 'Tin Gods', 'https://image.tmdb.org/t/p/original/3AzSLXOObTAjzcGHHc1AvWRHAkq.jpg', 'In a mountain village in South America, Dr. McCoy and the padre watch Roger Drake enter a small chapel near a towering bridge, and McCoy recounts the story of Drake\'s life: As a rising engineer, he marries Janet Stone, the ambitious daughter of a wealthy family, and neglects his career while Janet becomes a candidate for the State Assembly. Drake comes into conflict with her political friends, and when their baby falls from its nursery window, the couple remorsefully decide to separate. Drake, degenerated by drink, goes to South America to construct a bridge; there he is stricken by fever and is redeemed by the love and care of Carita, a dancer. Carita, however, learns of Janet\'s political defeat and her attempt to effect a reconciliation with Drake; thinking he still loves his wife, she leaps from the bridge. Drake returns each year to the chapel he has erected in her memory. A lost film.', 90, '0+', '1926-09-19', 'Drama'),
(1063609, 'Spectre', 'https://image.tmdb.org/t/p/original/rhVQtNDiibrnGTuH80v8OEKD1w5.jpg', 'A cryptic message from Bond’s past sends him on a trail to uncover a sinister organization. While M battles political forces to keep the secret service alive, Bond peels back the layers of deceit to reveal the terrible truth behind SPECTRE.', 148, '16', '2015-10-26', 'Action/Adventure/Thriller'),
(1063610, 'Pulp Fiction', 'https://image.tmdb.org/t/p/original/5Whi9po8MTPyUTxAioXfyXGHNQE.jpg', 'A burger-loving hit man, his philosophical partner, a drug-addled gangster\'s moll and a washed-up boxer converge in this sprawling, comedic crime caper. Their adventures unfurl in three stories that ingeniously trip back and forth in time.', 154, '15', '1994-09-10', 'Thriller/Crime/Comedy'),
(1063611, 'Azam', 'https://image.tmdb.org/t/p/original/rv7ipagcfhhkWgiQOjuVlq3nsJ9.jpg', 'Azam, who is convicted on charges of robbery is finally released after serving a 17-year sentence. With hopes of starting life anew, he hopes to reconcile with his family. However his ex-wife Latifah and daughter Haniza does not welcome his presence in their lives. Even Musa, Latifah\'s new husband forbids them from communicating. Helpless, Azam finds his own new life and befriends Ayub. Unknown to Azam, Ayub is Musa\'s friend, who is plotting his downfall behind Azam\'s back. When things turn for the worst and Azam is desperate without family and money, he began turning to his bad company of friends. Will he follow his past footsteps and be bathed in crime again? Or will life brings new hope for Azam?', 87, '0+', '1997-01-01', 'Action/Drama'),
(1063612, 'En fånge har rymt', 'https://image.tmdb.org/t/p/original/9thfERGtyhGOL8w48AAt7JX9DUK.jpg', '\"A Prisoner Has Escaped\" - Franz is imprisoned for blowing up a factory. He escapes in order to prove his innocence.', 73, '0+', '1943-12-26', 'Crime/Drama'),
(1063613, 'Changes', 'https://image.tmdb.org/t/p/original/xF8fHysFHBbET0MSNY3NJoYr6DJ.jpg', 'It\'s the late sixties, a time of peace signs, free love and revolution; and Kent like others of his generation, is looking for a meaning to his life. Driving alone along the Big Sur, he flashes back to difficult memories about college, drugs, family and relationships. The flashback over, Kent is back in his car, but he loses control and crashes over an embankment. Stunned and hurt, Kent starts hitchhiking, not caring which direction. He wanders aimlessly, taking rides from strangers, never making real contact. Then he meets Julie who intrigues him and they move in together. Kent still has to find himself and the meaning of his existence.', 93, '0+', '1969-02-11', 'Drama/Romance'),
(1063614, 'Russian Snark', 'https://image.tmdb.org/t/p/original/i495UGLaZA5qoG8ESpNBeG2A7Ie.jpg', 'Misha (Stephen Papps), a once celebrated filmmaker who has fallen on hard times, resolves to leave his homeland in search of a film-friendly country where he can pursue his career. With his wife Nadia (Elena Stejko) in tow he sets sail from Russia in a tiny lifeboat, drifting cross the Pacific to finally arrive in New Zealand. Before long Misha realises that New Zealand is no more receptive to his ideas and aesthetic than Russia. Yet he perseveres with his experimental film, ignoring his wife’s pleas to find work. Misha increasingly withdraws into himself, and his relationship with Nadia collapses. Alone, his obsessions take hold and he steadily descends into madness. Only a chance encounter with a young Polynesian woman saves him from the ultimate act of self-destruction. His friendship with Roseanna (Stephanie Tauevihi) inspires a re-awakening, as he begins to reconnect with the world around him.', 79, '0+', '2010-07-20', 'Drama/Comedy'),
(1063615, 'Pals First', 'https://image.tmdb.org/t/p/original/zjUl15xj3kCWpZNpp777OuCaImN.jpg', 'Richard Castleman, master of Winnecrest Hall in Louisiana, goes on a sea voyage recommended by his cousin and physician, Harry Chilton, who thereupon begins romancing Castleman\'s fiancée, Jeanne Lamont. When word arrives of Castleman\'s death, Chilton prepares to usurp the fortune and property of the dead man. Danny Rowland, who is found wounded by two wandering crooks, Dominie and The Squirrel, opportunely arrives at the estate seeking food and rest; and because of his resemblance to Castleman, he is welcomed as the master. Dominie is introduced as an English cleric and The Squirrel as an Italian count, while Danny falls in love with Jeanne, who believes him to be her fiancé. Chilton, however, suspects the trio and finally unmasks them. It then develops that Danny actually is Castleman, who had decided to reform the two men who befriended him and to expose the dishonesty of his cousin.', 70, '0+', '1926-08-08', 'Crime/Drama/Romance'),
(1063616, 'Il Turco in Italia - Festival d\'Aix-en-Provence', 'https://image.tmdb.org/t/p/original/fQEeXuqcfdNtfbrBDl76cZvvLMs.jpg', 'In the bright sunlight of opera buffa, a handsome Turkish prince (with an agile bass voice) lands on the coast of Naples looking for amorous adventures. In no time at all he meets a vivacious Italian girl (a coquettish virtuoso soprano), who is accustomed to flitting between admirers, much to the displeasure of her elderly husband. This little group carries on its flirtations, rivalries and quarrels under the delighted eyes of the poet Prosdocimo, who, as it happens, has been seeking inspiration for a dramma buffo.', 174, '0+', '2014-04-07', 'Music'),
(1063617, 'Ash', 'https://image.tmdb.org/t/p/original/nRa8B3tQCUK6pVwjasIyQehbvpF.jpg', 'On the mysterious planet of Ash, Riya awakens to find her crew slaughtered. When a man named Brion arrives to rescue her, an ordeal of psychological and physical terror ensues while Riya and Brion must decide if they can trust one another to survive.', 95, '0+', '2025-03-20', 'Horror/Science Fiction'),
(1063618, 'Skowyt', 'https://image.tmdb.org/t/p/original/p3ZQxdz6NVS2wZe0BKluhyBWRwO.jpg', 'When passengers on a train are attacked by a creature, they must band together in order to survive until morning.', 89, '0+', '2015-10-01', 'Horror'),
(1063619, 'A feltaláló', 'https://image.tmdb.org/t/p/original/lhorI4bvmV8zG22Hw9hJAr9ZSeI.jpg', 'This biopic traces the life of Dr. József Béres from the development of the \"Béres drops\" to his struggles under the Communist regime in Hungary.', 126, '0+', '2020-02-06', 'Drama'),
(1063620, 'Dangerous Touch', 'https://image.tmdb.org/t/p/original/ffz93TvSA02QumNvn2kysJw3UyO.jpg', 'A promiscuous radio sex therapist is dragged into blackmail by a young hustler.', 101, '0+', '1995-05-17', 'Thriller'),
(1063621, 'The Candidate', 'https://image.tmdb.org/t/p/original/6zcDSOe1akUXsc2Q1APfchKcVaI.jpg', 'Bill McKay is a candidate for the U.S. Senate from California. He has no hope of winning, so he is willing to tweak the establishment.', 110, '0+', '1972-06-29', 'Comedy/Drama'),
(1063622, 'Inside Life', 'https://image.tmdb.org/t/p/original', 'A new Nollywood movie, ‘Inside Life’, premiered at the Silverbird Galleria, Victoria Island, Lagos, last week.  It was produced by Chuks Enete and directed by Tope Adebayo Salami. The movie is the debut release of a new Nigerian film production house, Sillo studios.  Inspired by actual events, the movie revolves around the faltering Nigerian Judicial system and its effect on a man’s life.  In attendance at the premiere were actors and comic stars; Wole Ojo and Nedu Wazobia, and others. Also, the victim of the unfair Judicial system Lanre Olorunnisola, whose story inspired the film, was present at the event.', 0, '0+', '2022-09-09', 'Comedy/Drama'),
(1063623, 'Stalked!', 'https://image.tmdb.org/t/p/original/scRvKpf1DdhZDtQe1GE9WHuROfW.jpg', 'In The Intruder Part 1, a young woman (Vanessa Carlton) is stalked by a rapist (David Shore) and then held captive by her attacker until he’s ready to act!  In The Intruder Part 2, Vanessa Carlton stars as Devlin, the cop who can’t seem to bring her suspects in alive and in one piece! After her last experience in, Devlin finds herself going undercover in a seedy go-go bar as a dancer in an attempt to stop a serial killer! Her superior, Lt. Juliano (GW Lawrence), has set her up as the next target. But unknown to all of them, a person from her past may cause her untimely death!', 0, '0+', '1993-10-06', 'Horror'),
(1063624, 'Hobbit: Bitwa Pięciu Armii', 'https://image.tmdb.org/t/p/original/m3Lfi8084o3oGrbJ3oGJvToM2no.jpg', 'Following Smaug\'s attack on Laketown, Bilbo and the dwarves try to defend Erebor\'s mountain of treasure from others who claim it: the men of the ruined Laketown and the elves of Mirkwood. Meanwhile an army of Orcs led by Azog the Defiler is marching on Erebor, fueled by the rise of the dark lord Sauron. Dwarves, elves and men must unite, and the hope for Middle-Earth falls into Bilbo\'s hands.', 144, '16', '2014-12-10', 'Action/Adventure/Fantasy'),
(1063625, 'The Bigtop', 'https://image.tmdb.org/t/p/original', 'Vincent O\'Malley endures a home life on the prairie under the oppressive eyes of his father. The arrival of a circus in Vincent\'s home town leads Vincent to run away. Vincent assumes the role of a clown, but realizes that his new family is in need of an audience and the muscle and daring to acquire it. Vincent leads his friends in missions to gather crowds to the circus tent. The arrival of a young girl, however, sets Vincent on edge as he begins to suspect that those around him are thwarting the acquisition of his true love. As jealousy leads to a precipice of loneliness and annihilation, Vincent must come to a reckoning with his true nature and with his place in the universe.', 83, '0+', '2010-01-01', 'Drama/Music'),
(1063626, 'Sky High', 'https://image.tmdb.org/t/p/original/acmwMpjo0JynWBGYkFKA1BclSJF.jpg', 'When he is told that he is to spend three more years as a tailgunner, goofball GI Herbert Pumice thinks that a promotion--which he has little to no chance of getting--will get him out of the job he hates. He asks his girlfriend Sally, who owns the base café, for help. She goes to the base commander, Col. Baker--who she knows has a crush on her--to help out Herbert. Col. Baker schedules a promotion hearing for Herbert that Friday. He naturally fails it miserably, and then learns that Col. Baker is going out on a date with Sally. Meanwhile, the base military intelligence officer discovers that Herbert is a dead-ringer for the head of a spy ring intending to sabotage a new automated plane, and gets Herbert assigned to infiltrate the gang. Complications ensue.', 60, '0+', '1951-10-19', 'Comedy'),
(1063627, 'The Shore', 'https://image.tmdb.org/t/p/original/ihwjhnpbhf2xT2tk6MEMbpYgesp.jpg', 'Hungering for some quality alone time with her new boyfriend, Ray, single mother Kaliope Harris leaves her young daughter, Anna, in the care of loving grandmother Mrs. Harris. An idyllic day at the beach turns to tragedy for the Harris family, however, when in the blink of an eye the precious young Anna seemingly disappears into the vast sand. While Mrs. Harris struggles to accept the startling disappearance, her enraged husband hounds the authorities to step up their search and Kaliope and Ray comb the beach in a desperate bid to retrace Anna\'s every step on that fateful and tragic day.', 100, '0+', '2005-09-11', 'Drama/Mystery/Thriller'),
(1063628, 'W niebepieczeństwie', 'https://image.tmdb.org/t/p/original/1IrfAddMJfnROUf4fKOheO7ujd4.jpg', 'It’s 1941 and the Japanese attack on Pearl Harbor has destroyed America’s morale. The US President Franklin D. Roosevelt then decides to risk it all by bombing Tokyo and raise more hope for his citizens. After completing its mission, a unit of the US Air Force is forced to make an emergency landing in China. Its commander Jack Turner (Emilie Hirsch) barely survives but gets rescued by Ying (Crystal Liu), a local widow who will stop at nothing to hide him from the Japanese occupant.', 97, '0+', '2017-11-10', 'Drama/Romance/History/War'),
(1063629, 'Erzulie', 'https://image.tmdb.org/t/p/original/31MGaMBBCYpL18PQtmxebgRyktm.jpg', 'A reunion between 4 friends quickly goes awry when they find themselves face to face with Erzulie the swamp mermaid goddess.', 90, '0+', '2022-06-14', 'Horror/Fantasy/Adventure'),
(1063630, 'Grinch: Świąt nie będzie', 'https://image.tmdb.org/t/p/original/zBQWTcFqiLimmLLUVR9SrRXQNF3.jpg', 'The Grinch decides to rob Whoville of Christmas - but a dash of kindness from little Cindy Lou Who and her family may be enough to melt his heart...', 104, '12', '2000-11-17', 'Family/Comedy'),
(1063631, 'Getting Over', 'https://image.tmdb.org/t/p/original/mmoSXDjYC27mZI0GU47dmZmyEDw.jpg', 'Senor Daniels stars as Mike, a man with a dream of making it big in the music industry. He gets conned by a bigoted board chairman, and has his label, \'Impossibly Funky Records\' taken over. As surmised by Alllmovie, this tuneful drama features the rock group Love Machine as it tells the tale of a record promoter hired by a crooked producer to fulfill affirmative action quotas. It is the hard-working, independent-minded promoter who discovers and develops the Love Machine, an all female group. The trouble begins when the group\'s lead singer is kidnapped and the promoter learns that his employer\'s label is really a front for the mob.', 108, '0+', '1981-04-24', NULL),
(1063632, 'Ostateczne Rozwiązanie', 'https://image.tmdb.org/t/p/original/Onqn8XXyhANuy1LIL7AIN6unQk.jpg', 'At the Wannsee Conference on January 20, 1942, senior Nazi officials meet to determine the manner in which the so-called \"Final Solution to the Jewish Question\" can be best implemented.', 96, '0+', '2001-05-19', 'History/Drama/War/TV Movie'),
(1063633, 'Khel', 'https://image.tmdb.org/t/p/original/kf7RBph4apQPa3tUjClSzdIZrO2.jpg', 'Two friends falling in love with the same girl leads to murder and intrigue.', 174, '0+', '2003-10-03', 'Action/Thriller'),
(1063634, 'Intruz', 'https://image.tmdb.org/t/p/original/pib25gFtNCShcyRpFvp1jrcJ1Xk.jpg', 'The overnight stock crew of a local supermarket find themselves being stalked and slashed by a mysterious maniac.', 88, '0+', '1989-01-27', 'Horror/Mystery'),
(1063635, 'Savageland', 'https://image.tmdb.org/t/p/original/7updnUGOoeQx9TWxqGxiNLFODam.jpg', 'When a small town near the Arizona-Mexico border is wiped out overnight, suspicion falls on the lone survivor. But a roll of photos the survivor took that night tells a different story.', 80, '0+', '2015-11-01', 'Horror/Crime/Thriller'),
(1063636, 'Zielona mila', 'https://image.tmdb.org/t/p/original/brSYDZZ2epodl8lxdzaQqYapNlM.jpg', 'A supernatural tale set on death row in a Southern prison, where gentle giant John Coffey possesses the mysterious power to heal people\'s ailments. When the cell block\'s head guard, Paul Edgecomb, recognizes Coffey\'s miraculous gift, he tries desperately to help stave off the condemned man\'s execution.', 189, '18', '1999-12-10', 'Fantasy/Drama/Crime'),
(1063637, 'Magkakapatid', 'https://image.tmdb.org/t/p/original/baXlfZqYWZ6qHK26mKdLbiPA5sm.jpg', 'Magkakapatid is a story about a family that drifts apart due to socio-economic differences. Three siblings, three narratives, one tragedy, wherein a brother kills his own brother, a father struggles to accept a daughter’s marriage, and a daughter who could not mourn. In a situation where even traditions can’t pull them together, a tragedy drags them together.', 87, '0+', '2010-07-10', 'Drama'),
(1063638, 'Alibi perfetto', 'https://image.tmdb.org/t/p/original/59RXTTOIN6TS6HfzXTeczHEwDvW.jpg', 'Michael Woods stars as Tony Giordani, a narcotics agent who learns that his wife has been murdered while he is recuperating from an attack by a mysterious stranger. His boss thinks it\'s a Mafia vendetta, but Tony follows the clues to an empty house which his wife had been photographing on the day of her murder. There, he finds a burned corpse and several clues leading to the Full Moon Killer, who has been decapitating prostitutes around the city. The owner of the house is an insane countess, whose escape from an asylum leads to yet another murder. Before long, Tony and his partner, Lisa, with whom he is engaged in a passionate affair, find themselves targeted for murder unless they can solve the case.', 92, '0+', '1992-08-27', 'Thriller'),
(1063639, 'Moving Alan', 'https://image.tmdb.org/t/p/original/hmk8kQ8s34mw6Me6aOxRLsWCJa4.jpg', 'The story follows the two sisters Melissa and Emily, the former who accidentally killed her husband Alan and the latter who agrees to help her bury her husband in the desert. While there, they encounter a trucker who hates his dogs and takes a special dislike to the sisters, a Park Ranger who takes a shine to Melissa and finally a strange, homeless man who thinks he is in a soap opera. While Melissa and Emily try their best to find a suitable place to bury Alan, much of their history is revealed and the day in the desert has a great impact on their lives.', 83, '0+', '2003-04-04', NULL),
(1063640, 'Wooden Chair', 'https://image.tmdb.org/t/p/original/qFHbU8AWGRgJvcXnz4a6dKK4ACW.jpg', 'Wooden Chair is narrated by a third person omniscient. He tells the story of two orphaned siblings and their journey to overcoming poverty. Judy Ann, 10 years old, and John Lloyd, 7 years old, were named by their mother after her favorite actress and actor. To provide for the two of them, Judy Ann no longer goes to school but instead, sells root crops that she plants in their small backyard, and fruits and vegetables that she picks up from the floor of the public market. To cope with feelings of abandonment, Judy Ann talks to their imaginary mother who guides and encourages her.', 90, '0+', '2019-05-15', 'Drama'),
(1063641, 'Moon Saga 義経秘伝', 'https://image.tmdb.org/t/p/original/1F0HyqgMDYTQI6LrAHAdsqzB97g.jpg', 'The theatre play is set in the late Heian (794–1185) and early Kamakura period (1185–1333) in Japan. The main character is young adult Minamoto no Yoshitsune, from the Minamoto clan. Like previous chapters, it is a historical fiction, a world with supernatural powers and spirits (Mononokes). The idea was to create a story where the Oni (Japanese demons) were the origin of vampires, and eventually of the central character.[19] In the Heian period existed those called as Mononoke (spirits), and Mononofu, who were born between humans and Mononoke, and with special powers dominated both Mononoke and humans. The story from Mysteries of Yoshitsune spreads out when the member with inherited blood crossed over to Europe, and became the progenitor of the later vampires.', 122, '0+', '2012-07-15', 'Fantasy/Music/History/War'),
(1063642, 'Divided Loyalties', 'https://image.tmdb.org/t/p/original/5Olwk0o8m7YoCMLwxj3ZUrFMDOc.jpg', 'Story of Joseph Brant, chief of the Mohawks, and the events that led to the birth of Canada as a nation. During the time of the American Revolution, while Britain faces full scale insurrection in its American colonies, the great Indian empire of the Six Nations must choose between longtime British allies and the American Patriots, whose democratic ideals they share.', 102, '0+', '1990-02-13', 'History/Drama'),
(1063643, '13 jours, 13 nuits', 'https://image.tmdb.org/t/p/original/j3FN1msfXUOFGhy9viu4NNL6btF.jpg', 'Kabul, August 15, 2021. US troops are preparing to withdraw from Afghanistan, while the Taliban are marching on the capital to seize power. Amid the chaos, Commander Mohamed Bida and his men are in charge of security at the French embassy, the last Western mission to remain open. Trapped along with 500 people, left to their own devices, the team must reach the airport at all costs. A perilous mission with no guarantee of success to flee the hell of Kabul and rescue what remains of humanity.', 112, '0+', '2025-06-27', 'Action/War/Thriller'),
(1063644, 'Bloodshot', 'https://image.tmdb.org/t/p/original/8WUVHemHFH2ZIP6NWkwlHWsyrEL.jpg', 'After he and his wife are murdered, marine Ray Garrison is resurrected by a team of scientists. Enhanced with nanotechnology, he becomes a superhuman, biotech killing machine—\'Bloodshot\'. As Ray first trains with fellow super-soldiers, he cannot recall anything from his former life. But when his memories flood back and he remembers the man that killed both him and his wife, he breaks out of the facility to get revenge, only to discover that there\'s more to the conspiracy than he thought.', 110, '16', '2020-03-05', 'Action/Science Fiction/Adventure'),
(1063645, 'Kung Fu Panda', 'https://image.tmdb.org/t/p/original/wWt4JYXTg5Wr3xBW2phBrMKgp3x.jpg', 'When the Valley of Peace is threatened, lazy Po the panda discovers his destiny as the \"chosen one\" and trains to become a kung fu hero, but transforming the unsleek slacker into a brave warrior won\'t be easy. It\'s up to Master Shifu and the Furious Five -- Tigress, Crane, Mantis, Viper and Monkey -- to give it a try.', 90, '12', '2008-06-04', 'Animation/Family/Comedy/Action/Adventure'),
(1063646, 'Ocalić córkę', 'https://image.tmdb.org/t/p/original/gsRDrAML7hJC8ZCgRQobHIrzbxR.jpg', 'A former Marine and his old war buddy face off against the Mexican cartel behind the disappearance of his daughter.', 89, '0+', '2023-07-28', 'Action/Thriller/Drama'),
(1063647, 'Spekulant', 'https://image.tmdb.org/t/p/original/t10DvWj5Yeog5jsJZuBoFDJJbhP.jpg', 'Rogue Trader tells the true story of Nick Leeson, an employee of Barings Bank who--after a successful trading run--ends up accumulating $1.4 billion in losses hidden in account #88888.', 101, '0+', '1999-06-25', 'Drama/History/Thriller'),
(1063648, 'Speed King', 'https://image.tmdb.org/t/p/original/ofusIJ7JselHI4o36AKzkuVxBcq.jpg', 'Jimmy Martin, king of the motorcycle speedsters, visits the Kingdom of Mandavia for a race. There he is persuaded to impersonate the king by a traitor, Rodolph D\'Henri, who intends to annex part of Mandavia for neighboring Selmarnia. The real king is in jail. D\'Henri\'s plot is successful until Martin falls in love with Princess Margaret of Alvernia. Then he discloses his true identity, releases the real king, exposes the traitor, earns knighthood, and marries Margaret.', 0, '0+', '1923-01-01', 'Drama'),
(1063649, 'Toy Story', 'https://image.tmdb.org/t/p/original/94tkkZYlr35UC4JzrtiACfpF6Ua.jpg', 'Led by Woody, Andy\'s toys live happily in his room until Andy\'s birthday brings Buzz Lightyear onto the scene. Afraid of losing his place in Andy\'s heart, Woody plots against Buzz. But when circumstances separate Buzz and Woody from their owner, the duo eventually learns to put aside their differences.', 81, '0+', '1995-11-22', 'Family/Comedy/Animation/Adventure'),
(1063650, 'グリザイア：ファントムトリガー THE ANIMATION', 'https://image.tmdb.org/t/p/original/yEtlPrsyC2Ge3EYKvSXxyAouCzT.jpg', 'Following the Heath Oslo incident, the existence of the US-Japanese anti-terror organization CIRS has become a matter of public knowledge. CIRS has been rebuilt from the ground up, and its most covert functions spun off to a new agency: SORD (Social Ops, Research & Development).  The goal of SORD is to train a new generation of operatives to defend the country against future threats. To that end, the organization has established a series of schools up and down the country. Mihama Academy, more-or-less left to rot after its abrupt closure, has been given new purpose as one such \'specialist training school\'. It now entrusts the misfit girls who attend it with guns and live ammunition.  No matter how much life grinds them down, what future awaits these girls, who\'ve themselves chosen the path of the gun?', 90, '0+', '2019-03-15', 'Action/Animation'),
(1063651, 'Victor', 'https://image.tmdb.org/t/p/original/nhdD6Ui0eDBxMaW86iUgaAwhvLU.jpg', 'Victor is the story of a conscientious if somewhat withdrawn traffic warden who through a series of mishaps finally finds his place in life. While the setting is unusual the film addresses a wide range of emotions and morality; Love, deceit, frustrated longings and human dignity.  Victor, the eponymous hero of the film, is torn between his desire for the supermodel Kate le Font and the genuine affection of his co-worker Herdis. Victor\'s story comes to a head when a crooked traffic warden accuses him to hide his own crimes. With Herdis\' help our hero narrowly avoids disaster.  In a surprisingly complex plot, the film illustrates the dangers of repressed emotions, the liberating power of love and the ultimate triumph of good. All this takes place within the microcosmic context of the traffic warden\'s world which becomes a reflection of all human drama.', 28, '0+', '2000-01-01', 'Comedy'),
(1063652, 'Głębia', 'https://image.tmdb.org/t/p/original/h1Nx2Q4Wb0s6K7QUWA2LAPNacZv.jpg', 'A pair of young vacationers are involved in a dangerous conflict with treasure hunters when they discover a way into a deadly wreck in Bermuda waters.', 123, '0+', '1977-06-17', 'Mystery/Thriller/Adventure'),
(1063653, 'Ponad wszystko', 'https://image.tmdb.org/t/p/original/gbaWqiq6XYI3k3CzE7rf6YVxA0B.jpg', 'A teenager who\'s lived a sheltered life because she\'s allergic to everything, falls for the boy who moves in next door.', 96, '16', '2017-05-18', 'Drama/Romance'),
(1063654, 'Being Earnest', 'https://image.tmdb.org/t/p/original/5fipVoEwAnOkhhhfaVToy2XF3Yc.jpg', 'A Groovy 1960s Musical Take on Wilde’s Most Popular Play. Being Earnest takes place in a mod, 1960’s, Austin Powers-era setting. All of the brilliant wit in Wilde’s most popular play intact in this effervescent musical about two young couples and the societal conventions, over-bearing mothers, and misplaced handbags in railway stations that they must overcome in the course of finding true love. The score is a sparkling homage to 1960’s rock groups such as Herman’s Hermits, The Dave Clark Five, The Rolling Stones, The Seekers, The Hollies, The Lovin’ Spoonful and more.', 108, '0+', '2021-09-17', 'Music/Comedy/Romance'),
(1063655, 'Nakuru Song', 'https://image.tmdb.org/t/p/original', 'Told from the perspectives of local residents, Nakuru Song provides a first-person look at a country where hope is struggling to survive against monumental complacency. While Ken coaches a football team to keep boys off the street and James works tirelessly at the Melon Orphanage, countless other Kenyans live on: legions of children sniff glue to avoid hunger, other collect scrap metals for their income, and middle-aged men mix formaldehyde and jet fuel to create the \"illicit brew.\"', 14, '0+', '2008-01-01', 'Documentary'),
(1063656, 'Sekrety i grzeszki', 'https://image.tmdb.org/t/p/original/qRSUfOi7tdv1qvq4qhgQEpZrwyg.jpg', 'Longtime friends Ronny and Nick are partners in an auto-design firm. They are hard at work on a presentation for a dream project that would really launch their company. Then Ronny spots Nick\'s wife out with another man, and in the process of investigating the possible affair, he learns that Nick has a few secrets of his own. As the presentation nears, Ronny agonizes over what might happen if the truth gets out.', 111, '16', '2011-01-13', 'Comedy/Drama'),
(1063657, 'Star Struck', 'https://image.tmdb.org/t/p/original/kvFZJjU2sNokZzL5zcSWAl58BNT.jpg', 'A man thinks he\'s found a cheap thrill, but discovers it\'s thrown him into a world of danger in this steamy drama. A filmmaker (Nero Campbell) who has moved into a new home discovers to his pleasant surprise that his next door neighbor is a beautiful woman (Amber Smith) who isn\'t inclined to keep her shades drawn. However, one night while watching her, he unwittingly becomes a witness to a murder, and soon the police have named the director as the prime suspect.', 92, '0+', '2000-01-01', 'Thriller'),
(1063658, 'Ucieczka gangstera', 'https://image.tmdb.org/t/p/original/sB3FDnzEAXM4paE4PY28qe8cPx1.jpg', 'An ex-con and his devoted wife must flee from danger when a heist doesn\'t go as planned.', 115, '0+', '1994-02-11', 'Action/Crime/Mystery/Thriller'),
(1063659, 'Phoney Baloney', 'https://image.tmdb.org/t/p/original/gbIrgPZ6GE3vg95V3OFI0Ro3W7d.jpg', 'A $5,000 reward is put out for the capture of a notorious wolf. Two of the wanted posters are put on the trees where the Fox and the Crow live. When they see the posters, each thinks the other is the wanted one, and they try to capture each other for the reward money. After many attempts, they end up at a police station where their mistake is pointed out to them. They then punish themselves profusely for making the error. Re-released theatrically in 1956.', 7, '0+', '1945-11-01', 'Animation/Comedy');
INSERT INTO `movies` (`id`, `title`, `poster`, `description`, `duration_minutes`, `age_rating`, `release_date`, `genre`) VALUES
(1063660, 'After Dark', 'https://image.tmdb.org/t/p/original', 'An act of violence resonates through the night, touching  upon the lives of different characters, who otherwise would not necessarily exist in each other’s daily narrative. The story is seen through the self contained world of seven characters as they drift along the otherwise mundane night meandering around the graphical symmetry of a ‘modern’ city.  The story is based on excerpts taken from a novel by Haruki Murakami by the same name', 49, '0+', '2017-04-19', NULL),
(1063661, 'Stallion Canyon', 'https://image.tmdb.org/t/p/original/eDQUr48t3gsHZJjgkHcBk5sfMlD.jpg', 'It took a lot of courage to set up a new production company devoted to \"B\" westerns in 1949, a year when the genre was showing signs of winding down. Filmed in Trucolor, Stallion Canyon was the maiden effort from Kanab Productions, a Utah-based organization. Former Sons of the Pioneers vocalist Ken Curtis made his starring debut in this one, playing a ranch foreman who does his best to track down a rogue stallion. The rest of the cast is comprised of unknowns, save for villains Ted Adams and Forrest Taylor. Cheaply produced, Stallion Canyon has the twin advantages of a relatively new leading man and excellent location photography.', 72, '0+', '1949-06-15', 'Western'),
(1063662, 'To Olivia', 'https://image.tmdb.org/t/p/original/ldrwhZLKac9z6jhD5M80mUH9rcU.jpg', 'In 1962, Patricia Neal and Roald Dahl retreat to the English countryside to bring up their young family. The seemingly unlikely pair find their relationship put to the test by a tragic loss.', 99, '0+', '2021-02-19', 'Drama'),
(1063663, 'Przebudzenie', 'https://image.tmdb.org/t/p/original/9gztZXuHLG6AJ0fgqGd7Q43cWRI.jpg', 'Dr. Malcolm Sayer, a shy research physician, uses an experimental drug to \"awaken\" the catatonic victims of a rare disease. Leonard is the first patient to receive the controversial treatment. His awakening, filled with awe and enthusiasm, proves a rebirth for Sayer too, as the exuberant patient reveals life\'s simple but unutterably sweet pleasures to the introverted doctor.', 120, '16', '1990-12-04', 'Drama'),
(1063664, 'Bestia', 'https://image.tmdb.org/t/p/original/iTFSqPdEjjV1gSFa5IEJhUDDnx6.jpg', 'A recently widowed man and his two teenage daughters travel to a game reserve in South Africa. However, their journey of healing soon turns into a fight for survival when a bloodthirsty lion starts to stalk them.', 92, '16', '2022-08-11', 'Thriller/Action/Horror/Adventure'),
(1063665, 'Cross Now', 'https://image.tmdb.org/t/p/original/A4xboJaGUT3B9Th7dsvdyc2GrrL.jpg', 'In Cross Now, during a blazing row with his boss, strangely enough architect Michael Ponsford still gets his promotion. However, he does not get much time to enjoy it, because, in the middle of the argument, his boss suffers a heart attack. And he is not the only one to die. Ponsford is haunted by death: the woman with whom he had been flirting for too long, his wife\'s father, one of his competitors, they all succumb. Finally, Ponsford\'s young son also dies.', 61, '0+', '1977-10-30', 'TV Movie'),
(1063666, 'Zinda', 'https://image.tmdb.org/t/p/original/o5u3Rx0hFvPEGsZGTi3faAiIQMQ.jpg', 'The film is about a man, who has been imprisoned for 14 years, who has been released and has four days to figure out why he was imprisoned in the first place.', 116, '0+', '2006-01-12', 'Action/Thriller'),
(1063667, 'Baghead', 'https://image.tmdb.org/t/p/original/pO3Au8iDpZsJt7Xco6fRsNvm3vz.jpg', 'Four actors go to a cabin in the woods to write, direct, and act in a film that will jump-start their careers. Their idea is a horror film about a man with a bag over his head, but what happens when that man mysteriously shows up?', 84, '0+', '2008-01-21', 'Comedy/Drama/Horror'),
(1063668, 'Street Credit', 'https://image.tmdb.org/t/p/original', 'STREET is an Ex Prize Fighter turned P.I. He\'s currently sitting, in his run-down motel room, sipping Jack Daniels and popping Anti- Psychotics like they’re skittles while staring at the walls dedicated to capturing The “BABYLON BUTCHER”. The Butcher has claimed another victim, and P.K.’s 7-year search has him no closer to finding the elusive serial killer responsible for his wife’s death. But believe it or not, he has more immediate problems. His current girlfriend CHINA WHITE is ranting about his emotional unavailability. To make matters worse his Schizophrenic hallucinations won\'t stop pestering him to take on a new case.\r\n Street Credit is Hip-Hop Noir tale where mental illness, LA Gangs, #metoo movement, “coked-out” cops and genocidal, government conspiracies collide.', 30, '0+', '2016-02-01', NULL),
(1063669, 'Quitters', 'https://image.tmdb.org/t/p/original/oTnlhihOXqYs0cAwBxRdFV4adRM.jpg', 'The story of the Raymans, a wealthy Jewish family that\'s falling apart. The son, Clark, is a bright and curious high schooler with a talent for manipulation. As his mother May enters treatment for a pill addiction, and he and his father Roger stop getting along, Clark thinks about running away from home. He just needs to decide where to go.', 90, '0+', '2015-03-16', 'Drama/Comedy'),
(1063670, 'Strange Tales', 'https://image.tmdb.org/t/p/original/1s5Tt2T27BTs2hzjBAmPVu5vXoL.jpg', 'Aliens! Junkyard hoes! This highly varied anthology of whacked out stories, some of which have no real dialogue, pretty much all of which will leave you wondering what the hell is going on. Most have really cool music that sets the mood, some genuinely creepy moments and good atmosphere throughout. The first story, \"The Visitant\", features a man in a cemetery visiting his dead son\'s grave after he died in a car accident. He is soon tormented by visions of his son, as well as other spirits, including an axe-wielding ghoul! The second story, entitled, \"Desire In A Public Dump\", starts out with a man in a junkyard fixating on a paper with an attractive woman on it. The picture then disappears, and the woman is suddenly in front of him!', 58, '0+', '1986-01-21', 'Comedy/Horror'),
(1063671, 'Nowe szaty króla', 'https://image.tmdb.org/t/p/original/tXbXosTijXbK4k1BRPczFVMIOQN.jpg', 'When self-centered Emperor Kuzco is turned into a llama by his scheming advisor, he is forced to rely on good-hearted peasant Pacha to get back home.', 78, '12', '2000-12-15', 'Adventure/Animation/Comedy/Family/Fantasy'),
(1063672, 'Final Mission', 'https://image.tmdb.org/t/p/original/8G6fFGjKLNsgUX2wQP6z6goVBJ.jpg', 'When his family are murdered Vietnam War veteran, Vince Deacon, tracks down the man responsible for the murders and to get his revenge.', 101, '0+', '1984-07-25', 'Crime/Action/Thriller'),
(1063673, 'Church Ball', 'https://image.tmdb.org/t/p/original/iG2mVQlZciA1p7xcl4x53dZ9yw9.jpg', 'Dennis Buckstead has the hardest calling in his church. Not only has he been asked to coach a group of non-basketball players in his church but the bishop has demanded that he lead the team to the Basketball Championship. Word from the top is that this is the last season of church ball and Bishop Linderman isn\'t about to have his team lose for the 20th year in a row in the last season of church ball history! What was supposed to strengthen the body, invigorate the mind and cultivate brotherly love seems to bring out the worst in these church-going ball players. Dennis must find a way to bring his team together and build unity along the way to win the championship or go down in church ball history as the worst team that ever played.', 91, '0+', '2006-03-17', 'Comedy'),
(1063674, 'Il corrodoio', 'https://image.tmdb.org/t/p/original/lSV1aW8Zlg7Xt3NvE0pvTfSKnPh.jpg', 'Nicola is a 6-year-old boy who lives with his family in an old apartment divided in two by a long corridor. His parents\' relationship is slowly falling apart, as money is running low and love is fading. To escape the violence, Nicola hides himself in the fantasy world of his toy soldiers. But as the tension increases day after day, the young boy begins to see the corridor slowly turning into a war trench and getting to the front door is no longer a matter of going to school, but the only way to survive.', 16, '0+', '2002-01-01', NULL),
(1063675, 'Klub zabójców', 'https://image.tmdb.org/t/p/original/y2d2SBqK33mGOG2CqAYMo3YbWE4.jpg', 'In this world of contract killers, Morgan Gaines is the best of the best. When Morgan is hired to kill six people around the world, he soon discovers all the targets are also assassins unknowingly hired to kill each other.', 113, '16', '2023-02-24', 'Action/Adventure/Thriller'),
(1063676, 'Uciekający Kociak', 'https://image.tmdb.org/t/p/original/2QnqQn7W2IjVEgK6mmUIkfQWY19.jpg', 'When a sexy, high-end escort holds the key evidence to a scandalous government cover-up, two bumbling young detectives become her unlikely protectors from a ruthless assassin hired to silence her.', 106, '0+', '2011-04-01', 'Action/Comedy/Thriller'),
(1063677, 'Śnieżka', 'https://image.tmdb.org/t/p/original/fPGT8MTYsr1vm0ZI1Yk9jNWiJnK.jpg', 'Following the benevolent King\'s disappearance, the Evil Queen dominated the once fair land with a cruel streak. Princess Snow White flees the castle when the Queen, in her jealousy over Snow White\'s inner beauty, tries to kill her. Deep into the dark woods, she stumbles upon seven magical dwarves and a young bandit named Jonathan. Together, they strive to survive the Queen\'s relentless pursuit and aspire to take back the kingdom.', 109, '0+', '2025-03-19', 'Family/Fantasy'),
(1063678, 'Opętani', 'https://image.tmdb.org/t/p/original/vJ4nYZ5qUcKUslSCg4OgHKvgewP.jpg', 'Four friends find themselves trapped in their small hometown after they discover their friends and neighbors going quickly and horrifically insane.', 101, '0+', '2010-02-26', 'Mystery/Horror/Action'),
(1063679, '365 dni: Ten dzień', 'https://image.tmdb.org/t/p/original/ee7qhbFyw4adAHgDTAELuiskkht.jpg', 'Laura and Massimo are back and hotter than ever. But the reunited couple\'s new beginning is complicated by Massimo’s family ties and a mysterious man who enters Laura’s life to win her heart and trust, at any cost.', 111, '16', '2022-04-26', 'Romance/Drama'),
(1063680, 'Piła VI', 'https://image.tmdb.org/t/p/original/iLycWnND0ZXe83WFyfAIaIHG8r2.jpg', 'Special Agent Strahm is dead, and Detective Hoffman has emerged as the unchallenged successor to Jigsaw\'s legacy. However, when the FBI draws closer to Hoffman, he is forced to set a game into motion, and Jigsaw\'s grand scheme is finally understood.', 90, '18', '2009-10-22', 'Horror/Thriller'),
(1063681, 'Diuna', 'https://image.tmdb.org/t/p/original/4L3Dkdujbrq5EKcrVdWEdTEvhtb.jpg', 'Paul Atreides, a brilliant and gifted young man born into a great destiny beyond his understanding, must travel to the most dangerous planet in the universe to ensure the future of his family and his people. As malevolent forces explode into conflict over the planet\'s exclusive supply of the most precious resource in existence-a commodity capable of unlocking humanity\'s greatest potential-only those who can conquer their fear will survive.', 155, '12', '2021-09-15', 'Science Fiction/Adventure'),
(1063682, 'Toy Story 2', 'https://image.tmdb.org/t/p/original/yFWQkz2ynjwsazT6xQiIXEUsyuh.jpg', 'Andy heads off to Cowboy Camp, leaving his toys to their own devices. Things shift into high gear when an obsessive toy collector named Al McWhiggen, owner of Al\'s Toy Barn kidnaps Woody. Andy\'s toys mount a daring rescue mission, Buzz Lightyear meets his match and Woody has to decide where he and his heart truly belong.', 92, '0+', '1999-10-30', 'Animation/Comedy/Family'),
(1063683, 'Saga „Zmierzch”: Księżyc w nowiu', 'https://image.tmdb.org/t/p/original/eqgPeYE5MuZqiZZ1jibJ4EnkRll.jpg', 'Forks, Washington resident Bella Swan is reeling from the departure of her vampire love, Edward Cullen, and finds comfort in her friendship with Jacob Black, a werewolf. But before she knows it, she\'s thrust into a centuries-old conflict, and her desire to be with Edward at any cost leads her to take greater and greater risks.', 131, '16', '2009-11-18', 'Adventure/Fantasy/Drama/Romance'),
(1063684, 'Drama fra riddertiden', 'https://image.tmdb.org/t/p/original/a1f48TDm9dDG7kgOspY5ScXYZ3y.jpg', 'A young nobleman arrives at Frederiksborg Castle where a mayor lives with his beautiful daughter. He immediately falls in love with the daughter, who – much to her fiancée\'s resentment – reciprocates his feelings. Sick with jealousy, the fiancée spies on the new lovers and plans how to get rid of his rival once and for all. (stumfilm.dk)', 7, '0+', '1907-08-27', 'Drama'),
(1063685, 'Irish Homecoming', 'https://image.tmdb.org/t/p/original/yps4l1cWseGzEcJtth0hv6zlmBb.jpg', 'This live concert, recorded at Whitewell Metropolitan Tabernacle in Belfast, is spiced with Celtic sounds. Joy Gardner is joined by an Irish choir on \"The Promise\" while Larry Ford, who has developed a following in Ireland in recent years, performs \"What A Friend We Have In Jesus.\" Anthony Burger offers a dazzling piano solo on \"Holy, Holy, Holy.\" Russ Taff moves close to the audience to sing \"Ain\'t No Grave\" and the Gaither Vocal Band raises the roof on \"It Is Finished.\"', 70, '0+', '2000-01-01', 'Music'),
(1063686, 'Potwór z Cleveland', 'https://image.tmdb.org/t/p/original/uo1OCJrh2fErmuSdrz4gVw67q5n.jpg', 'A single mother becomes Ariel Castro\'s first kidnapping victim, and finds herself trapped in his home with two other women for 11 years.', 88, '0+', '2015-05-02', 'Drama/Crime/TV Movie'),
(1063687, 'Noc Oczyszczenia: Anarchia', 'https://image.tmdb.org/t/p/original/bsmrKZo65fc9oogNG4ecL4HHgUd.jpg', 'One night per year, the government sanctions a 12-hour period in which citizens can commit any crime they wish -- including murder -- without fear of punishment or imprisonment. Leo, a sergeant who lost his son, plans a vigilante mission of revenge during the mayhem. However, instead of a death-dealing avenger, he becomes the unexpected protector of four innocent strangers who desperately need his help if they are to survive the night.', 103, '16', '2014-07-17', 'Horror/Thriller'),
(1063688, 'Fire & Ice', 'https://image.tmdb.org/t/p/original/kJqzKZwMcrM6lkwOMS2qLyvoPve.jpg', 'While many celebrities believe their fame gives them good luck with the opposite gender, one man with a successful television career discovers fame is spoiling his chances with the woman he loves in the made-for-TV romantic drama. Holly Aimes (Lark Voorhies) is the daughter of a prominent politician (Glynn Turman), and recently broke off her engagement with a well-known actor. Holly has spent most of her life in the spotlight, and wants nothing more than to be left alone without the glare of public scrutiny. When Holly meets talk show host Michael Williams (Kadeem Hardison), he\'s soon convinced that she\'s the woman with whom he wants to share his life, but can he convince her of his sincerity so she will brave another high-profile romance? Based on the popular romance novel by Carla Fredd, Fire and Ice also features Tempestt Bledsoe and Freda Payne. ~ Mark Deming, Rovi', 87, '0+', '2001-01-22', 'TV Movie'),
(1063689, 'Águas Mil', 'https://image.tmdb.org/t/p/original/gra7gRvuh01BGAu7vYBdb9BvxpI.jpg', 'April 1974 saw the fall of a long lasting dictatorship. The young democracy developed in the midst of much social and political turmoil. The armed wing of a leftist group changed the future of one family - the father disappears without trace, the mother denies their past, and the son grows up with unanswered questions. As a young man, Pedro is determined to reach for answers, aided by his apparently batty grandmother. Collecting clues and meeting people who would rather prefer to remain forgotten. His inner journey leads him Portugal to Spanish through the deserted roads of Alentejo. Pedro will find himself, but there is a price to pay.', 78, '0+', '2009-01-26', 'Drama'),
(1063690, 'Christmas in Midnight Clear', 'https://image.tmdb.org/t/p/original/gFJ0aLK7ERCe3CjXemsMG44LjYe.jpg', 'Hillary Shaw, a successful corporate real estate developer, arrives in the economically struggling town with decisive plans to acquire every possible property, declare the rest eminent domain, and to modernize the town from the inside out. But when Hillary encounters Daniel Porter, local pastor and multi-generational pillar of the community, her vision faces more than legal challenges. As Hillary and Daniel’s worldviews spark conflict, something deeper begins to blossom.', 88, '0+', '2025-11-01', 'TV Movie/Comedy/Romance'),
(1063691, 'Dangerous Business', 'https://image.tmdb.org/t/p/original', 'Clarence Brooks is a shy, timid man working for Mr. Flavell. He is love with Flavell\'s daughter, Nancy. Nancy is shallow and fickle, always chasing after other, less-upstanding men. Clarence enlists when World War I erupts. While Clarence is off defending his country, Nancy\'s mother arranges for her daughter to marry the wealthy Mr. Braille. When Braille is drafted, Nancy\'s mother starts arranging a rush wedding, against Nancy\'s wishes. Nancy claims that she and Clarence are already secretly married. When the war is over and Clarence returns home, he refuses to be a part of her charade. When Clarence declines the offer to marry Nancy for real, she must mature to win his affections back. A lost film.', 50, '0+', '1920-11-28', 'Romance/Comedy'),
(1063692, 'Baphomet', 'https://image.tmdb.org/t/p/original/1l6S3EID762dvTOrNwoCRNTESa3.jpg', 'An American family celebrates their 28-year-old daughter\'s pregnancy. The celebration is interrupted when a Satanic cult leader, Henrik Brandr, unexpectedly visits their ranch. Henrik offers to pay the family a large sum for ownership of their land. Jacob Richardson, the father, rejects the offer due to the priceless sentimental value of the ranch. Henrik, displeased, begins to put devastating curses on the Richardsons, trying to force them off their land - even if it means murdering them. After suffering unexplainable tragedies, the Richardsons seek help from Marybeth, a white witch high priestess. They soon discover a terrible secret about their house, revealing why their land is so valuable to the cult. They realize they must protect their house from the cult at all costs, and a violent battle between good and evil ensues.', 72, '0+', '2021-06-08', 'Horror/Thriller'),
(1063693, 'Floris', 'https://image.tmdb.org/t/p/original/cWR58OgTz9g4xeL7bflMc1EWhWC.jpg', 'This adventurous feature film is a sequel to Paul Verhoeven\'s legendary youth series from 1969. In this modern film version - the Middle Ages are more imaginative and larded with anachronistic jokes - the story revolves around Floris (grandson of Rutger Hauer\'s character from the series), a peace-loving bloke whose father despises him because he refuses to carry on the family tradition of stout-hearted knights defending freedom: Floris is an actor. To prove to his father that he can still be a hero, he helps him search for a missing sacred relic with special powers. This is the last hope for the Duke of Burgundy, his father\'s boss, to eliminate the mean Duchess of Gelre. Along with his oriental girlfriend Pi, Floris goes through some perilous moments when he enters into battle with the duchess and her stooges Van Rossum jr., Kleine Pier jr. and Sergeant jr..', 105, '0+', '2004-12-16', 'Adventure/Family'),
(1063694, 'Spider-Man Uniwersum', 'https://image.tmdb.org/t/p/original/grU91DJPDzJv0sqDyEhzOEgwWEH.jpg', 'Struggling to find his place in the world while juggling school and family, Brooklyn teenager Miles Morales is unexpectedly bitten by a radioactive spider and develops unfathomable powers just like the one and only Spider-Man. While wrestling with the implications of his new abilities, Miles discovers a super collider created by the madman Wilson \"Kingpin\" Fisk, causing others from across the Spider-Verse to be inadvertently transported to his dimension.', 117, '0+', '2018-12-06', 'Animation/Action/Adventure/Science Fiction'),
(1063695, 'McCarthy', 'https://image.tmdb.org/t/p/original/1YyW0Klt5eDNSmSZ0iHMkWGrkYe.jpg', '\"McCarthy\" chronicles the rise and fall of Joseph McCarthy, the Wisconsin senator who came to power after a stunning victory in an election no one thought he could win. Once in office, he declared that there was a vast conspiracy threatening America — emanating not from a rival superpower, but from within. Free of restraint or oversight, he conducted a crusade against those he accused of being enemies of the state, a chilling campaign marked by groundless accusations, bullying intimidation, grandiose showmanship and cruel victimization. With lawyer Roy Cohn at his side, he belittled critics, spinning a web of lies and distortions while spreading fear and confusion. After years in the headlines, he was brought down by his own excesses and overreach. But his name lives on linked to the modern-day witch hunt we call “McCarthyism.”', 120, '0+', '2020-01-06', 'Documentary/History'),
(1063696, 'The Cobweb', 'https://image.tmdb.org/t/p/original/duT2743CkNIKvrwch5CqmB7Xmta.jpg', 'Patients and staff at a posh psychiatric clinic clash over who chooses the clinic’s new drapes – but drapes are the least of their problems.', 124, '0+', '1955-06-07', 'Drama'),
(1063697, 'Jackals', 'https://image.tmdb.org/t/p/original/roWDNPm5UAKo3LLi3BUXwmfDsHc.jpg', 'Set in the 1980s, an estranged family hires a cult deprogrammer to take back their teenage son from a murderous cult, but find themselves under siege when the cultists surround their cabin, demanding the boy back.', 86, '0+', '2017-09-01', 'Horror/Thriller'),
(1063698, 'Czarownica', 'https://image.tmdb.org/t/p/original/kiB8iDyuKmhBfAICG9T3LdLSH33.jpg', 'Thinking he can overshadow an unknown actress in the part, an egocentric actor unknowingly gets a witch cast in an upcoming television remake of the classic show \"Bewitched\".', 102, '16', '2005-06-21', 'Comedy/Fantasy/Romance'),
(1063699, 'Nastoletni wilkołak', 'https://image.tmdb.org/t/p/original/bv9rY9eoue2Hat6tcvrKVQ0ow8v.jpg', 'When a shy teenager\'s new-found powers help him score at basketball - and with the popular girls - he has some pretty hairy decisions to make.', 91, '0+', '1985-08-23', 'Comedy/Fantasy/Romance'),
(1063700, 'Lakier do włosów', 'https://image.tmdb.org/t/p/original/n78VVWG1jsEpMCtcye13wy1RiAx.jpg', '\'Pleasantly plump\' teenager Tracy Turnblad achieves her dream of becoming a regular on the Corny Collins Dance Show. Now a teen hero, she starts using her fame to speak out for the causes she believes in, most of all integration. In doing so, she earns the wrath of the show\'s former star, Amber Von Tussle, as well as Amber\'s manipulative, pro-segregation parents. The rivalry comes to a head as Amber and Tracy vie for the title of Miss Auto Show 1963.', 92, '7', '1988-02-26', 'Comedy/Music/Romance'),
(1063701, 'Lightning Guns', 'https://image.tmdb.org/t/p/original/29tzfxyZKlZbryJXHS6mMp6rG2e.jpg', 'The Durango Kid rides again in Lightning Guns. As ever, the masked Durango (alias Steve Brandon) is played by Charles Starrett, who this time around is on the trail of a gang of cold-blooded killers. Rancher Dan Saunders (Edgar Dearing) is held responsible for the killings because of his opposition to a politically expedient dam project. Durango believes that Saunders is innocent, and he intends to prove it.', 55, '0+', '1950-12-01', 'Comedy/Western/Action/Adventure'),
(1063702, 'The Killer', 'https://image.tmdb.org/t/p/original/6PCnxKZZIVRanWb710pNpYVkCSw.jpg', 'Zee is a feared contract killer known as \"the Queen of the Dead,\" but when she refuses to murder a young blind woman, she finds herself hunted both by criminal colleagues and a determined police detective.', 126, '0+', '2024-08-22', 'Action/Thriller/Crime'),
(1063703, 'Syndabocken', 'https://image.tmdb.org/t/p/original/wu7say7XZuxYF4K2SM7mC2RtyiG.jpg', 'In the shade of Malta’s scorching sun, around the edges of the Swedish online-gambling community, exiled con man Dimman shows up for a lavish wedding, kicking off a desperate and decadent pursuit of redemption.', 91, '0+', '2023-11-24', 'Drama/Crime/Thriller'),
(1063704, 'Baaz', 'https://image.tmdb.org/t/p/original/AaRC9GHB0Upoogwo2HWkAqmS9bK.jpg', 'Baaz is the story of SP Inder Pal Singh Sidhu. Sidhu is a man on a mission. With complete honesty and full determination, he vows to fight against evil. The movie focuses on the political influence and corruption prevailing in Police. It revolves around Darbara Singh, a businessman cum leader, who is a drug mafia and uses his influence to run his illegal activities right under the nose of Police.', 141, '0+', '2014-11-07', 'Action/Crime/Drama'),
(1063705, 'Shackles', 'https://image.tmdb.org/t/p/original/sN0hTepWWpg6qnGdsutyRTPIX0Z.jpg', 'An aspiring teacher (Hughley) takes the one job he\'s offered, a position at a school inside a prison.', 115, '0+', '2005-08-20', 'Drama/Documentary/TV Movie'),
(1063706, 'Slow Dance', 'https://image.tmdb.org/t/p/original/zVZ44oQSqTn4nHKdAO1tvHHPQR9.jpg', 'Surfer Dane Reynolds takes a sharp look into the timeless style of Craig Anderson. A modern approach with hints to the past, Slow Dance follows Craig in and out of the water as he travels the world meeting up with heroes and friends in Australia, Chile, India, West Africa and Tahiti to name a few. Dane attempts to unravel Craig\'s perspective on his role as a professional surfer and Craig provides vague glimpses into his psyche. However, what does become clear is that Craig\'s approach to surfing and his outlook on life is truly unique.', 35, '0+', '2013-04-22', NULL),
(1063707, 'Sixty Six', 'https://image.tmdb.org/t/p/original/tslE4UT0p4z6Qju2cdqpfFC46Hr.jpg', 'A boy\'s Bar Mitzvah looks set to be a disaster when it coincides with the 1966 World Cup Final.', 93, '0+', '2006-11-03', 'Comedy/Drama'),
(1063708, 'Immer & ewig', 'https://image.tmdb.org/t/p/original', 'Claude, a militant anarchist, is caught stealing and is shot by a policeman while fleeing the scene. Dodo, a hairdresser, is hit by one of the stray bullets. They meet in the realm of the dead and together they visit familiar places and their loved ones. By debating their past with each other, they become close and fall in love. Because of their feelings they get the chance to return to life for twelve hours in order to prove the depth love they share.', 91, '0+', '1991-01-25', 'Drama/Fantasy'),
(1063709, 'Władca życzeń', 'https://image.tmdb.org/t/p/original/t7rep7SCqiy4COUsq2cOcdQwzU0.jpg', 'The Djinn, having been released from his ancient prison, seeks to capture the soul of the woman who discovered him, thereby opening a portal and freeing his fellow Djinn to take over the earth.', 90, '0+', '1997-09-19', 'Horror/Fantasy'),
(1063710, 'Little Richard', 'https://image.tmdb.org/t/p/original/gc7xlAjT14AhzIrBO55YUWlC96B.jpg', 'The story of Little Richard Penniman, from his poor Southern upbringing to dealing with the trials and tribulations of being a Black singer in the 1950s, to his born-again phase and brief \"retirement\" from rock and roll.', 120, '0+', '2000-02-20', 'Drama/Music/TV Movie'),
(1063711, 'Berg: Lulu', 'https://image.tmdb.org/t/p/original/keq3b1LvwwV9WnMcfY5nNow40Bt.jpg', 'Since its premiere on 2 June 1937 in Zurich, Alban Berg\'s second opera \"Lulu\" has the reputation of being surrounded by scandals. On the one hand, this is due to the dubious character of the subject, the man-eating femme fatale, which Berg had taken from Frank Wedekind\'s two Lulu tragedies – \"The Earth Spirit\" and \"Pandora\'s Box\" – and combined into one opera libretto. On the other hand, Berg\'s window had (for personal reasons) repeatedly refused to have the opera completed, which was unfinished when Berg died. This video is of the unfinished two-act torso of \"Lulu.\"', 164, '0+', '2004-01-01', 'Music'),
(1063712, 'La revanche', 'https://image.tmdb.org/t/p/original/5OwygwUZRNJoNt5VJ4umkFuauaG.jpg', 'Luxembourg is a small country in the heart of Europe. It\'s a multi-cultural society, foreigners representing almost 40% of its population.  It\'s famous for its forward-thinking social policies and - especially - for its financial services.  It used to be known for its steel industry and it still boasts one of the most important media groups in the world.  But it\'s certainly not known either for soccer or unemployment.  So this is \'Revanche\'s\' recipe: take Luxembourg\'s unemployed. Put them in business suits. Encourage them to create an international football club which begins to win all its matches.  Into this strange mix, throw in a bunch of international criminals, and a bevy of glamorous Eastern European dream creatures all looking for husbands, fame and fortune.  The result is a delicious humanist fable, a comedy in which love conquers money.', 110, '0+', '2004-10-01', 'Comedy'),
(1063713, 'Stan spoczynku', 'https://image.tmdb.org/t/p/original/hsmZcNzPGnZwRgCKAfIr1JngYu5.jpg', 'A veteran soldier returns from his completed tour of duty in Iraq, only to find his life turned upside down when he is arbitrarily ordered to return to field duty by the Army.', 113, '16', '2008-03-28', 'Drama/War'),
(1063714, 'Doghouse', 'https://image.tmdb.org/t/p/original/8XBd0TLZRcnSpbeEyoYRxxDCafJ.jpg', 'A group of men, heading to a remote village to help one of their friends get over his divorce, soon discover that all the women have been infected with a virus that makes them man-hating cannibals.', 89, '0+', '2009-06-11', 'Comedy/Horror'),
(1063715, 'Kandidát', 'https://image.tmdb.org/t/p/original/w7ovuhR2BZhvxiOV8mDorRMshAG.jpg', 'The story of the film The Candidate takes place during two months of campaigning before a non-specific presidential election in one specific country. The author of the diary entries has no idea for whom he is recording the eavesdropping and enthusiasm for an interesting job in which he follows a bishop, a crazy owner of an advertising agency and a bland presidential candidate with the eloquent name Peter Potôň and an even sweeter-sounding family history, soon give way to disgust and confusion. His diary becomes a file with transcripts of conversations, information about characters and characters, emails, scraps from psychiatric medical records and pictures, which he scribbles at first out of boredom, later because words and rational explanations are no longer enough. The candidate is a political farce, a sad-funny depiction of what happened, is happening, and could very easily happen in this small country.', 106, '0+', '2013-10-10', 'Comedy'),
(1063716, 'Silent Madness', 'https://image.tmdb.org/t/p/original/npcLVLI8pcn4q6QPVgFJeLCdQAJ.jpg', 'A psychiatrist poses as an ex-sorority sister to stop a slasher freed by a computer error.', 93, '0+', '1984-10-26', 'Horror'),
(1063717, 'Gilda', 'https://image.tmdb.org/t/p/original/46eKPjoWEyNBAQKDoXEcDFBcaUw.jpg', 'A gambler discovers an old flame while in Argentina, but she\'s married to his new boss.', 110, '0+', '1946-04-25', 'Romance/Drama/Thriller'),
(1063718, 'Pele: Narodziny legendy', 'https://image.tmdb.org/t/p/original/ofpMndm9xOLw99TyICUVdwQ1RbW.jpg', 'The life story of Brazilian football legend, Pele.', 107, '0+', '2016-05-06', 'Drama'),
(1063719, 'Batanes', 'https://image.tmdb.org/t/p/original/z1lIaHktz27uSJHZDX8Y4s1NlZw.jpg', 'Pam meets Rico an Ivatan, and decides to leave her stressful life in the city to follow him to Batanes to meet his parents Boy and Lydia and marry him. Pam tries to adapt to the Ivatan way of life but hates the sea that Rico loves so much. Her hatred for the sea intensifies when her husband Rico dies in a fishing accident. Pam is devastated and decides to go back to Manila. But when she sensed that the sea was laughing at her failure, she chose to stay in Batanes to be with Rico\'s family. In one of her trips to the sea, she accidentally meets Kao Ken Chu, a Taiwanese, whom she rescues during a storm. As they spend time together, the two eventually fall for each other despite language barriers and cultural differences.', 100, '0+', '2007-12-05', 'Romance/Drama'),
(1063720, 'Małe potworki', 'https://image.tmdb.org/t/p/original/oQvUq7UmumBTcAnvgFLFvegY47d.jpg', 'A washed-up musician teams up with a teacher and a kids show personality to protect young children from a sudden outbreak of zombies.', 94, '0+', '2019-08-29', 'Horror/Comedy'),
(1063721, 'Ghutan', 'https://image.tmdb.org/t/p/original/gutqECREVLxgeN5bf0MRWrgfOZR.jpg', 'Ravi Kapoor (Aryan Vaid) manages a company owned by his wife Catherine (Hina Rehman), whom he doesn\'t love and constantly cheats on. And he now has his eyes on his secretary, Priya (Pooja Bharti). When Catherine learns what\'s going on, she confronts him. In the heated argument that follows, Ravi hits her and believes she\'s dead. Together with his friend, Jaggi (Tarun Arora), they take her body to the graveyard. Just as they\'re about ready to put it in the grave they realize Catherine isn\'t dead so they bury her alive. Catherine\'s ghost then returns for revenge.', 126, '0+', '2007-06-08', 'Horror'),
(1063722, 'El Japón －イスパニアのサムライ－ / アクアヴィーテ ～生命の水～', 'https://image.tmdb.org/t/p/original/lCo1qXkJbdGRTHGGlL3c5ER3YtC.jpg', 'Takarazuka Cosmos Troupe 2019-2020.  \"El Japón -The Samurai of España-\"  In the town of Coria del Río in southern Spain, there are people who use the surname “Japón” to identify themselves as descendants of the samurai. What gave birth to this curious legend of Japanese samurai in a far-off land...? This lighthearted and pleasurable tale of heroism has as its protagonist a retainer of Sendai Domain, dispatched to Europe on a diplomatic mission, starkly portraying the emotions of the samurai and an encounter with another culture.  \"Aqua Vitae!! -The Water of Life-\"  A show built upon the theme of that most aromatic and mature of deep-flavored spirits: whiskey. Experience the many varied talents of the stylish and cool Makaze Suzuho and the other members of Cosmos Troupe, in a performance based on unique whiskey.', 0, '0+', '2019-11-15', 'History'),
(1063723, 'Turret', 'https://image.tmdb.org/t/p/original', 'A devoted family man and B-17 turret gunner thrust into the perilous skies over WWII Europe. But the danger doesn’t end in the air—his survival sets off a chain of events that ripple far beyond the battlefield.', 0, '0+', NULL, 'Drama/War/Thriller'),
(1063724, 'Sprawy wewnętrzne', 'https://image.tmdb.org/t/p/original/rpksFP4m7c0j0XdqspBeB9fJYIP.jpg', 'Keen young Raymold Avila joins the Internal Affairs Department of the Los Angeles police. He and partner Amy Wallace are soon looking closely at the activities of cop Dennis Peck whose financial holdings start to suggest something shady. Indeed Peck is involved in any number of dubious or downright criminal activities. He is also devious, a womaniser, and a clever manipulator, and he starts to turn his attention on Avila.', 115, '0+', '1990-01-12', 'Crime/Drama'),
(1063725, 'Wyobraź sobie', 'https://image.tmdb.org/t/p/original/6gBEX26TZuRKORrM99G3CV2LPjg.jpg', 'A financial executive who can\'t stop his career downspiral is invited into his daughter\'s imaginary world, where solutions to his problems await.', 107, '0+', '2009-06-19', 'Family/Comedy/Drama'),
(1063726, 'Forever Young: How Rock \'n\' Roll Grew Up', 'https://image.tmdb.org/t/p/original', 'Despite the mantra of \'live fast, die young\', Britain\'s first rock \'n\' roll generations are now enjoying old age. What was once about youth and taking risks is now about longevity, survival, nostalgia and refusing to grow up, give up or shut up. But what happens when the music refuses to die and its performers refuse to leave the stage? What happens when rock\'s youthful rebelliousness is delivered wrapped in wrinkles?', 57, '0+', '2010-07-02', 'Music/Documentary'),
(1063727, 'Nadprzyrodzony pakt', 'https://image.tmdb.org/t/p/original/o0a4iSc5yKEiV15NCTI5GwrZudc.jpg', 'After their mother passes away, sisters Nicole and Annie reluctantly return to their childhood home to pay their last respects. While staying overnight in the house, the sisters sense a mysterious presence in their midst: noises startling them in the night, objects moving about, a fallen picture of an unknown woman posed next to their mother. Annie begins experiencing a series of intense and disturbing dreams - visions that lead her to uncover something terrible about her mother\'s past that is finally revealing itself.', 89, '0+', '2012-05-25', 'Horror/Mystery/Thriller'),
(1063728, 'Meenda Sorgam', 'https://image.tmdb.org/t/p/original/57iY3FxqkJNMxriSmrH2a6rMYRu.jpg', 'Nirmala (Padmini) is a poor but talented young dancer who falls in love with a rich man\'s son Sekar (Gemini Ganesan), but he is forced to marry a rich man\'s daughter Prathiba (Tambaram Lalitha). Nirmala promises to her lover that she will never dance in public. Due to various circumstances, Sekar\'s house is up for auction, and in order to save him, she performs in public. With the money thus earned, she saves his house, but Sekar is unaware of this. When he learns the truth, he begins searching of her, and in the meantime, Prathiba, who is now reformed, commits suicide. Sekar meets Nirmala, who is on the verge of committing suicide, and they are reunited.', 180, '0+', '1960-07-29', 'Drama'),
(1063729, 'Złowroga obecność', 'https://image.tmdb.org/t/p/original/dYxrsyUEdFOOq7xzIuvEb1858Sg.jpg', 'When Polly receives a mysterious box, it comes with one rule: place inside something she needs, something she hates, and something she loves. If she doesn’t obey, it will consume everything—and everyone—she’s ever known.', 98, '0+', '2025-09-19', 'Horror/Thriller'),
(1063730, 'Noc Dziękczynienia', 'https://image.tmdb.org/t/p/original/rA5GZRYeZTLTPVtu0LPbq0ZYkiO.jpg', 'After a Black Friday riot ends in tragedy, a mysterious Thanksgiving-inspired killer terrorizes Plymouth, Massachusetts - the birthplace of the holiday. Picking off residents one by one, what begins as random revenge killings are soon revealed to be part of a larger, sinister holiday plan.', 106, '0+', '2023-11-16', 'Horror/Mystery'),
(1063731, 'Obecność', 'https://image.tmdb.org/t/p/original/ymB7nzBRhjeVvOoONJbGuhWqXDQ.jpg', 'Paranormal investigators Ed and Lorraine Warren work to help a family terrorized by a dark presence in their farmhouse. Forced to confront a powerful entity, the Warrens find themselves caught in the most terrifying case of their lives.', 112, '15', '2013-07-18', 'Horror/Thriller'),
(1063732, 'Squared', 'https://image.tmdb.org/t/p/original/swekafx7YdZP6629gsNBAVgclUm.jpg', 'A one night stand gets competitive when two guys find out they are both tops.', 16, '0+', '2014-09-20', 'Romance/Comedy'),
(1063733, 'The Undertaker', 'https://image.tmdb.org/t/p/original/omc9Lb1IGVIUk0QiFBs1olX3Lln.jpg', 'A deranged undertaker kills various people to keep as his friends in his seedy funeral home.', 89, '0+', '1988-11-01', 'Horror'),
(1063734, 'Pocahontas', 'https://image.tmdb.org/t/p/original/8nFrCqe1Lp29UuuFBMFv2lReKEz.jpg', 'Set in Colonial America, Pocahontas has become a story of historical value known and loved internationally, among children of all ages. The film tells the story of the first English settlers in Virginia and the Native Americans who lived there.  It highlights the very different values of the two civilisations and particularly their attitude and respect for the land. It\'s a culture shock story and, on a personal level, a love story', 50, '0+', '1995-10-16', 'Animation'),
(1063735, 'Nieznani bohaterowie', 'https://image.tmdb.org/t/p/original/mtkAdP8l8Hx9bIF2JChLdpy3VQL.jpg', 'When David Smallbone\'s successful music company collapses, he moves his family from Australia to the United States in search of a brighter future. With nothing more than their six children, their suitcases, and their love of music, David and his pregnant wife Helen set out to rebuild their lives from the ground up. Based on a remarkable true story, a mum\'s faith stands against all odds; and inspires her husband and children to hold onto theirs.', 113, '0+', '2024-04-26', 'Drama/Music/Family'),
(1063736, 'Szesnaście świeczek', 'https://image.tmdb.org/t/p/original/A3WGCAgJF33kZdlxUdyXHYdbYax.jpg', 'With the occasion all but overshadowed by her sister\'s upcoming wedding, angst-ridden Samantha faces her 16th birthday with typical adolescent dread. Samantha pines for studly older boy Jake, but worries that her chastity will be a turnoff for the popular senior. Meanwhile, she must constantly rebuff the affections of nerdy Ted, who is unfortunately the only boy in school who seems to take an interest in her.', 93, '0+', '1984-05-04', 'Comedy/Romance'),
(1063737, 'Ostatnia kropla', 'https://image.tmdb.org/t/p/original/64JUsYfYigXgDL4uS61J0jHf92r.jpg', 'What will be her last straw? A devastatingly bad day pushes a hardworking single mother to the breaking point — and into a shocking act of desperation.', 105, '16', '2025-06-05', 'Thriller/Drama/Crime'),
(1063738, 'Gang z Boiska', 'https://image.tmdb.org/t/p/original/7sZx2Z5qx00Lty1COedll8Rs72E.jpg', 'Under the leadership of their counselor, teenagers at a juvenile detention center gain self-esteem by playing football together. Based on a true story.', 125, '0+', '2006-09-15', 'Crime/Drama'),
(1063739, 'Beach House', 'https://image.tmdb.org/t/p/original/nYz6aON2AvKXZNZAnI0pAiV0ZeX.jpg', 'Emma\'s quiet beach retreat takes an unsettling turn with the arrival of an enigmatic artist out of her mother\'s past. He challenges, enthralls, and frightens her, as she comes to suspect him of a terrible crime.', 87, '0+', '2017-10-20', 'Thriller/Mystery'),
(1063740, 'Inner Demons', 'https://image.tmdb.org/t/p/original/eTL7YduFGtcI1EsfZKLNvhf9CRM.jpg', 'After a near death experience, a young woman with a troubled past is tortured by visions and hallucinations as she fears she has brought something back with her from the afterlife. The woman becomes terrified her \"inner demons\" will take control to the point of no return. Is it too late to save her own soul? An ode to atmospheric creepy horror films Carnival of Souls, Jacobs Ladder with a smidgen of Drag Me to Hell and Evil Dead thrown in.', 0, '0+', '2024-11-05', NULL),
(1063741, 'Agent Orange', 'https://image.tmdb.org/t/p/original/9I3P8NFxktzh3DkbTKvplKCRb4T.jpg', 'A hooded youth carrying a goldfish in a plastic bag walks aimlessly through an underground NYC subway stop that has the look of a Wong Kar Wai film. Through the crowd comes a young woman all in orange, from her hair, sunglasses, lipstick, jewelry, and clothes to her nail polish. She drops a plastic bag containing a goldfish. He picks it up, gives chase, and stares at her after the train door has closed before he can reach her. He takes her photograph. The next day, wearing the same jacket, he waits for her, but on the wrong platform - again he sees her, runs, and reaches the train to stare at her as it pulls away. He has a surprise for her. Will all this ever bear fruit?', 5, '0+', '2004-11-16', 'Romance'),
(1063742, 'The Monster', 'https://image.tmdb.org/t/p/original/kOyxl0PCoYsZybEZnN32tOR2y0G.jpg', 'A general store clerk and aspiring detective investigates a mysterious disappearance that took place quite close to an empty insane asylum.', 86, '0+', '1925-03-16', 'Comedy/Horror/Mystery'),
(1063743, 'Czub-Czuby', 'https://image.tmdb.org/t/p/original/1MtQFiKWSlr5D8jUqYtfDVTld6J.jpg', 'A janitor at an alien night-club gets his wish to be a singer.', 5, '0+', '2002-07-03', 'Animation/Science Fiction/Comedy'),
(1063744, 'Dziewczyna Bad Boya', 'https://image.tmdb.org/t/p/original/nLiLTJta1pkGASjKiIxQsfLsRZb.jpg', 'Dallas, a burdened but headstrong dancer, is determined to get into the best dance school in the country—her late mother’s alma mater. However, that dream is suddenly derailed when the cheeky yet secretly grieving football star, Drayton, crashes into her life with a unique story of his own. Will the two of them be able to grow into their dreams together, or will their dreams be sidelined?', 99, '0+', '2025-02-06', 'Comedy/Romance'),
(1063745, 'The Comedians', 'https://image.tmdb.org/t/p/original/xlFWqgh0Uyyn21kIaDlRgJk0YYA.jpg', 'American and British tourists get caught up in political unrest in Haiti.', 152, '0+', '1967-10-31', 'Drama'),
(1063746, 'Lenny Blue', 'https://image.tmdb.org/t/p/original/dWVOKjJel8yy72BH2EgdTnFFrz0.jpg', 'Two years after the events of Tough Love, Lenny Milton has been transferred, but still finds that he is hated by his colleagues, who have branded him a grass. Meanwhile, when a friend of his Lenny\'s son dies during a heroin-related overdose, a drug-related gang war breaks out, and Lenny seizes his opportunity to re-ignite his feud with drug trafficker Barry Hindes. Obsessed with bring Hindes to justice, Lenny ignores the advice of his colleagues as he sees a chance for vengeance.', 141, '0+', '2002-07-01', 'Drama/Crime'),
(1063747, 'Kapsuła', 'https://image.tmdb.org/t/p/original/9X01Tq2U9mFCdJSdkUkRKnbJQcV.jpg', 'Guy is an experienced British fighter pilot who is in command of Britain\'s first manned mission to space. He has trained for this for three years at the height of the Cold War and now he is alone in space with a malfunctioning capsule. He has limited contact with the UK, some unusual communication with the US and some unorthodox communication with Roscosmos deep in Soviet Russia. Who will help him? Will he make the right choice?', 91, '0+', '2015-12-23', 'Drama/Science Fiction'),
(1063748, 'Sherdil', 'https://image.tmdb.org/t/p/original', 'Separated from his family, consisting of his dad, Ramkumar; mom, Mayadevi, and brother, Sanjay, Allahabad-based Prakash Saxena takes to a life of crime, calls himself Shera, but continues to search for them. He subsequently finds out that the person who knows their whereabouts is a Bombay-based male by the name of Shobhraj. He re-locates to Bombay, and this is where circumstances may force him to abandon his quest, for he will not only be arrested and held in prison, but also inadvertently jeopardize the lives of his family. - Written by rAjOo (gunwanti@hotmail.com)', 148, '0+', '1990-09-06', NULL),
(1063749, 'Wojownicy burzy', 'https://image.tmdb.org/t/p/original/rbziEQVh5qvFAeBCWCObfZlB0ea.jpg', 'Wind and Cloud find themselves up against a ruthless Japanese warlord intent on invading China.', 110, '0+', '2009-12-10', 'Action/Adventure/Fantasy'),
(1063750, 'The Remnant', 'https://image.tmdb.org/t/p/original/1sDTrClP9dh38EkqECoYIseYVLt.jpg', 'A team of con artists posing as paranormal investigators steal from the home of an affluent elderly woman, only to find themselves unleashing a dormant malevolent spirit.', 17, '0+', '2019-11-26', 'Horror'),
(1063751, 'Obecność 2', 'https://image.tmdb.org/t/p/original/wFCMrX1l3wbm0UK3WxMpzsfCTss.jpg', 'Lorraine and Ed Warren travel to north London to help a single mother raising four children alone in a house plagued by malicious spirits.', 134, '16', '2016-06-08', 'Horror'),
(1063752, 'Larong Bata', 'https://image.tmdb.org/t/p/original', 'It tells the story of Marlon a pathetic student but excellent in class who is regularly picked-on by his classmates and even cyber-violated by using a cellphone to film the attack. Dessa, a 16-year-old girl and a victim of child molestation, is being relentlessly bullied by three of her classmates as she tries hard to improve on herself. Amy, a junior high school student on the other hand is a social climber trying her best to please everyone but ended up being hated and despised. Gelo, an elementary pupil with average skills suffers emotional pain after a series of physical and mental abuse by his classmate and former basketball teammate. One final incident of bullying sends him over the edge and leads him to almost commit an act of violence that stunned the entire school community. The whole story is presented comically, highly amusing and entertaining for minor audiences but the message of bullying is emphasized and addressed.', 0, '0+', '2012-10-20', 'Drama'),
(1063753, 'Papierowy księżyc', 'https://image.tmdb.org/t/p/original/qRrXYEW9dQSOns3hyQuPaC4UlbO.jpg', 'During the Great Depression, a con man finds himself saddled with a young girl who may or may not be his daughter, and the two forge an unlikely partnership.', 102, '12', '1973-05-09', 'Comedy/Crime/Drama'),
(1063754, 'Rodzinne rewolucje', 'https://image.tmdb.org/t/p/original/p9CofRqLqUHrM66OADLiqmvZQGo.jpg', 'Recently divorced mom Lauren and widowed dad Jim let their friends push them into a blind date, which goes disastrously wrong. Unsurprisingly, neither wants to see the other ever again. However, fate intervenes when both Jim and Lauren, unbeknownst to each other, purchase one-half of the same vacation package at a South African resort for families, during spring break. They and their children are forced to share the same romantic suite and participate in a slew of family activities together.', 117, '16', '2014-05-21', 'Comedy/Romance');
