DELIMITER $$
--
-- Procedury
--
CREATE DEFINER=`root`@`localhost` PROCEDURE `generate_seats_for_screen` (IN `screenId` INT)  BEGIN
    DECLARE total INT;
    DECLARE seatIndex INT DEFAULT 0;
    DECLARE seatRow CHAR(1);
    DECLARE seatNumber INT;

    -- Pobranie liczby miejsc dla sali
    SELECT seats INTO total FROM screens WHERE id = screenId;

    WHILE seatIndex < total DO
        SET seatRow = CHAR(65 + (seatIndex DIV 12)); -- A, B, C, ...
        SET seatNumber = (seatIndex MOD 12) + 1;     -- 1–12

        VALUES (screenId, seatRow, seatNumber);

        SET seatIndex = seatIndex + 1;
    END WHILE;
END$$

DELIMITER ;

